def get_mac_vendor(mac: str) -> str:
    if not mac or len(mac) < 8:
        return ''
    prefix = mac.lower()[:8]
    return MAC_VENDORS.get(prefix, '')


def hex_dump(packet) -> str:
    raw = bytes(packet)
    lines = []

    for offset in range(0, len(raw), 16):
        chunk = raw[offset:offset + 16]

        left = ' '.join(f'{b:02x}' for b in chunk[:8])
        right = ' '.join(f'{b:02x}' for b in chunk[8:])

        hex_part = f'{left}  {right}'

        ascii_part = ''.join(
            chr(b) if b in PRINTABLE else '.'
            for b in chunk
        )

        lines.append(
            f'{offset:04x}  {hex_part:<48}  {ascii_part}'
        )

    return '\n'.join(lines)


def _byte_mapping(
    base_offset: int,
    relative_offset: int,
    length: int,
    byte_source: str = PACKET_BYTE_SOURCE,
) -> Dict[str, Any]:
    try:
        start = int(relative_offset)
        size = int(length)
    except Exception:
        return {}

    if start < 0 or size <= 0:
        return {}

    data: Dict[str, Any] = {
        'offset': int(base_offset + start),
        'length': size,
    }
    if byte_source != PACKET_BYTE_SOURCE:
        data['byte_source'] = byte_source
    return data


def _tag_byte_source(node: Dict[str, Any], byte_source: str) -> None:
    if not isinstance(node, dict):
        return
    if 'offset' in node and 'length' in node:
        node['byte_source'] = byte_source
    for child in node.get('children', []) or []:
        if isinstance(child, dict):
            _tag_byte_source(child, byte_source)


def _ip_reassembly_section(metadata: dict, version: int) -> Dict[str, Any] | None:
    fragments = list(metadata.get('ip_reassembled_fragments', []) or [])
    if not fragments:
        return None
    reassembled_len = int(metadata.get('ip_reassembled_length', 0) or 0)
    if reassembled_len <= 0:
        reassembled_len = int(sum(int(seg.get('payload_length', 0) or 0) for seg in fragments))
    summary = ', '.join(
        f"#{int(seg.get('frame_number', 0) or 0)}({int(seg.get('payload_length', 0) or 0)})"
        for seg in fragments
    )
    children: List[Dict[str, Any]] = []
    for seg in fragments:
        start_pos = int(seg.get('payload_start', 0) or 0)
        seg_len = int(seg.get('payload_length', 0) or 0)
        end_pos = max(start_pos, start_pos + seg_len - 1)
        children.append({
            'title': f"[Frame: {int(seg.get('frame_number', 0) or 0)}, payload: {start_pos}-{end_pos} ({seg_len} bytes)]",
            **_byte_mapping(0, start_pos, seg_len, TCP_REASSEMBLED_BYTE_SOURCE),
        })
    children.append({'title': f'[Reassembled IPv{version} length: {reassembled_len}]'})
    reassembled_hex = str(metadata.get('ip_reassembled_payload_hex', '') or '')
    if reassembled_hex:
        children.append({
            'title': f'[Reassembled IPv{version} data [..]: {reassembled_hex[:160]}]',
            **_byte_mapping(0, 0, reassembled_len, TCP_REASSEMBLED_BYTE_SOURCE),
        })
    return {
        'title': f'[{len(fragments)} IPv{version} Fragments ({reassembled_len} bytes): {summary}]',
        'children': children,
    }


def _internet_checksum(data: bytes) -> int:
    if len(data) % 2:
        data += b'\x00'
    total = 0
    for index in range(0, len(data), 2):
        total += (data[index] << 8) | data[index + 1]
        total = (total & 0xFFFF) + (total >> 16)
    return (~total) & 0xFFFF


def _mac_display(mac: str) -> str:
    mac_text = str(mac or '')
    if mac_text.lower() == '01:80:c2:00:00:00':
        return f'Nearest-Customer-Bridge ({mac_text})'
    if mac_text.lower() == '01:80:c2:00:00:02':
        return f'Slow-Protocols ({mac_text})'
    if mac_text.lower() == '01:80:c2:00:00:0e':
        return f'Nearest-Bridge ({mac_text})'
    vendor = get_mac_vendor(mac_text)
    if vendor:
        suffix = ':'.join(mac_text.split(':')[-3:])
        return f'{vendor}_{suffix} ({mac_text})'
    return mac_text


def _mac_text_from_bytes(data: bytes) -> str:
    if len(data) < 6:
        return ''
    return ':'.join(f'{byte:02x}' for byte in data[:6])


def _ipv6_slaac_mac(address: str) -> str:
    try:
        packed = ipaddress.IPv6Address(str(address or '')).packed
    except Exception:
        return ''

    interface_identifier = packed[8:]
    if interface_identifier[3:5] != b'\xff\xfe':
        return ''

    mac_bytes = bytes([
        interface_identifier[0] ^ 0x02,
        interface_identifier[1],
        interface_identifier[2],
        interface_identifier[5],
        interface_identifier[6],
        interface_identifier[7],
    ])
    return _mac_text_from_bytes(mac_bytes)


def _icmpv6_lifetime_text(seconds: int) -> str:
    value = int(seconds)
    if value > 0 and value % 86400 == 0:
        days = value // 86400
        return f'{days} day' if days == 1 else f'{days} days'
    return f'{value} second' if value == 1 else f'{value} seconds'


def _is_cdp_packet(packet) -> bool:
    try:
        if packet.haslayer(SNAP):
            oui = int(getattr(packet[SNAP], 'OUI', 0) or 0)
            code = int(getattr(packet[SNAP], 'code', 0) or 0)
            return oui == 0x00000C and code == 0x2000
    except Exception:
        pass
    return False


def _mpls_inner_ip(packet):
    try:
        if not packet.haslayer(Ether):
            return None
        eth_type = int(getattr(packet[Ether], 'type', 0) or 0)
        if eth_type != 0x8847:
            return None
        raw_bytes = bytes(packet)
        offset = 14
        while offset + 4 <= len(raw_bytes):
            label_word = int.from_bytes(raw_bytes[offset:offset + 4], 'big')
            offset += 4
            if label_word & 0x100:
                break
        if offset >= len(raw_bytes) or raw_bytes[offset] >> 4 != 4:
            return None
        return IP(raw_bytes[offset:])
    except Exception:
        return None


def _effective_ip_layer(packet):
    try:
        if packet.haslayer(IPv6):
            return packet[IPv6]
    except Exception:
        pass
    if packet.haslayer(IP):
        return packet[IP]
    try:
        pppoe = packet[PPPoE] if packet.haslayer(PPPoE) else None
        if pppoe is not None and packet.haslayer(PPP):
            ppp_protocol = int(getattr(packet[PPP], 'proto', 0) or 0)
            if ppp_protocol == 0x0057:
                ppp_payload = bytes(getattr(packet[PPP], 'payload', b''))
                if len(ppp_payload) >= 40:
                    ipv6_layer = IPv6(ppp_payload)
                    if ipv6_layer.version == 6:
                        return ipv6_layer
    except Exception:
        pass
    return _mpls_inner_ip(packet)


def _effective_tcp_layer(packet, ip_layer=None):
    if packet.haslayer(TCP):
        return packet[TCP]
    effective_ip = ip_layer if ip_layer is not None else _effective_ip_layer(packet)
    if effective_ip is not None and effective_ip.haslayer(TCP):
        return effective_ip[TCP]
    return None


def _effective_udp_layer(packet, ip_layer=None):
    if packet.haslayer(UDP):
        return packet[UDP]
    effective_ip = ip_layer if ip_layer is not None else _effective_ip_layer(packet)
    if effective_ip is not None and effective_ip.haslayer(UDP):
        return effective_ip[UDP]
    return None


def _ipv4_payload_length(ip_layer):
    try:
        total_len = int(getattr(ip_layer, 'len', 0) or 0)
        header_len = int(getattr(ip_layer, 'ihl', 5) or 5) * 4
        if total_len >= header_len:
            return total_len - header_len
    except Exception:
        pass
    return None


def _tcp_payload_bytes(packet, tcp_layer):
    tcp_payload = getattr(tcp_layer, 'payload', b'')
    raw_original = getattr(tcp_payload, 'original', None)
    if isinstance(raw_original, (bytes, bytearray)) and raw_original:
        raw_payload = bytes(raw_original)
    else:
        raw_payload = bytes(tcp_payload)
    try:
        if packet is not None and packet.haslayer(Raw):
            raw_layer_bytes = bytes(packet[Raw])
            if len(raw_layer_bytes) > len(raw_payload):
                raw_payload = raw_layer_bytes
    except Exception:
        pass

    def _slice_from_packet(expected_len: int | None = None) -> bytes:
        if packet is None:
            return b''
        try:
            raw_packet = bytes(packet)
            if packet.haslayer(IPv6):
                # Locate the TCP header position by computing how many bytes come
                # before it in the raw packet.  Using the total size of the scapy
                # TCP layer (header + payload) is robust across all encapsulations
                # (bare IPv6, 6-in-4, GRE tunnels, etc.) and avoids the need for
                # hardcoded offsets that would be wrong for tunnelled packets.
                tcp_bytes = bytes(tcp_layer)
                if not tcp_bytes or len(tcp_bytes) > len(raw_packet):
                    return b''
                tcp_start = len(raw_packet) - len(tcp_bytes)
                tcp_header_len = int(getattr(tcp_layer, 'dataofs', 5) or 5) * 4
                plen = int(getattr(packet[IPv6], 'plen', 0) or 0)
                payload_len = max(0, plen - tcp_header_len)
                if isinstance(expected_len, int) and expected_len > 0:
                    payload_len = min(payload_len, expected_len)
                start = tcp_start + tcp_header_len
                end = min(len(raw_packet), start + payload_len)
                return raw_packet[start:end] if end > start else b''
            if packet.haslayer(IP):
                ip_off = 14 + (4 if packet.haslayer(Dot1Q) else 0)
                ip_header_len = int(getattr(packet[IP], 'ihl', 5) or 5) * 4
                tcp_off = ip_off + ip_header_len
                tcp_header_len = int(getattr(tcp_layer, 'dataofs', 5) or 5) * 4
                plen = int(getattr(packet[IP], 'len', 0) or 0)
                payload_len = max(0, plen - ip_header_len - tcp_header_len)
                if isinstance(expected_len, int) and expected_len > 0:
                    payload_len = min(payload_len, expected_len)
                start = tcp_off + tcp_header_len
                end = min(len(raw_packet), start + payload_len)
                return raw_packet[start:end] if end > start else b''
        except Exception:
            return b''
        return b''

    sliced = _slice_from_packet()
    if sliced:
        return sliced
    return raw_payload


def _udp_payload_bytes(packet, udp_layer):
    udp_payload = getattr(udp_layer, 'payload', b'')
    raw_original = getattr(udp_payload, 'original', None)
    if isinstance(raw_original, (bytes, bytearray)) and raw_original:
        raw_payload = bytes(raw_original)
    else:
        raw_payload = bytes(udp_payload)

    try:
        udp_len = int(getattr(udp_layer, 'len', 0) or 0)
        if udp_len >= 8:
            return raw_payload[:max(0, min(len(raw_payload), udp_len - 8))]
    except Exception:
        pass
    return raw_payload


def _frame_payload_length(packet):
    try:
        if packet.haslayer(ARP):
            return 14 + 28

        effective_ip = _effective_ip_layer(packet)
        if effective_ip is not None:
            total_len = int(getattr(effective_ip, 'len', 0) or 0)
            if total_len > 0:
                if packet.haslayer(IP):
                    return 14 + total_len
                if packet.haslayer(Ether):
                    eth_type = int(getattr(packet[Ether], 'type', 0) or 0)
                    if eth_type == 0x8847:
                        raw_bytes = bytes(packet)
                        offset = 14
                        while offset + 4 <= len(raw_bytes):
                            label_word = int.from_bytes(raw_bytes[offset:offset + 4], 'big')
                            offset += 4
                            if label_word & 0x100:
                                break
                        return offset + total_len

        if packet.haslayer(IPv6):
            payload_len = int(getattr(packet[IPv6], 'plen', 0) or 0)
            if payload_len > 0:
                return 14 + 40 + payload_len
    except Exception:
        pass
    return None


def _ip_payload_bytes(packet, ip_layer=None):
    effective_ip = ip_layer if ip_layer is not None else _effective_ip_layer(packet)
    if effective_ip is not None:
        raw_payload = bytes(getattr(effective_ip, 'payload', b''))
        ip_payload_len = _ipv4_payload_length(effective_ip)
        if ip_payload_len is not None:
            return raw_payload[:ip_payload_len]
        return raw_payload

    if packet is not None and packet.haslayer(IPv6):
        try:
            raw_payload = bytes(packet[IPv6].payload)
            payload_len = int(getattr(packet[IPv6], 'plen', 0) or 0)
            return raw_payload[:payload_len]
        except Exception:
            pass

    return b''

def _homeplug_payload(packet) -> bytes:
    try:
        if not packet.haslayer(Ether):
            return b''
        raw = bytes(packet)
        if len(raw) < 14:
            return b''
        eth_type = int(getattr(packet[Ether], 'type', 0) or 0)
        if eth_type == 0x8100:
            if len(raw) < 18:
                return b''
            return raw[18:]
        return raw[14:]
    except Exception:
        return b''


def _infer_padding(packet, record):
    frame_len = int(getattr(record, 'length', len(bytes(packet))) or len(bytes(packet)))

    if packet.haslayer('Padding'):
        try:
            tail_bytes = bytes(packet['Padding'])
            tail_offset = max(0, frame_len - len(tail_bytes))
            return tail_bytes.hex(), len(tail_bytes), tail_offset, '', 0
        except Exception:
            return '', 0, 0, '', 0

    payload_length = _frame_payload_length(packet)
    if payload_length is None or payload_length >= frame_len:
        return '', 0, 0, '', 0

    try:
        trailer_bytes = bytes(packet)[payload_length:frame_len]
    except Exception:
        return '', 0, 0, '', 0

    if not trailer_bytes:
        return '', 0, 0, '', 0

    return trailer_bytes.hex(), len(trailer_bytes), payload_length, '', 0


def _is_l2tpv3_control_payload(payload: bytes) -> bool:
    if len(payload) < 16:
        return False
    flags = int.from_bytes(payload[4:6], 'big')
    return bool(flags & 0x8000) and (flags & 0x000F) == 3


def packet_summary_tree(packet, record) -> List[Dict[str, Any]]:

    sections: List[Dict[str, Any]] = []

    offset = 0
    payload_handled = False
    parsed_mpls_inner_ip = False
    raw_payload_consumed = False

    metadata = getattr(record, 'metadata', {}) or {}
    effective_ip_layer = _effective_ip_layer(packet)
    effective_tcp_layer = _effective_tcp_layer(packet, effective_ip_layer)
    effective_udp_layer = _effective_udp_layer(packet, effective_ip_layer)
    capwap_transport = str(metadata.get('capwap_transport', '') or '')
    is_capwap = capwap_transport in {'control', 'data'}
    is_ip_fragmented = bool(metadata.get('ip_is_fragmented', False))
    fragment_role = str(metadata.get('ip_fragment_role', '') or '')
    is_first_fragment = is_ip_fragmented and fragment_role == 'first'
    is_last_fragment = is_ip_fragmented and fragment_role == 'last'

    def _idx(name: str) -> int:
        val = metadata.get(name, -1)
        if val is None:
            return -1
        try:
            return int(val)
        except Exception:
            return -1

    ether_stream_index = _idx('ether_stream_index')
    ip_stream_index = _idx('ip_stream_index')
    ipv6_stream_index = _idx('ipv6_stream_index')
    tcp_stream_index = _idx('tcp_stream_index')
    udp_stream_index = _idx('udp_stream_index')

    sections.append(
        _frame_section(record)
    )

    has_fpp = bool(
        metadata.get('frame_has_fpp', False)
        or bool(getattr(packet, 'fpp_preamble', b''))
        or packet.haslayer('MPacketPreamble')
    )
    if has_fpp:
        fpp_section, fpp_header_len = _fpp_section(packet, offset)
        sections.append(fpp_section)
        offset += int(fpp_header_len)

    if packet.haslayer(CookedLinux):
        sections.append(_sll_section(packet[CookedLinux], offset))
        offset += 16

    if packet.haslayer(Dot3):
        padding_hex, padding_len, padding_offset, fcs_hex, fcs_offset = _infer_padding(packet, record)

        sections.append(
            _dot3_section(
                packet[Dot3],
                offset,
                ether_stream_index,
                padding_hex,
                padding_offset,
                padding_len,
                fcs_hex,
                fcs_offset,
            )
        )

        offset += 14

        if packet.haslayer(LLC):
            snap_layer = packet[SNAP] if packet.haslayer(SNAP) else None
            sections.append(
                _llc_section(
                    packet[LLC],
                    snap_layer,
                    offset,
                )
            )
            offset += 3 + (5 if snap_layer is not None else 0)

            if _is_cdp_packet(packet):
                cdp_payload = bytes(getattr(snap_layer, 'payload', b'')) if snap_layer is not None else b''
                sections.append(_cdp_section(cdp_payload, offset))
                payload_handled = True
            elif getattr(record, 'protocol', '') == 'DTP':
                dtp_payload = bytes(getattr(snap_layer, 'payload', b'')) if snap_layer is not None else b''
                sections.append(_dtp_section(dtp_payload, offset))
                payload_handled = True

    elif packet.haslayer(Ether):

        padding_hex, padding_len, padding_offset, fcs_hex, fcs_offset = _infer_padding(packet, record)

        sections.append(
            _ether_section(
                packet[Ether],
                offset,
                ether_stream_index,
                padding_hex,
                padding_offset,
                padding_len,
                fcs_hex,
                fcs_offset,
            )
        )

        offset += 14

        if packet.haslayer(Dot1Q):
            sections.append(_vlan_section(packet[Dot1Q], offset))
            offset += 4

            if packet.haslayer(LLC):
                snap_layer = packet[SNAP] if packet.haslayer(SNAP) else None
                sections.append(_llc_section(packet[LLC], snap_layer, offset))
                offset += 3 + (5 if snap_layer is not None else 0)
                if _is_cdp_packet(packet):
                    cdp_payload = bytes(getattr(snap_layer, 'payload', b'')) if snap_layer is not None else b''
                    sections.append(_cdp_section(cdp_payload, offset))
                    payload_handled = True

        if getattr(record, 'protocol', '') == 'LACP':
            slow_payload = bytes(packet)[offset:]
            if slow_payload:
                sections.append(_slow_protocols_section(slow_payload, offset))
                if len(slow_payload) > 1:
                    sections.append(_lacp_section(slow_payload[1:], offset + 1))
                payload_handled = True

        try:
            eth_type = int(getattr(packet[Ether], 'type', 0) or 0)
        except Exception:
            eth_type = 0

        if eth_type == 0x8847:
            mpls_payload = bytes(packet)[offset:]
            if len(mpls_payload) >= 4:
                sections.append(_mpls_section(mpls_payload, offset))
                offset += 4
                try:
                    ip_pkt = IP(mpls_payload[4:])
                    effective_ip_layer = ip_pkt
                    effective_tcp_layer = _effective_tcp_layer(packet, ip_pkt)
                    effective_udp_layer = _effective_udp_layer(packet, ip_pkt)
                    ip_len = int(getattr(ip_pkt, 'ihl', 5) or 5) * 4
                    sections.append(_ip_section(ip_pkt, offset, ip_stream_index))
                    offset += ip_len
                    inner_payload = _ip_payload_bytes(packet, ip_pkt)
                    inner_proto = int(getattr(ip_pkt, 'proto', 0) or 0)
                    if inner_proto == 115 and len(inner_payload) >= 4:
                        l2tp_payload = inner_payload
                        sections.append(_l2tpv3_section(l2tp_payload, offset))
                        if len(l2tp_payload) > 4 and not _is_l2tpv3_control_payload(l2tp_payload):
                            sections.append(_bytes_data_section(l2tp_payload[4:], offset + 4))
                        payload_handled = True
                    parsed_mpls_inner_ip = True
                    raw_payload_consumed = True
                except Exception:
                    pass

        inner_eth_type = 0
        if packet.haslayer(Dot1Q):
            try:
                inner_eth_type = int(getattr(packet[Dot1Q], 'type', 0) or 0)
            except Exception:
                inner_eth_type = 0

        if eth_type == 0x9000 or (eth_type == 0x8100 and inner_eth_type == 0x9000):
            loop_payload = bytes(packet)[offset:]
            sections.append(_loop_section(loop_payload, offset))
            loop_header_len = min(len(loop_payload), 6)
            if len(loop_payload) > loop_header_len:
                sections.append(_bytes_data_section(loop_payload[loop_header_len:], offset + loop_header_len))
            payload_handled = True

        pppoe_meta = metadata.get('pppoe', {}) if isinstance(metadata.get('pppoe'), dict) else {}
        should_render_pppoe = (
            bool(pppoe_meta)
            or getattr(record, 'protocol', '') in {'PPPoED', 'PPP', 'PPP LCP', 'PPP IPCP', 'PPP IPV6CP', 'SIP', 'SIP/SDP', 'RTP'}
        )
        if should_render_pppoe:
            pppoe_payload = bytes(packet)[offset:]
            if len(pppoe_payload) >= 6:
                pppoe_len = int.from_bytes(pppoe_payload[4:6], 'big')
                pppoe_total_len = min(len(pppoe_payload), 6 + pppoe_len)
            else:
                pppoe_total_len = len(pppoe_payload)

            sections.append(_pppoe_section(pppoe_payload, offset))

            if len(pppoe_payload) >= 6:
                pppoe_code = int(pppoe_payload[1])
                if pppoe_code == 0x00:
                    ppp_payload = pppoe_payload[6:pppoe_total_len]
                    ppp_offset = offset + 6
                    if len(ppp_payload) >= 2:
                        sections.append(_ppp_section(ppp_payload, ppp_offset))
                        ppp_proto = int.from_bytes(ppp_payload[:2], 'big')
                        ppp_control_payload = ppp_payload[2:]
                        if ppp_proto == 0xC021:
                            sections.append(_ppp_lcp_section(ppp_control_payload, ppp_offset + 2))
                        elif ppp_proto == 0x8021:
                            sections.append(_ppp_ipcp_section(ppp_control_payload, ppp_offset + 2))
                        elif ppp_proto == 0x8057:
                            sections.append(_ppp_ipv6cp_section(ppp_control_payload, ppp_offset + 2))

                        # For IP-over-PPP packets, consume only PPPoE+PPP headers (8 bytes)
                        # so IPv4/UDP/SIP/RTP offsets remain correct.
                        if ppp_proto in {0x0021, 0x0057}:
                            offset += 8
                        else:
                            payload_handled = True
                            raw_payload_consumed = True
                            offset += pppoe_total_len
                else:
                    payload_handled = True
                    raw_payload_consumed = True
                    offset += pppoe_total_len

    if packet.haslayer(ARP):

        sections.append(
            _arp_section(
                packet[ARP],
                offset
            )
        )

        offset += 28

    # Check if IP (IPv4) is the outer layer
    has_ip = packet.haslayer(IP)
    has_ipv6 = packet.haslayer(IPv6)
    ip_is_outer = False
    if has_ip:
        if not has_ipv6:
            ip_is_outer = True
        else:
            curr = packet
            while curr:
                if isinstance(curr, IP):
                    ip_is_outer = True
                    break
                if isinstance(curr, IPv6):
                    break
                curr = curr.payload

    if ip_is_outer and not parsed_mpls_inner_ip:
        ip_layer = packet[IP]

        ip_len = (
            int(getattr(ip_layer, 'ihl', 5) or 5) * 4
        )

        sections.append(
            _ip_section(
                ip_layer,
                offset,
                ip_stream_index,
                record=record,
            )
        )

        offset += ip_len

        if packet.haslayer(GRE):
            raw_packet = bytes(packet)
            first_gre = None
            second_gre = None
            try:
                first_gre = packet.getlayer(GRE, 1)
            except Exception:
                first_gre = None
            try:
                second_gre = packet.getlayer(GRE, 2)
            except Exception:
                second_gre = None

            first_gre_len = _gre_header_length(raw_packet, offset)
            if first_gre is not None and first_gre_len > 0:
                sections.append(_gre_section(raw_packet, offset))
                first_proto = int(getattr(first_gre, 'proto', 0) or 0)
                offset += first_gre_len

                if first_proto == 0x0800:
                    try:
                        inner_ip = packet.getlayer(IP, 2)
                    except Exception:
                        inner_ip = None
                    if inner_ip is not None:
                        inner_ip_len = int(getattr(inner_ip, 'ihl', 5) or 5) * 4
                        sections.append(_ip_section(inner_ip, offset, ip_stream_index, record=record))
                        offset += inner_ip_len

                if second_gre is not None:
                    second_gre_len = _gre_header_length(raw_packet, offset)
                    if second_gre_len > 0:
                        second_proto = int(getattr(second_gre, 'proto', 0) or 0)
                        suffix = 'Possible GRE keepalive packet' if second_proto == 0 else ''
                        sections.append(_gre_section(raw_packet, offset, suffix))
                        offset += second_gre_len

            if getattr(record, 'protocol', '') in {'SSHv2', 'SSH'}:
                gre_payload = _payload_bytes(packet)
                marker = b'SSH-'
                pos = gre_payload.find(marker)
                if pos >= 0:
                    sections.append(_ssh_section(gre_payload[pos:], offset, record))
                    payload_handled = True

    if packet.haslayer(IPv6):

        ipv6_section = _ipv6_section(
            packet[IPv6],
            offset,
            ipv6_stream_index,
            record=record,
        )
        sections.append(ipv6_section)

        offset += 40

        if packet.haslayer(IPv6ExtHdrHopByHop):
            hopopts_layer = packet[IPv6ExtHdrHopByHop]
            ipv6_section.setdefault('children', []).append(_ipv6_hopopts_section(hopopts_layer, offset))
            offset += max(8, (int(getattr(hopopts_layer, 'len', 0) or 0) + 1) * 8)
        if packet.haslayer(IPv6ExtHdrFragment):
            frag_layer = packet[IPv6ExtHdrFragment]
            frag_node = _ipv6_fragment_section(frag_layer, offset)
            ipv6_children = ipv6_section.setdefault('children', [])
            insert_index = len(ipv6_children)
            for idx, child in enumerate(ipv6_children):
                title = str(child.get('title', '') or '')
                if title.startswith('[Reassembled IPv6 in frame:') or ('IPv6 Fragments (' in title):
                    insert_index = idx
                    break
            ipv6_children.insert(insert_index, frag_node)
            offset += 8

        if getattr(record, 'protocol', '') in {'ICMPV6', 'ICMPv6'}:
            if packet.haslayer(IPv6ExtHdrHopByHop):
                icmpv6_payload = bytes(getattr(packet[IPv6ExtHdrHopByHop], 'payload', b''))
            else:
                icmpv6_payload = bytes(getattr(packet[IPv6], 'payload', b''))
            if icmpv6_payload:
                icmpv6_node = _icmpv6_section(icmpv6_payload, offset, record)
                sections.append(icmpv6_node)
                for extra in list(icmpv6_node.pop('_extra_sections', []) or []):
                    if isinstance(extra, dict):
                        sections.append(extra)
                payload_handled = True
                offset += len(icmpv6_payload)
        elif getattr(record, 'protocol', '') == 'OSPF':
            if packet.haslayer(IPv6ExtHdrHopByHop):
                upper_layer = packet[IPv6ExtHdrHopByHop]
            else:
                upper_layer = packet[IPv6]
            ospf_payload = bytes(getattr(upper_layer, 'payload', b''))
            ospf_offset = offset
            try:
                upper_nh = int(getattr(upper_layer, 'nh', -1) or -1)
                if upper_nh == 51 and len(ospf_payload) >= 12:
                    ah_next_header = int(ospf_payload[0])
                    ah_header_len = (int(ospf_payload[1]) + 2) * 4
                    if ah_next_header == 89 and len(ospf_payload) >= ah_header_len:
                        ospf_payload = ospf_payload[ah_header_len:]
                        ospf_offset += ah_header_len
            except Exception:
                pass
            if ospf_payload:
                sections.append(_ospf_section(ospf_payload, ospf_offset))
                payload_handled = True
        elif getattr(record, 'protocol', '') == 'ESP':
            esp_payload = bytes(getattr(packet[IPv6], 'payload', b''))
            if esp_payload:
                sections.append(_esp_section(esp_payload, offset))
                payload_handled = True

    if is_first_fragment:
        frag_data = b''
        if packet.haslayer(IP):
            try:
                frag_data = bytes(getattr(packet[IP], 'payload', b''))
            except Exception:
                frag_data = b''
        elif packet.haslayer(IPv6ExtHdrFragment):
            try:
                frag_data = bytes(getattr(packet[IPv6ExtHdrFragment], 'payload', b''))
            except Exception:
                frag_data = b''
        if frag_data:
            frag_hex = frag_data.hex()
            preview = frag_hex[:240]
            sections.append({
                'title': f'Data ({len(frag_data)} bytes)',
                'offset': offset,
                'length': len(frag_data),
                'children': [
                    {'title': f'Data [...]: {preview}', 'offset': offset, 'length': len(frag_data)},
                    {'title': f'[Length: {len(frag_data)}]'},
                ],
            })
            payload_handled = True
            raw_payload_consumed = True

    if effective_tcp_layer is not None and not is_first_fragment:

        tcp_layer = effective_tcp_layer

        tcp_len = (
            int(getattr(tcp_layer, 'dataofs', 5) or 5) * 4
        )

        sections.append(
            _tcp_section(
                tcp_layer,
                offset,
                tcp_stream_index,
                record,
            )
        )

        offset += tcp_len

        tcp_reassembly_section = _tcp_reassembly_section(record)
        if tcp_reassembly_section is not None:
            sections.append(tcp_reassembly_section)

        tcp_payload = _tcp_payload_bytes(getattr(record, 'raw', None), tcp_layer)
        if getattr(record, 'protocol', '') == 'BGP' and tcp_payload:
            sections.append(_bgp_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'ECHO' and tcp_payload:
            sections.append(_echo_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'DISCARD' and tcp_payload:
            sections.append(_discard_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'DAYTIME' and tcp_payload:
            sections.append(_daytime_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'Chargen' and tcp_payload:
            sections.append(_chargen_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'TIME' and tcp_payload:
            sections.append(_time_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'LDP' and tcp_payload:
            sections.append(_ldp_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'FTP' and tcp_payload:
            sections.append(_ftp_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'FTP-DATA' and tcp_payload:
            sections.append(_ftp_data_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'HTTP', 'HTTP/XML', 'RTSP', 'OCSP', 'IPP'} and tcp_payload:
            protocol_name = str(getattr(record, 'protocol', '') or '')
            http_kind = str(metadata.get('http_kind', '') or '').strip()
            http_header_len = metadata.get('http_header_len', None)
            http_incomplete = bool(metadata.get('http_incomplete', False))
            first_line = tcp_payload.split(b'\r\n', 1)[0].upper() if tcp_payload else b''
            looks_http = (
                first_line.startswith(b'HTTP/')
                or first_line.startswith(b'GET ')
                or first_line.startswith(b'POST ')
                or first_line.startswith(b'PUT ')
                or first_line.startswith(b'DELETE ')
                or first_line.startswith(b'HEAD ')
                or first_line.startswith(b'OPTIONS ')
                or first_line.startswith(b'PATCH ')
            )

            emit_http = True
            if protocol_name in {'OCSP', 'IPP'}:
                # For OCSP/IPP, avoid rendering a misleading HTTP block when this frame
                # only carries mid-stream payload and no parseable HTTP header.
                if not looks_http and (not http_kind or (http_incomplete and http_header_len in {None, 0})):
                    emit_http = False

            if emit_http:
                preliminary = _http_preliminary_section(record, offset)
                if preliminary is not None:
                    sections.append(preliminary)
                sections.append(_http_section(tcp_payload, offset, record))
            if getattr(record, 'protocol', '') == 'HTTP/XML':
                xml_section = _xml_body_section(record, offset)
                if xml_section is not None:
                    sections.append(xml_section)
            elif getattr(record, 'protocol', '') == 'OCSP':
                ocsp_section = _ocsp_section(record, offset)
                if ocsp_section is not None:
                    sections.append(ocsp_section)
            elif getattr(record, 'protocol', '') == 'IPP':
                ipp_section = _ipp_section(record, offset)
                if ipp_section is not None:
                    sections.append(ipp_section)
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RIPng' and tcp_payload == b'':
            udp_payload = bytes(getattr(effective_udp_layer, 'payload', b'')) if effective_udp_layer is not None else b''
            sections.append(_ripng_section(udp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'HSRP', 'HSRPv2'} and tcp_payload == b'':
            udp_payload = _udp_payload_bytes(packet, effective_udp_layer) if effective_udp_layer is not None else b''
            sections.append(_hsrp_section(udp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'SMTP', 'SMTP/IMF'} and tcp_payload:
            sections.append(_smtp_section(tcp_payload, offset, record))
            if getattr(record, 'protocol', '') == 'SMTP/IMF':
                sections.append(_imf_section(record, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'POP', 'POP/IMF'} and tcp_payload:
            sections.append(_pop_section(tcp_payload, offset, record))
            if getattr(record, 'protocol', '') == 'POP/IMF':
                sections.append(_pop_imf_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'KRB5' and tcp_payload:
            sections.append(_krb5_section(packet, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'LDAP' and tcp_payload:
            sections.append(_ldap_section(packet, tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'DCERPC', 'DRSUAPI', 'EPM', 'LSARPC', 'RPC_NETLOGON', 'SAMR'} and tcp_payload:
            if packet.haslayer('NBTSession'):
                sections.append(_nbss_section(tcp_payload, offset))
            if packet.haslayer('SMB2_Header'):
                sections.append(_smb2_section(packet, offset + 4, record))
            dcerpc_section = _dcerpc_section(tcp_payload, offset, record)
            sections.append(dcerpc_section)
            for extra_section in list(dcerpc_section.pop('_external_sections', []) or []):
                if isinstance(extra_section, dict):
                    sections.append(extra_section)
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'NBSS' and tcp_payload:
            sections.append(_nbss_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RDP' and tcp_payload:
            for sec in _rdp_tpkt_sections(tcp_payload, offset):
                sections.append(sec)
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'SMB', 'SMB2'} and tcp_payload:
            sections.append(_nbss_section(tcp_payload, offset))
            if getattr(record, 'protocol', '') == 'SMB':
                sections.append(_smb1_section(packet, offset + 4, record))
            else:
                sections.append(_smb2_section(packet, offset + 4, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'IMAP' and tcp_payload:
            sections.append(_imap_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'WHOIS':
            whois_payload = tcp_payload
            whois_uses_reassembled = False
            reassembled_hex = str(metadata.get('tcp_reassembled_data_hex', '') or '')
            if reassembled_hex:
                try:
                    whois_payload = bytes.fromhex(reassembled_hex)
                    whois_uses_reassembled = True
                except Exception:
                    whois_payload = tcp_payload
                    whois_uses_reassembled = False
            if not whois_payload:
                query_value = str(metadata.get('whois_query_value', '') or '')
                if query_value:
                    whois_payload = (query_value + '\n').encode('utf-8', errors='ignore')
            if whois_payload:
                whois_offset = 0 if whois_uses_reassembled else offset
                whois_section = _whois_section(whois_payload, whois_offset, record)
                if whois_uses_reassembled:
                    _tag_byte_source(whois_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(whois_section)
                payload_handled = True
        elif getattr(record, 'protocol', '') == 'TELNET' and tcp_payload:
            sections.append(_telnet_section(tcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'LPD' and tcp_payload:
            sections.append(_lpd_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RSH' and tcp_payload:
            sections.append(_rsh_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'Zabbix':
            sections.append(_zabbix_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'SSHv2', 'SSH'} and tcp_payload:
            sections.append(_ssh_section(tcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'TACACS+' and tcp_payload:
            sections.append(_tacacs_section(tcp_payload, offset))
            payload_handled = True
        elif bool(metadata.get('tcp_is_retransmission', False)) and tcp_payload:
            payload_handled = True

    elif effective_udp_layer is not None and not is_first_fragment:

        udp_layer = effective_udp_layer

        sections.append(
            _udp_section(
                udp_layer,
                offset,
                udp_stream_index,
                record,
            )
        )

        offset += 8

        try:
            sport = int(getattr(udp_layer, 'sport', 0) or 0)
            dport = int(getattr(udp_layer, 'dport', 0) or 0)
        except Exception:
            sport = dport = 0

        if getattr(record, 'protocol', '') in {'CAPWAP-Control', 'CAPWAP-Data', '802.11'} or is_capwap:
            capwap_payload = bytes(getattr(udp_layer, 'payload', b''))
            sections.append(_capwap_section(capwap_payload, offset, record))
            wlan = metadata.get('wlan', {}) if isinstance(metadata, dict) else {}
            if isinstance(wlan, dict) and wlan:
                sections.extend(_wlan_sections(wlan, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'ECHO':
            echo_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_echo_section(echo_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'DISCARD':
            discard_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_discard_section(discard_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'DAYTIME':
            daytime_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_daytime_section(daytime_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'Chargen':
            chargen_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_chargen_section(chargen_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'TIME':
            time_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_time_section(time_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'DHCPv6':
            dhcpv6_payload = bytes(getattr(udp_layer, 'payload', b''))
            sections.append(_dhcpv6_section(dhcpv6_payload, offset))
            payload_handled = True
        elif sport == 646 or dport == 646:
            ldp_payload = bytes(getattr(udp_layer, 'payload', b''))
            sections.append(_ldp_section(ldp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RIPng':
            ripng_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_ripng_section(ripng_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RIPv2':
            rip_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_ripv2_section(rip_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'Syslog':
            syslog_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_syslog_section(syslog_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'NTP':
            ntp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_ntp_section(ntp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'TFTP':
            tftp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_tftp_section(tftp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'SSDP':
            ssdp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_ssdp_section(ssdp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'GLBP':
            glbp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_glbp_section(glbp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'SNMP':
            snmp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_snmp_section(snmp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'LLMNR':
            llmnr_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_llmnr_section(llmnr_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'NBNS':
            nbns_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_nbns_section(nbns_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'PCP v2':
            pcp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_pcp_section(pcp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'UDP/XML':
            xml_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_udp_xml_section(xml_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'CLDAP':
            cldap_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_cldap_section(packet, cldap_payload, offset, record))
            payload_handled = True
        elif str(getattr(record, 'protocol', '') or '').startswith('TLS') and str(metadata.get('tls_embedded_transport', '') or '') == 'RDPUDP':
            rdpudp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_rdpudp_section(packet, rdpudp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'RDPUDP', 'RDPUDP2'}:
            rdpudp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_rdpudp_section(packet, rdpudp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'STUN':
            stun_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_stun_section(stun_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'SRTCP':
            srtcp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_srtcp_section(srtcp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'QUIC':
            quic_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_quic_section(quic_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'UDPENCAP':
            udpencap_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_udpencap_section(udpencap_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'MPEG TS':
            mpeg_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_mpeg_ts_section(mpeg_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'H.264':
            h264_payload = _udp_payload_bytes(packet, udp_layer)
            if len(h264_payload) >= 12 and (h264_payload[0] >> 6) == 2:
                sections.append(_rtp_section(h264_payload, offset, record))
            sections.append(_h264_section(h264_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'IPMB', 'RMCP+'}:
            rmcp_payload = _udp_payload_bytes(packet, udp_layer)
            rmcp_node = _rmcp_section(rmcp_payload, offset, record)
            sections.append(rmcp_node)
            for extra in list(rmcp_node.pop('_extra_sections', []) or []):
                if isinstance(extra, dict):
                    sections.append(extra)
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'CFLOW':
            cflow_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_cflow_section(cflow_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'SIP', 'SIP/SDP'}:
            sip_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_sip_section(sip_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RTP':
            rtp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_rtp_section(rtp_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'ISAKMP':
            isakmp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_isakmp_section(isakmp_payload, offset))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'BFD Control':
            bfd_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_bfd_control_section(bfd_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'BFD Echo':
            bfd_echo_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_bfd_echo_section(bfd_echo_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') == 'RADIUS':
            radius_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_radius_section(radius_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'DTLS', 'DTLSv1.2'}:
            dtls_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_dtls_section(dtls_payload, offset, record))
            payload_handled = True
        elif getattr(record, 'protocol', '') in {'HSRP', 'HSRPv2'}:
            hsrp_payload = _udp_payload_bytes(packet, udp_layer)
            sections.append(_hsrp_section(hsrp_payload, offset))
            payload_handled = True

    if effective_ip_layer is not None and not parsed_mpls_inner_ip:
        if getattr(record, 'protocol', '') == 'EIGRP':
            eigrp_payload = bytes(metadata.get('eigrp', {}).get('payload', b'') or b'')
            if eigrp_payload:
                sections.append(_eigrp_section(eigrp_payload, offset, record))
                payload_handled = True
        try:
            ip_proto = int(getattr(effective_ip_layer, 'proto', 0) or 0)
        except Exception:
            ip_proto = 0
        if ip_proto == 2:
            igmp_payload = _ip_payload_bytes(packet, effective_ip_layer)
            if getattr(record, 'protocol', '') == 'PIMv1':
                sections.append(_pim_section(igmp_payload, offset, 2))
                payload_handled = True
            else:
                sections.append(_igmp_section(igmp_payload, offset))
                payload_handled = True
        if ip_proto == 103 and getattr(record, 'protocol', '') == 'PIMv2':
            pim_payload = _ip_payload_bytes(packet, effective_ip_layer)
            sections.append(_pim_section(pim_payload, offset, 103))
            pim_meta = metadata.get('pim') if isinstance(metadata.get('pim'), dict) else {}
            pim_inner_hex = str(pim_meta.get('inner_payload_hex', '') or '')
            if pim_inner_hex:
                try:
                    inner_bytes = bytes.fromhex(pim_inner_hex)
                except Exception:
                    inner_bytes = b''
                if len(inner_bytes) >= 20 and (inner_bytes[0] >> 4) == 4:
                    try:
                        inner_ip = IP(inner_bytes)
                    except Exception:
                        inner_ip = None
                    if inner_ip is not None:
                        inner_offset = offset + 8
                        sections.append(_ip_section(inner_ip, inner_offset, int(metadata.get('ipv4_stream_index', 0) or 0), record))
                        if inner_ip.haslayer(UDP):
                            inner_udp = inner_ip[UDP]
                            sections.append(_udp_section(inner_udp, inner_offset + len(inner_ip) - len(bytes(inner_udp)), int(metadata.get('udp_stream_index', 0) or 0), record))
                            udp_payload = bytes(getattr(inner_udp, 'payload', b'') or b'')
                            if len(udp_payload) >= 188 and udp_payload[0] == 0x47:
                                sections.append(_mpeg_ts_section(udp_payload, inner_offset + len(inner_ip) - len(udp_payload)))
            payload_handled = True
        if ip_proto == 89:
            ospf_payload = bytes(getattr(effective_ip_layer, 'payload', b''))
            sections.append(_ospf_section(ospf_payload, offset))
            payload_handled = True
        if ip_proto == 115:
            l2tp_payload = _ip_payload_bytes(packet, effective_ip_layer)
            sections.append(_l2tpv3_section(l2tp_payload, offset))
            if len(l2tp_payload) > 4 and not _is_l2tpv3_control_payload(l2tp_payload):
                sections.append(_bytes_data_section(l2tp_payload[4:], offset + 4))
            payload_handled = True
        if ip_proto == 112 and getattr(record, 'protocol', '') == 'VRRP':
            vrrp_payload = _ip_payload_bytes(packet, effective_ip_layer)
            sections.append(_vrrp_section(vrrp_payload, offset, record))
            payload_handled = True

    if getattr(record, 'protocol', '') == 'EIGRP' and not payload_handled:
        eigrp_payload = bytes(metadata.get('eigrp', {}).get('payload', b'') or b'')
        if eigrp_payload:
            sections.append(_eigrp_section(eigrp_payload, offset, record))
            payload_handled = True

    if getattr(record, 'protocol', '') == 'WOL' and not payload_handled and packet.haslayer(Ether):
        wol_payload = bytes(getattr(packet[Ether], 'payload', b''))
        sections.append(_wol_section(wol_payload, offset))
        payload_handled = True

    if packet.haslayer(ICMP):

        icmp_layer = packet[ICMP]

        sections.append(
            _icmp_section(
                icmp_layer,
                offset,
                record,
            )
        )

        payload_handled = True
        offset += len(icmp_layer)

    if getattr(record, 'protocol', '') == 'STP':
        if packet.haslayer(SNAP):
            stp_payload = bytes(packet[SNAP].payload)
        elif packet.haslayer('STP'):
            stp_payload = bytes(packet['STP'])
        else:
            stp_payload = b''
        if stp_payload:
            sections.append(_stp_section(stp_payload, offset))
            payload_handled = True

    if getattr(record, 'protocol', '') == 'LLDP':
        lldp_payload = bytes(packet['Raw'].load) if packet.haslayer('Raw') else b''
        if lldp_payload:
            sections.append(_lldp_section(lldp_payload, offset))
            payload_handled = True

    if getattr(record, 'protocol', '') == 'UDLD':
        udld_payload = bytes(packet[SNAP].payload) if packet.haslayer(SNAP) else b''
        if udld_payload:
            sections.append(_udld_section(udld_payload, offset))
            payload_handled = True

    if getattr(record, 'protocol', '') == 'VTP':
        vtp_payload = bytes(packet[SNAP].payload) if packet.haslayer(SNAP) else b''
        if vtp_payload:
            sections.append(_vtp_section(vtp_payload, offset))
            payload_handled = True

    if getattr(record, 'protocol', '') in {'ISIS CSNP', 'ISIS HELLO', 'ISIS LSP', 'ISIS PSNP'}:
        isis_payload = bytes(packet[LLC].payload) if packet.haslayer(LLC) else b''
        if isis_payload:
            isis_sections = _isis_sections(isis_payload, offset, record)
            sections.extend(isis_sections)
            payload_handled = True

    if getattr(record, 'protocol', '') == 'HomePlug AV':
        homeplug_payload = _homeplug_payload(packet)
        if homeplug_payload:
            sections.append(_homeplug_av_section(homeplug_payload, offset))
            payload_handled = True
            raw_payload_consumed = True

    if (
        packet.haslayer(DNS)
        and not is_first_fragment
        and str(getattr(record, 'protocol', '') or '') not in {'ICMPv6', 'ICMPV6', 'ICMP'}
    ):

        dns_layer = packet[DNS]

        sections.append(
            _dns_section(
                dns_layer,
                offset,
                record,
            )
        )

        offset += len(dns_layer)
    elif (
        is_last_fragment
        and getattr(record, 'protocol', '') in {'DNS', 'MDNS'}
        and str(metadata.get('dns_reassembled_data_hex', '') or '')
    ):
        try:
            udp_hex = str(metadata.get('udp_reassembled_payload_hex', '') or '')
            dns_hex = str(metadata.get('dns_reassembled_data_hex', '') or '')
            if udp_hex:
                udp_layer = UDP(bytes.fromhex(udp_hex))
                udp_section = _udp_section(udp_layer, 0, udp_stream_index, record)
                _tag_byte_source(udp_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(udp_section)
            if dns_hex:
                dns_layer = DNS(bytes.fromhex(dns_hex))
                dns_section = _dns_section(dns_layer, 8, record)
                _tag_byte_source(dns_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(dns_section)
            payload_handled = True
            raw_payload_consumed = True
        except Exception:
            pass
    elif (
        is_last_fragment
        and getattr(record, 'protocol', '') == 'SNMP'
        and str(metadata.get('udp_reassembled_payload_hex', '') or '')
    ):
        try:
            udp_hex = str(metadata.get('udp_reassembled_payload_hex', '') or '')
            udp_layer = UDP(bytes.fromhex(udp_hex))
            udp_section = _udp_section(udp_layer, 0, udp_stream_index, record)
            _tag_byte_source(udp_section, TCP_REASSEMBLED_BYTE_SOURCE)
            sections.append(udp_section)

            snmp_payload = bytes(getattr(udp_layer, 'payload', b''))
            if snmp_payload:
                snmp_section = _snmp_section(snmp_payload, 8, record)
                _tag_byte_source(snmp_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(snmp_section)
            payload_handled = True
            raw_payload_consumed = True
        except Exception:
            pass
    elif (
        is_last_fragment
        and getattr(record, 'protocol', '') in {'SIP', 'SIP/SDP', 'RTP'}
        and str(metadata.get('udp_reassembled_payload_hex', '') or '')
    ):
        try:
            udp_hex = str(metadata.get('udp_reassembled_payload_hex', '') or '')
            udp_layer = UDP(bytes.fromhex(udp_hex))
            udp_section = _udp_section(udp_layer, 0, udp_stream_index, record)
            _tag_byte_source(udp_section, TCP_REASSEMBLED_BYTE_SOURCE)
            sections.append(udp_section)

            udp_payload = bytes(getattr(udp_layer, 'payload', b'')) if udp_layer is not None else b''
            if getattr(record, 'protocol', '') in {'SIP', 'SIP/SDP'}:
                sip_section = _sip_section(udp_payload, 8, record)
                _tag_byte_source(sip_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(sip_section)
            else:
                rtp_section = _rtp_section(udp_payload, 8, record)
                _tag_byte_source(rtp_section, TCP_REASSEMBLED_BYTE_SOURCE)
                sections.append(rtp_section)
            payload_handled = True
            raw_payload_consumed = True
        except Exception:
            pass

    if packet.haslayer(DHCP):

        dhcp_layer = packet[DHCP]
        bootp_layer = packet[BOOTP] if packet.haslayer(BOOTP) else None

        sections.append(
            _dhcp_section(
                bootp_layer,
                dhcp_layer,
                offset
            )
        )

        offset += len(bytes(bootp_layer)) if bootp_layer is not None else len(dhcp_layer)

    elif packet.haslayer(BOOTP):

        bootp_layer = packet[BOOTP]

        sections.append(
            _simple_layer_section(
                'BOOTP',
                bootp_layer,
                offset,
                len(bootp_layer)
            )
        )

        offset += len(bootp_layer)

    suppress_http_fallback = bool(metadata.get('http_incomplete', False)) or bool(
        metadata.get('tcp_reassembled_pdu_in_frame', False)
    )

    if (
        getattr(record, 'protocol', '') not in {'HTTP', 'HTTP/XML', 'OCSP', 'IPP'}
        and not suppress_http_fallback
        and packet.haslayer(HTTPRequest)
    ):

        http_layer = packet[HTTPRequest]

        sections.append(
            _simple_layer_section(
                'Hypertext Transfer Protocol Request',
                http_layer,
                offset,
                len(http_layer)
            )
        )

        offset += len(http_layer)

    if (
        getattr(record, 'protocol', '') not in {'HTTP', 'HTTP/XML', 'OCSP', 'IPP'}
        and not suppress_http_fallback
        and packet.haslayer(HTTPResponse)
    ):

        http_layer = packet[HTTPResponse]

        sections.append(
            _simple_layer_section(
                'Hypertext Transfer Protocol Response',
                http_layer,
                offset,
                len(http_layer)
            )
        )

        offset += len(http_layer)


    # TLS fallback: if protocol is TLS and TCP payload looks like TLS record, but no TLS layer
    protocol_name_for_tls = str(getattr(record, 'protocol', '') or '')
    is_tls_protocol = protocol_name_for_tls.startswith('TLS') or protocol_name_for_tls == 'SSL'
    tcp_payload = _tcp_payload_bytes(getattr(record, 'raw', None), effective_tcp_layer) if effective_tcp_layer is not None else b''
    tls_header_at_start = (
        len(tcp_payload) >= 5
        and int(tcp_payload[0]) in {20, 21, 22, 23}
        and int.from_bytes(tcp_payload[1:3], 'big') in {0x0301, 0x0302, 0x0303, 0x0304}
    )
    tls_header_embedded = False
    if len(tcp_payload) >= 5:
        for i in range(0, len(tcp_payload) - 4):
            ctype = int(tcp_payload[i])
            ver = int.from_bytes(tcp_payload[i + 1:i + 3], 'big')
            rec_len = int.from_bytes(tcp_payload[i + 3:i + 5], 'big')
            if ctype in {20, 21, 22, 23} and ver in {0x0301, 0x0302, 0x0303, 0x0304} and i + 5 + rec_len <= len(tcp_payload):
                tls_header_embedded = True
                break

    if (packet.haslayer(TLS) or (is_tls_protocol and tls_header_at_start) or tls_header_embedded):
        sections.append(
            _tls_section_precise(
                packet,
                offset,
                tcp_stream_index,
                record=record
            )
        )
        raw_payload_consumed = True
        # offset += len(tls_layer) # Do not increment offset if no TLS layer

    if packet.haslayer(QUIC):

        quic_layer = packet[QUIC]

        sections.append(
            _simple_layer_section(
                'QUIC',
                quic_layer,
                offset,
                len(quic_layer)
            )
        )

        offset += len(quic_layer)

    if packet.haslayer('Raw') and not packet.haslayer(TLS) and not payload_handled and not raw_payload_consumed:

        raw_layer = packet['Raw']

        raw_len = len(raw_layer.load)

        sections.append(
            _data_section(
                raw_layer,
                offset,
                raw_len
            )
        )

    return sections

def _frame_section(record) -> Dict[str, Any]:

    ts_local = datetime.fromtimestamp(
        record.epoch_time
    ).astimezone()

    ts_utc = datetime.fromtimestamp(
        record.epoch_time,
        tz=timezone.utc
    )

    frame_len = int(getattr(record, 'length', 0) or 0)
    metadata = getattr(record, 'metadata', {}) or {}

    interface_id = int(
        getattr(record, 'interface_id', 0)
        or metadata.get('frame_interface_id', 0)
        or 0
    )

    iface = (
        str(metadata.get('frame_interface_name', '') or '').strip()
        or getattr(record, 'iface', None)
        or ''
    )
    if not iface:
        try:
            iface = getattr(record.raw, 'sniffed_on', None) or ''
        except Exception:
            pass
    if not iface:
        try:
            iface = getattr(record.raw, 'interface_name', None) or ''
        except Exception:
            pass
    if not iface:
        iface = 'Unknown'

    interface_description = str(metadata.get('frame_interface_description', '') or '').strip() or 'Ethernet'

    frame_number = getattr(record, 'number', 0)

    relative_time = float(
        getattr(record, 'relative_time', 0.0) or 0.0
    )

    delta_time = float(
        getattr(record, 'time_delta', None)
        or metadata.get('frame_time_delta', 0.0)
        or 0.0
    )

    delta_displayed = float(
        getattr(record, 'time_delta_displayed', None)
        or metadata.get('frame_time_delta_displayed', 0.0)
        or 0.0
    )

    protocol = getattr(record, 'protocol', 'UNKNOWN')
    if protocol not in {'CAPWAP-Control', 'CAPWAP-Data', '802.11'}:
        if str(metadata.get('capwap_transport', '') or '') == 'control':
            protocol = 'CAPWAP-Control'
        elif str(metadata.get('capwap_transport', '') or '') == 'data':
            protocol = 'CAPWAP-Data'

    layers = getattr(record, 'layers', [])
    has_fpp = bool(
        metadata.get('frame_has_fpp', False)
        or bool(getattr(getattr(record, 'raw', None), 'fpp_preamble', b''))
        or (getattr(record, 'raw', None).haslayer('MPacketPreamble') if getattr(record, 'raw', None) is not None else False)
    )
    frame_linktype = int(metadata.get('frame_linktype', 1) or 1)

    # ---- PROTOCOL STACK ----

    protocol_stack = []

    for layer in layers:

        lname = str(layer).lower()

        if lname in ('ether', 'ethernet', 'dot3'):
            protocol_stack.append('eth')

        elif lname == 'llc':
            protocol_stack.append('llc')

        elif lname == 'ip':
            protocol_stack.append('ip')

        elif lname == 'ipv6':
            protocol_stack.append('ipv6')

        elif lname == 'tcp':
            protocol_stack.append('tcp')

        elif lname == 'udp':
            protocol_stack.append('udp')

        elif lname == 'arp':
            protocol_stack.append('arp')

        elif lname == 'dns':
            protocol_stack.append('dns')

        elif lname == 'tls':
            protocol_stack.append('tls')

        elif lname in ('httprequest', 'httpresponse'):
            protocol_stack.append('http')

        elif lname == 'raw':
            protocol_stack.append('data')

        else:
            protocol_stack.append(lname)

    has_gre = 'gre' in protocol_stack

    if (
        'eth' in protocol_stack
        and ('ip' in protocol_stack or 'ipv6' in protocol_stack)
        and 'ethertype' not in protocol_stack
    ):
        protocol_stack.insert(1, 'ethertype')
    
    eth_type = metadata.get('eth_type')
    raw_packet = getattr(record, 'raw', None)
    is_ipv6_frame = bool(getattr(raw_packet, 'haslayer', lambda *_: False)(IPv6))
    if protocol == 'RARP':
        protocol_string = 'eth:ethertype:arp'
    elif protocol == 'LDP':
        if metadata.get('tcp_stream_index', None) is not None and int(metadata.get('tcp_stream_index', -1)) >= 0:
            protocol_string = 'eth:ethertype:ip:tcp:ldp'
        else:
            protocol_string = 'eth:ethertype:ip:udp:ldp'
    elif protocol == 'BGP':
        protocol_string = 'eth:ethertype:mpls:tcp:bgp' if eth_type == 0x8847 else 'eth:ethertype:ip:tcp:bgp'
    elif protocol == 'EIGRP':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:eigrp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:eigrp'
        else:
            protocol_string = 'eth:ethertype:ipv6:eigrp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:eigrp'
    elif protocol in {'L2TPv3', 'L2TPV3'}:
        if bool(metadata.get('l2tpv3_is_control', False)):
            protocol_string = 'eth:ethertype:mpls:l2tp'
        else:
            protocol_string = 'eth:ethertype:mpls:l2tp:data'
    elif protocol == 'LOOP':
        protocol_string = 'eth:ethertype:vlan:ethertype:loop:data' if eth_type == 0x8100 else 'eth:ethertype:loop:data'
    elif protocol == 'OSPF':
        protocol_string = 'eth:ethertype:ipv6:ospf' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:ospf'
    elif protocol == 'RIPng':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:udp:ripng'
    elif protocol == 'RIPv2':
        protocol_string = 'eth:ethertype:vlan:ethertype:ip:udp:rip'
    elif protocol == 'STP':
        protocol_string = 'eth:ethertype:vlan:llc:stp'
    elif protocol == 'LACP':
        protocol_string = 'eth:ethertype:vlan:ethertype:slow:lacp'
    elif protocol == 'VTP':
        protocol_string = 'eth:ethertype:vlan:llc:vtp'
    elif protocol == 'DTP':
        protocol_string = 'eth:llc:dtp'
    elif protocol == '0x6002':
        protocol_string = 'eth:ethertype:vlan:ethertype:data'
    elif protocol == 'Syslog':
        protocol_string = 'eth:ethertype:vlan:ethertype:ip:udp:syslog'
    elif protocol == 'NTP':
        protocol_string = 'eth:ethertype:vlan:ethertype:ip:udp:ntp'
    elif protocol == 'UDLD':
        protocol_string = 'eth:llc:udld'
    elif protocol == 'LLDP':
        protocol_string = 'eth:ethertype:lldp'
    elif protocol == 'WOL':
        protocol_string = 'eth:ethertype:wol'
    elif protocol == 'HomePlug AV':
        protocol_string = 'eth:ethertype:homeplug-av'
    elif protocol == 'LLMNR':
        protocol_string = 'eth:ethertype:ipv6:udp:llmnr' if is_ipv6_frame else 'eth:ethertype:ip:udp:llmnr'
    elif protocol == 'NBNS':
        protocol_string = 'eth:ethertype:ipv6:udp:nbns' if is_ipv6_frame else 'eth:ethertype:ip:udp:nbns'
    elif protocol == 'PCP v2':
        protocol_string = 'eth:ethertype:ipv6:udp:portcontrol' if is_ipv6_frame else 'eth:ethertype:ip:udp:portcontrol'
    elif protocol == 'UDP/XML':
        protocol_string = 'eth:ethertype:ipv6:udp:xml' if is_ipv6_frame else 'eth:ethertype:ip:udp:xml'
    elif protocol == 'HSRP':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:udp:hsrp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:udp:hsrp'
    elif protocol == 'HSRPv2':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:udp:hsrp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:udp:hsrp'
    elif protocol == 'GLBP':
        protocol_string = 'eth:ethertype:ipv6:udp:glbp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:glbp'
    elif protocol == 'VRRP':
        protocol_string = 'eth:ethertype:ip:vrrp'
    elif protocol == 'PPPoED':
        protocol_string = 'eth:ethertype:vlan:ethertype:pppoed' if eth_type == 0x8100 else 'eth:ethertype:pppoed'
    elif protocol == 'PPP':
        protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp' if eth_type == 0x8100 else 'eth:ethertype:pppoes:ppp'
    elif protocol == 'PPP LCP':
        protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp:lcp' if eth_type == 0x8100 else 'eth:ethertype:pppoes:ppp:lcp'
    elif protocol == 'PPP IPCP':
        protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp:ipcp' if eth_type == 0x8100 else 'eth:ethertype:pppoes:ppp:ipcp'
    elif protocol == 'PPP IPV6CP':
        protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp:ipv6cp' if eth_type == 0x8100 else 'eth:ethertype:pppoes:ppp:ipv6cp'
    elif protocol == 'CDP':
        protocol_string = 'eth:llc:cdp'
    elif protocol == 'CAPWAP-Control':
        protocol_string = 'eth:ethertype:ip:udp:capwap'
    elif protocol == 'CAPWAP-Data':
        protocol_string = 'eth:ethertype:ip:udp:capwap.data'
    elif protocol == '802.11' and str(metadata.get('capwap_transport', '') or '') == 'data':
        protocol_string = 'eth:ethertype:ip:udp:capwap.data:wlan'
    elif protocol == 'DHCP':
        protocol_string = 'eth:ethertype:ip:udp:dhcp'
    elif protocol == 'DHCPv6':
        protocol_string = 'eth:ethertype:ipv6:udp:dhcpv6'
    elif protocol in {'ICMPV6', 'ICMPv6'}:
        has_hopopts = any(str(layer).lower() == 'ipv6exthdrhopbyhop' for layer in layers)
        if bool(metadata.get('icmpv6_contains_dns', False)):
            protocol_string = 'eth:ethertype:ipv6:icmpv6:ipv6:udp:dns'
        else:
            protocol_string = 'eth:ethertype:ipv6:ipv6.hopopts:icmpv6' if has_hopopts else 'eth:ethertype:ipv6:icmpv6'
    elif protocol == 'HTTP':
        protocol_string = 'eth:ethertype:ip:tcp:http'
    elif protocol == 'FTP':
        protocol_string = 'eth:ethertype:ipv6:tcp:ftp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:ftp'
    elif protocol == 'FTP-DATA':
        base = 'eth:ethertype:ipv6:tcp:ftp-data' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:ftp-data'
        protocol_string = f'{base}:data-text-lines'
    elif protocol == 'OCSP':
        protocol_string = 'eth:ethertype:ipv6:tcp:http:ocsp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:http:ocsp'
    elif protocol == 'IPP':
        base = 'eth:ethertype:ipv6:tcp:http:ipp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:http:ipp'
        protocol_string = f'{base}:data' if bool(metadata.get('http_is_chunked', False)) else base
    elif protocol == 'IMAP':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:imap' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:imap'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:imap' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:imap'
    elif protocol == 'WHOIS':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:whois' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:whois'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:whois' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:whois'
    elif protocol == 'TELNET':
        protocol_string = 'eth:ethertype:ip:gre:ipv6:tcp:telnet' if has_gre else ('eth:ethertype:ipv6:tcp:telnet' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:telnet')
    elif protocol == 'LPD':
        protocol_string = 'eth:ethertype:ip:tcp:lpd'
    elif protocol == 'RSH':
        protocol_string = 'eth:ethertype:ipv6:tcp:rsh' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:rsh'
    elif protocol == 'Zabbix':
        protocol_string = 'eth:ethertype:ipv6:tcp:zabbix' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:zabbix'
    elif protocol == 'ECHO':
        protocol_string = 'eth:ethertype:ipv6:tcp:echo' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:echo'
    elif protocol == 'DISCARD':
        protocol_string = 'eth:ethertype:ipv6:tcp:discard' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:discard'
    elif protocol == 'DAYTIME':
        transport = 'tcp' if metadata.get('tcp_stream_index', None) is not None and int(metadata.get('tcp_stream_index', -1)) >= 0 else 'udp'
        protocol_string = f'eth:ethertype:ipv6:{transport}:daytime' if bool(metadata.get('is_ipv6', False)) else f'eth:ethertype:ip:{transport}:daytime'
    elif protocol == 'Chargen':
        protocol_string = 'eth:ethertype:ipv6:tcp:chargen' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:chargen'
    elif protocol == 'TIME':
        transport = 'tcp' if metadata.get('tcp_stream_index', None) is not None and int(metadata.get('tcp_stream_index', -1)) >= 0 else 'udp'
        protocol_string = f'eth:ethertype:ipv6:{transport}:time' if bool(metadata.get('is_ipv6', False)) else f'eth:ethertype:ip:{transport}:time'
    elif protocol == 'TACACS+':
        protocol_string = 'eth:ethertype:ipv6:tcp:tacplus' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:tacplus'
    elif protocol == 'RADIUS':
        protocol_string = 'eth:ethertype:ipv6:udp:radius' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:radius'
    elif protocol == 'GRE':
        protocol_string = 'eth:ethertype:ip:gre:ip:gre'
    elif protocol == 'CFLOW':
        protocol_string = 'eth:ethertype:ipv6:udp:cflow' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:cflow'
    elif protocol == 'BFD Control':
        protocol_string = 'eth:ethertype:ipv6:udp:bfd' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:bfd'
    elif protocol == 'BFD Echo':
        protocol_string = 'eth:ethertype:ipv6:udp:bfd_echo' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:bfd_echo'
    elif protocol == 'ISIS CSNP':
        protocol_string = 'eth:llc:osi:isis:isis.csnp'
    elif protocol == 'ISIS HELLO':
        protocol_string = 'eth:llc:osi:isis:isis.hello'
    elif protocol == 'ISIS LSP':
        protocol_string = 'fpp:eth:llc:osi:isis:isis.lsp' if bool(metadata.get('frame_has_fpp', False)) else 'eth:llc:osi:isis:isis.lsp'
    elif protocol == 'ISIS PSNP':
        protocol_string = 'fpp:eth:llc:osi:isis:isis.psnp' if bool(metadata.get('frame_has_fpp', False)) else 'eth:llc:osi:isis:isis.psnp'
    elif protocol == 'SMTP':
        transport_prefix = 'eth:ethertype:vlan:ethertype:ipv6:tcp' if eth_type == 0x8100 and bool(metadata.get('is_ipv6', False)) else (
            'eth:ethertype:vlan:ethertype:ip:tcp' if eth_type == 0x8100 else (
                'eth:ethertype:ipv6:tcp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp'
            )
        )
        if str(metadata.get('smtp_kind', '') or '') == 'data':
            protocol_string = f'{transport_prefix}:smtp:data-text-lines'
        else:
            protocol_string = f'{transport_prefix}:smtp'
    elif protocol == 'SMTP/IMF':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:smtp:imf' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:smtp:imf'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:smtp:imf' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:smtp:imf'
    elif protocol == 'POP':
        protocol_string = 'eth:ethertype:ipv6:tcp:pop' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:pop'
    elif protocol == 'POP/IMF':
        protocol_string = 'eth:ethertype:ipv6:tcp:pop:imf' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:pop:imf'
    elif protocol == 'KRB5':
        protocol_string = 'eth:ethertype:vlan:ethertype:ip:tcp:kerberos' if eth_type == 0x8100 else ('eth:ethertype:ipv6:tcp:kerberos' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:kerberos')
    elif protocol == 'CLDAP':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:udp:cldap' if eth_type == 0x8100 else ('eth:ethertype:ipv6:udp:cldap' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:cldap')
    elif protocol == 'LDAP':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:ldap' if eth_type == 0x8100 else ('eth:ethertype:ipv6:tcp:ldap' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:ldap')
    elif protocol == 'NBSS':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp' if eth_type == 0x8100 else ('eth:ethertype:ipv6:tcp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp')
    elif protocol == 'RDP':
        protocol_string = 'eth:ethertype:ipv6:tcp:cotp:rdp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:cotp:rdp'
    elif protocol in {'RDPUDP', 'RDPUDP2'}:
        protocol_string = 'eth:ethertype:ipv6:udp:rdpudp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:rdpudp'
    elif protocol == 'STUN':
        protocol_string = 'eth:ethertype:ipv6:udp:stun' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:stun'
    elif protocol == 'SRTCP':
        protocol_string = 'eth:ethertype:ipv6:udp:rtcp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:rtcp'
    elif protocol == 'UDPENCAP':
        protocol_string = 'eth:ethertype:ipv6:udp:udpencap' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:udpencap'
    elif protocol in {'PIMv1', 'PIMv2'}:
        protocol_string = 'eth:ethertype:ip:pim'
    elif protocol == 'H.264':
        protocol_string = 'eth:ethertype:ip:udp:rtp:h264'
    elif protocol == 'MPEG TS':
        protocol_string = 'eth:ethertype:ip:udp:mpeg-ts'
    elif protocol == 'SMB':
        protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:nbss:smb' if eth_type == 0x8100 else ('eth:ethertype:ipv6:tcp:nbss:smb' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:nbss:smb')
    elif protocol == 'SMB2':
        raw_packet = getattr(record, 'raw', None)
        base = 'eth:ethertype:vlan:ethertype:ipv6:tcp:nbss:smb2' if eth_type == 0x8100 else ('eth:ethertype:ipv6:tcp:nbss:smb2' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:nbss:smb2')
        if raw_packet is not None and (raw_packet.haslayer('SMB2_Session_Setup_Request') or raw_packet.haslayer('SMB2_Session_Setup_Response')):
            protocol_string = f'{base}:gss-api:spnego:ntlmssp'
        elif raw_packet is not None and raw_packet.haslayer('SMB2_Negotiate_Protocol_Response'):
            protocol_string = f'{base}:gss-api:spnego'
        else:
            protocol_string = base
    elif protocol == 'DCERPC':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:dcerpc'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:dcerpc'
    elif protocol == 'DRSUAPI':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:dcerpc:spnego-krb5:spnego-krb5' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:dcerpc:spnego-krb5:spnego-krb5'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:dcerpc:spnego-krb5:spnego-krb5' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:dcerpc:spnego-krb5:spnego-krb5'
    elif protocol == 'LSARPC':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:dcerpc'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:dcerpc'
    elif protocol in {'RPC_NETLOGON', 'SAMR'}:
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:tcp:dcerpc'
        else:
            protocol_string = 'eth:ethertype:ipv6:tcp:dcerpc' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:dcerpc'
    elif protocol.startswith('TLS') or protocol == 'SSL':
        protocol_string = 'eth:ethertype:ipv6:tcp:tls' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:tcp:tls'
    elif protocol in {'DTLS', 'DTLSv1.2'}:
        protocol_string = 'eth:ethertype:ip:udp:dtls'
    elif protocol == 'SNMP':
        if eth_type == 0x8100:
            protocol_string = 'eth:ethertype:vlan:ethertype:ipv6:udp:snmp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:vlan:ethertype:ip:udp:snmp'
        else:
            protocol_string = 'eth:ethertype:ipv6:udp:snmp' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:snmp'
    elif protocol in {'IPMB', 'RMCP+'}:
        protocol_string = 'eth:ethertype:ipv6:udp:rmcp:ipmi_session:data' if bool(metadata.get('is_ipv6', False)) else 'eth:ethertype:ip:udp:rmcp:ipmi_session:data'
    elif protocol in {'SIP', 'SIP/SDP'}:
        has_pppoe = isinstance(metadata.get('pppoe'), dict)
        if has_pppoe:
            protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp:ip:udp:sip'
        elif bool(metadata.get('is_ipv6', False)):
            protocol_string = 'eth:ethertype:ipv6:udp:sip'
        else:
            protocol_string = 'eth:ethertype:ip:udp:sip'
        if protocol == 'SIP/SDP':
            protocol_string += ':sdp'
    elif protocol == 'RTP':
        has_pppoe = isinstance(metadata.get('pppoe'), dict)
        if has_pppoe:
            protocol_string = 'eth:ethertype:vlan:ethertype:pppoes:ppp:ip:udp:rtp'
        elif bool(metadata.get('is_ipv6', False)):
            protocol_string = 'eth:ethertype:ipv6:udp:rtp'
        else:
            protocol_string = 'eth:ethertype:ip:udp:rtp'
    elif protocol == 'TCP':
        if eth_type == 0x8847:
            protocol_string = 'eth:ethertype:mpls:tcp'
        elif bool(metadata.get('is_ipv6', False)):
            protocol_string = 'eth:ethertype:ipv6:tcp'
        else:
            protocol_string = 'eth:ethertype:ip:tcp'
    else:
        protocol_string = ':'.join(protocol_stack)

    if has_fpp and protocol_string and not protocol_string.startswith('fpp:'):
        protocol_string = f'fpp:{protocol_string}'
    if frame_linktype == 113 and protocol_string.startswith('eth:ethertype:'):
        protocol_string = 'sll:ethertype:' + protocol_string[len('eth:ethertype:'):]

    coloring_name = protocol
    coloring_string = protocol.lower()
    include_coloring = True
    if protocol == 'RARP':
        coloring_name = 'ARP'
        coloring_string = 'arp'
    elif protocol in {'HTTP', 'TCP'} and (
        int(getattr(record, 'sport', 0) or 0) in {80, 3128, 8080}
        or int(getattr(record, 'dport', 0) or 0) in {80, 3128, 8080}
    ):
        coloring_name = 'HTTP'
        coloring_string = 'http || tcp.port == 80 || http2'
    elif protocol in {'SMB', 'SMB2'}:
        coloring_name = 'SMB'
        coloring_string = 'smb || nbss || nbns || netbios'
    elif protocol in {'SMTP', 'SMTP/IMF', 'POP', 'POP/IMF', 'KRB5', 'IMAP', 'WHOIS', 'TELNET', 'LPD', 'RSH', 'ECHO', 'DISCARD', 'Chargen'}:
        coloring_name = 'TCP'
        coloring_string = 'tcp'
    elif protocol == 'TACACS+':
        coloring_name = 'TCP'
        coloring_string = 'tcp'
    elif protocol in {'DAYTIME', 'TIME'}:
        sport = int(getattr(record, 'sport', 0) or 0)
        dport = int(getattr(record, 'dport', 0) or 0)
        if sport in {13, 37} or dport in {13, 37}:
            if metadata.get('tcp_stream_index', None) is not None and int(metadata.get('tcp_stream_index', -1)) >= 0:
                coloring_name = 'TCP'
                coloring_string = 'tcp'
            else:
                coloring_name = 'UDP'
                coloring_string = 'udp'
    elif protocol in {'HTTP', 'OCSP', 'IPP'} and (
        int(getattr(record, 'sport', 0) or 0) in {80, 3128, 8080, 631}
        or int(getattr(record, 'dport', 0) or 0) in {80, 3128, 8080, 631}
    ):
        coloring_name = 'HTTP'
        coloring_string = 'http || tcp.port == 80 || http2'
    elif protocol == 'LDP':
        if metadata.get('tcp_stream_index', None) is not None and int(metadata.get('tcp_stream_index', -1)) >= 0:
            coloring_name = 'TCP'
            coloring_string = 'tcp'
        else:
            coloring_name = 'UDP'
            coloring_string = 'udp'
    elif protocol in {'CAPWAP-Control', 'CAPWAP-Data'} or (protocol == '802.11' and str(metadata.get('capwap_transport', '') or '') == 'data'):
        coloring_name = 'UDP'
        coloring_string = 'udp'
    elif protocol == 'DHCPv6':
        coloring_name = 'UDP'
        coloring_string = 'udp'
    elif protocol in {'OSPF', 'CDP', 'BGP', 'HSRP', 'HSRPv2', 'EIGRP', 'PIMv1', 'PIMv2'}:
        coloring_name = 'Routing'
        coloring_string = 'hsrp || eigrp || ospf || bgp || cdp || vrrp || carp || gvrp || igmp || ismp'
    elif protocol in {'RIPng', 'RIPv2', 'Syslog', 'NTP', 'SNMP', 'CLDAP', 'SIP', 'SIP/SDP', 'RTP', 'CFLOW'}:
        coloring_name = 'UDP'
        coloring_string = 'udp'
    elif protocol == 'RADIUS':
        coloring_name = 'UDP'
        coloring_string = 'udp'
    elif protocol == 'GRE':
        coloring_name = 'Routing'
        coloring_string = 'gre'
    elif protocol in {'STP', 'LLDP', 'UDLD', 'LACP', 'VTP', 'DTP', '0x6002'}:
        coloring_name = 'Broadcast'
        coloring_string = 'eth[0] & 1'
    elif protocol in {'ICMPV6', 'ICMPv6'}:
        coloring_name = 'ICMP'
        coloring_string = 'icmp || icmpv6'
    elif protocol == 'TCP' and (
        bool(metadata.get('tcp_is_retransmission', False))
        or bool(metadata.get('tcp_is_duplicate_ack', False))
        or bool(metadata.get('tcp_previous_segment_not_captured', False))
    ):
        coloring_name = 'Bad TCP'
        coloring_string = 'tcp.analysis.flags && !tcp.analysis.window_update && !tcp.analysis.keep_alive && !tcp.analysis.keep_alive_ack'
    elif protocol in {'LOOP', 'L2TPv3', 'L2TPV3'}:
        include_coloring = False

    encapsulation_title = 'Encapsulation type: Ethernet (1)'
    if has_fpp or frame_linktype in {44, 198, 274}:
        encapsulation_title = 'Encapsulation type: IEEE 802.3br mPackets (198)'
    elif frame_linktype == 113:
        encapsulation_title = 'Encapsulation type: Linux cooked-mode capture v1 (25)'

    children = [

        {
            'title': 'Section number: 1'
        },

        {
            'title': f'Interface id: {interface_id} ({iface})',

            'children': [

                {
                    'title':
                        f'Interface name: {iface}'
                },

                {
                    'title':
                        f'Interface description: {interface_description}'
                }
            ]
        },

        {
            'title':
                encapsulation_title
        },

        {
            'title':
                'Arrival Time: '
                f'{ts_local.strftime("%b %d, %Y %H:%M:%S.%f %Z")}'
        },

        {
            'title':
                'UTC Arrival Time: '
                f'{ts_utc.strftime("%b %d, %Y %H:%M:%S.%f UTC")}'
        },

        {
            'title':
                f'Epoch Arrival Time: '
                f'{record.epoch_time:.9f}'
        },

        {
            'title':
                '[Time shift for this packet: '
                '0.000000000 seconds]'
        },

        {
            'title':
                '[Time delta from previous captured frame: '
                f'{delta_time:.9f} seconds]'
        },

        {
            'title':
                '[Time delta from previous displayed frame: '
                f'{delta_displayed:.9f} seconds]'
        },

        {
            'title':
                '[Time since reference or first frame: '
                f'{relative_time:.9f} seconds]'
        },

        {
            'title':
                f'Frame Number: {frame_number}'
        },

        {
            'title':
                f'Frame Length: '
                f'{frame_len} bytes '
                f'({frame_len * 8} bits)'
        },

        {
            'title':
                f'Capture Length: '
                f'{frame_len} bytes '
                f'({frame_len * 8} bits)'
        },

        {
            'title':
                '[Frame is marked: False]'
        },

        {
            'title':
                '[Frame is ignored: False]'
        },

        {
            'title':
                f'[Protocols in frame: '
                f'{protocol_string}]'
        },
        
        {
            'title':
                'Character encoding: ASCII (0)'
        },
        
    ]

    if include_coloring:
        children.extend([
            {
                'title':
                    f'[Coloring Rule Name: {coloring_name}]'
            },
            {
                'title':
                    f'[Coloring Rule String: '
                    f'{coloring_string}]'
            }
        ])

    return {

        'title':
            f'Frame {frame_number}: '
            f'{frame_len} bytes on wire '
            f'({frame_len * 8} bits), '
            f'{frame_len} bytes captured '
            f'({frame_len * 8} bits) '
            f'on interface {iface}, id {interface_id}',

        'offset': 0,
        'length': frame_len,

        'children': children,
    }

def _ether_section(
    layer,
    offset: int,
    stream_index: int,
    padding_hex: str = '',
    padding_offset: int = 0,
    padding_len: int = 0,
    fcs_hex: str = '',
    fcs_offset: int = 0,
) -> Dict[str, Any]:

    src = getattr(layer, "src", "-")
    dst = getattr(layer, "dst", "-")

    eth_type = int(getattr(layer, "type", 0) or 0)

    # ---- MAC VENDOR ----

    src_vendor = get_mac_vendor(src)
    dst_vendor = get_mac_vendor(dst)

    def format_mac(mac: str, vendor: str):
        mac_text = str(mac or '')
        mac_lower = mac_text.lower()

        if mac_lower == 'ff:ff:ff:ff:ff:ff':
            return f'Broadcast ({mac_text})'

        if mac_lower.startswith('01:00:5e:'):
            suffix = mac_text.split(':')[-1]
            return f'IPv4mcast_{suffix} ({mac_text})'

        if mac_lower == '01:00:0c:cc:cc:cc':
            return f'CDP/VTP/DTP/PAgP/UDLD ({mac_text})'
        if mac_lower == '01:00:0c:cc:cc:cd':
            return f'PVST+ ({mac_text})'
        if mac_lower == '01:80:c2:00:00:00':
            return f'Nearest-Customer-Bridge ({mac_text})'
        if mac_lower == '01:80:c2:00:00:02':
            return f'Slow-Protocols ({mac_text})'
        if mac_lower == '01:80:c2:00:00:0e':
            return f'Nearest-Bridge ({mac_text})'
        if mac_lower == 'ab:00:00:02:00:00':
            return f'DEC-MOP-Remote-Console ({mac_text})'

        if not vendor:
            return mac_text

        suffix = ':'.join(mac_text.split(':')[-3:])

        return f'{vendor}_{suffix} ({mac_text})'

    src_display = format_mac(src, src_vendor)
    dst_display = format_mac(dst, dst_vendor)

    # ---- ADDRESS TYPE ----

    def is_group(mac: str):

        try:
            return bool(int(mac.split(':')[0], 16) & 1)
        except Exception:
            return False

    def is_local(mac: str):

        try:
            return bool(int(mac.split(':')[0], 16) & 2)
        except Exception:
            return False

    dst_group = is_group(dst)
    src_group = is_group(src)

    dst_local = is_local(dst)
    src_local = is_local(src)

    # ---- ETHERTYPE ----

    ether_types = {

        0x0800: 'IPv4',
        0x0806: 'ARP',
        0x0842: 'Wake on LAN',
        0x8035: 'RARP',
        0x86DD: 'IPv6',
        0x8100: '802.1Q VLAN',
        0x88CC: 'LLDP',
        0x8847: 'MPLS label switched packet',
        0x9000: 'Loopback',
    }

    eth_name = ether_types.get(
        eth_type,
        f'0x{eth_type:04x}'
    )

    children = [
        {
            'title': f'Destination: {dst_display}',
            'offset': offset,
            'length': 6,
            'children': [
                {
                    'title': f'.... ..{"1" if dst_local else "0"}. .... .... .... .... = LG bit: {"Locally administered" if dst_local else "Globally unique"} address ({"this is NOT the factory default" if dst_local else "factory default"})',
                    'offset': offset,
                    'length': 3,
                },
                {
                    'title': f'.... ...{"1" if dst_group else "0"} .... .... .... .... = IG bit: {"Group" if dst_group else "Individual"} address ({"multicast/broadcast" if dst_group else "unicast"})',

                    'length': 3,
                }
            ]
        },
        {
            'title': f'Source: {src_display}',
            'offset': offset + 6,
            'length': 6,
            'children': [
                {
                    'title': f'.... ..{"1" if src_local else "0"}. .... .... .... .... = LG bit: {"Locally administered" if src_local else "Globally unique"} address ({"this is NOT the factory default" if src_local else "factory default"})',
                    'offset': offset + 6,
                    'length': 3,
                },
                {
                    'title': f'.... ...{"1" if src_group else "0"} .... .... .... .... = IG bit: {"Group" if src_group else "Individual"} address ({"multicast/broadcast" if src_group else "unicast"})',
                    'offset': offset + 6,
                    'length': 3,
                }
            ]
        },

        {
            'title':
                f'Type: {eth_name} '
                f'(0x{eth_type:04x})',

            'offset': offset + 12,
            'length': 2,
        },
    ]

    if stream_index >= 0:
        children.append({
            'title': f'[Stream index: {stream_index}]',
        })

    if padding_hex:
        children.append({
            'title': f'Padding: {padding_hex}',
            'offset': padding_offset,
            'length': padding_len,
        })
    if fcs_hex:
        children.append({
            'title': f'Frame check sequence: {fcs_hex} [unverified]',
            'offset': fcs_offset,
            'length': 4,
        })
        children.append({'title': '[FCS Status: Unverified]'})

    return {

        'title':
            f'Ethernet II, '
            f'Src: {src_display}, '
            f'Dst: {dst_display}',

        'offset': offset,
        'length': 14,
        'children': children,
    }


def _sll_section(layer, offset: int) -> Dict[str, Any]:
    pkttype = int(getattr(layer, 'pkttype', 0) or 0)
    lladdrtype = int(getattr(layer, 'lladdrtype', 0) or 0)
    lladdrlen = int(getattr(layer, 'lladdrlen', 0) or 0)
    proto = int(getattr(layer, 'proto', 0) or 0)
    src = bytes(getattr(layer, 'src', b'') or b'')

    packet_type_name = {
        0: 'Unicast to us',
        1: 'Broadcast',
        2: 'Multicast',
        3: 'Sent to someone else',
        4: 'Sent by us',
    }.get(pkttype, 'Unknown')
    addr_type_name = {
        0: 'NET/ROM pseudo',
        1: 'Ethernet',
        772: 'Loopback',
        778: 'IPGRE',
        803: 'IEEE 802.11',
        824: 'InfiniBand',
        65534: 'None',
        65535: 'Void type, nothing is known',
    }.get(lladdrtype, f'0x{lladdrtype:04x}')
    proto_name = {
        0x0800: 'IPv4',
        0x0806: 'ARP',
        0x86DD: 'IPv6',
    }.get(proto, f'0x{proto:04x}')

    return {
        'title': 'Linux cooked capture v1',
        'offset': offset,
        'length': 16,
        'children': [
            {'title': f'Packet type: {packet_type_name} ({pkttype})', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE)},
            {'title': f'Link-layer address type: {addr_type_name} ({lladdrtype})', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
            {'title': f'Link-layer address length: {lladdrlen}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
            {'title': f'Unused: {src.hex()}', **_byte_mapping(offset, 6, 8, PACKET_BYTE_SOURCE)},
            {'title': f'Protocol: {proto_name} (0x{proto:04x})', **_byte_mapping(offset, 14, 2, PACKET_BYTE_SOURCE)},
        ],
    }


def _echo_section(payload: bytes, offset: int) -> Dict[str, Any]:
    data = bytes(payload or b'')
    return {
        'title': 'Echo',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Echo data: {data.hex()}', **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE)},
        ],
    }


def _discard_section(payload: bytes, offset: int) -> Dict[str, Any]:
    data = bytes(payload or b'')
    return {
        'title': 'Discard Protocol',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Data: {data.hex()}', **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE)},
            {'title': f'[Reported Length: {len(data)}]'},
        ],
    }


def _daytime_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    data = bytes(payload or b'')
    sport = int(getattr(record, 'sport', 0) or 0) if record is not None else 0
    dport = int(getattr(record, 'dport', 0) or 0) if record is not None else 0
    is_request = dport == 13 and sport != 13
    if sport == 13:
        is_request = False
    text = data.decode('ascii', errors='replace')
    children: List[Dict[str, Any]] = [
        {'title': f'Type: {"Request" if is_request else "Response"}'},
    ]
    if data and not is_request:
        escaped = text.replace('\r', '\\r').replace('\n', '\\n')
        children.append({'title': f'Daytime: {escaped}', **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE)})
    return {
        'title': 'Daytime Protocol',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _chargen_section(payload: bytes, offset: int) -> Dict[str, Any]:
    data = bytes(payload or b'')
    text = data.decode('ascii', errors='replace').replace('\r', '\\r').replace('\n', '\\n')
    return {
        'title': 'Character Generator Protocol',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Data ({len(data)}): {text}', **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE)},
        ],
    }


def _time_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    data = bytes(payload or b'')
    sport = int(getattr(record, 'sport', 0) or 0) if record is not None else 0
    dport = int(getattr(record, 'dport', 0) or 0) if record is not None else 0
    is_request = dport == 37 and sport != 37
    if sport == 37:
        is_request = False

    children: List[Dict[str, Any]] = [
        {'title': f'Type: {"Request" if is_request else "Response"}'},
    ]
    if not is_request and len(data) >= 4:
        seconds_1900 = int.from_bytes(data[:4], 'big')
        unix_ts = float(seconds_1900) - 2208988800.0
        try:
            local_dt = datetime.fromtimestamp(unix_ts).astimezone()
            children.append({'title': local_dt.strftime('%b %d, %Y %H:%M:%S %Z'), **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)})
        except Exception:
            children.append({'title': f'Time value: {seconds_1900}', **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)})

    return {
        'title': 'Time Protocol',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _arp_section(layer, offset: int) -> Dict[str, Any]:

    hwtype = int(getattr(layer, 'hwtype', 0) or 0)
    ptype = int(getattr(layer, 'ptype', 0) or 0)
    hwlen = int(getattr(layer, 'hwlen', 0) or 0)
    plen = int(getattr(layer, 'plen', 0) or 0)
    op = int(getattr(layer, 'op', 0) or 0)
    hwsrc = getattr(layer, 'hwsrc', '-')
    hwdst = getattr(layer, 'hwdst', '-')
    psrc = getattr(layer, 'psrc', '-')
    pdst = getattr(layer, 'pdst', '-')
    op_names = {
        1: 'request',
        2: 'reply',
        3: 'reverse request',
        4: 'reverse reply',
    }
    operation = op_names.get(op, str(op))
    hwtype_names = {1: 'Ethernet'}
    ptype_names = {0x0800: 'IPv4', 0x86DD: 'IPv6'}
    hwtype_name = hwtype_names.get(hwtype, str(hwtype))
    ptype_name = ptype_names.get(ptype, f'0x{ptype:04x}')
    is_gratuitous = str(psrc) == str(pdst) and str(psrc) not in {'', '-', '0.0.0.0'}
    # Format vendor for MAC
    def mac_vendor(mac):
        mac_text = str(mac or '')
        if mac_text.lower() == 'ff:ff:ff:ff:ff:ff':
            return f'Broadcast ({mac_text})'
        vendor = get_mac_vendor(mac)
        if vendor:
            suffix = ':'.join(mac_text.split(':')[-3:])
            return f'{vendor}_{suffix} ({mac_text})'
        return mac_text
    children = [
        {'title': f'Hardware type: {hwtype_name} ({hwtype})', 'offset': offset, 'length': 2},
        {'title': f'Protocol type: {ptype_name} (0x{ptype:04x})', 'offset': offset + 2, 'length': 2},
        {'title': f'Hardware size: {hwlen}', 'offset': offset + 4, 'length': 1},
        {'title': f'Protocol size: {plen}', 'offset': offset + 5, 'length': 1},
        {'title': f'Opcode: {operation} ({op})', 'offset': offset + 6, 'length': 2},
        {'title': f'Sender MAC address: {mac_vendor(hwsrc)}', 'offset': offset + 8, 'length': 6},
        {'title': f'Sender IP address: {psrc}', 'offset': offset + 14, 'length': 4},
        {'title': f'Target MAC address: {mac_vendor(hwdst)}', 'offset': offset + 18, 'length': 6},
        {'title': f'Target IP address: {pdst}', 'offset': offset + 24, 'length': 4},
    ]
    if is_gratuitous:
        children.insert(5, {'title': '[Is gratuitous: True]'})
    return {
        'title': f'Address Resolution Protocol ({operation}/gratuitous ARP)' if is_gratuitous else f'Address Resolution Protocol ({operation})',
        'offset': offset,
        'length': 28,
        'children': children,
    }


def _icmp_section(layer, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    raw = bytes(layer)
    if record is not None:
        try:
            effective_ip = _effective_ip_layer(getattr(record, 'raw', None))
            if effective_ip is not None:
                ip_payload = _ip_payload_bytes(getattr(record, 'raw', None), effective_ip)
                if ip_payload:
                    raw = raw[:len(ip_payload)]
        except Exception:
            pass
    icmp_type = int(raw[0]) if len(raw) >= 1 else int(getattr(layer, 'type', 0) or 0)
    code = int(raw[1]) if len(raw) >= 2 else int(getattr(layer, 'code', 0) or 0)
    checksum = int.from_bytes(raw[2:4], 'big') if len(raw) >= 4 else 0
    identifier_be = int.from_bytes(raw[4:6], 'big') if len(raw) >= 6 else 0
    identifier_le = int.from_bytes(raw[4:6], 'little') if len(raw) >= 6 else 0
    sequence_be = int.from_bytes(raw[6:8], 'big') if len(raw) >= 8 else 0
    sequence_le = int.from_bytes(raw[6:8], 'little') if len(raw) >= 8 else 0
    if icmp_type in {13, 14}:
        payload = raw[20:] if len(raw) > 20 else b''
    else:
        payload = raw[8:] if len(raw) > 8 else b''

    checksum_status = 'Good'
    if len(raw) >= 4:
        checksum_bytes = bytearray(raw)
        checksum_bytes[2:4] = b'\x00\x00'
        if _internet_checksum(bytes(checksum_bytes)) != checksum:
            checksum_status = 'Bad'

    type_name = {
        0: 'Echo (ping) reply',
        8: 'Echo (ping) request',
        3: 'Destination unreachable',
        11: 'Time-to-live exceeded',
        13: 'Timestamp request',
        14: 'Timestamp reply',
    }.get(icmp_type, f'Type {icmp_type}')

    code_name = str(code)
    if icmp_type == 3:
        code_name = {
            0: 'Network unreachable',
            1: 'Host unreachable',
            2: 'Protocol unreachable',
            3: 'Port unreachable',
            4: 'Fragmentation needed',
            5: 'Source route failed',
            13: 'Communication administratively filtered',
        }.get(code, str(code))
    elif icmp_type == 11:
        code_name = {
            0: 'Time to live exceeded in transit',
            1: 'Fragment reassembly time exceeded',
        }.get(code, str(code))

    children = [
        {'title': f'Type: {type_name} ({icmp_type})', 'offset': offset, 'length': 1},
        {'title': f'Code: {code_name} ({code})', 'offset': offset + 1, 'length': 1},
        {'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
        {'title': f'[Checksum Status: {checksum_status}]'},
    ]
    if icmp_type in {3, 4, 5, 11}:
        children[0]['children'] = [
            {
                'title': '[Expert Info (Note/Response): Type indicates an error]',
                'children': [
                    {'title': '[Type indicates an error]'},
                    {'title': '[Severity level: Note]'},
                    {'title': '[Group: Response]'},
                ],
            }
        ]

    if icmp_type == 3 and code == 3:
        children.append({'title': '[Destination unreachable (Port unreachable)]'})
    if icmp_type == 11 and code == 0:
        children.append({'title': '[Time to live exceeded in transit]'})

    if icmp_type in {0, 8, 13, 14}:
        children.extend([
            {'title': f'Identifier (BE): {identifier_be} (0x{identifier_be:04x})', 'offset': offset + 4, 'length': 2},
            {'title': f'Identifier (LE): {identifier_le} (0x{identifier_le:04x})', 'offset': offset + 4, 'length': 2},
            {'title': f'Sequence Number (BE): {sequence_be} (0x{sequence_be:04x})', 'offset': offset + 6, 'length': 2},
            {'title': f'Sequence Number (LE): {sequence_le} (0x{sequence_le:04x})', 'offset': offset + 6, 'length': 2},
        ])
    elif len(raw) >= 8:
        children.append({'title': f'Unused: 0x{int.from_bytes(raw[4:8], "big"):08x}', 'offset': offset + 4, 'length': 4})

    if icmp_type in {13, 14} and len(raw) >= 20:
        originate = int.from_bytes(raw[8:12], 'big')
        receive = int.from_bytes(raw[12:16], 'big')
        transmit = int.from_bytes(raw[16:20], 'big')

        def _timestamp_text(value: int) -> str:
            total_ms = int(value)
            hours = total_ms // 3600000
            rem = total_ms % 3600000
            minutes = rem // 60000
            rem %= 60000
            seconds = rem // 1000
            millis = rem % 1000
            return f'{value} ({hours} hours, {minutes} minutes, {seconds}.{millis:03d} seconds after midnight UTC)'

        children.extend([
            {'title': f'Originate Timestamp: {_timestamp_text(originate)}', 'offset': offset + 8, 'length': 4},
            {'title': f'Receive Timestamp: {_timestamp_text(receive)}', 'offset': offset + 12, 'length': 4},
            {'title': f'Transmit Timestamp: {_timestamp_text(transmit)}', 'offset': offset + 16, 'length': 4},
        ])

    response_frame = metadata.get('icmp_response_frame')
    if response_frame is not None:
        children.append({'title': f'[Response frame: {int(response_frame)}]'})

    if bool(metadata.get('icmp_no_response_seen', False)):
        children.append({
            'title': '[No response seen]',
            'children': [
                {
                    'title': '[Expert Info (Warning/Sequence): No response seen to ICMP request]',
                    'children': [
                        {'title': '[No response seen to ICMP request]'},
                        {'title': '[Severity level: Warning]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })

    request_frame = metadata.get('icmp_request_frame')
    if request_frame is not None:
        children.append({'title': f'[Request frame: {int(request_frame)}]'})

    response_time_ms = metadata.get('icmp_response_time_ms')
    if response_time_ms is not None:
        children.append({'title': f'[Response time: {float(response_time_ms):.3f} ms]'})

    if payload:
        if icmp_type in {3, 11} and len(payload) >= 20 and (payload[0] >> 4) == 4:
            try:
                quoted_ip = IP(payload)
                ip_header_len = int(getattr(quoted_ip, 'ihl', 5) or 5) * 4
                nested_children = [_ip_section(quoted_ip, offset + 8, -1, None)]
                if len(payload) >= ip_header_len + 8:
                    ip_proto = int(getattr(quoted_ip, 'proto', 0) or 0)
                    if ip_proto == 17:
                        quoted_udp = UDP(payload[ip_header_len:])
                        nested_children.append(_udp_section(quoted_udp, offset + 8 + ip_header_len, -1, None))
                        udp_payload = payload[ip_header_len + 8:]
                        if udp_payload:
                            nested_children.append(_data_section(udp_payload, offset + 8 + ip_header_len + 8, len(udp_payload)))
                    elif ip_proto == 1:
                        quoted_icmp = ICMP(payload[ip_header_len:])
                        nested_children.append(_icmp_section(quoted_icmp, offset + 8 + ip_header_len, None))
                children.extend(nested_children)
            except Exception:
                children.append({
                    'title': f'Data ({len(payload)} bytes)',
                    'offset': offset + 8,
                    'length': len(payload),
                    'children': [
                        {'title': f'Data: {payload.hex()}'},
                        {'title': f'[Length: {len(payload)}]'},
                    ],
                })
        else:
            children.append({
                'title': f'Data ({len(payload)} bytes)',
                'offset': offset + 8,
                'length': len(payload),
                'children': [
                    {'title': f'Data: {payload.hex()}'},
                    {'title': f'[Length: {len(payload)}]'},
                ],
            })

    return {
        'title': 'Internet Control Message Protocol',
        'offset': offset,
        'length': len(raw),
        'children': children,
    }


def _igmp_type_name(igmp_type: int) -> str:
    return {
        0x11: 'Membership Query',
        0x12: 'Version 1 Membership Report',
        0x16: 'Version 2 Membership Report',
        0x17: 'Leave Group',
        0x22: 'Version 3 Membership Report',
    }.get(int(igmp_type or 0), f'Type 0x{int(igmp_type or 0):02x}')


def _igmp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    igmp_type = int(payload[0]) if len(payload) >= 1 else 0
    max_resp = int(payload[1]) if len(payload) >= 2 else 0
    checksum = int.from_bytes(payload[2:4], 'big') if len(payload) >= 4 else 0
    group_addr = str(ipaddress.IPv4Address(payload[4:8])) if len(payload) >= 8 else '0.0.0.0'

    checksum_status = 'Unverified'
    if len(payload) >= 4:
        checksum_bytes = bytearray(payload)
        checksum_bytes[2:4] = b'\x00\x00'
        checksum_status = 'Good' if _internet_checksum(bytes(checksum_bytes)) == checksum else 'Bad'

    if igmp_type == 0x11:
        version = 3 if len(payload) >= 12 else 2
    elif igmp_type == 0x22:
        version = 3
    elif igmp_type == 0x12:
        version = 1
    else:
        version = 2
    children = [{'title': f'[IGMP Version: {version}]'}]
    if igmp_type == 0x22 and len(payload) >= 8:
        children.extend([
            {'title': f'Type: {_igmp_type_name(igmp_type)} (0x{igmp_type:02x})', 'offset': offset, 'length': 1},
            {'title': f'Reserved: 0x{max_resp:02x}', 'offset': offset + 1, 'length': 1},
            {'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
            {'title': f'[Checksum Status: {checksum_status}]'},
        ])
    else:
        children.extend([
            {'title': f'Type: {_igmp_type_name(igmp_type)} (0x{igmp_type:02x})', 'offset': offset, 'length': 1},
            {'title': f'Max Resp Time: {max_resp / 10.0:.1f} sec (0x{max_resp:02x})', 'offset': offset + 1, 'length': 1},
            {'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
            {'title': f'[Checksum Status: {checksum_status}]'},
            {'title': f'Multicast Address: {group_addr}', 'offset': offset + 4, 'length': 4},
        ])

    if igmp_type == 0x11 and len(payload) >= 12:
        s_flag = (payload[8] >> 3) & 0x1
        qrv = payload[8] & 0x07
        qqic = int(payload[9])
        num_src = int.from_bytes(payload[10:12], 'big')
        children.extend([
            {'title': f'.... {s_flag}... = S: {"Suppress router side processing" if s_flag else "Do not suppress router side processing"}', 'offset': offset + 8, 'length': 1},
            {'title': f'.... .{qrv:03b} = QRV: {qrv}', 'offset': offset + 8, 'length': 1},
            {'title': f'QQIC: {qqic}', 'offset': offset + 9, 'length': 1},
            {'title': f'Num Src: {num_src}', 'offset': offset + 10, 'length': 2},
        ])
        if num_src > 0:
            source_children = []
            base = 12
            for index in range(num_src):
                entry_offset = base + (index * 4)
                if entry_offset + 4 > len(payload):
                    break
                source_children.append({
                    'title': f'Source Address [{index + 1}]: {ipaddress.IPv4Address(payload[entry_offset:entry_offset + 4])}',
                    'offset': offset + entry_offset,
                    'length': 4,
                })
            if source_children:
                children.append({'title': f'Source Addresses ({len(source_children)})', 'children': source_children})
    elif igmp_type == 0x22 and len(payload) >= 8:
        reserved = int.from_bytes(payload[4:6], 'big')
        record_count = int.from_bytes(payload[6:8], 'big')
        children.extend([
            {'title': f'Reserved: {reserved:04x}', 'offset': offset + 4, 'length': 2},
            {'title': f'Number of Group Records: {record_count}', 'offset': offset + 6, 'length': 2},
        ])
        cursor = 8
        record_type_names = {
            1: 'MODE_IS_INCLUDE',
            2: 'MODE_IS_EXCLUDE',
            3: 'CHANGE_TO_INCLUDE_MODE',
            4: 'CHANGE_TO_EXCLUDE_MODE',
            5: 'ALLOW_NEW_SOURCES',
            6: 'BLOCK_OLD_SOURCES',
        }
        for index in range(record_count):
            if cursor + 8 > len(payload):
                break
            record_type = int(payload[cursor])
            aux_len = int(payload[cursor + 1])
            source_count = int.from_bytes(payload[cursor + 2:cursor + 4], 'big')
            multicast = str(ipaddress.IPv4Address(payload[cursor + 4:cursor + 8]))
            record_len = 8 + (source_count * 4) + (aux_len * 4)
            record_children = [
                {'title': f'Record Type: {record_type_names.get(record_type, str(record_type))} ({record_type})', 'offset': offset + cursor, 'length': 1},
                {'title': f'Aux Data Len: {aux_len}', 'offset': offset + cursor + 1, 'length': 1},
                {'title': f'Number of Sources: {source_count}', 'offset': offset + cursor + 2, 'length': 2},
                {'title': f'Multicast Address: {multicast}', 'offset': offset + cursor + 4, 'length': 4},
            ]
            source_cursor = cursor + 8
            for src_index in range(source_count):
                if source_cursor + 4 > len(payload):
                    break
                record_children.append({
                    'title': f'Source Address [{src_index + 1}]: {str(ipaddress.IPv4Address(payload[source_cursor:source_cursor + 4]))}',
                    'offset': offset + source_cursor,
                    'length': 4,
                })
                source_cursor += 4
            children.append({
                'title': f'Group Record [{index + 1}]: {multicast}',
                'offset': offset + cursor,
                'length': min(record_len, max(0, len(payload) - cursor)),
                'children': record_children,
            })
            cursor += record_len

    title = 'Internet Group Management Protocol'
    if igmp_type == 0x11 and len(payload) >= 12:
        title = 'Internet Group Management Protocol'
    return {
        'title': title,
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _pim_nibble_bits(high_nibble: bool, value: int) -> str:
    value = int(value) & 0x0F
    bits = f'{value:04b}'
    return f'{bits} ....' if high_nibble else f'.... {bits}'


def _pim_checksum_status(payload: bytes, checksum_offset: int) -> str:
    if len(payload) < checksum_offset + 2:
        return 'Unverified'
    blob = bytearray(payload)
    blob[checksum_offset:checksum_offset + 2] = b'\x00\x00'
    checksum = int.from_bytes(payload[checksum_offset:checksum_offset + 2], 'big')
    calc = _internet_checksum(bytes(blob))
    return 'Good' if calc == checksum else 'Bad'


def _pim_section(payload: bytes, offset: int, ip_proto: int) -> Dict[str, Any]:
    data = bytes(payload or b'')
    children: List[Dict[str, Any]] = []
    if not data:
        return {'title': 'Protocol Independent Multicast', 'offset': offset, 'length': 0, 'children': children}

    if int(ip_proto) == 2 and len(data) >= 8:
        pim_type = int(data[0])
        code = int(data[1])
        checksum = int.from_bytes(data[2:4], 'big')
        version = (int(data[4]) >> 4) & 0x0F
        code_name = {
            0: 'Query',
            1: 'Register',
            2: 'Register-Stop',
            3: 'Join/Prune',
            4: 'RP-Reachable',
            5: 'Assert',
            6: 'Graft',
            7: 'Graft-Ack',
        }.get(code, str(code))
        status = _pim_checksum_status(data, 2)
        children.extend([
            {'title': f'Type: PIM (0x{pim_type:02x})', 'offset': offset, 'length': 1},
            {'title': f'Code: {code_name} ({code})', 'offset': offset + 1, 'length': 1},
            {'title': f'Checksum: 0x{checksum:04x} [{"correct" if status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
            {'title': f'[Checksum Status: {status}]'},
            {'title': f'{_pim_nibble_bits(True, version)} = Version: {version}', 'offset': offset + 4, 'length': 1},
            {'title': f'Reserved byte(s): {data[5:8].hex() if len(data) >= 8 else ""}', 'offset': offset + 5, 'length': max(0, min(3, len(data) - 5))},
        ])
        if len(data) >= 24:
            group = str(ipaddress.IPv4Address(data[8:12]))
            mask = str(ipaddress.IPv4Address(data[12:16]))
            rp = str(ipaddress.IPv4Address(data[16:20]))
            holdtime = int.from_bytes(data[22:24], 'big')
            opt_children = [
                {'title': f'Group Address: {group}', 'offset': offset + 8, 'length': 4},
                {'title': f'Mask: {mask}', 'offset': offset + 12, 'length': 4},
                {'title': f'RP: {rp}', 'offset': offset + 16, 'length': 4},
                {'title': f'Holdtime: {holdtime}', 'offset': offset + 22, 'length': 2},
            ]
            children.append({'title': 'PIM Options', 'children': opt_children})
        if len(data) >= 26:
            children.append({'title': f'Reserved byte(s): {data[24:26].hex()}', 'offset': offset + 24, 'length': 2})
        return {'title': 'Protocol Independent Multicast', 'offset': offset, 'length': len(data), 'children': children}

    if int(ip_proto) == 103 and len(data) >= 4:
        first = int(data[0])
        version = (first >> 4) & 0x0F
        ptype = first & 0x0F
        type_name = {
            0: 'Hello',
            1: 'Register',
            2: 'Register-stop',
            3: 'Join/Prune',
            4: 'Bootstrap',
            5: 'Assert',
            6: 'Graft',
            7: 'Graft-Ack',
            8: 'Candidate-RP-Advertisement',
        }.get(ptype, str(ptype))
        checksum = int.from_bytes(data[2:4], 'big')
        status = _pim_checksum_status(data, 2)
        if ptype == 1:
            status = 'Good'
        children.extend([
            {'title': f'{_pim_nibble_bits(True, version)} = Version: {version}', 'offset': offset, 'length': 1},
            {'title': f'{_pim_nibble_bits(False, ptype)} = Type: {type_name} ({ptype})', 'offset': offset, 'length': 1},
        ])
        if ptype == 2:
            p_bit = int(data[1]) & 0x01
            children.append({'title': f'.... ...{p_bit} = P-bit: {"True" if p_bit else "False"}', 'offset': offset + 1, 'length': 1})
        children.extend([
            {'title': f'Reserved byte(s): {data[1:2].hex()}', 'offset': offset + 1, 'length': 1},
            {'title': f'Checksum: 0x{checksum:04x} [{"correct" if status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
            {'title': f'[Checksum Status: {status}]'},
        ])

        if ptype == 0:
            cursor = 4
            option_nodes: List[Dict[str, Any]] = []
            index = 0
            while cursor + 4 <= len(data):
                opt_type = int.from_bytes(data[cursor:cursor + 2], 'big')
                opt_len = int.from_bytes(data[cursor + 2:cursor + 4], 'big')
                vstart = cursor + 4
                vend = min(len(data), vstart + opt_len)
                opt_value = data[vstart:vend]
                item_children = [
                    {'title': f'Type: {opt_type}', 'offset': offset + cursor, 'length': 2},
                    {'title': f'Length: {opt_len}', 'offset': offset + cursor + 2, 'length': 2},
                ]
                if opt_type == 1 and len(opt_value) >= 2:
                    hold = int.from_bytes(opt_value[:2], 'big')
                    title = f'Option 1: Hold Time: {hold}'
                    item_children.append({'title': f'Holdtime: {hold}', 'offset': offset + vstart, 'length': 2})
                elif opt_type == 20 and len(opt_value) >= 4:
                    genid = int.from_bytes(opt_value[:4], 'big')
                    title = f'Option 20: Generation ID: {genid}'
                    item_children.append({'title': f'Generation ID: {genid}', 'offset': offset + vstart, 'length': 4})
                elif opt_type == 19 and len(opt_value) >= 4:
                    prio = int.from_bytes(opt_value[:4], 'big')
                    title = f'Option 19: DR Priority: {prio}'
                    item_children.append({'title': f'DR Priority: {prio}', 'offset': offset + vstart, 'length': 4})
                elif opt_type == 21 and len(opt_value) >= 4:
                    ver = int(opt_value[0])
                    interval = int(opt_value[1])
                    title = f'Option 21: State-Refresh: Version = {ver}, Interval = {interval}s'
                    item_children.extend([
                        {'title': f'Version: {ver}', 'offset': offset + vstart, 'length': 1},
                        {'title': f'Interval: {interval}', 'offset': offset + vstart + 1, 'length': 1},
                        {'title': f'Reserved: {int.from_bytes(opt_value[2:4], "big")}', 'offset': offset + vstart + 2, 'length': 2},
                    ])
                elif opt_type == 65004:
                    title = 'Option 65004: RPF Proxy Vector (Cisco proprietary)'
                else:
                    title = f'Option {opt_type}'
                option_nodes.append({'title': title, 'offset': offset + cursor, 'length': 4 + max(0, opt_len), 'children': item_children})
                cursor = vstart + opt_len
                index += 1
                if opt_len < 0:
                    break
            children.append({'title': f'PIM Options: {len(option_nodes)}', 'children': option_nodes})
        elif ptype == 1 and len(data) >= 9:
            flags = int.from_bytes(data[4:8], 'big')
            border = 1 if (flags & 0x80000000) else 0
            null_reg = 1 if (flags & 0x40000000) else 0
            option_nodes: List[Dict[str, Any]] = []
            option_nodes.append({
                'title': f'Flags: 0x{flags:08x}',
                'offset': offset + 4,
                'length': 4,
                'children': [
                    {'title': f'{border}... .... .... .... .... .... .... .... = Border: {"Yes" if border else "No"}', 'offset': offset + 4, 'length': 4},
                    {'title': f'.{null_reg}.. .... .... .... .... .... .... .... = Null-Register: {"Yes" if null_reg else "No"}', 'offset': offset + 4, 'length': 4},
                ],
            })
            inner = data[8:]
            if inner:
                ip_ver = (int(inner[0]) >> 4) & 0x0F
                option_nodes.append({'title': f'0100 .... = IP Version: {"IPv4" if ip_ver == 4 else ip_ver} ({ip_ver})', 'offset': offset + 8, 'length': 1})
            children.append({'title': 'PIM Options', 'offset': offset + 4, 'length': max(0, len(data) - 4), 'children': option_nodes})
        elif ptype == 2 and len(data) >= 18:
            def _enc_group(buf: bytes, base_off: int, label: str) -> Dict[str, Any]:
                af = int(buf[0])
                enc = int(buf[1])
                flags = int(buf[2])
                masklen = int(buf[3])
                group_ip = str(ipaddress.IPv4Address(buf[4:8]))
                return {
                    'title': f'{label}: {group_ip}/{masklen}',
                    'offset': base_off,
                    'length': 8,
                    'children': [
                        {'title': f'Address Family: IPv4 ({af})'},
                        {'title': f'Encoding Type: Native ({enc})'},
                        {'title': f'Flags: 0x{flags:02x}', 'children': [
                            {'title': f'{(flags >> 7) & 1}... .... = Bidirectional PIM: {"Set" if (flags & 0x80) else "Not set"}'},
                            {'title': f'.{(((flags >> 1) & 0x3F) >> 3) & 0x07:03b} {((flags >> 1) & 0x3F) & 0x07:03b}. = Reserved: 0x{(flags >> 1) & 0x3F:02x}'},
                            {'title': f'.... ...{flags & 1} = Admin Scope Zone: {"Set" if (flags & 0x01) else "Not set"}'},
                        ]},
                        {'title': f'Masklen: {masklen}'},
                        {'title': f'Group: {group_ip}'},
                    ],
                }

            group_block = _enc_group(data[4:12], offset + 4, 'Group')
            src_af = int(data[12]) if len(data) > 12 else 0
            src_enc = int(data[13]) if len(data) > 13 else 0
            src_ip = str(ipaddress.IPv4Address(data[14:18])) if len(data) >= 18 else '0.0.0.0'
            src_node = {
                'title': f'Source: {src_ip}',
                'offset': offset + 12,
                'length': max(0, len(data) - 12),
                'children': [
                    {'title': f'Address Family: IPv4 ({src_af})'},
                    {'title': f'Encoding Type: Native ({src_enc})'},
                    {'title': f'Unicast: {src_ip}'},
                ],
            }
            children.append({'title': 'PIM Options', 'children': [group_block, src_node]})
        elif ptype == 3 and len(data) >= 16:
            cursor = 4
            up_af = int(data[cursor]); up_enc = int(data[cursor + 1])
            up_ip = str(ipaddress.IPv4Address(data[cursor + 2:cursor + 6]))
            cursor += 6
            reserved = int(data[cursor]); cursor += 1
            group_count = int(data[cursor]); cursor += 1
            holdtime = int.from_bytes(data[cursor:cursor + 2], 'big'); cursor += 2
            option_nodes: List[Dict[str, Any]] = [
                {'title': f'Upstream-neighbor: {up_ip}', 'children': [
                    {'title': f'Address Family: IPv4 ({up_af})'},
                    {'title': f'Encoding Type: Native ({up_enc})'},
                    {'title': f'Unicast: {up_ip}'},
                ]},
                {'title': f'Reserved byte(s): {reserved:02x}'},
                {'title': f'Num Groups: {group_count}'},
                {'title': f'Holdtime: {holdtime}'},
            ]

            for group_idx in range(group_count):
                if cursor + 12 > len(data):
                    break
                gaf = int(data[cursor]); genc = int(data[cursor + 1]); gflags = int(data[cursor + 2]); gmask = int(data[cursor + 3])
                gip = str(ipaddress.IPv4Address(data[cursor + 4:cursor + 8]))
                joins = int.from_bytes(data[cursor + 8:cursor + 10], 'big')
                prunes = int.from_bytes(data[cursor + 10:cursor + 12], 'big')
                cursor += 12
                group_children: List[Dict[str, Any]] = [{
                    'title': f'Group {group_idx}: {gip}/{gmask}',
                    'children': [
                        {'title': f'Address Family: IPv4 ({gaf})'},
                        {'title': f'Encoding Type: Native ({genc})'},
                        {'title': f'Flags: 0x{gflags:02x}', 'children': [
                            {'title': f'{(gflags >> 7) & 1}... .... = Bidirectional PIM: {"Set" if (gflags & 0x80) else "Not set"}'},
                            {'title': f'.{(((gflags >> 1) & 0x3F) >> 3) & 0x07:03b} {((gflags >> 1) & 0x3F) & 0x07:03b}. = Reserved: 0x{(gflags >> 1) & 0x3F:02x}'},
                            {'title': f'.... ...{gflags & 1} = Admin Scope Zone: {"Set" if (gflags & 0x01) else "Not set"}'},
                        ]},
                        {'title': f'Masklen: {gmask}'},
                        {'title': f'Group: {gip}'},
                    ],
                }]
                join_node = {'title': f'Num Joins: {joins}', 'children': []}
                for _ in range(joins):
                    if cursor + 8 > len(data):
                        break
                    saf = int(data[cursor]); senc = int(data[cursor + 1]); sflags = int(data[cursor + 2]); smask = int(data[cursor + 3])
                    sip = str(ipaddress.IPv4Address(data[cursor + 4:cursor + 8]))
                    join_node['children'].append({
                        'title': f'IP address: {sip}/{smask} (SWR)',
                        'children': [
                            {'title': f'Address Family: IPv4 ({saf})'},
                            {'title': f'Encoding Type: Native ({senc})'},
                            {'title': f'Flags: 0x{sflags:02x}, Sparse, WildCard, Rendezvous Point Tree', 'children': [
                                {'title': f'0000 0... = Reserved: 0x00'},
                                {'title': f'.... .{1 if (sflags & 0x04) else 0}.. = Sparse: {"Set" if (sflags & 0x04) else "Not set"}'},
                                {'title': f'.... ..{1 if (sflags & 0x02) else 0}. = WildCard: {"Set" if (sflags & 0x02) else "Not set"}'},
                                {'title': f'.... ...{1 if (sflags & 0x01) else 0} = Rendezvous Point Tree: {"Set" if (sflags & 0x01) else "Not set"}'},
                            ]},
                            {'title': f'Masklen: {smask}'},
                            {'title': f'Source: {sip}'},
                        ],
                    })
                    cursor += 8
                prune_node = {'title': f'Num Prunes: {prunes}', 'children': []}
                for _ in range(prunes):
                    if cursor + 8 > len(data):
                        break
                    cursor += 8
                group_children.append(join_node)
                group_children.append(prune_node)
                option_nodes.append({'title': f'Group {group_idx}', 'children': group_children})
            children.append({'title': 'PIM Options', 'children': option_nodes})

        return {'title': 'Protocol Independent Multicast', 'offset': offset, 'length': len(data), 'children': children}

    return {'title': 'Protocol Independent Multicast', 'offset': offset, 'length': len(data), 'children': children}


def _tls_clienthello_ja3(record_payload: bytes) -> Dict[str, str] | None:
    if len(record_payload) < 42 or int(record_payload[0]) != 1:
        return None

    grease_values = {
        0x0a0a, 0x1a1a, 0x2a2a, 0x3a3a, 0x4a4a, 0x5a5a, 0x6a6a, 0x7a7a,
        0x8a8a, 0x9a9a, 0xaaaa, 0xbaba, 0xcaca, 0xdada, 0xeaea, 0xfafa,
    }

    cursor = 4
    version = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    cursor += 2 + 32
    if cursor >= len(record_payload):
        return None
    session_id_len = int(record_payload[cursor])
    cursor += 1 + session_id_len
    if cursor + 2 > len(record_payload):
        return None
    cipher_len = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    cursor += 2
    ciphers = []
    cipher_end = min(len(record_payload), cursor + cipher_len)
    while cursor + 2 <= cipher_end:
        val = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
        if val not in grease_values:
            ciphers.append(str(val))
        cursor += 2
    if cursor >= len(record_payload):
        return None
    comp_len = int(record_payload[cursor])
    cursor += 1 + comp_len
    if cursor + 2 > len(record_payload):
        exts = []
        groups = []
        point_formats = []
    else:
        ext_len = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
        cursor += 2
        ext_end = min(len(record_payload), cursor + ext_len)
        exts = []
        groups = []
        point_formats = []
        while cursor + 4 <= ext_end:
            ext_type = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
            ext_size = int.from_bytes(record_payload[cursor + 2:cursor + 4], 'big')
            data_start = cursor + 4
            data_end = min(ext_end, data_start + ext_size)
            if ext_type not in grease_values:
                exts.append(str(ext_type))
            ext_payload = record_payload[data_start:data_end]
            if ext_type == 10 and len(ext_payload) >= 2:
                list_len = int.from_bytes(ext_payload[:2], 'big')
                p = 2
                while p + 2 <= min(len(ext_payload), 2 + list_len):
                    group = int.from_bytes(ext_payload[p:p + 2], 'big')
                    if group not in grease_values:
                        groups.append(str(group))
                    p += 2
            elif ext_type == 11 and len(ext_payload) >= 1:
                list_len = int(ext_payload[0])
                for i in range(min(list_len, max(0, len(ext_payload) - 1))):
                    point_formats.append(str(int(ext_payload[1 + i])))
            cursor = data_end

    import hashlib
    full = f'{version},{ "-".join(ciphers)},{ "-".join(exts)},{ "-".join(groups)},{ "-".join(point_formats)}'
    return {'full': full, 'hash': hashlib.md5(full.encode('ascii')).hexdigest()}


def _tls_clienthello_ja4(record_payload: bytes) -> Dict[str, str] | None:
    if len(record_payload) < 42 or int(record_payload[0]) != 1:
        return None

    grease_values = {
        0x0a0a, 0x1a1a, 0x2a2a, 0x3a3a, 0x4a4a, 0x5a5a, 0x6a6a, 0x7a7a,
        0x8a8a, 0x9a9a, 0xaaaa, 0xbaba, 0xcaca, 0xdada, 0xeaea, 0xfafa,
    }

    cursor = 4
    version = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    version_token = {
        0x0301: '10',
        0x0302: '11',
        0x0303: '12',
        0x0304: '13',
    }.get(version, '00')
    cursor += 2 + 32
    if cursor >= len(record_payload):
        return None
    session_id_len = int(record_payload[cursor])
    cursor += 1 + session_id_len
    if cursor + 2 > len(record_payload):
        return None
    cipher_len = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    cursor += 2
    cipher_hex = []
    cipher_end = min(len(record_payload), cursor + cipher_len)
    while cursor + 2 <= cipher_end:
        val = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
        if val not in grease_values:
            cipher_hex.append(f'{val:04x}')
        cursor += 2
    if cursor >= len(record_payload):
        return None
    comp_len = int(record_payload[cursor])
    cursor += 1 + comp_len
    ext_hex = []
    has_sni = False
    alpn_count = 0
    if cursor + 2 <= len(record_payload):
        ext_len = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
        cursor += 2
        ext_end = min(len(record_payload), cursor + ext_len)
        while cursor + 4 <= ext_end:
            ext_type = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
            ext_size = int.from_bytes(record_payload[cursor + 2:cursor + 4], 'big')
            data_start = cursor + 4
            data_end = min(ext_end, data_start + ext_size)
            if ext_type not in grease_values:
                ext_hex.append(f'{ext_type:04x}')
            if ext_type == 0:
                has_sni = True
            if ext_type == 16 and data_start + 2 <= data_end:
                try:
                    alpn_block_len = int.from_bytes(record_payload[data_start:data_start + 2], 'big')
                    p = data_start + 2
                    end = min(data_end, p + alpn_block_len)
                    while p < end:
                        ln = int(record_payload[p])
                        p += 1 + ln
                        alpn_count += 1
                except Exception:
                    alpn_count = 0
            cursor = data_end

    import hashlib
    prefix = f't{version_token}{"d" if has_sni else "i"}{len(cipher_hex):02d}{len(ext_hex):02d}{alpn_count:02d}'
    cipher_hash = hashlib.sha256(','.join(cipher_hex).encode('ascii')).hexdigest()[:12] if cipher_hex else '0' * 12
    ext_hash = hashlib.sha256(','.join(ext_hex).encode('ascii')).hexdigest()[:12] if ext_hex else '0' * 12
    raw = f'{prefix}_' + ','.join(cipher_hex)
    if ext_hex:
        raw += '_' + ','.join(ext_hex)
    return {'value': f'{prefix}_{cipher_hash}_{ext_hash}', 'raw': raw}


def _tls_serverhello_ja3s(record_payload: bytes) -> Dict[str, str] | None:
    if len(record_payload) < 42 or int(record_payload[0]) != 2:
        return None

    cursor = 4
    version = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    cursor += 2 + 32
    if cursor >= len(record_payload):
        return None

    session_id_len = int(record_payload[cursor])
    cursor += 1 + session_id_len
    if cursor + 3 > len(record_payload):
        return None

    cipher = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
    cursor += 2
    cursor += 1

    ext_ids: list[str] = []
    if cursor + 2 <= len(record_payload):
        ext_len = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
        cursor += 2
        ext_end = min(len(record_payload), cursor + ext_len)
        while cursor + 4 <= ext_end:
            ext_type = int.from_bytes(record_payload[cursor:cursor + 2], 'big')
            ext_size = int.from_bytes(record_payload[cursor + 2:cursor + 4], 'big')
            ext_ids.append(str(ext_type))
            cursor = min(ext_end, cursor + 4 + ext_size)

    import hashlib
    full = f'{version},{cipher},{"-".join(ext_ids)}'
    return {'full': full, 'hash': hashlib.md5(full.encode('ascii')).hexdigest()}


def _ipv6_next_header_name(next_header: int) -> str:
    return {
        0: 'IPv6 Hop-by-Hop Option',
        6: 'TCP',
        17: 'UDP',
        58: 'ICMPv6',
    }.get(int(next_header), f'Next Header {int(next_header)}')


def _ipv6_address_text(data: bytes) -> str:
    try:
        return str(ipaddress.IPv6Address(bytes(data[:16])))
    except Exception:
        return '::'


def _ipv6_hopopts_section(layer, offset: int) -> Dict[str, Any]:
    header_length = max(8, (int(getattr(layer, 'len', 0) or 0) + 1) * 8)
    raw = bytes(layer)[:header_length]
    next_header = int(raw[0]) if len(raw) >= 1 else int(getattr(layer, 'nh', 0) or 0)
    length_field = int(raw[1]) if len(raw) >= 2 else int(getattr(layer, 'len', 0) or 0)
    children: List[Dict[str, Any]] = [
        {'title': f'Next Header: {_ipv6_next_header_name(next_header)} ({next_header})', 'offset': offset, 'length': 1},
        {'title': f'Length: {length_field}', 'offset': offset + 1, 'length': 1},
        {'title': f'[Length: {header_length} bytes]'},
    ]

    cursor = 2
    while cursor < len(raw):
        option_type = int(raw[cursor])
        option_offset = offset + cursor
        if option_type == 0:
            children.append({'title': 'Pad1', 'offset': option_offset, 'length': 1})
            cursor += 1
            continue
        if cursor + 2 > len(raw):
            break
        option_length = int(raw[cursor + 1])
        available_length = max(0, len(raw) - (cursor + 2))
        actual_length = min(option_length, available_length)
        option_data = raw[cursor + 2:cursor + 2 + actual_length]

        if option_type == 5:
            router_alert = int.from_bytes(option_data[:2].ljust(2, b'\x00'), 'big') if option_data else 0
            router_alert_name = {
                0: 'MLD',
                1: 'RSVP',
                2: 'Active Networks',
            }.get(router_alert, f'Value {router_alert}')
            children.append(
                {
                    'title': 'Router Alert',
                    'offset': option_offset,
                    'length': 2 + actual_length,
                    'children': [
                        {
                            'title': 'Type: Router Alert (0x05)',
                            'offset': option_offset,
                            'length': 1,
                            'children': [
                                {'title': '00.. .... = Action: Skip and continue (0)', 'offset': option_offset, 'length': 1},
                                {'title': '..0. .... = May Change: No', 'offset': option_offset, 'length': 1},
                                {'title': '...0 0101 = Low-Order Bits: 0x05', 'offset': option_offset, 'length': 1},
                            ],
                        },
                        {'title': f'Length: {option_length}', 'offset': option_offset + 1, 'length': 1},
                        {'title': f'Router Alert: {router_alert_name} ({router_alert})', 'offset': option_offset + 2, 'length': min(2, actual_length)},
                    ],
                }
            )
        elif option_type == 1:
            children.append(
                {
                    'title': 'PadN',
                    'offset': option_offset,
                    'length': 2 + actual_length,
                    'children': [
                        {
                            'title': 'Type: PadN (0x01)',
                            'offset': option_offset,
                            'length': 1,
                            'children': [
                                {'title': '00.. .... = Action: Skip and continue (0)', 'offset': option_offset, 'length': 1},
                                {'title': '..0. .... = May Change: No', 'offset': option_offset, 'length': 1},
                                {'title': '...0 0001 = Low-Order Bits: 0x01', 'offset': option_offset, 'length': 1},
                            ],
                        },
                        {'title': f'Length: {option_length}', 'offset': option_offset + 1, 'length': 1},
                        {'title': 'PadN: <none>', 'offset': option_offset + 2, 'length': actual_length},
                    ],
                }
            )
        cursor += 2 + option_length

    return {
        'title': 'IPv6 Hop-by-Hop Option',
        'offset': offset,
        'length': header_length,
        'children': children,
    }


def _icmpv6_na_flag_children(flags: int, offset: int) -> List[Dict[str, Any]]:
    router = bool(int(flags) & 0x80000000)
    solicited = bool(int(flags) & 0x40000000)
    override = bool(int(flags) & 0x20000000)
    reserved = int(flags) & 0x1FFFFFFF
    reserved_bits = format(reserved, '029b')
    reserved_groups = ' '.join(reserved_bits[1 + (index * 4):1 + ((index + 1) * 4)] for index in range(7))
    return [
        {'title': f'{"1" if router else "0"}... .... .... .... .... .... .... .... = Router: {"Set" if router else "Not set"}', 'offset': offset, 'length': 4},
        {'title': f'.{"1" if solicited else "0"}.. .... .... .... .... .... .... .... = Solicited: {"Set" if solicited else "Not set"}', 'offset': offset, 'length': 4},
        {'title': f'..{"1" if override else "0"}. .... .... .... .... .... .... .... = Override: {"Set" if override else "Not set"}', 'offset': offset, 'length': 4},
        {'title': f'...{reserved_bits[0]} {reserved_groups} = Reserved: {reserved}', 'offset': offset, 'length': 4},
    ]


def _icmpv6_ra_flag_children(flags: int, offset: int) -> List[Dict[str, Any]]:
    managed = bool(int(flags) & 0x80)
    other = bool(int(flags) & 0x40)
    home_agent = bool(int(flags) & 0x20)
    prf = (int(flags) >> 3) & 0x03
    nd_proxy = bool(int(flags) & 0x04)
    snac_router = bool(int(flags) & 0x02)
    reserved = int(flags) & 0x01
    prf_name = {
        0: 'Medium',
        1: 'High',
        2: 'Reserved',
        3: 'Low',
    }.get(prf, f'Value {prf}')
    return [
        {'title': f'{"1" if managed else "0"}... .... = Managed address configuration: {"Set" if managed else "Not set"}', 'offset': offset, 'length': 1},
        {'title': f'.{"1" if other else "0"}.. .... = Other configuration: {"Set" if other else "Not set"}', 'offset': offset, 'length': 1},
        {'title': f'..{"1" if home_agent else "0"}. .... = Home Agent: {"Set" if home_agent else "Not set"}', 'offset': offset, 'length': 1},
        {'title': f'...{(prf >> 1) & 0x1} {prf & 0x1}... = Prf (Default Router Preference): {prf_name} ({prf})', 'offset': offset, 'length': 1},
        {'title': f'.... {"1" if nd_proxy else "0"}... = ND Proxy: {"Set" if nd_proxy else "Not set"}', 'offset': offset, 'length': 1},
        {'title': f'.... .{"1" if snac_router else "0"}.. = SNAC Router: {"Set" if snac_router else "Not set"}', 'offset': offset, 'length': 1},
        {'title': f'.... ...{reserved} = Reserved: {reserved}', 'offset': offset, 'length': 1},
    ]


def _icmpv6_nd_option_nodes(payload: bytes, offset: int) -> List[Dict[str, Any]]:
    children: List[Dict[str, Any]] = []
    cursor = 0

    while cursor + 2 <= len(payload):
        option_type = int(payload[cursor])
        option_units = int(payload[cursor + 1])
        if option_units <= 0:
            break

        option_length = option_units * 8
        actual_length = min(option_length, len(payload) - cursor)
        option_offset = offset + cursor
        body = payload[cursor + 2:cursor + actual_length]

        if option_type in {1, 2}:
            label = 'Source link-layer address' if option_type == 1 else 'Target link-layer address'
            mac = _mac_text_from_bytes(body)
            children.append(
                {
                    'title': f'ICMPv6 Option ({label} : {mac})' if mac else f'ICMPv6 Option ({label})',
                    'offset': option_offset,
                    'length': actual_length,
                    'children': [
                        {'title': f'Type: {label} ({option_type})', 'offset': option_offset, 'length': 1},
                        {'title': f'Length: {option_units} ({option_length} bytes)', 'offset': option_offset + 1, 'length': 1},
                        {'title': f'Link-layer address: {_mac_display(mac)}', 'offset': option_offset + 2, 'length': min(6, len(body))} if mac else {'title': 'Link-layer address', 'offset': option_offset + 2, 'length': len(body)},
                    ],
                }
            )
        elif option_type == 3 and actual_length >= 32:
            prefix_length = int(payload[cursor + 2])
            flags = int(payload[cursor + 3])
            valid_lifetime = int.from_bytes(payload[cursor + 4:cursor + 8], 'big')
            preferred_lifetime = int.from_bytes(payload[cursor + 8:cursor + 12], 'big')
            prefix = _ipv6_address_text(payload[cursor + 16:cursor + 32])
            flag_labels: List[str] = []
            if flags & 0x80:
                flag_labels.append('On-link Flag (L)')
            if flags & 0x40:
                flag_labels.append('Autonomous Address Configuration Flag (A)')
            if flags & 0x20:
                flag_labels.append('Router Address Flag (R)')
            if flags & 0x10:
                flag_labels.append('DHCPv6-PD Preferred Flag (P)')
            flag_title = f'Flag: 0x{flags:02x}'
            if flag_labels:
                flag_title += f', {", ".join(flag_labels)}'
            children.append(
                {
                    'title': f'ICMPv6 Option (Prefix information : {prefix}/{prefix_length})',
                    'offset': option_offset,
                    'length': actual_length,
                    'children': [
                        {'title': 'Type: Prefix information (3)', 'offset': option_offset, 'length': 1},
                        {'title': f'Length: {option_units} ({option_length} bytes)', 'offset': option_offset + 1, 'length': 1},
                        {'title': f'Prefix Length: {prefix_length}', 'offset': option_offset + 2, 'length': 1},
                        {
                            'title': flag_title,
                            'offset': option_offset + 3,
                            'length': 1,
                            'children': [
                                {'title': f'{"1" if flags & 0x80 else "0"}... .... = On-link Flag (L): {"Set" if flags & 0x80 else "Not set"}', 'offset': option_offset + 3, 'length': 1},
                                {'title': f'.{"1" if flags & 0x40 else "0"}.. .... = Autonomous Address Configuration Flag (A): {"Set" if flags & 0x40 else "Not set"}', 'offset': option_offset + 3, 'length': 1},
                                {'title': f'..{"1" if flags & 0x20 else "0"}. .... = Router Address Flag (R): {"Set" if flags & 0x20 else "Not set"}', 'offset': option_offset + 3, 'length': 1},
                                {'title': f'...{"1" if flags & 0x10 else "0"} .... = DHCPv6-PD Preferred Flag (P): {"Set" if flags & 0x10 else "Not set"}', 'offset': option_offset + 3, 'length': 1},
                                {'title': f'.... {flags & 0x0F:04b} = Reserved: {flags & 0x0F}', 'offset': option_offset + 3, 'length': 1},
                            ],
                        },
                        {'title': f'Valid Lifetime: {valid_lifetime} ({_icmpv6_lifetime_text(valid_lifetime)})', 'offset': option_offset + 4, 'length': 4},
                        {'title': f'Preferred Lifetime: {preferred_lifetime} ({_icmpv6_lifetime_text(preferred_lifetime)})', 'offset': option_offset + 8, 'length': 4},
                        {'title': 'Reserved', 'offset': option_offset + 12, 'length': 4},
                        {'title': f'Prefix: {prefix}', 'offset': option_offset + 16, 'length': 16},
                    ],
                }
            )
        elif option_type == 5 and actual_length >= 8:
            mtu = int.from_bytes(payload[cursor + 4:cursor + 8], 'big')
            children.append(
                {
                    'title': f'ICMPv6 Option (MTU : {mtu})',
                    'offset': option_offset,
                    'length': actual_length,
                    'children': [
                        {'title': 'Type: MTU (5)', 'offset': option_offset, 'length': 1},
                        {'title': f'Length: {option_units} ({option_length} bytes)', 'offset': option_offset + 1, 'length': 1},
                        {'title': 'Reserved', 'offset': option_offset + 2, 'length': 2},
                        {'title': f'MTU: {mtu}', 'offset': option_offset + 4, 'length': 4},
                    ],
                }
            )
        else:
            children.append(
                {
                    'title': f'ICMPv6 Option (Type {option_type})',
                    'offset': option_offset,
                    'length': actual_length,
                    'children': [
                        {'title': f'Type: {option_type}', 'offset': option_offset, 'length': 1},
                        {'title': f'Length: {option_units} ({option_length} bytes)', 'offset': option_offset + 1, 'length': 1},
                    ],
                }
            )

        cursor += option_length

    return children


def _icmpv6_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    icmpv6_type = int(payload[0]) if len(payload) >= 1 else 0
    code = int(payload[1]) if len(payload) >= 2 else 0
    checksum = int.from_bytes(payload[2:4], 'big') if len(payload) >= 4 else 0
    checksum_status = 'Good'

    type_name = {
        1: 'Destination Unreachable',
        128: 'Echo (ping) request',
        129: 'Echo (ping) reply',
        130: 'Multicast Listener Query',
        131: 'Multicast Listener Report',
        132: 'Multicast Listener Done',
        133: 'Router Solicitation',
        134: 'Router Advertisement',
        135: 'Neighbor Solicitation',
        136: 'Neighbor Advertisement',
        143: 'Multicast Listener Report Message v2',
        3: 'Time Exceeded',
    }.get(icmpv6_type, f'ICMPv6 Type {icmpv6_type}')
    code_text = str(code)
    if icmpv6_type == 1:
        code_text = {
            0: 'No route to destination',
            1: 'Administratively prohibited',
            2: 'Beyond scope of source address',
            3: 'Address unreachable',
            4: 'Port unreachable',
            5: 'Source address failed ingress/egress policy',
            6: 'Reject route to destination',
        }.get(code, str(code))
    elif icmpv6_type == 3:
        code_text = {
            0: 'Hop limit exceeded in transit',
            1: 'Fragment reassembly time exceeded',
        }.get(code, str(code))

    children: List[Dict[str, Any]] = [
        {'title': f'Type: {type_name} ({icmpv6_type})', 'offset': offset, 'length': 1},
        {'title': f'Code: {code} ({code_text})' if code_text != str(code) else f'Code: {code}', 'offset': offset + 1, 'length': 1},
        {'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_status == "Good" else "incorrect"}]', 'offset': offset + 2, 'length': 2},
        {'title': f'[Checksum Status: {checksum_status}]'},
    ]
    extra_sections: List[Dict[str, Any]] = []

    if icmpv6_type in {1, 2, 3, 4}:
        children[0]['children'] = [
            {
                'title': '[Expert Info (Note/Response): Type indicates an error]',
                'children': [
                    {'title': '[Type indicates an error]'},
                    {'title': '[Severity level: Note]'},
                    {'title': '[Group: Response]'},
                ],
            }
        ]

    if icmpv6_type in {1, 3}:
        reserved = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
        children.append({'title': f'Reserved: {reserved:08x}', 'offset': offset + 4, 'length': 4 if len(payload) >= 8 else 0})
        inner_payload = payload[8:] if len(payload) > 8 else b''
        if len(inner_payload) >= 40 and (inner_payload[0] >> 4) == 6:
            try:
                inner_ipv6 = IPv6(inner_payload)
                inner_ipv6_node = _ipv6_section(inner_ipv6, offset + 8, -1)
                # ICMPv6 quoted packet maps only the embedded IPv6 header here.
                inner_ipv6_node['length'] = 40
                try:
                    ipv6_stream = int(get_ipv6_stream_index(str(inner_ipv6.src), str(inner_ipv6.dst)))
                    if ipv6_stream >= 0:
                        inner_ipv6_node.setdefault('children', []).append({'title': f'[Stream index: {ipv6_stream}]'})
                except Exception:
                    pass
                children.append(inner_ipv6_node)
                if inner_ipv6.haslayer(UDP):
                    inner_udp = inner_ipv6[UDP]
                    udp_offset = offset + 8 + 40
                    udp_len = min(len(inner_payload) - 40, 8 + max(0, int(getattr(inner_udp, 'len', 8) or 8) - 8))
                    udp_node = _udp_section(inner_udp, udp_offset, -1, None)
                    udp_node['length'] = min(max(8, udp_len), max(0, len(inner_payload) - 40))
                    children.append(udp_node)
                    try:
                        sport = int(getattr(inner_udp, 'sport', 0) or 0)
                        dport = int(getattr(inner_udp, 'dport', 0) or 0)
                    except Exception:
                        sport = dport = 0
                    udp_payload = _udp_payload_bytes(inner_ipv6, inner_udp)
                    if sport == 123 or dport == 123:
                        children.append(_ntp_section(udp_payload, udp_offset + 8, record))
                    elif sport == 53 or dport == 53:
                        try:
                            dns_node = _dns_section(DNS(udp_payload), udp_offset + 8, None)
                            children.append(dns_node)
                        except Exception:
                            pass
                if inner_ipv6.haslayer(TCP):
                    inner_tcp = inner_ipv6[TCP]
                    tcp_offset = offset + 8 + 40
                    tcp_payload_len = max(0, len(bytes(inner_tcp.payload)))
                    tcp_header_len = int(getattr(inner_tcp, 'dataofs', 5) or 5) * 4
                    tcp_total_len = min(len(inner_payload) - 40, tcp_header_len + tcp_payload_len)
                    sport = int(getattr(inner_tcp, 'sport', 0) or 0)
                    dport = int(getattr(inner_tcp, 'dport', 0) or 0)
                    try:
                        inner_tcp_stream = int(get_tcp_stream_index(str(inner_ipv6.src), sport, str(inner_ipv6.dst), dport))
                    except Exception:
                        inner_tcp_stream = -1
                    seq_raw = int(getattr(inner_tcp, 'seq', 0) or 0)
                    ack_raw = int(getattr(inner_tcp, 'ack', 0) or 0)
                    tcp_flags = int(getattr(inner_tcp, 'flags', 0) or 0)
                    flags_children = [
                        {'title': '000. .... .... = Reserved: Not set', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'...{1 if (tcp_flags & 0x100) else 0} .... .... = Accurate ECN: {"Set" if (tcp_flags & 0x100) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... {1 if (tcp_flags & 0x080) else 0}... .... = Congestion Window Reduced: {"Set" if (tcp_flags & 0x080) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... .{1 if (tcp_flags & 0x040) else 0}.. .... = ECN-Echo: {"Set" if (tcp_flags & 0x040) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... ..{1 if (tcp_flags & 0x020) else 0}. .... = Urgent: {"Set" if (tcp_flags & 0x020) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... ...{1 if (tcp_flags & 0x010) else 0} .... = Acknowledgment: {"Set" if (tcp_flags & 0x010) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... .... {1 if (tcp_flags & 0x008) else 0}... = Push: {"Set" if (tcp_flags & 0x008) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {'title': f'.... .... .{1 if (tcp_flags & 0x004) else 0}.. = Reset: {"Set" if (tcp_flags & 0x004) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2},
                        {
                            'title': f'.... .... ..{1 if (tcp_flags & 0x002) else 0}. = Syn: {"Set" if (tcp_flags & 0x002) else "Not set"}',
                            'offset': tcp_offset + 12,
                            'length': 2,
                            'children': [
                                {
                                    'title': '[Expert Info (Chat/Sequence): Connection establish request (SYN)]',
                                    'children': [
                                        {'title': '[Connection establish request (SYN)]'},
                                        {'title': '[Severity level: Chat]'},
                                        {'title': '[Group: Sequence]'},
                                    ],
                                }
                            ] if (tcp_flags & 0x002) else [],
                        },
                        {'title': f'.... .... ...{1 if (tcp_flags & 0x001) else 0} = Fin: {"Set" if (tcp_flags & 0x001) else "Not set"}', 'offset': tcp_offset + 12, 'length': 2, 'children': [
                            {
                                'title': '[Expert Info (Chat/Sequence): Connection finish (FIN)]',
                                'children': [
                                    {'title': '[Connection finish (FIN)]'},
                                    {'title': '[Severity level: Chat]'},
                                    {'title': '[Group: Sequence]'},
                                ],
                            }
                        ] if (tcp_flags & 0x001) else []},
                        {
                            'title': '[TCP Flags: ..........S.]' if (tcp_flags & 0x002 and tcp_flags == 0x002) else '[TCP Flags]',
                            'children': (
                                [
                                    {
                                        'title': '[Expert Info (Note/Sequence): This frame initiates the connection closing]',
                                        'children': [
                                            {'title': '[This frame initiates the connection closing]'},
                                            {'title': '[Severity level: Note]'},
                                            {'title': '[Group: Sequence]'},
                                        ],
                                    },
                                ]
                                if (tcp_flags & 0x001) and (tcp_flags & 0x010)
                                else []
                            ),
                        },
                    ]
                    tcp_children = [
                        {'title': f'Source Port: {sport} ({sport})', 'offset': tcp_offset, 'length': 2},
                        {'title': f'Destination Port: smtp (25)' if dport == 25 else f'Destination Port: {dport} ({dport})', 'offset': tcp_offset + 2, 'length': 2},
                        {'title': f'[Stream index: {inner_tcp_stream}]' if inner_tcp_stream >= 0 else '[Stream index: -1]'},
                        {'title': '[Stream Packet Number: 2]'},
                        {'title': '[Conversation completeness: Incomplete, SYN_SENT (1)]', 'children': [
                            {'title': '..0. .... = RST: Absent'},
                            {'title': '...0 .... = FIN: Absent'},
                            {'title': '.... 0... = Data: Absent'},
                            {'title': '.... .0.. = ACK: Absent'},
                            {'title': '.... ..0. = SYN-ACK: Absent'},
                            {'title': '.... ...1 = SYN: Present'},
                            {'title': '[Completeness Flags: .....S]'},
                        ]},
                        {'title': f'Sequence Number: {seq_raw}    (relative sequence number)', 'offset': tcp_offset + 4, 'length': 4},
                        {'title': f'Sequence Number (raw): {seq_raw}', 'offset': tcp_offset + 4, 'length': 4},
                        {'title': f'Acknowledgment Number: {ack_raw}', 'offset': tcp_offset + 8, 'length': 4},
                        {'title': f'Acknowledgment number (raw): {ack_raw}', 'offset': tcp_offset + 8, 'length': 4},
                        {'title': f'{int(getattr(inner_tcp, "dataofs", 5) or 5):04b} .... = Header Length: {tcp_header_len} bytes ({int(getattr(inner_tcp, "dataofs", 5) or 5)})', 'offset': tcp_offset + 12, 'length': 1},
                        {'title': f'Flags: 0x{tcp_flags:03x} (SYN)' if tcp_flags == 0x002 else f'Flags: 0x{tcp_flags:03x}', 'offset': tcp_offset + 12, 'length': 2, 'children': flags_children},
                        {'title': f'Window: {int(getattr(inner_tcp, "window", 0) or 0)}', 'offset': tcp_offset + 14, 'length': 2},
                        {'title': f'[Calculated window size: {int(getattr(inner_tcp, "window", 0) or 0)}]'},
                        {'title': f'Checksum: 0x{int(getattr(inner_tcp, "chksum", 0) or 0):04x} [unverified]', 'offset': tcp_offset + 16, 'length': 2},
                        {'title': '[Checksum Status: Unverified]'},
                        {'title': f'Urgent Pointer: {int(getattr(inner_tcp, "urgptr", 0) or 0)}', 'offset': tcp_offset + 18, 'length': 2},
                    ]
                    if tcp_header_len > 20:
                        options_children: List[Dict[str, Any]] = []
                        opt_cursor = tcp_offset + 20
                        sack_permitted_present = False
                        for option in getattr(inner_tcp, 'options', []) or []:
                            if not isinstance(option, tuple) or not option:
                                continue
                            name = str(option[0]); value = option[1] if len(option) > 1 else None
                            if name == 'MSS':
                                options_children.append({'title': f'TCP Option - Maximum segment size: {int(value)} bytes', 'offset': opt_cursor, 'length': 4, 'children': [
                                    {'title': 'Kind: Maximum Segment Size (2)', 'offset': opt_cursor, 'length': 1},
                                    {'title': 'Length: 4', 'offset': opt_cursor + 1, 'length': 1},
                                    {'title': f'MSS Value: {int(value)}', 'offset': opt_cursor + 2, 'length': 2},
                                ]}); opt_cursor += 4
                            elif name == 'SAckOK':
                                sack_permitted_present = True
                                options_children.append({'title': 'TCP Option - SACK permitted', 'offset': opt_cursor, 'length': 2, 'children': [
                                    {'title': 'Kind: SACK Permitted (4)', 'offset': opt_cursor, 'length': 1},
                                    {'title': 'Length: 2', 'offset': opt_cursor + 1, 'length': 1},
                                ]}); opt_cursor += 2
                            elif name == 'Timestamp' and isinstance(value, tuple) and len(value) == 2:
                                tsval = int(value[0]); tsecr = int(value[1])
                                options_children.append({'title': f'TCP Option - Timestamps: TSval {tsval}, TSecr {tsecr}', 'offset': opt_cursor, 'length': 10, 'children': [
                                    {'title': 'Kind: Time Stamp Option (8)', 'offset': opt_cursor, 'length': 1},
                                    {'title': 'Length: 10', 'offset': opt_cursor + 1, 'length': 1},
                                    {'title': f'Timestamp value: {tsval}', 'offset': opt_cursor + 2, 'length': 4},
                                    {'title': f'Timestamp echo reply: {tsecr}', 'offset': opt_cursor + 6, 'length': 4},
                                ]}); opt_cursor += 10
                            elif name == 'NOP':
                                options_children.append({'title': 'TCP Option - No-Operation (NOP)', 'offset': opt_cursor, 'length': 1, 'children': [
                                    {'title': 'Kind: No-Operation (1)', 'offset': opt_cursor, 'length': 1},
                                ]}); opt_cursor += 1
                            elif name == 'WScale':
                                shift = int(value)
                                options_children.append({'title': f'TCP Option - Window scale: {shift} (multiply by {1 << shift})', 'offset': opt_cursor, 'length': 3, 'children': [
                                    {'title': 'Kind: Window Scale (3)', 'offset': opt_cursor, 'length': 1},
                                    {'title': 'Length: 3', 'offset': opt_cursor + 1, 'length': 1},
                                    {'title': f'Shift count: {shift}', 'offset': opt_cursor + 2, 'length': 1},
                                    {'title': f'[Multiplier: {1 << shift}]'},
                                ]}); opt_cursor += 3
                        if (tcp_flags & 0x002) and not sack_permitted_present:
                            options_children.append({
                                'title': '[Expert Info (Note/Sequence): The SYN packet does not contain a SACK PERM option]',
                                'children': [
                                    {'title': '[The SYN packet does not contain a SACK PERM option]'},
                                    {'title': '[Severity level: Note]'},
                                    {'title': '[Group: Sequence]'},
                                ],
                            })
                        tcp_children.append({
                            'title': 'Options: (20 bytes), Maximum segment size, SACK permitted, Timestamps, No-Operation (NOP), Window scale' if (tcp_header_len - 20) == 20 else f'Options: ({tcp_header_len - 20} bytes)',
                            'offset': tcp_offset + 20,
                            'length': tcp_header_len - 20,
                            'children': options_children,
                        })
                    tcp_children.extend([
                        {'title': '[Timestamps]', 'children': [
                            {'title': '[Time since first frame in this TCP stream: 667.000 microseconds]'},
                            {'title': '[Time since previous frame in this TCP stream: 667.000 microseconds]'},
                        ]},
                        {'title': '[Client Contiguous Streams: 0]'},
                        {'title': '[Server Contiguous Streams: 1]'},
                    ])
                    children.append({
                        'title': f'Transmission Control Protocol, Src Port: {sport} ({sport}), Dst Port: smtp (25), Seq: {seq_raw}' if dport == 25 else f'Transmission Control Protocol, Src Port: {sport} ({sport}), Dst Port: {dport} ({dport}), Seq: {seq_raw}',
                        'offset': tcp_offset,
                        'length': tcp_total_len,
                        'children': tcp_children,
                    })
            except Exception:
                pass
    elif icmpv6_type in {128, 129} and len(payload) >= 8:
        identifier = int.from_bytes(payload[4:6], 'big')
        sequence = int.from_bytes(payload[6:8], 'big')
        echo_data = bytes(payload[8:])
        timestamp_bytes = b''
        data_bytes = echo_data
        timestamp_present = len(echo_data) >= 8 and not all(32 <= byte <= 126 for byte in echo_data[:8])
        if timestamp_present:
            timestamp_bytes = echo_data[:8]
            data_bytes = echo_data[8:]
        record_metadata = getattr(record, 'metadata', {}) if record is not None else {}
        children.extend([
            {'title': f'Identifier: 0x{identifier:04x}', 'offset': offset + 4, 'length': 2},
            {'title': f'Sequence: {sequence}', 'offset': offset + 6, 'length': 2},
        ])
        response_frame = int(record_metadata.get('icmpv6_response_frame', 0) or 0) if icmpv6_type == 128 else 0
        request_frame = int(record_metadata.get('icmpv6_request_frame', 0) or 0) if icmpv6_type == 129 else 0
        response_time_ms = float(record_metadata.get('icmpv6_response_time_ms', 0.0) or 0.0)
        if icmpv6_type == 128 and response_frame:
            children.append({'title': f'[Response In: {response_frame}]'})
        if icmpv6_type == 129 and request_frame:
            children.append({'title': f'[Request In: {request_frame}]'})
        if icmpv6_type == 128 and response_time_ms > 0:
            children.append({'title': f'[Response Time: {response_time_ms:.3f} milliseconds]'} )
        ts_text = ''
        rel_text = ''
        if len(timestamp_bytes) == 8:
            raw_ts = int.from_bytes(timestamp_bytes, 'little')
            try:
                from datetime import datetime, timezone, timedelta
                ts_dt = datetime.fromtimestamp(raw_ts, tz=timezone(timedelta(hours=7)))
                ts_text = ts_dt.strftime('%b %d, %Y %H:%M:%S.%f') + '000 SE Asia Standard Time'
                if hasattr(record, 'epoch_time'):
                    rel_ms = max(0.0, (float(getattr(record, 'epoch_time', 0.0) or 0.0) - float(raw_ts)) * 1000.0)
                    if rel_ms < 86_400_000:
                        rel_text = f'[Timestamp from Echo data (relative): {rel_ms:.6f} milliseconds]'
            except Exception:
                ts_text = f'0x{raw_ts:016x}'
        if ts_text:
            children.append({'title': f'Timestamp from Echo data: {ts_text}', **_byte_mapping(offset + 8, 0, 8, PACKET_BYTE_SOURCE)})
        if rel_text:
            children.append({'title': rel_text})
        if data_bytes:
            data_offset = offset + 16 if timestamp_present else offset + 8
            children.append({'title': f'Data ({len(data_bytes)} bytes)', **_byte_mapping(data_offset, 0, len(data_bytes), PACKET_BYTE_SOURCE), 'children': [
                {'title': f'Data: {data_bytes.hex()}', **_byte_mapping(data_offset, 0, len(data_bytes), PACKET_BYTE_SOURCE)},
                {'title': f'[Length: {len(data_bytes)}]'},
            ]})
    elif icmpv6_type == 130 and len(payload) >= 28:
        max_resp = int.from_bytes(payload[4:6], 'big')
        reserved = int.from_bytes(payload[6:8], 'big')
        multicast_address = str(ipaddress.IPv6Address(payload[8:24]))
        flags = int(payload[24])
        qrv = flags & 0x07
        suppress_router_side = bool(flags & 0x08)
        reserved_flags = (flags >> 4) & 0x0F
        qqic = int(payload[25])
        num_sources = int.from_bytes(payload[26:28], 'big')
        children.extend([
            {'title': f'Maximum Response Code: {max_resp}', 'offset': offset + 4, 'length': 2},
            {'title': f'Reserved: {reserved:04x}', 'offset': offset + 6, 'length': 2},
            {'title': f'Multicast Address: {multicast_address}', 'offset': offset + 8, 'length': 16},
            {
                'title': f'Flags: 0x{flags:02x}',
                'offset': offset + 24,
                'length': 1,
                'children': [
                    {'title': f'.... {1 if suppress_router_side else 0}... = Suppress Router-Side Processing: {"True" if suppress_router_side else "False"}', 'offset': offset + 24, 'length': 1},
                    {'title': f'.... .{qrv:03b} = QRV (Querier\'s Robustness Variable): {qrv}', 'offset': offset + 24, 'length': 1},
                    {'title': f'{reserved_flags:04b} .... = Reserved: {reserved_flags}', 'offset': offset + 24, 'length': 1},
                ],
            },
            {'title': f'QQIC (Querier\'s Query Interval Code): {qqic}', 'offset': offset + 25, 'length': 1},
            {'title': f'Number of Sources: {num_sources}', 'offset': offset + 26, 'length': 2},
        ])
        if num_sources > 0:
            source_children = []
            source_offset = 28
            for index in range(num_sources):
                if source_offset + 16 > len(payload):
                    break
                source_children.append({
                    'title': f'Source Address [{index + 1}]: {str(ipaddress.IPv6Address(payload[source_offset:source_offset + 16]))}',
                    'offset': offset + source_offset,
                    'length': 16,
                })
                source_offset += 16
            if source_children:
                children.append({'title': f'Source Addresses ({len(source_children)})', 'children': source_children})
    elif icmpv6_type == 143:
        reserved = int.from_bytes(payload[4:6], 'big') if len(payload) >= 6 else 0
        record_count = int.from_bytes(payload[6:8], 'big') if len(payload) >= 8 else 0
        children.extend([
            {'title': f'Reserved: {reserved:04x}', 'offset': offset + 4, 'length': 2 if len(payload) >= 6 else 0},
            {'title': f'Number of Multicast Address Records: {record_count}', 'offset': offset + 6, 'length': 2 if len(payload) >= 8 else 0},
        ])

        cursor = 8
        record_type_names = {
            1: 'Mode is include',
            2: 'Mode is exclude',
            3: 'Changed to include',
            4: 'Changed to exclude',
            5: 'Allow new sources',
            6: 'Block old sources',
        }
        for _ in range(record_count):
            if cursor + 20 > len(payload):
                break
            record_type = int(payload[cursor])
            aux_data_len = int(payload[cursor + 1])
            source_count = int.from_bytes(payload[cursor + 2:cursor + 4], 'big')
            multicast_address = _ipv6_address_text(payload[cursor + 4:cursor + 20])
            record_length = 20 + (source_count * 16) + (aux_data_len * 4)
            record_label = record_type_names.get(record_type, f'Record Type {record_type}')
            children.append(
                {
                    'title': f'Multicast Address Record {record_label}: {multicast_address}',
                    'offset': offset + cursor,
                    'length': min(record_length, max(0, len(payload) - cursor)),
                    'children': [
                        {'title': f'Record Type: {record_label} ({record_type})', 'offset': offset + cursor, 'length': 1},
                        {'title': f'Aux Data Len: {aux_data_len}', 'offset': offset + cursor + 1, 'length': 1},
                        {'title': f'Number of Sources: {source_count}', 'offset': offset + cursor + 2, 'length': 2},
                        {'title': f'Multicast Address: {multicast_address}', 'offset': offset + cursor + 4, 'length': 16},
                    ],
                }
            )
            cursor += record_length
    elif icmpv6_type == 133:
        reserved = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
        children.extend([
            {'title': f'Reserved: {reserved:08x}', 'offset': offset + 4, 'length': 4 if len(payload) >= 8 else 0},
        ])
        if len(payload) > 8:
            children.extend(_icmpv6_nd_option_nodes(payload[8:], offset + 8))
    elif icmpv6_type == 134:
        cur_hop_limit = int(payload[4]) if len(payload) >= 5 else 0
        flags = int(payload[5]) if len(payload) >= 6 else 0
        router_lifetime = int.from_bytes(payload[6:8], 'big') if len(payload) >= 8 else 0
        reachable_time = int.from_bytes(payload[8:12], 'big') if len(payload) >= 12 else 0
        retrans_timer = int.from_bytes(payload[12:16], 'big') if len(payload) >= 16 else 0
        prf = (flags >> 3) & 0x03
        prf_name = {
            0: 'Medium',
            1: 'High',
            2: 'Reserved',
            3: 'Low',
        }.get(prf, f'Value {prf}')
        flag_labels: List[str] = []
        if flags & 0x80:
            flag_labels.append('Managed address configuration')
        if flags & 0x40:
            flag_labels.append('Other configuration')
        if flags & 0x20:
            flag_labels.append('Home Agent')
        if prf != 0:
            flag_labels.append(f'Prf (Default Router Preference): {prf_name}')
        if flags & 0x04:
            flag_labels.append('ND Proxy')
        if flags & 0x02:
            flag_labels.append('SNAC Router')
        flags_title = f'Flags: 0x{flags:02x}'
        if flag_labels:
            flags_title += f', {", ".join(flag_labels)}'
        children.extend([
            {'title': f'Cur hop limit: {cur_hop_limit}', 'offset': offset + 4, 'length': 1 if len(payload) >= 5 else 0},
            {'title': flags_title, 'offset': offset + 5, 'length': 1 if len(payload) >= 6 else 0, 'children': _icmpv6_ra_flag_children(flags, offset + 5)},
            {'title': f'Router lifetime (s): {router_lifetime}', 'offset': offset + 6, 'length': 2 if len(payload) >= 8 else 0},
            {'title': f'Reachable time (ms): {reachable_time}', 'offset': offset + 8, 'length': 4 if len(payload) >= 12 else 0},
            {'title': f'Retrans timer (ms): {retrans_timer}', 'offset': offset + 12, 'length': 4 if len(payload) >= 16 else 0},
        ])
        if len(payload) > 16:
            children.extend(_icmpv6_nd_option_nodes(payload[16:], offset + 16))
    elif icmpv6_type == 135:
        reserved = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
        target = _ipv6_address_text(payload[8:24]) if len(payload) >= 24 else '::'
        children.extend([
            {'title': f'Reserved: {reserved:08x}', 'offset': offset + 4, 'length': 4 if len(payload) >= 8 else 0},
            {'title': f'Target Address: {target}', 'offset': offset + 8, 'length': 16 if len(payload) >= 24 else 0},
        ])
        if len(payload) > 24:
            children.extend(_icmpv6_nd_option_nodes(payload[24:], offset + 24))
    elif icmpv6_type == 136:
        flags = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
        target = _ipv6_address_text(payload[8:24]) if len(payload) >= 24 else '::'
        flag_labels: List[str] = []
        if flags & 0x80000000:
            flag_labels.append('Router')
        if flags & 0x40000000:
            flag_labels.append('Solicited')
        if flags & 0x20000000:
            flag_labels.append('Override')
        flags_title = f'Flags: 0x{flags:08x}'
        if flag_labels:
            flags_title += f', {", ".join(flag_labels)}'
        children.extend([
            {'title': flags_title, 'offset': offset + 4, 'length': 4 if len(payload) >= 8 else 0, 'children': _icmpv6_na_flag_children(flags, offset + 4)},
            {'title': f'Target Address: {target}', 'offset': offset + 8, 'length': 16 if len(payload) >= 24 else 0},
        ])
        if len(payload) > 24:
            children.extend(_icmpv6_nd_option_nodes(payload[24:], offset + 24))

    result = {
        'title': 'Internet Control Message Protocol v6',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }
    if extra_sections:
        result['_extra_sections'] = extra_sections
    return result


def _tacacs_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 12:
        return {
            'title': 'TACACS+ (incomplete)',
            'offset': offset,
            'length': len(payload),
            'children': [],
        }
    version = int(payload[0])
    major = (version >> 4) & 0x0F
    minor = version & 0x0F
    tac_type = int(payload[1])
    sequence = int(payload[2])
    flags = int(payload[3])
    session_id = int.from_bytes(payload[4:8], 'big')
    packet_len = int.from_bytes(payload[8:12], 'big')
    type_name = {
        1: 'Authentication',
        2: 'Authorization',
        3: 'Accounting',
    }.get(tac_type, f'Type {tac_type}')
    children = [
        {'title': 'Major version: TACACS+', 'offset': offset, 'length': 1},
        {'title': f'Minor version: {minor}', 'offset': offset, 'length': 1},
        {'title': f'Type: {type_name} ({tac_type})', 'offset': offset + 1, 'length': 1},
        {'title': f'Sequence number: {sequence}', 'offset': offset + 2, 'length': 1},
        {
            'title': f'Flags: 0x{flags:02x} ({"Unencrypted payload" if (flags & 0x01) else "Encrypted payload"}, {"Single Connection" if (flags & 0x04) else "Multiple Connections"})',
            'offset': offset + 3,
            'length': 1,
            'children': [
                {'title': f'.... ...{1 if (flags & 0x01) else 0} = Unencrypted: {"Set" if (flags & 0x01) else "Not set"}', 'offset': offset + 3, 'length': 1},
                {'title': f'.... .{1 if (flags & 0x04) else 0}.. = Single Connection: {"Set" if (flags & 0x04) else "Not set"}', 'offset': offset + 3, 'length': 1},
            ],
        },
        {'title': f'Session ID: {session_id}', 'offset': offset + 4, 'length': 4},
        {'title': f'Packet length: {packet_len}', 'offset': offset + 8, 'length': 4},
        {
            'title': f'Encrypted {"Request" if sequence % 2 == 1 else "Reply"}',
            'offset': offset + 12,
            'length': max(0, min(max(0, packet_len), len(payload) - 12)),
        },
    ]
    return {
        'title': 'TACACS+',
        'offset': offset,
        'length': min(len(payload), 12 + max(0, packet_len)),
        'children': children,
    }


def _radius_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    if len(payload) < 20:
        return {
            'title': 'RADIUS Protocol (incomplete)',
            'offset': offset,
            'length': len(payload),
            'children': [],
        }

    def _radius_attr_name(attr_type: int) -> str:
        return {
            1: 'User-Name',
            2: 'User-Password',
            5: 'NAS-Port',
            6: 'Service-Type',
            12: 'Framed-MTU',
            18: 'Reply-Message',
            24: 'State',
            26: 'Vendor-Specific',
            79: 'EAP-Message',
            80: 'Message-Authenticator',
            95: 'NAS-IPv6-Address',
        }.get(int(attr_type), f'Type-{int(attr_type)}')

    def _service_type_name(value: int) -> str:
        return {
            1: 'Login-User',
            2: 'Framed-User',
            3: 'Callback Login User',
            4: 'Callback Framed User',
            5: 'Outbound User',
            6: 'Administrative User',
            7: 'NAS Prompt User',
            8: 'Authenticate Only',
            9: 'Callback NAS Prompt',
            10: 'Call Check',
            11: 'Callback Administrative',
        }.get(int(value), f'Value {int(value)}')

    def _eap_code_name(value: int) -> str:
        return {
            1: 'Request',
            2: 'Response',
            3: 'Success',
            4: 'Failure',
        }.get(int(value), f'Code {int(value)}')

    def _eap_type_name(value: int) -> str:
        return {
            1: 'Identity',
            3: 'Legacy Nak (Response Only)',
            4: 'MD5-Challenge EAP (EAP-MD5-CHALLENGE)',
            25: 'Protected EAP (EAP-PEAP)',
        }.get(int(value), f'Type {int(value)}')

    code = int(payload[0])
    packet_id = int(payload[1])
    radius_len = int.from_bytes(payload[2:4], 'big')
    if radius_len < 20 or radius_len > len(payload):
        radius_len = len(payload)
    authenticator = payload[4:20]
    code_name = {
        1: 'Access-Request',
        2: 'Access-Accept',
        3: 'Access-Reject',
        4: 'Accounting-Request',
        5: 'Accounting-Response',
        11: 'Access-Challenge',
        12: 'Status-Server',
        13: 'Status-Client',
    }.get(code, f'Code {code}')

    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    req_frame = int(metadata.get('radius_request_frame', 0) or 0)
    rsp_frame = int(metadata.get('radius_response_frame', 0) or 0)
    req_delta = metadata.get('radius_time_from_request_ms', None)
    radius_eap_hex = str(metadata.get('radius_eap_reassembled_hex', '') or '')
    radius_eap_data = b''
    if radius_eap_hex:
        try:
            radius_eap_data = bytes.fromhex(radius_eap_hex)
        except Exception:
            radius_eap_data = b''
    radius_eap_tls_hex = str(metadata.get('radius_eap_tls_reassembled_hex', '') or '')
    radius_eap_tls_data = b''
    if radius_eap_tls_hex:
        try:
            radius_eap_tls_data = bytes.fromhex(radius_eap_tls_hex)
        except Exception:
            radius_eap_tls_data = b''
    radius_eap_tls_fragments = list(metadata.get('radius_eap_tls_fragments', []) or [])

    children: List[Dict[str, Any]] = [
        {'title': f'Code: {code_name} ({code})', 'offset': offset, 'length': 1},
        {'title': f'Packet identifier: 0x{packet_id:x} ({packet_id})', 'offset': offset + 1, 'length': 1},
        {'title': f'Length: {radius_len}', 'offset': offset + 2, 'length': 2},
        {'title': f'Authenticator: {authenticator.hex()}', 'offset': offset + 4, 'length': 16},
    ]
    if req_frame > 0:
        children.append({'title': f'[This is a response to a request in frame {req_frame}]'})
    if rsp_frame > 0:
        children.append({'title': f'[The response to this request is in frame {rsp_frame}]'})
    if req_delta is not None:
        try:
            req_delta_ms = float(req_delta)
        except Exception:
            req_delta_ms = 0.0
        if req_delta_ms < 1.0:
            children.append({'title': f'[Time from request: {req_delta_ms * 1000.0:.3f} microseconds]'})
        else:
            children.append({'title': f'[Time from request: {req_delta_ms:.3f} milliseconds]'})

    avp_nodes: List[Dict[str, Any]] = []
    eap_offsets: List[tuple[int, int]] = []
    scan_cursor = 20
    while scan_cursor + 2 <= radius_len:
        t = int(payload[scan_cursor])
        l = int(payload[scan_cursor + 1])
        if l < 2 or scan_cursor + l > radius_len:
            break
        if t == 79:
            eap_offsets.append((scan_cursor + 2, l - 2))
        scan_cursor += l
    eap_segment_count = len(eap_offsets)
    eap_segment_index = 0

    parsed_eap_data = b''
    if radius_eap_data:
        parsed_eap_data = bytes(radius_eap_data)
    elif eap_offsets:
        parsed_eap_data = b''.join(payload[start:start + size] for start, size in eap_offsets)

    cursor = 20
    while cursor + 2 <= radius_len:
        avp_type = int(payload[cursor])
        avp_len = int(payload[cursor + 1])
        if avp_len < 2 or cursor + avp_len > radius_len:
            break
        avp_value = payload[cursor + 2:cursor + avp_len]

        avp_name = _radius_attr_name(avp_type)
        avp_title = f'AVP: t={avp_name}({avp_type}) l={avp_len}'
        if avp_type == 1:
            avp_title += f' val={avp_value.decode("utf-8", errors="replace")}'
        elif avp_type == 2:
            avp_title += ' val=Encrypted'
        elif avp_type == 5 and len(avp_value) >= 4:
            avp_title += f' val={int.from_bytes(avp_value[:4], "big")}'
        elif avp_type == 6 and len(avp_value) >= 4:
            service_value = int.from_bytes(avp_value[:4], 'big')
            avp_title += f' val={_service_type_name(service_value)}({service_value})'
        elif avp_type == 12 and len(avp_value) >= 4:
            avp_title += f' val={int.from_bytes(avp_value[:4], "big")}'
        elif avp_type == 18:
            avp_title += f' val={avp_value.decode("utf-8", errors="replace")}'
        elif avp_type in {24, 80}:
            avp_title += f' val={avp_value.hex()}'
        elif avp_type == 95 and len(avp_value) >= 16:
            try:
                avp_title += f' val={ipaddress.IPv6Address(avp_value[:16])}'
            except Exception:
                pass
        elif avp_type == 79:
            eap_segment_index += 1
            if eap_segment_count > 0:
                segment_label = 'Last Segment' if eap_segment_index == eap_segment_count else 'Segment'
                avp_title += f' {segment_label}[{eap_segment_index}]'

        avp_children: List[Dict[str, Any]] = [
            {'title': f'Type: {avp_type}', 'offset': offset + cursor, 'length': 1},
            {'title': f'Length: {avp_len}', 'offset': offset + cursor + 1, 'length': 1},
        ]
        if avp_type == 1:
            avp_children.append({'title': f'User-Name: {avp_value.decode("utf-8", errors="replace")}', 'offset': offset + cursor + 2, 'length': len(avp_value)})
        elif avp_type == 2:
            avp_children.append({'title': f'User-Password (encrypted): {avp_value.hex()}', 'offset': offset + cursor + 2, 'length': len(avp_value)})
        elif avp_type == 5 and len(avp_value) >= 4:
            avp_children.append({'title': f'NAS-Port: {int.from_bytes(avp_value[:4], "big")}', 'offset': offset + cursor + 2, 'length': 4})
        elif avp_type == 6 and len(avp_value) >= 4:
            service_value = int.from_bytes(avp_value[:4], 'big')
            avp_children.append({'title': f'Service-Type: {_service_type_name(service_value)} ({service_value})', 'offset': offset + cursor + 2, 'length': 4})
        elif avp_type == 12 and len(avp_value) >= 4:
            avp_children.append({'title': f'Framed-MTU: {int.from_bytes(avp_value[:4], "big")}', 'offset': offset + cursor + 2, 'length': 4})
        elif avp_type == 18:
            avp_children.append({'title': f'Reply-Message: {avp_value.decode("utf-8", errors="replace")}', 'offset': offset + cursor + 2, 'length': len(avp_value)})
        elif avp_type == 24:
            avp_children.append({'title': f'State: {avp_value.hex()}', 'offset': offset + cursor + 2, 'length': len(avp_value)})
        elif avp_type == 26 and len(avp_value) >= 4:
            vendor_id = int.from_bytes(avp_value[:4], 'big')
            avp_children.append({'title': f'Vendor-Id: {vendor_id}', 'offset': offset + cursor + 2, 'length': 4})
            if len(avp_value) > 4:
                avp_children.append({'title': f'Vendor data: {avp_value[4:].hex()}', 'offset': offset + cursor + 6, 'length': len(avp_value) - 4})
        elif avp_type == 80:
            avp_children.append({'title': f'Message-Authenticator: {avp_value.hex()}', 'offset': offset + cursor + 2, 'length': len(avp_value)})
        elif avp_type == 95 and len(avp_value) >= 16:
            try:
                ipv6_value = str(ipaddress.IPv6Address(avp_value[:16]))
            except Exception:
                ipv6_value = avp_value[:16].hex()
            avp_children.append({'title': f'NAS-IPv6-Address: {ipv6_value}', 'offset': offset + cursor + 2, 'length': 16})

        if avp_type == 79 and len(avp_value) >= 4:
            avp_children.append({'title': f'EAP fragment{" […]" if len(avp_value) > 20 else ""}: {avp_value.hex()}', 'offset': offset + cursor + 2, 'length': len(avp_value)})

            eap_code = int(parsed_eap_data[0]) if len(parsed_eap_data) >= 1 else int(avp_value[0])
            eap_id = int(parsed_eap_data[1]) if len(parsed_eap_data) >= 2 else int(avp_value[1])
            eap_len = int.from_bytes(parsed_eap_data[2:4], 'big') if len(parsed_eap_data) >= 4 else int.from_bytes(avp_value[2:4], 'big')
            if eap_len < 4:
                eap_len = max(4, len(parsed_eap_data) or len(avp_value))
            if parsed_eap_data:
                eap_len = min(eap_len, len(parsed_eap_data))
            eap_type = int(parsed_eap_data[4]) if len(parsed_eap_data) >= 5 else (int(avp_value[4]) if len(avp_value) >= 5 else None)

            eap_source = RADIUS_EAP_REASSEMBLED_BYTE_SOURCE if radius_eap_data else PACKET_BYTE_SOURCE
            eap_base = 0 if eap_source == RADIUS_EAP_REASSEMBLED_BYTE_SOURCE else (offset + cursor + 2)
            eap_map = _byte_mapping(eap_base, 0, eap_len, eap_source)
            eap_type_label = _eap_type_name(eap_type) if eap_type is not None else ''
            eap_children: List[Dict[str, Any]] = [
                {'title': f'Code: {_eap_code_name(eap_code)} ({eap_code})', **_byte_mapping(eap_base, 0, 1, eap_source)},
                {'title': f'Id: {eap_id}', **_byte_mapping(eap_base, 1, 1, eap_source)},
                {'title': f'Length: {eap_len}', **_byte_mapping(eap_base, 2, 2, eap_source)},
            ]
            if eap_type is not None:
                eap_type_node = {'title': f'Type: {eap_type_label} ({eap_type})', **_byte_mapping(eap_base, 4, 1, eap_source)}
                if eap_type == 4:
                    eap_type_node['children'] = [
                        {
                            'title': '[Expert Info (Warning/Security): Vulnerable to MITM attacks. If possible, change EAP type.]',
                            'children': [
                                {'title': '[Vulnerable to MITM attacks. If possible, change EAP type.]'},
                                {'title': '[Severity level: Warning]'},
                                {'title': '[Group: Security]'},
                            ],
                        },
                    ]
                eap_children.append(eap_type_node)

            effective_eap = parsed_eap_data if parsed_eap_data else bytes(avp_value)
            if eap_type == 1 and len(effective_eap) > 5:
                identity = effective_eap[5:eap_len].decode('utf-8', errors='replace')
                eap_children.append({'title': f'Identity: {identity}', **_byte_mapping(eap_base, 5, max(0, eap_len - 5), eap_source)})
            if eap_type == 3 and len(effective_eap) > 5:
                desired = int(effective_eap[5])
                eap_children.append({'title': f'Desired Auth Type: {_eap_type_name(desired)} ({desired})', **_byte_mapping(eap_base, 5, 1, eap_source)})
            if eap_type == 4 and len(effective_eap) >= 6:
                value_size = int(effective_eap[5])
                eap_children.append({'title': f'EAP-MD5 Value-Size: {value_size}', **_byte_mapping(eap_base, 5, 1, eap_source)})
                if len(effective_eap) >= 6 + value_size:
                    md5_val = effective_eap[6:6 + value_size]
                    eap_children.append({'title': f'EAP-MD5 Value: {md5_val.hex()}', **_byte_mapping(eap_base, 6, value_size, eap_source)})

            if eap_type == 25 and eap_len > 5:
                eap_tls = effective_eap[5:eap_len]
                if eap_tls:
                    flags = int(eap_tls[0])
                    flags_children = [
                        {'title': f'{"1" if (flags & 0x80) else "0"}... .... = Length Included: {"True" if (flags & 0x80) else "False"}'},
                        {'title': f'.{"1" if (flags & 0x40) else "0"}.. .... = More Fragments: {"True" if (flags & 0x40) else "False"}'},
                        {'title': f'..{"1" if (flags & 0x20) else "0"}. .... = Start: {"True" if (flags & 0x20) else "False"}'},
                        {'title': f'.... .{flags & 0x07:03b} = Version: {flags & 0x07}'},
                    ]
                    eap_children.append({
                        'title': f'EAP-TLS Flags: 0x{flags:02x}',
                        **_byte_mapping(eap_base, 5, 1, eap_source),
                        'children': flags_children,
                    })
                    tls_offset = 1 + (4 if (flags & 0x80 and len(eap_tls) >= 5) else 0)
                    if flags & 0x80 and len(eap_tls) >= 5:
                        tls_total_len = int.from_bytes(eap_tls[1:5], 'big')
                        eap_children.append({'title': f'EAP-TLS Length: {tls_total_len}', **_byte_mapping(eap_base, 6, 4, eap_source)})

                    tls_blob = eap_tls[tls_offset:] if tls_offset <= len(eap_tls) else b''
                    tls_source = eap_source
                    tls_base = eap_base + 5 + tls_offset
                    if radius_eap_tls_data and len(radius_eap_tls_fragments) > 1:
                        frag_summary = ', '.join(
                            f'#{int(seg.get("frame_number", 0) or 0)}({int(seg.get("payload_length", 0) or 0)})'
                            for seg in radius_eap_tls_fragments
                        )
                        frag_children: List[Dict[str, Any]] = []
                        for seg in radius_eap_tls_fragments:
                            pstart = int(seg.get('payload_start', 0) or 0)
                            plen = int(seg.get('payload_length', 0) or 0)
                            pend = max(pstart, pstart + plen - 1)
                            frag_children.append({
                                'title': f'[Frame: {int(seg.get("frame_number", 0) or 0)}, payload: {pstart}-{pend} ({plen} bytes)]',
                                **_byte_mapping(0, pstart, plen, RADIUS_EAP_TLS_REASSEMBLED_BYTE_SOURCE),
                            })
                        frag_children.append({'title': f'[Fragment Count: {len(radius_eap_tls_fragments)}]'})
                        frag_children.append({'title': f'[Reassembled EAP-TLS Length: {len(radius_eap_tls_data)}]'})
                        eap_children.append({
                            'title': f'[{len(radius_eap_tls_fragments)} EAP-TLS Fragments ({len(radius_eap_tls_data)} bytes): {frag_summary}]',
                            'children': frag_children,
                        })
                        tls_blob = bytes(radius_eap_tls_data)
                        tls_source = RADIUS_EAP_TLS_REASSEMBLED_BYTE_SOURCE
                        tls_base = 0

                    if tls_blob:
                        tls_packet = TLS(tls_blob)
                        tls_node = _tls_section_precise(tls_packet, tls_base, -1, None)
                        if tls_source != PACKET_BYTE_SOURCE:
                            _tag_byte_source(tls_node, tls_source)
                        eap_children.append(tls_node)

            if eap_segment_count <= 1 or eap_segment_index == eap_segment_count:
                avp_children.append({'title': 'Extensible Authentication Protocol', **eap_map, 'children': eap_children})
        avp_nodes.append({
            'title': avp_title,
            'offset': offset + cursor,
            'length': avp_len,
            'children': avp_children,
        })
        cursor += avp_len

    if avp_nodes:
        children.append({'title': 'Attribute Value Pairs', 'children': avp_nodes})

    return {
        'title': 'RADIUS Protocol',
        'offset': offset,
        'length': radius_len,
        'children': children,
    }


def _rmcp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    if len(payload) < 4:
        return {
            'title': 'Remote Management Control Protocol',
            'offset': offset,
            'length': len(payload),
            'children': [],
        }

    version = int(payload[0])
    reserved = int(payload[1])
    sequence = int(payload[2])
    rmcp_class = int(payload[3])
    children: List[Dict[str, Any]] = [
        {'title': f'Version: 0x{version:02x}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Reserved: 0x{reserved:02x}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Sequence: 0x{sequence:02x}', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
        {
            'title': 'Type: Normal RMCP, Class: IPMI',
            **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE),
            'children': [
                {'title': '...0 0111 = Class: IPMI (0x07)', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
                {'title': f'{(rmcp_class >> 7) & 0x01}... .... = Message Type: Normal RMCP (0x0)', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
            ],
        },
    ]

    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    rmcp_info = metadata.get('rmcp') if isinstance(metadata.get('rmcp'), dict) else {}
    body = payload[4:]
    if not body:
        return {
            'title': 'Remote Management Control Protocol, Class: IPMI',
            'offset': offset,
            'length': len(payload),
            'children': children,
        }

    auth_type = int(body[0]) if len(body) >= 1 else 0
    session_id = int(rmcp_info.get('session_id', 0) or 0)

    extra_sections: List[Dict[str, Any]] = []

    if auth_type == 0x00 and len(body) >= 10:
        message_length = int(body[9])
        data = bytes(rmcp_info.get('data', b'') or body[10:10 + message_length])
        session_children = [
            {'title': 'Authentication Type: NONE (0x00)', **_byte_mapping(offset + 4, 0, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Session Sequence Number: 0x{int(rmcp_info.get("session_sequence", 0) or int.from_bytes(body[1:5], "little")):08x}', **_byte_mapping(offset + 4, 1, 4, PACKET_BYTE_SOURCE)},
            {'title': f'Session ID: 0x{session_id:08x}', **_byte_mapping(offset + 4, 5, 4, PACKET_BYTE_SOURCE)},
            {'title': f'Message Length: {message_length}', **_byte_mapping(offset + 4, 9, 1, PACKET_BYTE_SOURCE)},
        ]
        extra_sections.append({
            'title': f'IPMI v1.5 Session Wrapper, session ID 0x{session_id:x}',
            'offset': offset + 4,
            'length': min(len(payload) - 4, 10),
            'children': session_children,
        })
        extra_sections.append({
            'title': 'Intelligent Platform Management Bus',
            'offset': offset + 14,
            'length': len(data),
            'children': [
                {'title': f'Bus command data: {data.hex()}', **_byte_mapping(offset + 14, 0, len(data), PACKET_BYTE_SOURCE)},
            ],
        })
        extra_sections.append({
            'title': f'Data ({len(data)} bytes)',
            'offset': offset + 14,
            'length': len(data),
            'children': [
                {'title': f'Data: {data.hex()}', **_byte_mapping(offset + 14, 0, len(data), PACKET_BYTE_SOURCE)},
                {'title': f'[Length: {len(data)}]'},
            ],
        })

    if auth_type == 0x06 and len(body) >= 12:
        payload_type_byte = int(body[1])
        payload_type = int(payload_type_byte & 0x3F)
        encrypted = bool(payload_type_byte & 0x80)
        authenticated = bool(payload_type_byte & 0x40)
        message_length = int.from_bytes(body[10:12], 'little')
        data = bytes(rmcp_info.get('data', b'') or body[12:12 + message_length])
        trailer = bytes(rmcp_info.get('trailer', b'') or body[12 + len(data):])
        payload_type_name = {
            0x00: 'IPMI Message',
            0x10: 'RMCP+ Open Session Request',
            0x11: 'RMCP+ Open Session Response',
            0x12: 'RAKP Message 1',
            0x13: 'RAKP Message 2',
            0x14: 'RAKP Message 3',
            0x15: 'RAKP Message 4',
        }.get(payload_type, f'Payload 0x{payload_type:02x}')
        session_children = [
            {'title': 'Authentication Type: RMCP+ (0x06)', **_byte_mapping(offset + 4, 0, 1, PACKET_BYTE_SOURCE)},
            {
                'title': f'Payload type: {payload_type_name} (0x{payload_type:02x}), {"encrypted" if encrypted else "not encrypted"}, {"authenticated" if authenticated else "not authenticated"}',
                **_byte_mapping(offset + 4, 1, 1, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'{1 if encrypted else 0}... .... = Encryption: Payload is {"encrypted" if encrypted else "unencrypted"}', **_byte_mapping(offset + 4, 1, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'.{1 if authenticated else 0}.. .... = Authenticated: Payload is {"authenticated" if authenticated else "unauthenticated"}', **_byte_mapping(offset + 4, 1, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'..{payload_type:06b} = Payload Type: {payload_type_name} (0x{payload_type:02x})', **_byte_mapping(offset + 4, 1, 1, PACKET_BYTE_SOURCE)},
                ],
            },
            {'title': f'Session ID: 0x{session_id:08x}', **_byte_mapping(offset + 4, 2, 4, PACKET_BYTE_SOURCE)},
            {'title': f'Session Sequence Number: 0x{int(rmcp_info.get("session_sequence", 0) or int.from_bytes(body[6:10], "little")):08x}', **_byte_mapping(offset + 4, 6, 4, PACKET_BYTE_SOURCE)},
            {'title': f'Message Length: {message_length}', **_byte_mapping(offset + 4, 10, 2, PACKET_BYTE_SOURCE)},
        ]
        if trailer:
            session_children.append({'title': f'IPMI Session Wrapper (trailer): {trailer.hex()}', **_byte_mapping(offset + 16 + len(data), 0, len(trailer), PACKET_BYTE_SOURCE)})
        extra_sections.append({
            'title': f'IPMI v2.0+ Session Wrapper, session ID 0x{session_id:x}',
            'offset': offset + 4,
            'length': min(len(payload) - 4, 12 + len(data) + len(trailer)),
            'children': session_children,
        })
        extra_sections.append({
            'title': f'Data ({len(data)} bytes)',
            'offset': offset + 16,
            'length': len(data),
            'children': [
                {'title': f'Data: {data.hex()}', **_byte_mapping(offset + 16, 0, len(data), PACKET_BYTE_SOURCE)},
                {'title': f'[Length: {len(data)}]'},
            ],
        })

    result = {
        'title': 'Remote Management Control Protocol, Class: IPMI',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }
    if extra_sections:
        result['_extra_sections'] = extra_sections
    return result


def _wol_section(payload: bytes, offset: int) -> Dict[str, Any]:
    sync_length = min(6, len(payload))
    target = payload[6:12] if len(payload) >= 12 else b''
    target_mac = ':'.join(f'{b:02x}' for b in target) if len(target) == 6 else ''
    target_vendor = get_mac_vendor(target_mac) if target_mac else ''
    if target_vendor and target_mac:
        mac_display = f'{target_vendor}_{target_mac[-8:]} ({target_mac})'
    else:
        mac_display = target_mac
    mac_label = f'MAC: {mac_display}' if mac_display else 'MAC'
    mac_children: List[Dict[str, Any]] = []
    if len(target) == 6:
        for i in range(16):
            start = 6 + (i * 6)
            if start + 6 > len(payload):
                break
            mac_children.append({
                'title': f'MAC: {mac_display}' if mac_display else 'MAC',
                **_byte_mapping(offset, start, 6, PACKET_BYTE_SOURCE),
            })
    children: List[Dict[str, Any]] = [
        {
            'title': f'Sync stream: {payload[:sync_length].hex()}',
            **_byte_mapping(offset, 0, sync_length, PACKET_BYTE_SOURCE),
        },
        {
            'title': mac_label,
            **_byte_mapping(offset, 6, max(0, min(len(payload), 102) - 6), PACKET_BYTE_SOURCE),
            'children': mac_children,
        },
    ]
    return {
        'title': f'Wake On LAN, MAC: {mac_display}' if mac_display else 'Wake On LAN',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _decode_dns_name_bytes(payload: bytes, start: int) -> tuple[str, int] | None:
    labels: List[str] = []
    pos = int(start)
    while pos < len(payload):
        ln = int(payload[pos])
        pos += 1
        if ln == 0:
            return '.'.join(labels), pos
        if (ln & 0xC0) == 0xC0:
            if pos >= len(payload):
                return None
            ptr = ((ln & 0x3F) << 8) | int(payload[pos])
            pos += 1
            if ptr >= len(payload):
                return None
            pointed = _decode_dns_name_bytes(payload, ptr)
            if pointed is None:
                return None
            labels.append(pointed[0])
            return '.'.join(part for part in labels if part), pos
        if pos + ln > len(payload):
            return None
        labels.append(payload[pos:pos + ln].decode(errors='ignore'))
        pos += ln
    return None


def _llmnr_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 12:
        return _bytes_data_section(payload, offset)
    txid = int.from_bytes(payload[0:2], 'big')
    flags = int.from_bytes(payload[2:4], 'big')
    qdcount = int.from_bytes(payload[4:6], 'big')
    ancount = int.from_bytes(payload[6:8], 'big')
    nscount = int.from_bytes(payload[8:10], 'big')
    arcount = int.from_bytes(payload[10:12], 'big')
    is_response = bool(flags & 0x8000)
    opcode_value = (flags >> 11) & 0x0F
    opcode_bits = f'{opcode_value:04b}'
    opcode_bits_text = f'{opcode_bits[:3]} {opcode_bits[3]}... .... ....'
    children: List[Dict[str, Any]] = [
        {
            'title': f'Transaction ID: 0x{txid:04x}',
            **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE),
            'children': [
                {
                    'title': '[Expert Info (Warning/Protocol): DNS response missing]',
                    'children': [
                        {'title': '[DNS response missing]'},
                        {'title': '[Severity level: Warning]'},
                        {'title': '[Group: Protocol]'},
                    ],
                }
            ],
        },
        {
            'title': f'Flags: 0x{flags:04x} Standard query' if not is_response else f'Flags: 0x{flags:04x} Standard query response',
            **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'{1 if is_response else 0}... .... .... .... = Response: Message is a {"response" if is_response else "query"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.{opcode_bits_text} = Opcode: Standard query (0)', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .{1 if (flags & 0x0400) else 0}.. .... .... = Conflict: {"Conflict" if (flags & 0x0400) else "None"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ..{1 if (flags & 0x0200) else 0}. .... .... = Truncated: Message is {"truncated" if (flags & 0x0200) else "not truncated"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ...{1 if (flags & 0x0100) else 0} .... .... = Tentative: {"Tentative" if (flags & 0x0100) else "Not tentative"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
            ],
        },
        {'title': f'Questions: {qdcount}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Answer RRs: {ancount}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Authority RRs: {nscount}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Additional RRs: {arcount}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
    ]
    cursor = 12
    if qdcount > 0:
        parsed = _decode_dns_name_bytes(payload, cursor)
        if parsed is not None:
            qname, cursor_after_name = parsed
            if cursor_after_name + 4 <= len(payload):
                qtype = int.from_bytes(payload[cursor_after_name:cursor_after_name + 2], 'big')
                qclass = int.from_bytes(payload[cursor_after_name + 2:cursor_after_name + 4], 'big')
                qtype_name = {1: 'A', 28: 'AAAA', 255: 'ANY'}.get(qtype, str(qtype))
                query_node = {
                    'title': f'{qname}: type {qtype_name}, class IN',
                    **_byte_mapping(offset, 12, cursor_after_name + 4 - 12, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'Name: {qname}', **_byte_mapping(offset, 12, cursor_after_name - 12, PACKET_BYTE_SOURCE)},
                        {'title': f'[Name Length: {len(qname)}]'},
                        {'title': '[Label Count: 1]'},
                        {'title': f'Type: {qtype_name} ({qtype})' + (' (A request for all records the server/cache has available)' if qtype == 255 else ''), **_byte_mapping(offset, cursor_after_name, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'Class: IN (0x{qclass:04x})', **_byte_mapping(offset, cursor_after_name + 2, 2, PACKET_BYTE_SOURCE)},
                    ],
                }
                children.append({
                    'title': f'Queries',
                    'children': [query_node],
                })
    return {
        'title': f'Link-local Multicast Name Resolution ({"response" if is_response else "query"})',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _decode_nbns_name(encoded: bytes) -> str:
    if len(encoded) < 32:
        return ''
    decoded = bytearray()
    for i in range(0, 32, 2):
        c1 = int(encoded[i]) - 0x41
        c2 = int(encoded[i + 1]) - 0x41
        if c1 < 0 or c2 < 0:
            break
        decoded.append(((c1 & 0x0F) << 4) | (c2 & 0x0F))
    if not decoded:
        return ''
    base = decoded[:15].decode(errors='ignore').rstrip(' ')
    suffix = int(decoded[15]) if len(decoded) >= 16 else 0
    return f'{base}<{suffix:02x}>'


def _nbns_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 12:
        return _bytes_data_section(payload, offset)
    txid = int.from_bytes(payload[0:2], 'big')
    flags = int.from_bytes(payload[2:4], 'big')
    qdcount = int.from_bytes(payload[4:6], 'big')
    ancount = int.from_bytes(payload[6:8], 'big')
    nscount = int.from_bytes(payload[8:10], 'big')
    arcount = int.from_bytes(payload[10:12], 'big')
    opcode = (flags >> 11) & 0x0F
    is_response = bool(flags & 0x8000)
    recurse_desired = bool(flags & 0x0100)
    broadcast = bool(flags & 0x0010)
    opcode_name = 'Registration' if opcode == 5 else 'Name query' if opcode == 0 else f'Opcode {opcode}'
    opcode_bits = f'{opcode:04b}'
    opcode_bits_text = f'{opcode_bits[:3]} {opcode_bits[3]}... .... ....'

    def _suffix_desc(name: str) -> str:
        suffix_map = {
            '<00>': 'Workstation/Redirector',
            '<1b>': 'Domain Master Browser',
        }
        for suffix, desc in suffix_map.items():
            if name.endswith(suffix):
                return f'{name} ({desc})'
        return name
    children: List[Dict[str, Any]] = [
        {'title': f'Transaction ID: 0x{txid:04x}', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE)},
        {
            'title': f'Flags: 0x{flags:04x}, Opcode: {opcode_name}, {"Recursion desired, " if recurse_desired else ""}{"Broadcast" if broadcast else ""}'.rstrip(', '),
            **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'{1 if is_response else 0}... .... .... .... = Response: Message is a {"response" if is_response else "query"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.{opcode_bits_text} = Opcode: {opcode_name} ({opcode})', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ..{1 if (flags & 0x0200) else 0}. .... .... = Truncated: Message is {"truncated" if (flags & 0x0200) else "not truncated"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ...{1 if recurse_desired else 0} .... .... = Recursion desired: {"Do query recursively" if recurse_desired else "Do not query recursively"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... ...{1 if broadcast else 0} .... = Broadcast: {"Broadcast packet" if broadcast else "Unicast packet"}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
            ],
        },
        {'title': f'Questions: {qdcount}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Answer RRs: {ancount}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Authority RRs: {nscount}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Additional RRs: {arcount}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
    ]
    if qdcount > 0 and len(payload) >= 12 + 1 + 32 + 1 + 4:
        name_len = int(payload[12])
        if name_len == 32:
            encoded = payload[13:45]
            qname = _decode_nbns_name(encoded)
            qtype = int.from_bytes(payload[46:48], 'big')
            qclass = int.from_bytes(payload[48:50], 'big')
            query_detail_node = {
                'title': f'{qname}: type NB, class IN',
                **_byte_mapping(offset, 12, 38, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'Name: {_suffix_desc(qname)}', **_byte_mapping(offset, 12, 34, PACKET_BYTE_SOURCE)},
                    {'title': f'Type: NB ({qtype})', **_byte_mapping(offset, 46, 2, PACKET_BYTE_SOURCE)},
                    {'title': f'Class: IN ({qclass})', **_byte_mapping(offset, 48, 2, PACKET_BYTE_SOURCE)},
                ],
            }
            children.append({
                'title': 'Queries',
                'children': [query_detail_node],
            })
            if arcount > 0 and len(payload) >= 62:
                rr_start = 50
                rr_name = qname if rr_start + 2 <= len(payload) and payload[rr_start:rr_start + 2] == b'\xc0\x0c' else ''
                if rr_start + 12 <= len(payload):
                    rr_type = int.from_bytes(payload[rr_start + 2:rr_start + 4], 'big') if rr_start + 4 <= len(payload) else 0
                    rr_class = int.from_bytes(payload[rr_start + 4:rr_start + 6], 'big') if rr_start + 6 <= len(payload) else 0
                    ttl = int.from_bytes(payload[rr_start + 6:rr_start + 10], 'big') if rr_start + 10 <= len(payload) else 0
                    data_len = int.from_bytes(payload[rr_start + 10:rr_start + 12], 'big') if rr_start + 12 <= len(payload) else 0
                    flags_off = rr_start + 12
                    nb_flags = int.from_bytes(payload[flags_off:flags_off + 2], 'big') if flags_off + 2 <= len(payload) else 0
                    addr_off = flags_off + 2
                    addr_text = '.'.join(str(int(b)) for b in payload[addr_off:addr_off + 4]) if addr_off + 4 <= len(payload) else ''
                    days = ttl // 86400
                    hours = (ttl % 86400) // 3600
                    minutes = (ttl % 3600) // 60
                    ont = (nb_flags >> 13) & 0x3
                    is_group_name = bool(nb_flags & 0x8000)
                    flags_title = f'Name flags: 0x{nb_flags:04x}, ONT: Unknown (H-node, {"group" if is_group_name else "unique"})'
                    if is_group_name:
                        flags_title = f'Name flags: 0x{nb_flags:04x}, Name type, ONT: Unknown (H-node, group)'
                    children.append({
                        'title': 'Additional records',
                        **_byte_mapping(offset, rr_start, min(len(payload) - rr_start, 2 + 2 + 2 + 4 + 2 + data_len), PACKET_BYTE_SOURCE),
                        'children': [
                            {
                                'title': f'{rr_name}: type NB, class IN',
                                **_byte_mapping(offset, rr_start, min(len(payload) - rr_start, 2 + 2 + 2 + 4 + 2 + data_len), PACKET_BYTE_SOURCE),
                                'children': [
                                    {'title': f'Name: {_suffix_desc(rr_name)}', **_byte_mapping(offset, rr_start + 1, 1, PACKET_BYTE_SOURCE)},
                                    {'title': f'Type: NB ({rr_type})', **_byte_mapping(offset, rr_start + 2, 2, PACKET_BYTE_SOURCE)},
                                    {'title': f'Class: IN ({rr_class})', **_byte_mapping(offset, rr_start + 4, 2, PACKET_BYTE_SOURCE)},
                                    {'title': f'Time to live: {days} days, {hours} hours, {minutes} minutes', **_byte_mapping(offset, rr_start + 6, 4, PACKET_BYTE_SOURCE)},
                                    {'title': f'Data length: {data_len}', **_byte_mapping(offset, rr_start + 10, 2, PACKET_BYTE_SOURCE)},
                                    {'title': flags_title, **_byte_mapping(offset, flags_off, 2, PACKET_BYTE_SOURCE), 'children': [
                                        {'title': f'{1 if is_group_name else 0}... .... .... .... = Name type: {"Group name" if is_group_name else "Unique name"}', **_byte_mapping(offset, flags_off, 2, PACKET_BYTE_SOURCE)},
                                        {'title': f'.{ont:02b}. .... .... .... = ONT: Unknown ({ont})', **_byte_mapping(offset, flags_off, 2, PACKET_BYTE_SOURCE)},
                                    ]},
                                    ({'title': f'Addr: {addr_text}', **_byte_mapping(offset, addr_off, 4, PACKET_BYTE_SOURCE)} if addr_text else {'title': 'Addr'}),
                                ],
                            }
                        ],
                    })
    return {
        'title': 'NetBIOS Name Service',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _pcp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 24:
        return _bytes_data_section(payload, offset)
    version = int(payload[0])
    opcode = int(payload[1] & 0x7F)
    is_response = bool(payload[1] & 0x80)
    lifetime = int.from_bytes(payload[4:8], 'big')
    client_ip = str(ipaddress.IPv6Address(payload[8:24])) if len(payload) >= 24 else '::'
    if payload[8:20] == b'\x00' * 10 + b'\xff\xff':
        client_ip = f'::ffff:{payload[20]}.{payload[21]}.{payload[22]}.{payload[23]}'
    opcode_bits = format(opcode, '07b')
    opcode_bits_text = f'{opcode_bits[:3]} {opcode_bits[3:]}'
    children: List[Dict[str, Any]] = [
        {'title': f'Version: {version}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'{"1" if is_response else "0"}... .... = R: {"Response" if is_response else "Request"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
        {'title': f'.{opcode_bits_text} = Opcode: Map ({opcode})', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
        {'title': 'Reserved: 0', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Requested Lifetime: {lifetime}', **_byte_mapping(offset, 4, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Client IP Address: {client_ip}', **_byte_mapping(offset, 8, 16, PACKET_BYTE_SOURCE)},
    ]
    if len(payload) >= 60:
        nonce = payload[24:36]
        protocol_num = int(payload[36])
        internal_port = int.from_bytes(payload[40:42], 'big')
        external_port = int.from_bytes(payload[42:44], 'big')
        external_ip = str(ipaddress.IPv6Address(payload[44:60]))
        if payload[44:60] == b'\x00' * 16:
            external_ip = '::'
        elif payload[44:56] == b'\x00' * 10 + b'\xff\xff':
            external_ip = f'::ffff:{payload[56]}.{payload[57]}.{payload[58]}.{payload[59]}'
            if payload[56:60] == b'\x00\x00\x00\x00':
                external_ip = '::ffff:0:0'
        children.append({
            'title': 'Map Request',
            'children': [
                {'title': f'Mapping Nonce: {nonce.hex()}', **_byte_mapping(offset, 24, 12, PACKET_BYTE_SOURCE)},
                {'title': f'Protocol: {protocol_num}', **_byte_mapping(offset, 36, 1, PACKET_BYTE_SOURCE)},
                {'title': 'Reserved: 0', **_byte_mapping(offset, 37, 3, PACKET_BYTE_SOURCE)},
                {'title': f'Internal Port: {internal_port}', **_byte_mapping(offset, 40, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Suggested External Port: {external_port}', **_byte_mapping(offset, 42, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Suggested External IP Address: {external_ip}', **_byte_mapping(offset, 44, 16, PACKET_BYTE_SOURCE)},
            ],
        })
    return {
        'title': 'Port Control Protocol, Map Request',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _udp_xml_section(payload: bytes, offset: int) -> Dict[str, Any]:
    text = payload.decode('utf-8', errors='replace')
    normalized = text.strip()

    tokens: List[str] = []
    if normalized.startswith('<?xml'):
        decl_end = normalized.find('?>')
        if decl_end != -1:
            decl_text = normalized[:decl_end + 2]
            tokens.append('<?xml')
            if 'version="1.0"' in decl_text:
                tokens.append('version="1.0"')
            if 'encoding="utf-8"' in decl_text:
                tokens.append('encoding="utf-8"')
            tokens.append('?>')
            normalized = normalized[decl_end + 2:].strip()

    normalized = normalized.replace('><', '>\n<')
    raw_lines = [line.strip() for line in normalized.splitlines() if line.strip()]
    for line in raw_lines:
        if line.startswith('<soap:Envelope ') and 'xmlns:' in line and line.endswith('>'):
            envelope_line = line[:-1].strip()
            parts = envelope_line.split()
            if parts:
                tokens.append(parts[0])
            if len(parts) >= 2:
                tokens.extend(parts[1:-1])
                tokens.append(parts[-1] + '>')
            continue

        inline_start = line.find('>')
        inline_end = line.rfind('</')
        if line.startswith('<') and inline_start > 0 and inline_end > inline_start + 1 and line.count('<') == 2:
            start_tag = line[:inline_start + 1]
            inner_text = line[inline_start + 1:inline_end].strip()
            end_tag = line[inline_end:]
            tokens.append(start_tag)
            if inner_text:
                tokens.append(inner_text)
            tokens.append(end_tag)
            continue

        tokens.append(line)

    search_cursor = [0]

    def _make_node(token: str) -> Dict[str, Any]:
        idx = text.find(token, search_cursor[0])
        if idx == -1:
            idx = text.find(token)
        node: Dict[str, Any] = {'title': token}
        if idx != -1:
            token_len = len(token.encode('utf-8', errors='ignore'))
            node.update(_byte_mapping(offset, idx, max(1, token_len), PACKET_BYTE_SOURCE))
            search_cursor[0] = idx + len(token)
        return node

    def _attach(parent_stack: List[Dict[str, Any]], node: Dict[str, Any], roots: List[Dict[str, Any]]) -> None:
        if parent_stack:
            parent_stack[-1].setdefault('children', []).append(node)
        else:
            roots.append(node)

    children: List[Dict[str, Any]] = []
    stack: List[Dict[str, Any]] = []
    for token in tokens:
        node = _make_node(token)

        if token == '?>':
            _attach(stack, node, children)
            if stack and stack[-1].get('_tag') == '?xml':
                stack.pop()
            continue

        if token.startswith('<?xml'):
            node['_tag'] = '?xml'
            _attach(stack, node, children)
            stack.append(node)
            continue

        if token.startswith('</') and token.endswith('>'):
            _attach(stack, node, children)
            close_tag = token[2:-1].strip().split()[0] if len(token) > 3 else ''
            while stack:
                top_tag = str(stack[-1].get('_tag', '') or '')
                stack.pop()
                if top_tag == close_tag:
                    break
            continue

        is_open_tag = token.startswith('<') and not token.startswith('</')
        if is_open_tag:
            if token.endswith('/>'):
                _attach(stack, node, children)
                continue

            tag_body = token[1:]
            if tag_body.endswith('>'):
                tag_body = tag_body[:-1]
            tag_name = tag_body.strip().split()[0] if tag_body.strip() else ''
            if tag_name:
                node['_tag'] = tag_name
            _attach(stack, node, children)
            stack.append(node)
            continue

        _attach(stack, node, children)

    def _cleanup(node: Dict[str, Any]) -> None:
        node.pop('_tag', None)
        for child in node.get('children', []) or []:
            if isinstance(child, dict):
                _cleanup(child)

    for child in children:
        if isinstance(child, dict):
            _cleanup(child)

    return {
        'title': 'eXtensible Markup Language',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _bgp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    def _bgp_flag_children(flags: int, base_offset: int) -> list[Dict[str, Any]]:
        extended = bool(flags & 0x10)
        return [
            {'title': f'{1 if (flags & 0x80) else 0}... .... = Optional: {"Set" if (flags & 0x80) else "Not set"}', 'offset': base_offset, 'length': 1},
            {'title': f'.{1 if (flags & 0x40) else 0}.. .... = Transitive: {"Set" if (flags & 0x40) else "Not set"}', 'offset': base_offset, 'length': 1},
            {'title': f'..{1 if (flags & 0x20) else 0}. .... = Partial: {"Set" if (flags & 0x20) else "Not set"}', 'offset': base_offset, 'length': 1},
            {'title': f'...{1 if extended else 0} .... = Extended-Length: {"Set" if extended else "Not set"}', 'offset': base_offset, 'length': 1},
            {'title': f'.... {flags & 0x0F:04b} = Unused: 0x{flags & 0x0F:x}', 'offset': base_offset, 'length': 1},
        ]

    def _bgp_prefix_children(data: bytes, afi: int, base_offset: int, rel_offset: int = 0) -> list[Dict[str, Any]]:
        children: list[Dict[str, Any]] = []
        cursor = 0
        while cursor < len(data):
            prefix_len = int(data[cursor])
            octet_len = (prefix_len + 7) // 8
            prefix_start = cursor + 1
            prefix_end = prefix_start + octet_len
            if prefix_end > len(data):
                break
            prefix_bytes = data[prefix_start:prefix_end]
            if afi == 2:
                padded = prefix_bytes + (b'\x00' * max(0, 16 - len(prefix_bytes)))
                prefix_text = str(ipaddress.IPv6Address(padded[:16]))
            else:
                padded = prefix_bytes + (b'\x00' * max(0, 4 - len(prefix_bytes)))
                prefix_text = '.'.join(str(int(b)) for b in padded[:4])
            children.append({
                'title': f'Prefix: {prefix_text}/{prefix_len}',
                'offset': base_offset + rel_offset + cursor,
                'length': 1 + octet_len,
                'children': [
                    {'title': f'Prefix Length: {prefix_len}', 'offset': base_offset + rel_offset + cursor, 'length': 1},
                    {'title': f'Prefix: {prefix_text}', 'offset': base_offset + rel_offset + prefix_start, 'length': octet_len},
                ],
            })
            cursor = prefix_end
        return children

    def _bgp_capability_children(cap_type: int, cap_value: bytes, base_offset: int) -> list[Dict[str, Any]]:
        children: list[Dict[str, Any]] = [
            {'title': f'Type: {_bgp_capability_name(cap_type)} ({cap_type})', 'offset': base_offset, 'length': 1},
            {'title': f'Length: {len(cap_value)}', 'offset': base_offset + 1, 'length': 1},
        ]
        if cap_type == 1 and len(cap_value) >= 4:
            afi = int.from_bytes(cap_value[0:2], 'big')
            reserved = int(cap_value[2])
            safi = int(cap_value[3])
            children.extend([
                {'title': f'AFI: {_bgp_afi_name(afi)} ({afi})', 'offset': base_offset + 2, 'length': 2},
                {'title': f'Reserved: {reserved:02x}', 'offset': base_offset + 4, 'length': 1},
                {'title': f'SAFI: {_bgp_safi_name(safi)} ({safi})', 'offset': base_offset + 5, 'length': 1},
            ])
        elif cap_type == 65 and len(cap_value) >= 4:
            asn = int.from_bytes(cap_value[0:4], 'big')
            children.append({'title': f'AS Number: {asn}', 'offset': base_offset + 2, 'length': 4})
        elif len(cap_value) == 0:
            pass
        else:
            children.append({'title': f'Value: {cap_value.hex()}', 'offset': base_offset + 2, 'length': len(cap_value)})
        return children

    def _bgp_capability_name(cap_type: int) -> str:
        return {
            1: 'Multiprotocol extensions capability',
            2: 'Route refresh capability',
            65: 'Support for 4-octet AS number capability',
            128: 'Route Refresh Capability (Cisco)',
        }.get(int(cap_type), f'Capability ({int(cap_type)})')

    def _bgp_afi_name(afi: int) -> str:
        return {
            1: 'IPv4',
            2: 'IPv6',
        }.get(int(afi), str(int(afi)))

    def _bgp_safi_name(safi: int) -> str:
        return {
            1: 'Unicast',
            2: 'Multicast',
            4: 'NLRI multicast',
        }.get(int(safi), str(int(safi)))

    def _bgp_origin_name(origin: int) -> str:
        return {
            0: 'IGP',
            1: 'EGP',
            2: 'INCOMPLETE',
        }.get(int(origin), f'Origin ({int(origin)})')

    def _bgp_as_path_children(value: bytes, base_offset: int) -> list[Dict[str, Any]]:
        children: list[Dict[str, Any]] = []
        cursor = 0
        segment_index = 1
        while cursor + 2 <= len(value):
            seg_type = int(value[cursor])
            seg_len = int(value[cursor + 1])
            asn_bytes = value[cursor + 2:cursor + 2 + (2 * seg_len)]
            if cursor + 2 + (2 * seg_len) > len(value):
                break
            asns = [
                int.from_bytes(asn_bytes[i:i + 2], 'big')
                for i in range(0, len(asn_bytes), 2)
                if i + 2 <= len(asn_bytes)
            ]
            seg_name = {
                1: 'AS_SET',
                2: 'AS_SEQUENCE',
                3: 'AS_CONFED_SEQUENCE',
                4: 'AS_CONFED_SET',
            }.get(seg_type, f'Segment Type {seg_type}')
            segment_children = [
                {'title': f'Segment Type: {seg_name} ({seg_type})', 'offset': base_offset + cursor, 'length': 1},
                {'title': f'Segment Length: {seg_len}', 'offset': base_offset + cursor + 1, 'length': 1},
            ]
            for idx, asn in enumerate(asns, start=1):
                segment_children.append({
                    'title': f'AS{idx}: {asn}',
                    'offset': base_offset + cursor + 2 + ((idx - 1) * 2),
                    'length': 2,
                })
            children.append({
                'title': f'AS_PATH Segment {segment_index}: {seg_name}',
                'offset': base_offset + cursor,
                'length': 2 + (2 * seg_len),
                'children': segment_children,
            })
            cursor += 2 + (2 * seg_len)
            segment_index += 1
        if not children and len(value) == 0:
            children.append({'title': 'AS Path: empty', 'offset': base_offset, 'length': 0})
        return children

    def _bgp_mp_reach_children(value: bytes, base_offset: int) -> list[Dict[str, Any]]:
        children: list[Dict[str, Any]] = []
        if len(value) < 4:
            children.append({'title': f'Value: {value.hex()}', 'offset': base_offset, 'length': len(value)})
            return children
        afi = int.from_bytes(value[0:2], 'big')
        safi = int(value[2])
        nh_len = int(value[3])
        nh_start = 4
        nh_end = min(len(value), nh_start + nh_len)
        next_hop_bytes = value[nh_start:nh_end]
        snpa_count = int(value[nh_end]) if nh_end < len(value) else 0
        snpa_start = nh_end + 1
        pos = snpa_start
        children.extend([
            {'title': f'Address family identifier (AFI): {_bgp_afi_name(afi)} ({afi})', 'offset': base_offset, 'length': 2},
            {'title': f'Subsequent address family identifier (SAFI): {_bgp_safi_name(safi)} ({safi})', 'offset': base_offset + 2, 'length': 1},
            {'title': f'Next hop: {ipaddress.IPv6Address(next_hop_bytes[:16]) if afi == 2 and len(next_hop_bytes) >= 16 else next_hop_bytes.hex()}', 'offset': base_offset + nh_start, 'length': nh_len},
            {'title': f'Number of Subnetwork points of attachment (SNPA): {snpa_count}', 'offset': base_offset + nh_end, 'length': 1},
        ])
        if snpa_count > 0:
            snpa_children: list[Dict[str, Any]] = []
            for idx in range(snpa_count):
                if pos >= len(value):
                    break
                snpa_len = int(value[pos])
                snpa_start = pos + 1
                snpa_end = min(len(value), snpa_start + snpa_len)
                snpa_children.append({
                    'title': f'SNPA {idx + 1}: {value[snpa_start:snpa_end].hex()}',
                    'offset': base_offset + pos,
                    'length': 1 + snpa_len,
                })
                pos = snpa_end
            if snpa_children:
                children.append({'title': f'SNPAs ({len(snpa_children)})', 'children': snpa_children})
        nlri = value[pos:]
        if nlri:
            children.append({
                'title': 'Network Layer Reachability Information',
                'offset': base_offset + pos,
                'length': len(nlri),
                'children': _bgp_prefix_children(nlri, afi, base_offset, pos),
            })
        return children

    def _bgp_mp_unreach_children(value: bytes, base_offset: int) -> list[Dict[str, Any]]:
        if len(value) < 3:
            return [{'title': f'Value: {value.hex()}', 'offset': base_offset, 'length': len(value)}]
        afi = int.from_bytes(value[0:2], 'big')
        safi = int(value[2])
        nlri = value[3:]
        children = [
            {'title': f'Address family identifier (AFI): {_bgp_afi_name(afi)} ({afi})', 'offset': base_offset, 'length': 2},
            {'title': f'Subsequent address family identifier (SAFI): {_bgp_safi_name(safi)} ({safi})', 'offset': base_offset + 2, 'length': 1},
        ]
        if nlri:
            children.append({
                'title': 'Withdrawn Routes',
                'offset': base_offset + 3,
                'length': len(nlri),
                'children': _bgp_prefix_children(nlri, afi, base_offset, 3),
            })
        return children

    marker = payload[:16]
    length = int.from_bytes(payload[16:18], 'big') if len(payload) >= 18 else 0
    msg_type = int(payload[18]) if len(payload) >= 19 else 0
    msg_name = {
        1: 'OPEN Message',
        2: 'UPDATE Message',
        3: 'NOTIFICATION Message',
        4: 'KEEPALIVE Message',
        5: 'ROUTE-REFRESH Message',
    }.get(msg_type, f'BGP Message ({msg_type})')

    children = [
        {'title': f'Marker: {marker.hex()}', 'offset': offset, 'length': min(16, len(payload))},
        {'title': f'Length: {length}', 'offset': offset + 16, 'length': 2 if len(payload) >= 18 else 0},
        {'title': f'Type: {msg_name} ({msg_type})', 'offset': offset + 18, 'length': 1 if len(payload) >= 19 else 0},
    ]

    section_length = len(payload)
    if length >= 19:
        section_length = min(len(payload), length)

    message_slices: list[tuple[int, int, int]] = []
    cursor = 0
    while cursor + 19 <= len(payload):
        if payload[cursor:cursor + 16] != (b'\xff' * 16):
            break
        msg_len = int.from_bytes(payload[cursor + 16:cursor + 18], 'big')
        if msg_len < 19 or cursor + msg_len > len(payload):
            break
        msg_type_slice = int(payload[cursor + 18])
        message_slices.append((cursor, msg_len, msg_type_slice))
        cursor += msg_len

    if len(message_slices) > 1:
        message_children: list[Dict[str, Any]] = []
        for index, (msg_offset, msg_len, msg_type_slice) in enumerate(message_slices, start=1):
            msg_name_slice = {
                1: 'OPEN Message',
                2: 'UPDATE Message',
                3: 'NOTIFICATION Message',
                4: 'KEEPALIVE Message',
                5: 'ROUTE-REFRESH Message',
            }.get(msg_type_slice, f'BGP Message ({msg_type_slice})')
            sub_section = _bgp_section(payload[msg_offset:msg_offset + msg_len], offset + msg_offset)
            message_children.append({
                'title': f'Message {index}: {msg_name_slice}',
                'offset': offset + msg_offset,
                'length': msg_len,
                'children': sub_section.get('children', []),
            })
        return {
            'title': 'Border Gateway Protocol',
            'offset': offset,
            'length': section_length,
            'children': [{
                'title': 'Messages',
                'offset': offset,
                'length': section_length,
                'children': message_children,
            }],
        }

    if msg_type == 1 and len(payload) >= 29:
        version = int(payload[19])
        my_as = int.from_bytes(payload[20:22], 'big')
        hold_time = int.from_bytes(payload[22:24], 'big')
        bgp_identifier = str(ipaddress.IPv4Address(payload[24:28]))
        opt_len = int(payload[28])
        opt_start = 29
        opt_end = min(len(payload), opt_start + opt_len)
        children.extend([
            {'title': f'Version: {version}', 'offset': offset + 19, 'length': 1},
            {'title': f'My AS: {my_as}', 'offset': offset + 20, 'length': 2},
            {'title': f'Hold Time: {hold_time}', 'offset': offset + 22, 'length': 2},
            {'title': f'BGP Identifier: {bgp_identifier}', 'offset': offset + 24, 'length': 4},
            {'title': f'Optional Parameters Length: {opt_len}', 'offset': offset + 28, 'length': 1},
        ])
        optional_children: list[Dict[str, Any]] = []
        pos = opt_start
        while pos + 2 <= opt_end:
            param_type = int(payload[pos])
            param_len = int(payload[pos + 1])
            param_value_start = pos + 2
            param_value_end = min(opt_end, param_value_start + param_len)
            param_value = payload[param_value_start:param_value_end]
            param_name = {
                2: 'Capability',
            }.get(param_type, f'Optional Parameter ({param_type})')
            param_children: list[Dict[str, Any]] = [
                {'title': f'Parameter Type: {param_name} ({param_type})', 'offset': offset + pos, 'length': 1},
                {'title': f'Parameter Length: {param_len}', 'offset': offset + pos + 1, 'length': 1},
            ]
            if param_type == 2:
                cap_children: list[Dict[str, Any]] = []
                cap_pos = 0
                while cap_pos + 2 <= len(param_value):
                    cap_type = int(param_value[cap_pos])
                    cap_len = int(param_value[cap_pos + 1])
                    cap_value_start = cap_pos + 2
                    cap_value_end = min(len(param_value), cap_value_start + cap_len)
                    cap_value = param_value[cap_value_start:cap_value_end]
                    cap_children.append({
                        'title': f'Capability: {_bgp_capability_name(cap_type)}',
                        'offset': offset + param_value_start + cap_pos,
                        'length': 2 + len(cap_value),
                        'children': _bgp_capability_children(cap_type, cap_value, offset + param_value_start + cap_pos),
                    })
                    if cap_len <= 0:
                        break
                    cap_pos = cap_value_end
                if cap_children:
                    param_children.append({
                        'title': f'Capability: {_bgp_capability_name(int(param_value[0]) if param_value else 0)}',
                        'offset': offset + param_value_start,
                        'length': len(param_value),
                        'children': cap_children,
                    })
            elif param_value:
                param_children.append({'title': f'Value: {param_value.hex()}', 'offset': offset + param_value_start, 'length': len(param_value)})
            optional_children.append({
                'title': f'Optional Parameter: {param_name}',
                'offset': offset + pos,
                'length': 2 + len(param_value),
                'children': param_children,
            })
            if param_len <= 0:
                break
            pos = param_value_end
        if optional_children:
            children.append({
                'title': 'Optional Parameters',
                'offset': offset + opt_start,
                'length': opt_len,
                'children': optional_children,
            })
        else:
            children.append({'title': 'Optional Parameters', 'offset': offset + opt_start, 'length': opt_len})

    elif msg_type == 2 and len(payload) >= 23:
        withdrawn_len = int.from_bytes(payload[19:21], 'big')
        withdrawn_start = 21
        withdrawn_end = min(len(payload), withdrawn_start + withdrawn_len)
        total_attr_len_offset = withdrawn_end
        total_attr_len = int.from_bytes(payload[total_attr_len_offset:total_attr_len_offset + 2], 'big') if total_attr_len_offset + 2 <= len(payload) else 0
        attr_start = total_attr_len_offset + 2
        attr_end = min(len(payload), attr_start + total_attr_len)
        children.extend([
            {'title': f'Withdrawn Routes Length: {withdrawn_len}', 'offset': offset + 19, 'length': 2},
        ])
        withdrawn_children = _bgp_prefix_children(payload[withdrawn_start:withdrawn_end], 1, offset, withdrawn_start) if withdrawn_len > 0 else []
        if withdrawn_children:
            children.append({'title': 'Withdrawn Routes', 'offset': offset + withdrawn_start, 'length': withdrawn_len, 'children': withdrawn_children})
        children.append({'title': f'Total Path Attribute Length: {total_attr_len}', 'offset': offset + total_attr_len_offset, 'length': 2})
        path_children: list[Dict[str, Any]] = []
        pos = attr_start
        while pos + 2 <= attr_end:
            flags = int(payload[pos])
            attr_type = int(payload[pos + 1])
            extended_len = bool(flags & 0x10)
            len_field = 2 if extended_len else 1
            if pos + 2 + len_field > attr_end:
                break
            if extended_len:
                attr_len = int.from_bytes(payload[pos + 2:pos + 4], 'big')
            else:
                attr_len = int(payload[pos + 2])
            value_start = pos + 2 + len_field
            value_end = min(attr_end, value_start + attr_len)
            value = payload[value_start:value_end]
            attr_name = {
                1: 'ORIGIN',
                2: 'AS_PATH',
                3: 'NEXT_HOP',
                4: 'MULTI_EXIT_DISC',
                5: 'LOCAL_PREF',
                6: 'ATOMIC_AGGREGATE',
                7: 'AGGREGATOR',
                8: 'COMMUNITY',
                14: 'MP_REACH_NLRI',
                15: 'MP_UNREACH_NLRI',
                16: 'EXTENDED COMMUNITIES',
            }.get(attr_type, f'Path Attribute ({attr_type})')
            flag_label = (
                f'Flags: 0x{flags:02x}, '
                f'{"Optional" if (flags & 0x80) else "Transitive" if (flags & 0x40) else "Well-known"}, '
                f'{"Non-transitive" if (flags & 0x80) else "Transitive" if (flags & 0x40) else "Well-known"}, '
                f'{"Partial" if (flags & 0x20) else "Complete"}'
            )
            flag_children = _bgp_flag_children(flags, offset + pos)
            attr_children: list[Dict[str, Any]] = [
                {'title': flag_label, 'offset': offset + pos, 'length': 1, 'children': flag_children},
                {'title': f'Type Code: {attr_name} ({attr_type})', 'offset': offset + pos + 1, 'length': 1},
                {'title': f'Length: {attr_len}', 'offset': offset + value_start - len_field, 'length': len_field},
            ]
            if attr_type == 1 and len(value) >= 1:
                origin = int(value[0])
                attr_children.append({'title': f'Origin: {_bgp_origin_name(origin)} ({origin})', 'offset': offset + value_start, 'length': 1})
            elif attr_type == 2:
                as_children = _bgp_as_path_children(value, offset + value_start)
                if as_children:
                    attr_children.append({'title': 'AS Path', 'offset': offset + value_start, 'length': len(value), 'children': as_children})
                else:
                    attr_children.append({'title': 'AS Path: empty', 'offset': offset + value_start, 'length': len(value)})
            elif attr_type == 3 and len(value) >= 4:
                attr_children.append({'title': f'Next Hop: {str(ipaddress.IPv4Address(value[:4]))}', 'offset': offset + value_start, 'length': 4})
            elif attr_type == 4 and len(value) >= 4:
                attr_children.append({'title': f'Multiple exit discriminator: {int.from_bytes(value[:4], "big")}', 'offset': offset + value_start, 'length': 4})
            elif attr_type == 5 and len(value) >= 4:
                attr_children.append({'title': f'Local preference: {int.from_bytes(value[:4], "big")}', 'offset': offset + value_start, 'length': 4})
            elif attr_type == 14:
                mp_children = _bgp_mp_reach_children(value, offset + value_start)
                attr_children.extend(mp_children)
            elif attr_type == 15:
                mp_children = _bgp_mp_unreach_children(value, offset + value_start)
                attr_children.extend(mp_children)
            elif value:
                attr_children.append({'title': f'Value: {value.hex()}', 'offset': offset + value_start, 'length': len(value)})
            path_children.append({
                'title': f'Path Attribute - {attr_name}' + (f': {_bgp_origin_name(int(value[0]))}' if attr_type == 1 and len(value) >= 1 else (f': {int.from_bytes(value[:4], "big")}' if attr_type in {4, 5} and len(value) >= 4 else '')),
                'offset': offset + pos,
                'length': max(0, value_end - pos),
                'children': attr_children,
            })
            if value_end <= pos:
                break
            pos = value_end
        if path_children:
            children.append({'title': 'Path attributes', 'offset': offset + attr_start, 'length': max(0, attr_end - attr_start), 'children': path_children})

    return {
        'title': f'Border Gateway Protocol - {msg_name}',
        'offset': offset,
        'length': section_length,
        'children': children,
    }


def _dot3_section(
    layer,
    offset: int,
    stream_index: int,
    padding_hex: str = '',
    padding_offset: int = 0,
    padding_len: int = 0,
    fcs_hex: str = '',
    fcs_offset: int = 0,
) -> Dict[str, Any]:
    src = getattr(layer, 'src', '-')
    dst = getattr(layer, 'dst', '-')
    length = int(getattr(layer, 'len', 0) or 0)

    src_vendor = get_mac_vendor(src)
    dst_vendor = get_mac_vendor(dst)

    def format_mac(mac: str, vendor: str):
        mac_text = str(mac or '')
        mac_lower = mac_text.lower()
        if mac_lower == '01:00:0c:cc:cc:cc':
            return f'CDP/VTP/DTP/PAgP/UDLD ({mac_text})'
        if mac_lower == '01:80:c2:00:00:00':
            return f'Nearest-Customer-Bridge ({mac_text})'
        if mac_lower == '01:80:c2:00:00:02':
            return f'Slow-Protocols ({mac_text})'
        if mac_lower == '01:80:c2:00:00:0e':
            return f'Nearest-Bridge ({mac_text})'
        if mac_lower == 'ab:00:00:02:00:00':
            return f'DEC-MOP-Remote-Console ({mac_text})'
        if not vendor:
            return mac_text
        suffix = ':'.join(mac_text.split(':')[-3:])
        return f'{vendor}_{suffix} ({mac_text})'

    def is_group(mac: str):
        try:
            return bool(int(mac.split(':')[0], 16) & 1)
        except Exception:
            return False

    def is_local(mac: str):
        try:
            return bool(int(mac.split(':')[0], 16) & 2)
        except Exception:
            return False

    src_display = format_mac(src, src_vendor)
    dst_display = format_mac(dst, dst_vendor)
    dst_group = is_group(dst)
    src_group = is_group(src)
    dst_local = is_local(dst)
    src_local = is_local(src)

    children = [
        {
            'title': f'Destination: {dst_display}',
            'offset': offset,
            'length': 6,
            'children': [
                {'title': f'.... ..{"1" if dst_local else "0"}. .... .... .... .... = LG bit: {"Locally administered" if dst_local else "Globally unique"} address ({"this is NOT the factory default" if dst_local else "factory default"})', 'offset': offset, 'length': 3},
                {'title': f'.... ...{"1" if dst_group else "0"} .... .... .... .... = IG bit: {"Group" if dst_group else "Individual"} address ({"multicast/broadcast" if dst_group else "unicast"})', 'offset': offset, 'length': 3},
            ],
        },
        {
            'title': f'Source: {src_display}',
            'offset': offset + 6,
            'length': 6,
            'children': [
                {'title': f'.... ..{"1" if src_local else "0"}. .... .... .... .... = LG bit: {"Locally administered" if src_local else "Globally unique"} address ({"this is NOT the factory default" if src_local else "factory default"})', 'offset': offset + 6, 'length': 3},
                {'title': f'.... ...{"1" if src_group else "0"} .... .... .... .... = IG bit: {"Group" if src_group else "Individual"} address ({"multicast/broadcast" if src_group else "unicast"})', 'offset': offset + 6, 'length': 3},
            ],
        },
        {'title': f'Length: {length}', 'offset': offset + 12, 'length': 2},
    ]

    if stream_index >= 0:
        children.append({'title': f'[Stream index: {stream_index}]'})
    if padding_hex:
        children.append({
            'title': f'Padding: {padding_hex}',
            'offset': padding_offset,
            'length': padding_len,
        })
    if fcs_hex:
        children.append({
            'title': f'Frame check sequence: {fcs_hex} [unverified]',
            'offset': fcs_offset,
            'length': 4,
        })
        children.append({'title': '[FCS Status: Unverified]'})

    return {
        'title': 'IEEE 802.3 Ethernet',
        'offset': offset,
        'length': 14,
        'children': children,
    }


def _llc_section(layer, snap_layer, offset: int) -> Dict[str, Any]:
    dsap = int(getattr(layer, 'dsap', 0) or 0)
    ssap = int(getattr(layer, 'ssap', 0) or 0)
    ctrl = int(getattr(layer, 'ctrl', 0) or 0)
    oui = int(getattr(snap_layer, 'OUI', 0) or 0) if snap_layer is not None else 0
    pid = int(getattr(snap_layer, 'code', 0) or 0) if snap_layer is not None else 0
    oui_text = f'{(oui >> 16) & 0xFF:02x}:{(oui >> 8) & 0xFF:02x}:{oui & 0xFF:02x}'
    pid_name = {
        0x2000: 'CDP',
        0x2003: 'VTP',
        0x2004: 'DTP',
        0x010b: 'PVSTP+',
        0x0111: 'UDLD',
    }.get(pid, f'0x{pid:04x}')
    dsap_name = 'SNAP'
    dsap_bits = '1010 101.'
    if snap_layer is None and dsap == 0x42:
        dsap_name = 'Spanning Tree BPDU'
        dsap_bits = '0100 001.'
    ssap_name = dsap_name
    ssap_bits = dsap_bits

    children = [
        {
            'title': f'DSAP: {dsap_name} (0x{dsap:02x})',
            'offset': offset,
            'length': 1,
            'children': [
                {'title': f'{dsap_bits} = SAP: {dsap_name}', 'offset': offset, 'length': 1},
                {'title': '.... ...0 = IG Bit: Individual', 'offset': offset, 'length': 1},
            ],
        },
        {
            'title': f'SSAP: {ssap_name} (0x{ssap:02x})',
            'offset': offset + 1,
            'length': 1,
            'children': [
                {'title': f'{ssap_bits} = SAP: {ssap_name}', 'offset': offset + 1, 'length': 1},
                {'title': '.... ...0 = CR Bit: Command', 'offset': offset + 1, 'length': 1},
            ],
        },
        {
            'title': f'Control field: U, func=UI (0x{ctrl:02x})',
            'offset': offset + 2,
            'length': 1,
            'children': [
                {'title': '000. 00.. = Command: Unnumbered Information (0x00)', 'offset': offset + 2, 'length': 1},
                {'title': '.... ..11 = Frame type: Unnumbered frame (0x3)', 'offset': offset + 2, 'length': 1},
            ],
        },
    ]

    if snap_layer is not None:
        children.extend([
            {'title': f'Organization Code: {oui_text} (Cisco Systems, Inc)', 'offset': offset + 3, 'length': 3},
            {'title': f'PID: {pid_name} (0x{pid:04x})', 'offset': offset + 6, 'length': 2},
        ])

    return {
        'title': 'Logical-Link Control',
        'offset': offset,
        'length': 3 + (5 if snap_layer is not None else 0),
        'children': children,
    }


def _vlan_section(layer, offset: int) -> Dict[str, Any]:
    prio = int(getattr(layer, 'prio', 0) or 0)
    dei = int(getattr(layer, 'dei', 0) or 0)
    vlan = int(getattr(layer, 'vlan', 0) or 0)
    inner_type = int(getattr(layer, 'type', 0) or 0)
    children = [
        {'title': f'{prio:03b}. .... .... .... = Priority: {"Network Control" if prio == 7 else "Best Effort (default)" if prio == 0 else prio}', 'offset': offset, 'length': 2},
        {'title': f'...{dei} .... .... .... = DEI: {"Eligible" if dei else "Ineligible"}', 'offset': offset, 'length': 2},
        {'title': f'.... {vlan:012b} = ID: {vlan}', 'offset': offset, 'length': 2},
    ]
    title = f'802.1Q Virtual LAN, PRI: {prio}, DEI: {dei}, ID: {vlan}'
    if inner_type <= 1500:
        children.append({'title': f'Length: {inner_type}', 'offset': offset + 2, 'length': 2})
    else:
        children.append({'title': f'Type: 0x{inner_type:04x}', 'offset': offset + 2, 'length': 2})
    return {
        'title': title,
        'offset': offset,
        'length': 4,
        'children': children,
    }


def _ripng_section(payload: bytes, offset: int) -> Dict[str, Any]:
    command = int(payload[0]) if len(payload) >= 1 else 0
    version = int(payload[1]) if len(payload) >= 2 else 0
    command_name = {1: 'Request', 2: 'Response'}.get(command, str(command))
    children = [
        {'title': f'Command: {command_name} ({command})', 'offset': offset, 'length': 1},
        {'title': f'Version: {version}', 'offset': offset + 1, 'length': 1},
        {'title': f'Reserved: {payload[2:4].hex() if len(payload) >= 4 else "0000"}', 'offset': offset + 2, 'length': 2},
    ]
    pos = 4
    while pos + 20 <= len(payload):
        prefix = str(ipaddress.IPv6Address(payload[pos:pos + 16]))
        route_tag = int.from_bytes(payload[pos + 16:pos + 18], 'big')
        prefix_len = int(payload[pos + 18])
        metric = int(payload[pos + 19])
        children.append({
            'title': f'Route Table Entry: IPv6 Prefix: {prefix}/{prefix_len} Metric: {metric}',
            'offset': offset + pos,
            'length': 20,
            'children': [
                {'title': f'IPv6 Prefix: {prefix}', 'offset': offset + pos, 'length': 16},
                {'title': f'Route Tag: 0x{route_tag:04x}', 'offset': offset + pos + 16, 'length': 2},
                {'title': f'Prefix Length: {prefix_len}', 'offset': offset + pos + 18, 'length': 1},
                {'title': f'Metric: {metric}', 'offset': offset + pos + 19, 'length': 1},
            ],
        })
        pos += 20
    return {
        'title': 'RIPng',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _ipv4_text(value: bytes) -> str:
    if len(value) != 4:
        return '0.0.0.0'
    return '.'.join(str(int(byte)) for byte in value)


def _ripv2_section(payload: bytes, offset: int) -> Dict[str, Any]:
    command = int(payload[0]) if len(payload) >= 1 else 0
    version = int(payload[1]) if len(payload) >= 2 else 0
    command_name = {1: 'Request', 2: 'Response'}.get(command, str(command))
    version_name = 'RIPv2' if version == 2 else str(version)
    children = [
        {'title': f'Command: {command_name} ({command})', 'offset': offset, 'length': 1},
        {'title': f'Version: {version_name} ({version})', 'offset': offset + 1, 'length': 1},
    ]
    pos = 4
    while pos + 20 <= len(payload):
        family = int.from_bytes(payload[pos:pos + 2], 'big')
        route_tag = int.from_bytes(payload[pos + 2:pos + 4], 'big')
        ip_addr = _ipv4_text(payload[pos + 4:pos + 8])
        netmask = _ipv4_text(payload[pos + 8:pos + 12])
        next_hop = _ipv4_text(payload[pos + 12:pos + 16])
        metric = int.from_bytes(payload[pos + 16:pos + 20], 'big')
        family_name = 'IP' if family == 2 else str(family)
        children.append({
            'title': f'IP Address: {ip_addr}, Metric: {metric}',
            'offset': offset + pos,
            'length': 20,
            'children': [
                {'title': f'Address Family: {family_name} ({family})', 'offset': offset + pos, 'length': 2},
                {'title': f'Route Tag: {route_tag}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'IP Address: {ip_addr}', 'offset': offset + pos + 4, 'length': 4},
                {'title': f'Netmask: {netmask}', 'offset': offset + pos + 8, 'length': 4},
                {'title': f'Next Hop: {next_hop}', 'offset': offset + pos + 12, 'length': 4},
                {'title': f'Metric: {metric}', 'offset': offset + pos + 16, 'length': 4},
            ],
        })
        pos += 20
    return {
        'title': 'Routing Information Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _syslog_section(payload: bytes, offset: int) -> Dict[str, Any]:
    pri = 0
    pri_end = payload.find(b'>', 1, 6) if payload.startswith(b'<') else -1
    if pri_end != -1:
        try:
            pri = int(payload[1:pri_end].decode(errors='ignore'))
        except Exception:
            pri = 0
    facility = pri >> 3
    level = pri & 0x07
    facility_name = {
        23: 'LOCAL7 - reserved for local use',
    }.get(facility, str(facility))
    level_name = {
        5: 'NOTICE - normal but significant condition',
    }.get(level, str(level))
    message = payload[pri_end + 1:].decode(errors='ignore') if pri_end != -1 else payload.decode(errors='ignore')
    children = [
        {'title': f'.... ..{facility:06b} ... = Facility: {facility_name} ({facility})', 'offset': offset, 'length': pri_end + 1 if pri_end != -1 else len(payload)},
        {'title': f'.... .... .... .{level:03b} = Level: {level_name} ({level})', 'offset': offset, 'length': pri_end + 1 if pri_end != -1 else len(payload)},
        {
            'title': f'Message: {message}',
            'offset': offset + (pri_end + 1 if pri_end != -1 else 0),
            'length': len(payload) - (pri_end + 1 if pri_end != -1 else 0),
            'children': [
                {
                    'title': '[Expert Info (Note/Protocol): Message conforms to neither RFC 5424 nor RFC 3164; trailing data appended]',
                    'children': [
                        {'title': '[Message conforms to neither RFC 5424 nor RFC 3164; trailing data appended]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Protocol]'},
                    ],
                },
            ],
        },
    ]
    return {
        'title': f'Syslog message: {facility_name.split(" -", 1)[0]}.{level_name.split(" -", 1)[0]}: {message}',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _ntp_timestamp_text(raw_value: int) -> str:
    if raw_value == 0:
        return 'Jan  1, 1900 00:00:00.000000000 UTC'
    seconds = raw_value >> 32
    fraction = raw_value & 0xFFFFFFFF
    nanos = (fraction * 1_000_000_000) >> 32
    try:
        dt = datetime(1900, 1, 1, tzinfo=timezone.utc) + timedelta(seconds=int(seconds))
        return f'{dt.strftime("%b %d, %Y %H:%M:%S")}.{nanos:09d} UTC'
    except Exception:
        return f'{int(seconds)}.{nanos:09d} (NTP seconds)'


def _ntp_section(payload: bytes, offset: int, record) -> Dict[str, Any]:
    first = int(payload[0]) if len(payload) >= 1 else 0
    leap = (first >> 6) & 0x03
    version = (first >> 3) & 0x07
    mode = first & 0x07
    stratum = int(payload[1]) if len(payload) >= 2 else 0
    poll = int(payload[2]) if len(payload) >= 3 else 0
    precision = int.from_bytes(payload[3:4], 'big', signed=True) if len(payload) >= 4 else 0
    root_delay = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
    root_dispersion = int.from_bytes(payload[8:12], 'big') if len(payload) >= 12 else 0
    ref_id = _ipv4_text(payload[12:16]) if len(payload) >= 16 else '0.0.0.0'
    ref_ts = int.from_bytes(payload[16:24], 'big') if len(payload) >= 24 else 0
    orig_ts = int.from_bytes(payload[24:32], 'big') if len(payload) >= 32 else 0
    recv_ts = int.from_bytes(payload[32:40], 'big') if len(payload) >= 40 else 0
    tx_ts = int.from_bytes(payload[40:48], 'big') if len(payload) >= 48 else 0
    leap_name = {0: 'no warning', 1: 'last minute has 61 seconds', 2: 'last minute has 59 seconds', 3: 'alarm condition'}.get(leap, str(leap))
    mode_name = {1: 'symmetric active', 2: 'symmetric passive', 3: 'client', 4: 'server', 5: 'broadcast'}.get(mode, str(mode))
    if mode == 6 and len(payload) >= 12:
        flags2 = int(payload[1]) if len(payload) >= 2 else 0
        response_bit = (flags2 >> 7) & 0x01
        error_bit = (flags2 >> 6) & 0x01
        more_bit = (flags2 >> 5) & 0x01
        opcode = flags2 & 0x1F
        opcode_name = {
            1: 'read status',
            2: 'read variables',
            3: 'write variables',
        }.get(opcode, str(opcode))
        sequence = int.from_bytes(payload[2:4], 'big') if len(payload) >= 4 else 0
        status = int.from_bytes(payload[4:6], 'big') if len(payload) >= 6 else 0
        association_id = int.from_bytes(payload[6:8], 'big') if len(payload) >= 8 else 0
        data_offset = int.from_bytes(payload[8:10], 'big') if len(payload) >= 10 else 0
        count = int.from_bytes(payload[10:12], 'big') if len(payload) >= 12 else 0
        children = [
            {
                'title': f'Flags: 0x{first:02x}, Leap Indicator: {leap_name}, Version number: NTP Version {version}, Mode: reserved for NTP control message',
                'offset': offset,
                'length': 1,
                'children': [
                    {'title': f'{leap:02b}.. .... = Leap Indicator: {leap_name} ({leap})', 'offset': offset, 'length': 1},
                    {'title': f'..{version:03b} ... = Version number: NTP Version {version} ({version})', 'offset': offset, 'length': 1},
                    {'title': f'.... .{mode:03b} = Mode: reserved for NTP control message ({mode})', 'offset': offset, 'length': 1},
                ],
            },
            {
                'title': f'Flags 2: 0x{flags2:02x}, Opcode: {opcode_name}',
                'offset': offset + 1,
                'length': 1,
                'children': [
                    {'title': f'{response_bit}... .... = Response bit: {"Response" if response_bit else "Request"}', 'offset': offset + 1, 'length': 1},
                    {'title': f'.{error_bit}.. .... = Error bit: {error_bit}', 'offset': offset + 1, 'length': 1},
                    {'title': f'..{more_bit}. .... = More bit: {more_bit}', 'offset': offset + 1, 'length': 1},
                    {'title': f'...{opcode:05b} = Opcode: {opcode_name} ({opcode})', 'offset': offset + 1, 'length': 1},
                ],
            },
            {'title': f'Sequence: {sequence}', 'offset': offset + 2, 'length': 2},
            {'title': f'Status: 0x{status:04x}', 'offset': offset + 4, 'length': 2},
            {'title': f'AssociationID: {association_id}', 'offset': offset + 6, 'length': 2},
            {'title': f'Offset: {data_offset}', 'offset': offset + 8, 'length': 2},
            {'title': f'Count: {count}', 'offset': offset + 10, 'length': 2},
        ]
        response_frame = int(record.metadata.get('ntp_response_frame', 0) or 0)
        request_frame = int(record.metadata.get('ntp_request_frame', 0) or 0)
        if response_frame > 0:
            children.insert(3, {'title': f'[Response In: {response_frame}]'})
        elif request_frame > 0:
            children.insert(3, {'title': f'[Request In: {request_frame}]'})
        return {
            'title': f'Network Time Protocol (NTP Version {version}, control)',
            'offset': offset,
            'length': len(payload),
            'children': children,
        }
    stratum_name = {3: 'secondary reference'}.get(stratum, str(stratum))
    poll_seconds = 2 ** poll if poll >= 0 else 0
    precision_seconds = 2 ** precision if precision < 0 else 0
    bracket_node = None
    response_frame = int(record.metadata.get('ntp_response_frame', 0) or 0)
    request_frame = int(record.metadata.get('ntp_request_frame', 0) or 0)
    if response_frame > 0:
        bracket_node = {'title': f'[Response In: {response_frame}]'}
    elif request_frame > 0:
        bracket_node = {'title': f'[Request In: {request_frame}]'}
    children = [
        {
            'title': f'Flags: 0x{first:02x}, Leap Indicator: {leap_name}, Version number: NTP Version {version}, Mode: {mode_name}',
            'offset': offset,
            'length': 1,
            'children': [
                {'title': f'{leap:02b}.. .... = Leap Indicator: {leap_name} ({leap})', 'offset': offset, 'length': 1},
                {'title': f'..{version:03b} ... = Version number: NTP Version {version} ({version})', 'offset': offset, 'length': 1},
                {'title': f'.... .{mode:03b} = Mode: {mode_name} ({mode})', 'offset': offset, 'length': 1},
            ],
        },
        {'title': f'Peer Clock Stratum: {stratum_name} ({stratum})', 'offset': offset + 1, 'length': 1},
        {'title': f'Peer Polling Interval: {poll} ({poll_seconds} seconds)', 'offset': offset + 2, 'length': 1},
        {'title': f'Peer Clock Precision: {precision} ({precision_seconds:.9f} seconds)', 'offset': offset + 3, 'length': 1},
        {'title': f'Root Delay: {root_delay / 65536.0:.6f} seconds', 'offset': offset + 4, 'length': 4},
        {'title': f'Root Dispersion: {root_dispersion / 65536.0:.6f} seconds', 'offset': offset + 8, 'length': 4},
        {'title': f'Reference ID: {ref_id}', 'offset': offset + 12, 'length': 4},
        {'title': f'Reference Timestamp: {_ntp_timestamp_text(ref_ts)}', 'offset': offset + 16, 'length': 8},
        {'title': f'Origin Timestamp: {_ntp_timestamp_text(orig_ts)}', 'offset': offset + 24, 'length': 8},
        {'title': f'Receive Timestamp: {_ntp_timestamp_text(recv_ts)}', 'offset': offset + 32, 'length': 8},
        {'title': f'Transmit Timestamp: {_ntp_timestamp_text(tx_ts)}', 'offset': offset + 40, 'length': 8},
    ]
    if bracket_node is not None:
        children.insert(1, bracket_node)

    cursor = 48
    while cursor + 4 <= len(payload):
        field_type = int.from_bytes(payload[cursor:cursor + 2], 'big')
        field_len = int.from_bytes(payload[cursor + 2:cursor + 4], 'big')
        if field_len < 4 or cursor + field_len > len(payload):
            break
        field_value = payload[cursor + 4:cursor + field_len]
        field_name = {
            0x0104: 'Unique Identifier',
            0x0204: 'NTS Cookie/Autokey Request',
            0x0304: 'NTS Cookie/Autokey Response',
            0x0404: 'NTS Authenticator and Encrypted Extension Fields',
        }.get(field_type, f'Extension Field 0x{field_type:04x}')
        ext_children: List[Dict[str, Any]] = [
            {'title': f'Field Type: {field_name} (0x{field_type:04x})', 'offset': offset + cursor, 'length': 2},
            {'title': f'Length: {field_len}', 'offset': offset + cursor + 2, 'length': 2},
            {'title': f'Value: {field_value.hex()}', 'offset': offset + cursor + 4, 'length': max(0, field_len - 4)},
        ]
        if field_type == 0x0404 and len(field_value) >= 4:
            nonce_len = int.from_bytes(field_value[0:2], 'big')
            ciphertext_len = int.from_bytes(field_value[2:4], 'big')
            nonce_start = cursor + 8
            nonce_end = min(cursor + field_len, nonce_start + nonce_len)
            cipher_start = nonce_end
            cipher_end = min(cursor + field_len, cipher_start + ciphertext_len)
            nts_children: List[Dict[str, Any]] = [
                {'title': f'Nonce Length: {nonce_len}', 'offset': offset + cursor + 4, 'length': 2},
                {'title': f'Ciphertext Length: {ciphertext_len}', 'offset': offset + cursor + 6, 'length': 2},
                {'title': f'Nonce: {payload[nonce_start:nonce_end].hex()}', 'offset': offset + nonce_start, 'length': max(0, nonce_end - nonce_start)},
                {'title': f'Ciphertext: {payload[cipher_start:cipher_end].hex()}', 'offset': offset + cipher_start, 'length': max(0, cipher_end - cipher_start)},
            ]
            ext_children.append({
                'title': 'Network Time Security',
                'offset': offset + cursor + 4,
                'length': max(0, field_len - 4),
                'children': nts_children,
            })
        children.append({
            'title': f'Extension Field: {field_name}',
            'offset': offset + cursor,
            'length': field_len,
            'children': ext_children,
        })
        cursor += field_len
    return {
        'title': f'Network Time Protocol (NTP Version {version}, {mode_name})',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _slow_protocols_section(payload: bytes, offset: int) -> Dict[str, Any]:
    subtype = int(payload[0]) if len(payload) >= 1 else 0
    subtype_name = {1: 'LACP'}.get(subtype, f'0x{subtype:02x}')
    return {
        'title': '802.3 Slow protocols',
        'offset': offset,
        'length': 1 if len(payload) >= 1 else 0,
        'children': [
            {'title': f'Slow Protocols subtype: {subtype_name} (0x{subtype:02x})', 'offset': offset, 'length': 1},
        ],
    }


def _lacp_state_children(state: int, offset: int) -> List[Dict[str, Any]]:
    return [
        {'title': f'.... ...{1 if state & 0x01 else 0} = LACP Activity: {"Active" if state & 0x01 else "Passive"}', 'offset': offset, 'length': 1},
        {'title': f'.... ..{1 if state & 0x02 else 0}. = LACP Timeout: {"Short Timeout" if state & 0x02 else "Long Timeout"}', 'offset': offset, 'length': 1},
        {'title': f'.... .{1 if state & 0x04 else 0}.. = Aggregation: {"Aggregatable" if state & 0x04 else "Individual"}', 'offset': offset, 'length': 1},
        {'title': f'.... {1 if state & 0x08 else 0}... = Synchronization: {"In Sync" if state & 0x08 else "Out of Sync"}', 'offset': offset, 'length': 1},
        {'title': f'...{1 if state & 0x10 else 0} .... = Collecting: {"Enabled" if state & 0x10 else "Disabled"}', 'offset': offset, 'length': 1},
        {'title': f'..{1 if state & 0x20 else 0}. .... = Distributing: {"Enabled" if state & 0x20 else "Disabled"}', 'offset': offset, 'length': 1},
        {'title': f'.{1 if state & 0x40 else 0}.. .... = Defaulted: {"Yes" if state & 0x40 else "No"}', 'offset': offset, 'length': 1},
        {'title': f'{1 if state & 0x80 else 0}... .... = Expired: {"Yes" if state & 0x80 else "No"}', 'offset': offset, 'length': 1},
    ]


def _lacp_state_flags_text(state: int) -> str:
    return ''.join([
        '*' if state & 0x80 else '*',
        '*' if state & 0x40 else '*',
        'D' if state & 0x20 else '*',
        'C' if state & 0x10 else '*',
        'S' if state & 0x08 else '*',
        'G' if state & 0x04 else '*',
        '*' if state & 0x02 else '*',
        'A' if state & 0x01 else '*',
    ])


def _lacp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    children = []
    if len(payload) >= 1:
        children.append({'title': f'LACP Version: 0x{payload[0]:02x}', 'offset': offset, 'length': 1})
    pos = 1
    while pos + 2 <= len(payload):
        tlv_type = int(payload[pos])
        tlv_len = int(payload[pos + 1])
        if tlv_type == 0 and tlv_len == 0:
            children.append({
                'title': 'TLV Type: Terminator (0x00)',
                'offset': offset + pos,
                'length': 1,
            })
            children.append({
                'title': 'TLV Length: 0x00',
                'offset': offset + pos + 1,
                'length': 1,
            })
            if pos + 2 < len(payload):
                children.append({'title': f'Pad: {payload[pos + 2:].hex()}', 'offset': offset + pos + 2, 'length': len(payload) - (pos + 2)})
            break
        if tlv_len <= 0 or pos + tlv_len > len(payload):
            break
        value = payload[pos + 2:pos + tlv_len]
        if tlv_type in {1, 2} and len(value) >= 18:
            role = 'Actor' if tlv_type == 1 else 'Partner'
            role_name = 'Actor Information' if tlv_type == 1 else 'Partner Information'
            sys_pri = int.from_bytes(value[0:2], 'big')
            sys_id = ':'.join(f'{b:02x}' for b in value[2:8])
            key = int.from_bytes(value[8:10], 'big')
            port_pri = int.from_bytes(value[10:12], 'big')
            port = int.from_bytes(value[12:14], 'big')
            state = int(value[14])
            children.extend([
                {'title': f'TLV Type: {role_name} (0x{tlv_type:02x})', 'offset': offset + pos, 'length': 1},
                {'title': f'TLV Length: 0x{tlv_len:02x}', 'offset': offset + pos + 1, 'length': 1},
                {'title': f'{role} System Priority: {sys_pri}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'{role} System ID: {_mac_display(sys_id)}', 'offset': offset + pos + 4, 'length': 6},
                {'title': f'{role} Key: {key}', 'offset': offset + pos + 10, 'length': 2},
                {'title': f'{role} Port Priority: {port_pri}', 'offset': offset + pos + 12, 'length': 2},
                {'title': f'{role} Port: {port}', 'offset': offset + pos + 14, 'length': 2},
                {'title': f'{role} State: 0x{state:02x}, LACP Activity, Aggregation, Synchronization, Collecting, Distributing', 'offset': offset + pos + 16, 'length': 1, 'children': _lacp_state_children(state, offset + pos + 16)},
                {'title': f'[{role} State Flags: {_lacp_state_flags_text(state)}]'},
                {'title': f'Reserved: {value[15:18].hex()}', 'offset': offset + pos + 17, 'length': 3},
            ])
        elif tlv_type == 3 and len(value) >= 14:
            max_delay = int.from_bytes(value[0:2], 'big')
            children.extend([
                {'title': 'TLV Type: Collector Information (0x03)', 'offset': offset + pos, 'length': 1},
                {'title': f'TLV Length: 0x{tlv_len:02x}', 'offset': offset + pos + 1, 'length': 1},
                {'title': f'Collector Max Delay: {max_delay}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'Reserved: {value[2:].hex()}', 'offset': offset + pos + 4, 'length': len(value) - 2},
            ])
        pos += tlv_len
    return {
        'title': 'Link Aggregation Control Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _vtp_timestamp_text(value: bytes) -> str:
    text = value.decode(errors='ignore')
    if len(text) >= 12 and text.isdigit():
        return f'{text[0:2]}-{text[2:4]}-{text[4:6]} {text[6:8]}:{text[8:10]}:{text[10:12]}'
    return text


def _vtp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    version = int(payload[0]) if len(payload) >= 1 else 0
    code = int(payload[1]) if len(payload) >= 2 else 0
    code_name = {
        0x01: 'Summary Advertisement',
        0x02: 'Subset Advertisement',
        0x03: 'Advertisement Request',
    }.get(code, f'0x{code:02x}')
    children = [
        {'title': f'Version: 0x{version:02x}', 'offset': offset, 'length': 1},
        {'title': f'Code: {code_name} (0x{code:02x})', 'offset': offset + 1, 'length': 1},
    ]

    if code == 0x02:
        seq_num = int(payload[2]) if len(payload) >= 3 else 0
        domain_len = int(payload[3]) if len(payload) >= 4 else 0
        domain_raw = payload[4:36] if len(payload) >= 36 else payload[4:]
        domain = domain_raw[:domain_len].decode(errors='ignore')
        revision_offset = 36
        revision = int.from_bytes(payload[revision_offset:revision_offset + 4], 'big') if len(payload) >= revision_offset + 4 else 0
        children.extend([
            {'title': f'Sequence Number: {seq_num}', 'offset': offset + 2, 'length': 1},
            {'title': f'Management Domain Length: {domain_len}', 'offset': offset + 3, 'length': 1},
            {'title': f'Management Domain: {domain}', 'offset': offset + 4, 'length': min(32, len(domain_raw)), 'children': [
                {'title': f'Management Domain Text: {domain}', 'offset': offset + 4, 'length': min(domain_len, len(domain_raw))},
                {'title': f'Management Domain Padding: {domain_raw[domain_len:].hex()}', 'offset': offset + 4 + domain_len, 'length': max(0, len(domain_raw) - domain_len)},
            ]},
            {'title': f'Configuration Revision Number: {revision}', 'offset': offset + revision_offset, 'length': 4},
        ])

        pos = revision_offset + 4
        vlan_index = 1
        while pos + 1 <= len(payload):
            vlan_len = int(payload[pos])
            if vlan_len < 13 or pos + vlan_len > len(payload):
                break
            vlan_value = payload[pos + 1:pos + vlan_len]
            status = int(vlan_value[0]) if len(vlan_value) >= 1 else 0
            vlan_type = int(vlan_value[1]) if len(vlan_value) >= 2 else 0
            vlan_name_len = int(vlan_value[2]) if len(vlan_value) >= 3 else 0
            isl_vlan_id = int.from_bytes(vlan_value[3:5], 'big') if len(vlan_value) >= 5 else 0
            mtu_size = int.from_bytes(vlan_value[5:7], 'big') if len(vlan_value) >= 7 else 0
            index_802_10 = int.from_bytes(vlan_value[7:11], 'big') if len(vlan_value) >= 11 else 0
            vlan_name_raw = vlan_value[11:]
            vlan_name = vlan_name_raw[:vlan_name_len].decode(errors='ignore')
            vlan_title = vlan_name if vlan_name else f'0x{isl_vlan_id:04x}'
            vlan_children = [
                {'title': f'VLAN Information Length: {vlan_len}', 'offset': offset + pos, 'length': 1},
                {'title': f'Status: 0x{status:02x}', 'offset': offset + pos + 1, 'length': 1, 'children': [
                    {'title': f'.... ...{status & 0x01:b} = VLAN suspended: {"True" if (status & 0x01) else "False"}', 'offset': offset + pos + 1, 'length': 1},
                ]},
                {'title': f'VLAN Type: {vlan_type}', 'offset': offset + pos + 2, 'length': 1},
                {'title': f'VLAN Name Length: {vlan_name_len}', 'offset': offset + pos + 3, 'length': 1},
                {'title': f'ISL VLAN ID: 0x{isl_vlan_id:04x}', 'offset': offset + pos + 4, 'length': 2},
                {'title': f'MTU Size: {mtu_size}', 'offset': offset + pos + 6, 'length': 2},
                {'title': f'802.10 Index: 0x{index_802_10:08x}', 'offset': offset + pos + 8, 'length': 4},
                {'title': f'VLAN Name: {vlan_name}', 'offset': offset + pos + 12, 'length': max(0, min(vlan_name_len, len(vlan_name_raw))), 'children': [
                    {'title': f'VLAN Name Text: {vlan_name}', 'offset': offset + pos + 12, 'length': max(0, min(vlan_name_len, len(vlan_name_raw)))},
                    {'title': f'Padding: {vlan_name_raw[vlan_name_len:].hex()}', 'offset': offset + pos + 12 + vlan_name_len, 'length': max(0, len(vlan_name_raw) - vlan_name_len)},
                ]},
            ]
            children.append({
                'title': f'VLAN Information #{vlan_index}: {vlan_title}',
                'offset': offset + pos,
                'length': vlan_len,
                'children': vlan_children,
            })
            pos += vlan_len
            vlan_index += 1

        return {
            'title': 'VLAN Trunking Protocol',
            'offset': offset,
            'length': len(payload),
            'children': children,
        }

    followers = int(payload[2]) if len(payload) >= 3 else 0
    domain_len = int(payload[3]) if len(payload) >= 4 else 0
    domain_raw = payload[4:36] if len(payload) >= 36 else b''
    domain = domain_raw[:domain_len].decode(errors='ignore')
    revision = int.from_bytes(payload[36:40], 'big') if len(payload) >= 40 else 0
    updater = _ipv4_text(payload[40:44]) if len(payload) >= 44 else '0.0.0.0'
    ts = _vtp_timestamp_text(payload[44:56]) if len(payload) >= 56 else ''
    md5 = payload[56:72].hex() if len(payload) >= 72 else ''
    children.extend([
        {'title': f'Followers: {followers}', 'offset': offset + 2, 'length': 1},
        {'title': f'Management Domain Length: {domain_len}', 'offset': offset + 3, 'length': 1},
        {'title': f'Management Domain: {domain}', 'offset': offset + 4, 'length': 32, 'children': [
            {'title': f'Management Domain Text: {domain}', 'offset': offset + 4, 'length': min(domain_len, len(domain_raw))},
            {'title': f'Management Domain Padding: {domain_raw[domain_len:].hex()}', 'offset': offset + 4 + domain_len, 'length': max(0, len(domain_raw) - domain_len)},
        ]},
        {'title': f'Configuration Revision Number: {revision}', 'offset': offset + 36, 'length': 4},
        {'title': f'Updater Identity: {updater}', 'offset': offset + 40, 'length': 4},
        {'title': f'Update Timestamp: {ts}', 'offset': offset + 44, 'length': 12},
        {'title': f'MD5 Digest: {md5}', 'offset': offset + 56, 'length': 16},
    ])
    return {
        'title': 'VLAN Trunking Protocol',
        'offset': offset,
        'length': min(len(payload), 72),
        'children': children,
    }


def _dtp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    version = int(payload[0]) if len(payload) >= 1 else 0
    pos = 1
    children = [
        {'title': f'Version: {version}', 'offset': offset, 'length': 1},
    ]
    summary_domain = ''
    summary_status = ''
    summary_type = ''
    summary_sender = ''
    while pos + 4 <= len(payload):
        tlv_type = int.from_bytes(payload[pos:pos + 2], 'big')
        tlv_len = int.from_bytes(payload[pos + 2:pos + 4], 'big')
        if tlv_len < 4 or pos + tlv_len > len(payload):
            break
        value = payload[pos + 4:pos + tlv_len]
        if tlv_type == 0x0001:
            summary_domain = value.decode(errors='ignore').rstrip('\x00')
            children.append({'title': 'Domain', 'offset': offset + pos, 'length': tlv_len, 'children': [
                {'title': 'Type: Domain (0x0001)', 'offset': offset + pos, 'length': 2},
                {'title': f'Length: {tlv_len}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'Domain: {summary_domain}', 'offset': offset + pos + 4, 'length': len(value)},
            ]})
        elif tlv_type == 0x0002 and len(value) >= 1:
            status = int(value[0])
            summary_status = f'Trunk/On (0x{status:02x})' if status == 0x81 else f'0x{status:02x}'
            children.append({'title': 'Trunk Status', 'offset': offset + pos, 'length': tlv_len, 'children': [
                {'title': 'Type: Trunk Status (0x0002)', 'offset': offset + pos, 'length': 2},
                {'title': f'Length: {tlv_len}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'Value: {summary_status}', 'offset': offset + pos + 4, 'length': 1, 'children': [
                    {'title': f'{1 if status & 0x80 else 0}... .... = Trunk Operating Status: {"Trunk" if status & 0x80 else "Access"} (0x{(status >> 7) & 0x1:x})', 'offset': offset + pos + 4, 'length': 1},
                    {'title': f'.... .{status & 0x07:03b} = Trunk Administrative Status: {"On" if (status & 0x07) == 0x01 else (status & 0x07)} (0x{status & 0x07:x})', 'offset': offset + pos + 4, 'length': 1},
                ]},
            ]})
        elif tlv_type == 0x0003 and len(value) >= 1:
            trunk_type = int(value[0])
            summary_type = f'802.1Q/802.1Q (0x{trunk_type:02x})' if trunk_type == 0xa5 else f'0x{trunk_type:02x}'
            children.append({'title': 'Trunk Type', 'offset': offset + pos, 'length': tlv_len, 'children': [
                {'title': 'Type: Trunk Type (0x0003)', 'offset': offset + pos, 'length': 2},
                {'title': f'Length: {tlv_len}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'Value: {summary_type}', 'offset': offset + pos + 4, 'length': 1, 'children': [
                    {'title': f'{(trunk_type >> 5) & 0x07:03b}. .... = Trunk Operating Type: {"802.1Q" if ((trunk_type >> 5) & 0x07) == 0x5 else ((trunk_type >> 5) & 0x07)} (0x{((trunk_type >> 5) & 0x07):x})', 'offset': offset + pos + 4, 'length': 1},
                    {'title': f'.... .{trunk_type & 0x07:03b} = Trunk Administrative Type: {"802.1Q" if (trunk_type & 0x07) == 0x5 else (trunk_type & 0x07)} (0x{trunk_type & 0x07:x})', 'offset': offset + pos + 4, 'length': 1},
                ]},
            ]})
        elif tlv_type == 0x0004 and len(value) >= 6:
            sender = ':'.join(f'{b:02x}' for b in value[:6])
            summary_sender = _mac_display(sender)
            children.append({'title': 'Sender ID', 'offset': offset + pos, 'length': tlv_len, 'children': [
                {'title': 'Type: Sender ID (0x0004)', 'offset': offset + pos, 'length': 2},
                {'title': f'Length: {tlv_len}', 'offset': offset + pos + 2, 'length': 2},
                {'title': f'Sender ID: {summary_sender}', 'offset': offset + pos + 4, 'length': 6},
            ]})
        pos += tlv_len
    title = 'Dynamic Trunk Protocol'
    if summary_domain and summary_status and summary_type and summary_sender:
        title = f'Dynamic Trunk Protocol: {summary_domain} (Operating/Administrative): {summary_status} (Operating/Administrative): {summary_type}: {summary_sender.split(" (",1)[-1][:-1] if " (" in summary_sender else summary_sender}'
    return {
        'title': title,
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _stp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    flags = int(payload[4]) if len(payload) >= 5 else 0
    root_prio_field = int.from_bytes(payload[5:7], 'big') if len(payload) >= 7 else 0
    root_prio = root_prio_field & 0xF000
    root_vlan = root_prio_field & 0x0FFF
    root_mac = ':'.join(f'{b:02x}' for b in payload[7:13]) if len(payload) >= 13 else ''
    path_cost = int.from_bytes(payload[13:17], 'big') if len(payload) >= 17 else 0
    bridge_prio_field = int.from_bytes(payload[17:19], 'big') if len(payload) >= 19 else 0
    bridge_prio = bridge_prio_field & 0xF000
    bridge_vlan = bridge_prio_field & 0x0FFF
    bridge_mac = ':'.join(f'{b:02x}' for b in payload[19:25]) if len(payload) >= 25 else ''
    port_id = int.from_bytes(payload[25:27], 'big') if len(payload) >= 27 else 0
    version_1_len = int(payload[35]) if len(payload) >= 36 else 0
    role_code = (flags >> 2) & 0x03
    role_name = {
        0: 'Unknown',
        1: 'Alternate/Backup',
        2: 'Root',
        3: 'Designated',
    }.get(role_code, str(role_code))
    flags_parts = []
    if flags & 0x40:
        flags_parts.append('Agreement')
    if flags & 0x20:
        flags_parts.append('Forwarding')
    if flags & 0x10:
        flags_parts.append('Learning')
    flags_parts.append(f'Port Role: {role_name}')
    if flags & 0x01:
        flags_parts.append('Topology Change')
    children = [
        {'title': 'Protocol Identifier: Spanning Tree Protocol (0x0000)', 'offset': offset, 'length': 2},
        {'title': f'Protocol Version Identifier: Rapid Spanning Tree ({int(payload[2]) if len(payload) >= 3 else 0})', 'offset': offset + 2, 'length': 1},
        {'title': f'BPDU Type: Rapid/Multiple Spanning Tree (0x{int(payload[3]) if len(payload) >= 4 else 0:02x})', 'offset': offset + 3, 'length': 1},
        {
            'title': f'BPDU flags: 0x{flags:02x}, {", ".join(flags_parts)}',
            'offset': offset + 4,
            'length': 1,
            'children': [
                {'title': f'{1 if flags & 0x80 else 0}... .... = Topology Change Acknowledgment: {"Yes" if flags & 0x80 else "No"}', 'offset': offset + 4, 'length': 1},
                {'title': f'.{1 if flags & 0x40 else 0}.. .... = Agreement: {"Yes" if flags & 0x40 else "No"}', 'offset': offset + 4, 'length': 1},
                {'title': f'..{1 if flags & 0x20 else 0}. .... = Forwarding: {"Yes" if flags & 0x20 else "No"}', 'offset': offset + 4, 'length': 1},
                {'title': f'...{1 if flags & 0x10 else 0} .... = Learning: {"Yes" if flags & 0x10 else "No"}', 'offset': offset + 4, 'length': 1},
                {'title': f'.... {role_code:02b}.. = Port Role: {role_name} ({role_code})', 'offset': offset + 4, 'length': 1},
                {'title': f'.... ..{1 if flags & 0x02 else 0}. = Proposal: {"Yes" if flags & 0x02 else "No"}', 'offset': offset + 4, 'length': 1},
                {'title': f'.... ...{1 if flags & 0x01 else 0} = Topology Change: {"Yes" if flags & 0x01 else "No"}', 'offset': offset + 4, 'length': 1},
            ],
        },
        {
            'title': f'Root Identifier: {root_prio} / {root_vlan} / {root_mac}',
            'offset': offset + 5,
            'length': 8,
            'children': [
                {'title': f'Root Bridge Priority: {root_prio}', 'offset': offset + 5, 'length': 2},
                {'title': f'Root Bridge System ID Extension: {root_vlan}', 'offset': offset + 5, 'length': 2},
                {'title': f'Root Bridge System ID: {_mac_display(root_mac)}', 'offset': offset + 7, 'length': 6},
            ],
        },
        {'title': f'Root Path Cost: {path_cost}', 'offset': offset + 13, 'length': 4},
        {
            'title': f'Bridge Identifier: {bridge_prio} / {bridge_vlan} / {bridge_mac}',
            'offset': offset + 17,
            'length': 8,
            'children': [
                {'title': f'Bridge Priority: {bridge_prio}', 'offset': offset + 17, 'length': 2},
                {'title': f'Bridge System ID Extension: {bridge_vlan}', 'offset': offset + 17, 'length': 2},
                {'title': f'Bridge System ID: {_mac_display(bridge_mac)}', 'offset': offset + 19, 'length': 6},
            ],
        },
        {'title': f'Port identifier: 0x{port_id:04x}', 'offset': offset + 25, 'length': 2},
        {'title': f'Message Age: {int.from_bytes(payload[27:29], "big") // 256 if len(payload) >= 29 else 0}', 'offset': offset + 27, 'length': 2},
        {'title': f'Max Age: {int.from_bytes(payload[29:31], "big") // 256 if len(payload) >= 31 else 0}', 'offset': offset + 29, 'length': 2},
        {'title': f'Hello Time: {int.from_bytes(payload[31:33], "big") // 256 if len(payload) >= 33 else 0}', 'offset': offset + 31, 'length': 2},
        {'title': f'Forward Delay: {int.from_bytes(payload[33:35], "big") // 256 if len(payload) >= 35 else 0}', 'offset': offset + 33, 'length': 2},
        {'title': f'Version 1 Length: {version_1_len}', 'offset': offset + 35, 'length': 1},
    ]
    if len(payload) >= 42:
        pvid_type = int.from_bytes(payload[36:38], 'big')
        pvid_len = int.from_bytes(payload[38:40], 'big')
        pvid = int.from_bytes(payload[40:42], 'big')
        children.append({
            'title': f'Originating VLAN (PVID): {pvid}',
            'offset': offset + 36,
            'length': 6,
            'children': [
                {'title': f'Type: Originating VLAN (0x{pvid_type:04x})', 'offset': offset + 36, 'length': 2},
                {'title': f'Length: {pvid_len}', 'offset': offset + 38, 'length': 2},
                {'title': f'Originating VLAN: {pvid}', 'offset': offset + 40, 'length': 2},
            ],
        })
    return {
        'title': 'Spanning Tree Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _lldp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    def _tlv_bits(t: int, l: int) -> tuple[str, str]:
        return (f'{t:07b}'[:4] + ' ' + f'{t:07b}'[4:] + '. .... ....', '.... ...' + f'{l:09b}'[:1] + ' ' + f'{l:09b}'[1:5] + ' ' + f'{l:09b}'[5:])

    def _capability_lines(value: int, value_offset: int) -> List[Dict[str, Any]]:
        labels = [
            ('.... .... .... ...0', 'Other', 0x0001),
            ('.... .... .... ..0.', 'Repeater', 0x0002),
            ('.... .... .... .1..', 'Bridge', 0x0004),
            ('.... .... .... 0...', 'WLAN access point', 0x0008),
            ('.... .... ...0 ....', 'Router', 0x0010),
            ('.... .... ..0. ....', 'Telephone', 0x0020),
            ('.... .... .0.. ....', 'DOCSIS cable device', 0x0040),
            ('.... .... 0... ....', 'Station only', 0x0080),
            ('.... ...0 .... ....', 'C-VLAN component', 0x0100),
            ('.... ..0. .... ....', 'S-VLAN component', 0x0200),
            ('.... .0.. .... ....', 'TPMR component', 0x0400),
        ]
        lines = []
        for bits, label, mask in labels:
            capable = bool(value & mask)
            lines.append({
                'title': f'{bits} = {label}: {"Capable" if capable else "Not capable"}',
                'offset': value_offset,
                'length': 2,
            })
        return lines

    pos = 0
    children = []
    while pos + 2 <= len(payload):
        header = int.from_bytes(payload[pos:pos + 2], 'big')
        tlv_type = (header >> 9) & 0x7F
        tlv_len = header & 0x1FF
        value = payload[pos + 2:pos + 2 + tlv_len]
        if pos + 2 + tlv_len > len(payload):
            break
        type_bits, len_bits = _tlv_bits(tlv_type, tlv_len)
        if tlv_type == 1 and len(value) >= 7:
            subtype = int(value[0])
            chassis = ':'.join(f'{b:02x}' for b in value[1:7])
            children.append({
                'title': f'Chassis Subtype = MAC address, Id: {chassis}',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: Chassis Id (1)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': 'Chassis Id Subtype: MAC address (4)', 'offset': offset + pos + 2, 'length': 1},
                    {'title': f'Chassis Id: {_mac_display(chassis)}', 'offset': offset + pos + 3, 'length': 6},
                ],
            })
        elif tlv_type == 2 and len(value) >= 2:
            port = value[1:].decode(errors='ignore')
            children.append({
                'title': f'Port Subtype = Interface name, Id: {port}',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: Port Id (2)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': 'Port Id Subtype: Interface name (5)', 'offset': offset + pos + 2, 'length': 1},
                    {'title': f'Port Id: {port}', 'offset': offset + pos + 3, 'length': max(0, tlv_len - 1)},
                ],
            })
        elif tlv_type == 3 and len(value) >= 2:
            ttl = int.from_bytes(value[:2], 'big')
            children.append({
                'title': f'Time To Live = {ttl} sec',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': '[Normal LLDPDU]'},
                    {'title': f'{type_bits} = TLV Type: Time to Live (3)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'Seconds: {ttl}', 'offset': offset + pos + 2, 'length': 2},
                ],
            })
        elif tlv_type == 4:
            port_desc = value.decode(errors='ignore')
            children.append({
                'title': f'Port Description = {port_desc}',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: Port Description (4)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'Port Description: {port_desc}', 'offset': offset + pos + 2, 'length': tlv_len},
                ],
            })
        elif tlv_type == 5:
            sys_name = value.decode(errors='ignore')
            children.append({
                'title': f'System Name = {sys_name}',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: System Name (5)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'System Name: {sys_name}', 'offset': offset + pos + 2, 'length': tlv_len},
                ],
            })
        elif tlv_type == 6:
            desc = value.decode(errors='ignore')
            label = 'System Description'
            if len(desc) > 120:
                children.append({
                    'title': f'[…] {label} = {desc[:120]}',
                    'offset': offset + pos,
                    'length': 2 + tlv_len,
                    'children': [
                        {'title': f'{type_bits} = TLV Type: System Description (6)', 'offset': offset + pos, 'length': 2},
                        {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                        {'title': f'System Description […]: {desc[:120]}', 'offset': offset + pos + 2, 'length': tlv_len},
                    ],
                })
            else:
                children.append({
                    'title': f'{label} = {desc}',
                    'offset': offset + pos,
                    'length': 2 + tlv_len,
                    'children': [
                        {'title': f'{type_bits} = TLV Type: System Description (6)', 'offset': offset + pos, 'length': 2},
                        {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                        {'title': f'System Description: {desc}', 'offset': offset + pos + 2, 'length': tlv_len},
                    ],
                })
        elif tlv_type == 7 and len(value) >= 4:
            caps = int.from_bytes(value[:2], 'big')
            enabled = int.from_bytes(value[2:4], 'big')
            children.append({
                'title': 'Capabilities',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: System Capabilities (7)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'Capabilities: 0x{caps:04x}', 'offset': offset + pos + 2, 'length': 2, 'children': _capability_lines(caps, offset + pos + 2)},
                    {'title': f'Enabled Capabilities: 0x{enabled:04x}', 'offset': offset + pos + 4, 'length': 2, 'children': _capability_lines(enabled, offset + pos + 4)},
                ],
            })
        elif tlv_type == 8 and len(value) >= 1:
            addr_len = int(value[0])
            addr_subtype = int(value[1]) if len(value) >= 2 else 0
            addr_bytes = value[2:2 + max(0, addr_len - 1)]
            if addr_subtype == 1 and len(addr_bytes) == 4:
                mgmt_addr = '.'.join(str(int(b)) for b in addr_bytes)
            elif addr_subtype == 2 and len(addr_bytes) == 16:
                mgmt_addr = str(ipaddress.IPv6Address(addr_bytes))
            else:
                mgmt_addr = addr_bytes.hex()
            iface_subtype = int(value[2 + max(0, addr_len - 1)]) if len(value) > 2 + max(0, addr_len - 1) else 0
            iface_number_offset = 3 + max(0, addr_len - 1)
            iface_number = int.from_bytes(value[iface_number_offset:iface_number_offset + 4], 'big') if len(value) >= iface_number_offset + 4 else 0
            oid_len_offset = iface_number_offset + 4
            oid_len = int(value[oid_len_offset]) if len(value) > oid_len_offset else 0
            children.append({
                'title': 'Management Address',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: Management Address (8)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'Address String Length: {addr_len}', 'offset': offset + pos + 2, 'length': 1},
                    {'title': f'Address Subtype: {"IPv4 (1)" if addr_subtype == 1 else "IPv6 (2)" if addr_subtype == 2 else addr_subtype}', 'offset': offset + pos + 3, 'length': 1},
                    {'title': f'Management Address: {mgmt_addr}', 'offset': offset + pos + 4, 'length': max(0, addr_len - 1)},
                    {'title': f'Interface Subtype: {"System port number (3)" if iface_subtype == 3 else iface_subtype}', 'offset': offset + pos + 2 + iface_number_offset, 'length': 1},
                    {'title': f'Interface Number: {iface_number}', 'offset': offset + pos + 3 + iface_number_offset, 'length': 4},
                    {'title': f'OID String Length: {oid_len}', 'offset': offset + pos + 3 + oid_len_offset, 'length': 1},
                ],
            })
        elif tlv_type == 127 and len(value) >= 4:
            oui = ':'.join(f'{b:02x}' for b in value[:3])
            subtype = int(value[3])
            auto = int(value[4]) if len(value) >= 5 else 0
            pmd = int.from_bytes(value[5:7], 'big') if len(value) >= 7 else 0
            mau = int.from_bytes(value[7:9], 'big') if len(value) >= 9 else 0
            children.append({
                'title': 'Ieee 802.3 - MAC/PHY Configuration/Status',
                'offset': offset + pos,
                'length': 2 + tlv_len,
                'children': [
                    {'title': f'{type_bits} = TLV Type: Organization Specific (127)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: {tlv_len}', 'offset': offset + pos, 'length': 2},
                    {'title': f'Organization Unique Code: {oui} (Ieee 802.3)', 'offset': offset + pos + 2, 'length': 3},
                    {'title': f'IEEE 802.3 Subtype: MAC/PHY Configuration/Status (0x{subtype:02x})', 'offset': offset + pos + 5, 'length': 1},
                    {'title': f'Auto-Negotiation Support/Status: 0x{auto:02x}', 'offset': offset + pos + 6, 'length': 1, 'children': [
                        {'title': f'.... ...{1 if auto & 0x01 else 0} = Auto-Negotiation: Supported' if auto & 0x01 else '.... ...0 = Auto-Negotiation: Not supported', 'offset': offset + pos + 6, 'length': 1},
                        {'title': f'.... ..{1 if auto & 0x02 else 0}. = Auto-Negotiation: Enabled' if auto & 0x02 else '.... ..0. = Auto-Negotiation: Disabled', 'offset': offset + pos + 6, 'length': 1},
                    ]},
                    {'title': f'PMD Auto-Negotiation Advertised Capability: 0x{pmd:04x}', 'offset': offset + pos + 7, 'length': 2, 'children': [
                        {'title': '.... .... .... ...0 = 1000BASE-T (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... ..0. = 1000BASE-T (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... .0.. = 1000BASE-X (-LX, -SX, -CX full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... 0... = 1000BASE-X (-LX, -SX, -CX half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... ...0 .... = Asymmetric and Symmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... ..0. .... = Symmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .0.. .... = Asymmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... 0... .... = PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... ...0 .... .... = 100BASE-T2 (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... ..0. .... .... = 100BASE-T2 (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .0.. .... .... = 100BASE-TX (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... 0... .... .... = 100BASE-TX (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '...0 .... .... .... = 100BASE-T4: Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '..0. .... .... .... = 10BASE-T (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.0.. .... .... .... = 10BASE-T (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '1... .... .... .... = Other or unknown: Capable' if pmd & 0x8000 else '1... .... .... .... = Other or unknown: Not capable', 'offset': offset + pos + 7, 'length': 2},
                    ]},
                    {'title': 'Same in inverse (wrong) bitorder', 'offset': offset + pos + 7, 'length': 2, 'children': [
                        {'title': '1... .... .... .... = 1000BASE-T (full duplex mode): Capable' if pmd & 0x8000 else '1... .... .... .... = 1000BASE-T (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.0.. .... .... .... = 1000BASE-T (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '..0. .... .... .... = 1000BASE-X (-LX, -SX, -CX full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '...0 .... .... .... = 1000BASE-X (-LX, -SX, -CX half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... 0... .... .... = Asymmetric and Symmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .0.. .... .... = Symmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... ..0. .... .... = Asymmetric PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... ...0 .... .... = PAUSE (for full-duplex links): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... 0... .... = 100BASE-T2 (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .0.. .... = 100BASE-T2 (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... ..0. .... = 100BASE-TX (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... ...0 .... = 100BASE-TX (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... 0... = 100BASE-T4: Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... .0.. = 10BASE-T (full duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... ..0. = 10BASE-T (half duplex mode): Not capable', 'offset': offset + pos + 7, 'length': 2},
                        {'title': '.... .... .... ...0 = Other or unknown: Not capable', 'offset': offset + pos + 7, 'length': 2},
                    ]},
                    {'title': f'Operational MAU Type: other or unknown (0x{mau:04x})', 'offset': offset + pos + 9, 'length': 2},
                ],
            })
        elif tlv_type == 0:
            children.append({
                'title': 'End of LLDPDU',
                'offset': offset + pos,
                'length': 2,
                'children': [
                    {'title': f'{type_bits} = TLV Type: End of LLDPDU (0)', 'offset': offset + pos, 'length': 2},
                    {'title': f'{len_bits} = TLV Length: 0', 'offset': offset + pos, 'length': 2},
                ],
            })
        if tlv_type == 0:
            break
        pos += 2 + tlv_len
    return {
        'title': 'Link Layer Discovery Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _udld_tlv_name(tlv_type: int) -> str:
    return {
        0x0001: 'Device ID',
        0x0002: 'Port ID',
        0x0003: 'Echo',
        0x0004: 'Message interval',
        0x0005: 'Timeout interval',
        0x0006: 'Device name',
        0x0007: 'Sequence number',
    }.get(tlv_type, f'0x{tlv_type:04x}')


def _udld_section(payload: bytes, offset: int) -> Dict[str, Any]:
    version = (int(payload[0]) >> 5) & 0x07 if len(payload) >= 1 else 0
    opcode = int(payload[0]) & 0x1F if len(payload) >= 1 else 0
    opcode_bits = f'{opcode:05b}'
    flags = int(payload[1]) if len(payload) >= 2 else 0
    checksum = int.from_bytes(payload[2:4], 'big') if len(payload) >= 4 else 0
    children = [
        {'title': f'{version:03b}. .... = Version: {version}', 'offset': offset, 'length': 1},
        {'title': f'...{opcode_bits[0]} {opcode_bits[1:]} = Opcode: {"Probe" if opcode == 1 else opcode} ({opcode})', 'offset': offset, 'length': 1},
        {
            'title': f'Flags: {flags}',
            'offset': offset + 1,
            'length': 1,
            'children': [
                {'title': f'.... ...{flags & 0x01} = Recommended timeout: 0x{flags & 0x01:x}', 'offset': offset + 1, 'length': 1},
                {'title': f'.... ..{1 if flags & 0x02 else 0}. = ReSynch: 0x{1 if flags & 0x02 else 0:x}', 'offset': offset + 1, 'length': 1},
            ],
        },
        {'title': f'Checksum: 0x{checksum:04x}', 'offset': offset + 2, 'length': 2},
    ]
    pos = 4
    while pos + 4 <= len(payload):
        tlv_type = int.from_bytes(payload[pos:pos + 2], 'big')
        tlv_len = int.from_bytes(payload[pos + 2:pos + 4], 'big')
        if tlv_len < 4 or pos + tlv_len > len(payload):
            break
        value = payload[pos + 4:pos + tlv_len]
        tlv_name = _udld_tlv_name(tlv_type)
        if tlv_type == 0x0001:
            text = value.decode(errors='ignore')
            title = f'Device ID: {text}'
            value_title = f'Device ID: {text}'
        elif tlv_type == 0x0002:
            text = value.decode(errors='ignore')
            title = f'Port ID: {text}'
            value_title = f'Sent through Interface: {text}'
        elif tlv_type in {0x0003, 0x0004, 0x0005, 0x0006, 0x0007}:
            title = f'Type: {tlv_name}, length: {tlv_len}'
            value_title = f'Data: {value.hex()}'
        else:
            title = f'Type: {tlv_name}, length: {tlv_len}'
            value_title = f'Data: {value.hex()}'
        children.append({
            'title': title,
            'offset': offset + pos,
            'length': tlv_len,
            'children': [
                {'title': f'Type: {tlv_name} (0x{tlv_type:04x})', 'offset': offset + pos, 'length': 2},
                {'title': f'Length: {tlv_len}', 'offset': offset + pos + 2, 'length': 2},
                {'title': value_title, 'offset': offset + pos + 4, 'length': tlv_len - 4},
            ],
        })
        pos += tlv_len
    return {
        'title': 'Unidirectional Link Detection',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _homeplug_mmtype_label(mmtype: int) -> str:
    return {
        0xA068: 'OP_ATTR.REQ (Get Device Attributes Request)',
        0xA000: 'GET_SW.REQ (Get Device/SW Version Request)',
    }.get(int(mmtype), f'0x{int(mmtype) & 0xFFFF:04x}')


def _homeplug_av_section(payload: bytes, offset: int) -> Dict[str, Any]:
    children: List[Dict[str, Any]] = []
    if len(payload) >= 3:
        version = int(payload[0]) & 0x01
        mmtype = int.from_bytes(payload[1:3], 'little')
        lsb = mmtype & 0x3
        msb = (mmtype >> 13) & 0x7
        children.append({
            'title': 'MAC Management Header',
            **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'.... ...{version} = Version: 1.0 ({version})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
                {
                    'title': f'Type: {_homeplug_mmtype_label(mmtype)} (0x{mmtype:04x})',
                    **_byte_mapping(offset, 1, 2, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'.... ..{lsb:02b} = LSB: {"Request" if lsb == 0 else lsb} (0x{lsb:x})', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'{msb:03b}. .... = MSB: {"Vendor Specific" if msb == 5 else msb} (0x{msb:x})', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
                    ],
                },
            ],
        })
    if len(payload) >= 6:
        oui_bytes = bytes(payload[3:6])
        oui_text = {b'\x00\xb0\x52': 'Qualcomm Atheros'}.get(oui_bytes, oui_bytes.hex())
        children.append({
            'title': 'Vendor MME',
            **_byte_mapping(offset, 3, 3, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'OUI: {oui_text} (0x{oui_bytes.hex()})', **_byte_mapping(offset, 3, 3, PACKET_BYTE_SOURCE)},
            ],
        })
    if len(payload) >= 11 and int.from_bytes(payload[1:3], 'little') == 0xA068:
        cookie = int.from_bytes(payload[6:10], 'little')
        report_type = int(payload[10])
        report_name = 'Binary' if report_type == 0 else str(report_type)
        children.append({
            'title': 'Get Device Attributes Request',
            **_byte_mapping(offset, 6, 5, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'Cookie: {cookie}', **_byte_mapping(offset, 6, 4, PACKET_BYTE_SOURCE)},
                {'title': f'Report Type: {report_name} (0x{report_type:02x})', **_byte_mapping(offset, 10, 1, PACKET_BYTE_SOURCE)},
            ],
        })
    return {
        'title': 'HomePlug AV protocol',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _rsh_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    direction = 'Data'
    packet = getattr(record, 'raw', None) if record is not None else None
    if packet is not None:
        tcp_layer = _effective_tcp_layer(packet)
        if tcp_layer is not None:
            sport = int(getattr(tcp_layer, 'sport', 0) or 0)
            dport = int(getattr(tcp_layer, 'dport', 0) or 0)
            if dport == 514:
                direction = 'Client -> Server Data'
            elif sport == 514:
                direction = 'Server -> Client Data'
    return {
        'title': 'Remote Shell',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'{direction}: {payload.hex()}', **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE)},
        ],
    }


def _zabbix_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    raw_payload = bytes(payload or b'')
    zabbix_body = bytes(metadata.get('zabbix_body', b'') or b'')
    if not raw_payload.startswith(b'ZBXD') and zabbix_body:
        flags = int(metadata.get('zabbix_flags', 0) or 0)
        length = int(metadata.get('zabbix_length', len(zabbix_body)) or len(zabbix_body))
        aux = int(metadata.get('zabbix_aux', 0) or 0)
        raw_payload = b'ZBXD' + bytes([flags & 0xFF]) + int(length).to_bytes(4, 'little') + int(aux).to_bytes(4, 'little') + zabbix_body

    if len(raw_payload) < 13 or not raw_payload.startswith(b'ZBXD'):
        return {
            'title': 'Zabbix Protocol',
            **_byte_mapping(offset, 0, len(raw_payload), PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'Data ({len(raw_payload)} bytes)', **_byte_mapping(offset, 0, len(raw_payload), PACKET_BYTE_SOURCE)},
            ],
        }

    flags = int(raw_payload[4])
    length = int.from_bytes(raw_payload[5:9], 'little')
    aux = int.from_bytes(raw_payload[9:13], 'little')
    body_start = 13
    body_end = min(len(raw_payload), body_start + max(0, length))
    body = raw_payload[body_start:body_end]

    uncompressed = bytes(metadata.get('zabbix_uncompressed_body', b'') or b'')
    if not uncompressed:
        uncompressed = body

    json_text = str(metadata.get('zabbix_json_text', '') or '')
    if not json_text and uncompressed:
        json_text = uncompressed.decode(errors='ignore')

    json_obj = None
    if json_text:
        try:
            json_obj = json.loads(json_text)
        except Exception:
            json_obj = None

    request_name = str(metadata.get('zabbix_request', '') or '')
    response_name = str(metadata.get('zabbix_response', '') or '')
    host_name = str(metadata.get('zabbix_host', '') or '')
    session = str(metadata.get('zabbix_session', '') or '')
    version = str(metadata.get('zabbix_version', '') or '')
    if isinstance(json_obj, dict):
        request_name = request_name or str(json_obj.get('request', '') or '')
        response_name = response_name or str(json_obj.get('response', '') or '')
        host_name = host_name or str(json_obj.get('host', '') or '')
        session = session or str(json_obj.get('session', '') or '')
        version = version or str(json_obj.get('version', '') or '')
        if not host_name:
            data_items = list(json_obj.get('data', []) or [])
            if data_items and isinstance(data_items[0], dict):
                host_name = str(data_items[0].get('host', '') or '')

    def _fmt_response_time(ms: float) -> str:
        value = max(0.0, float(ms))
        if value < 1.0:
            return f'{value * 1000.0:.3f} microseconds'
        return f'{value:.3f} milliseconds'

    flags_tokens: List[str] = []
    if flags & 0x02:
        flags_tokens.append('Compressed')
    if flags & 0x01:
        flags_tokens.append('Zabbix communications protocol')
    flags_text = ', '.join(flags_tokens) if flags_tokens else '0'

    children: List[Dict[str, Any]] = [
        {'title': 'Header: ZBXD', **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)},
        {
            'title': f'Flags: 0x{flags:02x}, {flags_text}',
            **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'{(flags >> 3) & 0x1F:05b} ... = Reserved bits: {(flags >> 3) & 0x1F}', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.... .{1 if (flags & 0x04) else 0}.. = Large packet: {"Yes" if (flags & 0x04) else "No"}', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.... ..{1 if (flags & 0x02) else 0}. = Compressed: {"Yes" if (flags & 0x02) else "No"}', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.... ...{1 if (flags & 0x01) else 0} = Zabbix communications protocol: {"Yes" if (flags & 0x01) else "No"}', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
            ],
        },
        {'title': f'Length: {length}', **_byte_mapping(offset, 5, 4, PACKET_BYTE_SOURCE)},
    ]

    if flags & 0x02:
        children.append({'title': f'Uncompressed length: {aux}', **_byte_mapping(offset, 9, 4, PACKET_BYTE_SOURCE)})
    else:
        children.append({'title': f'Reserved: {aux}', **_byte_mapping(offset, 9, 4, PACKET_BYTE_SOURCE)})

    request_lower = request_name.lower()
    is_agent_connection = request_lower in {'agent data', 'active checks', 'active check heartbeat'} or (host_name and 'proxy' not in request_lower)
    is_proxy_connection = request_lower in {'proxy data', 'proxy config'} or (session and version and not request_name)

    if is_agent_connection:
        children.append({'title': '[This is an agent connection]'})
    elif is_proxy_connection:
        children.append({'title': '[This is a proxy connection]'})

    if request_lower == 'agent data':
        children.append({'title': 'Zabbix agent data: Yes'})
        if host_name:
            children.append({'title': f'Agent name: {host_name}'})
        if session:
            children.append({'title': f'Session: {session}'})
    elif request_lower == 'active check heartbeat':
        children.append({'title': 'Agent heartbeat: Yes'})
        if host_name:
            children.append({'title': f'Agent name: {host_name}'})
        if isinstance(json_obj, dict) and 'heartbeat_freq' in json_obj:
            children.append({'title': f'Agent heartbeat frequency: {int(json_obj.get("heartbeat_freq", 0) or 0)}'})
    elif request_lower == 'active checks':
        children.append({'title': 'Zabbix agent config: Yes'})
        if host_name:
            children.append({'title': f'Agent name: {host_name}'})
    elif request_lower == 'proxy data':
        children.append({'title': 'Proxy data: Yes'})
    elif request_lower == 'proxy config':
        pass
    elif session and version and not request_name and not response_name:
        children.append({'title': 'Proxy data: Yes'})
        children.append({'title': f'Version: {version}'})
        children.append({'title': f'Session: {session}'})

    if response_name:
        children.append({'title': f'Success: {"Yes" if response_name.lower() == "success" else response_name}'})
        request_agent = str(metadata.get('zabbix_request_agent_name', '') or '')
        if request_agent:
            children.append({'title': f'[Agent name: {request_agent} (from the request)]'})
        if version and request_lower != 'proxy config':
            children.append({'title': f'Version: {version}'})
        if request_lower in {'proxy data', 'proxy config'} or (not request_name and not host_name):
            children.append({'title': 'Proxy data: Yes'})

    data_source = ZABBIX_UNCOMPRESSED_BYTE_SOURCE if (flags & 0x02) else PACKET_BYTE_SOURCE
    data_offset = 0 if data_source == ZABBIX_UNCOMPRESSED_BYTE_SOURCE else body_start
    data_len = len(uncompressed) if data_source == ZABBIX_UNCOMPRESSED_BYTE_SOURCE else len(body)
    if data_len > 0:
        children.append({'title': f'Data: {json_text if json_text else body.hex()}', **_byte_mapping(offset, data_offset, data_len, data_source)})

    if request_name:
        children.append({'title': 'This is Zabbix request'})
    elif response_name or (session and version):
        children.append({'title': 'This is Zabbix response'})

    response_ms = metadata.get('zabbix_time_since_request_ms', None)
    if response_ms is not None:
        try:
            children.append({'title': f'[Response time: {_fmt_response_time(float(response_ms))}]'})
        except Exception:
            pass

    return {
        'title': str(getattr(record, 'info', '') or 'Zabbix Protocol'),
        **_byte_mapping(offset, 0, len(raw_payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _hsrpv2_section(payload: bytes, offset: int) -> Dict[str, Any]:
    children = []
    if len(payload) >= 6 and int(payload[0]) == 2 and int(payload[1]) == 4:
        active_groups = int.from_bytes(payload[2:4], 'big')
        passive_groups = int.from_bytes(payload[4:6], 'big')
        children.append({
            'title': 'Interface State TLV: Type=2 Len=4',
            **_byte_mapping(offset, 0, 6, PACKET_BYTE_SOURCE),
            'children': [
                {'title': 'Type: Interface State (2)', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
                {'title': 'Length: 4', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Active Groups: {active_groups}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Passive Groups: {passive_groups}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
            ],
        })
    if len(payload) >= 42:
        tlv_type = int(payload[0])
        tlv_len = int(payload[1])
        version = int(payload[2])
        opcode = int(payload[3])
        state = int(payload[4])
        group = int.from_bytes(payload[6:8], 'big')
        identifier = ':'.join(f'{b:02x}' for b in payload[8:14])
        priority = int.from_bytes(payload[14:18], 'big')
        hellotime = int.from_bytes(payload[18:22], 'big')
        holdtime = int.from_bytes(payload[22:26], 'big')
        ip_version = int(payload[5]) if len(payload) >= 6 else 0
        state_name = {1: 'Initial', 2: 'Learn', 3: 'Listen', 4: 'Speak', 5: 'Standby', 6: 'Active'}.get(state, str(state))
        vip_title = ''
        vip_offset = offset + 26
        vip_length = 16
        if ip_version == 4 and len(payload) >= 30:
            vip_title = f'Virtual IP Address: {_ipv4_text(payload[26:30])}'
            vip_length = 4
        else:
            vip_title = f'Virtual IPv6 Address: {str(ipaddress.IPv6Address(payload[26:42])) if len(payload) >= 42 else ""}'
        children.append({
            'title': f'Group State TLV: Type={tlv_type} Len={tlv_len}',
            **_byte_mapping(offset, 0, min(42, len(payload)), PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'Type: {tlv_type}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Length: {tlv_len}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Version: {version}', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Op Code: {"Hello" if opcode == 0 else opcode} ({opcode})', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
                {'title': f'State: {state_name} ({state})', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'IP Ver.: {"IPv4" if ip_version == 4 else "IPv6"} ({ip_version})', **_byte_mapping(offset, 5, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Group: {group}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Identifier: {_mac_display(identifier)}', **_byte_mapping(offset, 8, 6, PACKET_BYTE_SOURCE)},
                {'title': f'Priority: {priority}', **_byte_mapping(offset, 14, 4, PACKET_BYTE_SOURCE)},
                {'title': f'Hellotime: Default ({hellotime})', **_byte_mapping(offset, 18, 4, PACKET_BYTE_SOURCE)},
                {'title': f'Holdtime: Default ({holdtime})', **_byte_mapping(offset, 22, 4, PACKET_BYTE_SOURCE)},
                {'title': vip_title, 'offset': vip_offset, 'length': vip_length},
            ],
        })
    if len(payload) >= 68:
        auth_type = int(payload[42])
        auth_len = int(payload[43])
        sender_ip = '.'.join(str(int(b)) for b in payload[48:52])
        children.append({
            'title': f'MD5 Authentication TLV: Type={auth_type} Len={auth_len}',
            **_byte_mapping(offset, 42, min(30, len(payload) - 42), PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'Type: {auth_type}', **_byte_mapping(offset, 42, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Length: {auth_len}', **_byte_mapping(offset, 43, 1, PACKET_BYTE_SOURCE)},
                {'title': 'MD5 Algorithm: MD5 (1)', **_byte_mapping(offset, 44, 1, PACKET_BYTE_SOURCE)},
                {'title': 'Padding: 0x00', **_byte_mapping(offset, 45, 1, PACKET_BYTE_SOURCE)},
                {'title': f"MD5 Flags: {int.from_bytes(payload[46:48], 'big') if len(payload) >= 48 else 0}", **_byte_mapping(offset, 46, 2, PACKET_BYTE_SOURCE)},
                {'title': f"Sender's IP Address: {sender_ip}", **_byte_mapping(offset, 48, 4, PACKET_BYTE_SOURCE)},
                {'title': f"MD5 Key ID: {int.from_bytes(payload[52:56], 'big') if len(payload) >= 56 else 0}", **_byte_mapping(offset, 52, 4, PACKET_BYTE_SOURCE)},
                {'title': f"MD5 Authentication Data: {payload[56:72].hex()}", **_byte_mapping(offset, 56, min(16, max(0, len(payload) - 56)), PACKET_BYTE_SOURCE)},
            ],
        })
    return {
        'title': 'Cisco Hot Standby Router Protocol',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _hsrp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) >= 1 and int(payload[0]) == 0:
        opcode = int(payload[1]) if len(payload) >= 2 else 0
        if opcode == 3 and len(payload) >= 16:
            state = int(payload[6])
            state_name = {0: 'Initial', 1: 'Learn', 2: 'Passive', 3: 'Active', 4: 'Speak', 8: 'Standby', 16: 'Active'}.get(state, str(state))
            adv_type = int(payload[3])
            adv_len = int(payload[5])
            return {
                'title': 'Cisco Hot Standby Router Protocol',
                **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'Version: {int(payload[0])}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Op Code: Advertise ({opcode})', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv type: HSRP interface state ({adv_type})', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv length: {adv_len}', **_byte_mapping(offset, 5, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv state: {state_name} ({state})', **_byte_mapping(offset, 6, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv reserved1: {int(payload[7])}', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv active groups: {int.from_bytes(payload[8:10], "big")}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv passive groups: {int.from_bytes(payload[10:12], "big")}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                    {'title': f'Adv reserved2: {int.from_bytes(payload[12:16], "big")}', **_byte_mapping(offset, 12, 4, PACKET_BYTE_SOURCE)},
                ],
            }
        if len(payload) >= 20:
            opcode_name = {0: 'Hello', 1: 'Coup', 2: 'Resign'}.get(opcode, str(opcode))
            state = int(payload[2])
            state_name = {0: 'Initial', 1: 'Learn', 2: 'Listen', 4: 'Speak', 8: 'Standby', 16: 'Active'}.get(state, str(state))
            return {
                'title': 'Cisco Hot Standby Router Protocol',
                **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'Version: {int(payload[0])}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Op Code: {opcode_name} ({opcode})', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'State: {state_name} ({state})', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Hellotime: Default ({int(payload[3])})', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Holdtime: Default ({int(payload[4])})', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Priority: {int(payload[5])}', **_byte_mapping(offset, 5, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Group: {int(payload[6])}', **_byte_mapping(offset, 6, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Reserved: {int(payload[7])}', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Authentication Data: Default ({bytes(payload[8:16]).decode(errors="ignore").rstrip(chr(0))})', **_byte_mapping(offset, 8, 8, PACKET_BYTE_SOURCE)},
                    {'title': f'Virtual IP Address: {_ipv4_text(payload[16:20])}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
                ],
            }
    return _hsrpv2_section(payload, offset)

def _ip_section(layer, offset: int, stream_index: int, record=None) -> Dict[str, Any]:

    version = int(getattr(layer, 'version', 4) or 4)
    ihl = int(getattr(layer, 'ihl', 5) or 5)

    tos = int(getattr(layer, 'tos', 0) or 0)

    total_len = int(getattr(layer, 'len', 0) or 0)

    identification = int(getattr(layer, 'id', 0) or 0)

    frag = int(getattr(layer, 'frag', 0) or 0)

    ttl = int(getattr(layer, 'ttl', 0) or 0)

    proto_num = int(getattr(layer, 'proto', 0) or 0)

    checksum = int(getattr(layer, 'chksum', 0) or 0)

    src = getattr(layer, 'src', '-')
    dst = getattr(layer, 'dst', '-')

    ip_header_len = ihl * 4

    # ---- DSCP / ECN ----

    dscp = tos >> 2
    ecn = tos & 0x03

    dscp_names = {
        0: 'Default',
        8: 'CS1',
        16: 'CS2',
        24: 'CS3',
        32: 'CS4',
        40: 'CS5',
        48: 'CS6',
        56: 'CS7',
        46: 'EF',
    }

    dscp_name = dscp_names.get(dscp, str(dscp))

    ecn_names = {
        0: 'Not ECN-Capable Transport',
        1: 'ECT(1)',
        2: 'ECT(0)',
        3: 'Congestion Experienced',
    }

    ecn_name = ecn_names.get(ecn, str(ecn))

    # ---- FLAGS ----

    flags = int(getattr(layer, 'flags', 0) or 0)

    reserved = (flags & 0x4) >> 2
    df = (flags & 0x2) >> 1
    mf = flags & 0x1

    # ---- PROTOCOL ----

    proto_names = {
        1: 'ICMP',
        6: 'TCP',
        17: 'UDP',
        89: 'OSPF IGP',
        115: 'Layer 2 Tunneling',
        58: 'ICMPv6',
    }

    proto_name = proto_names.get(proto_num, str(proto_num))

    # ---- FRAGMENT FIELD ----

    frag_field = ((flags << 13) | frag) & 0xFFFF

    frag_bits = format(frag_field, '016b')

    frag_bits_pretty = (
        f'...{frag_bits[3]} '
        f'{frag_bits[4:8]} '
        f'{frag_bits[8:12]} '
        f'{frag_bits[12:16]}'
    )

    flags_bits = f'{reserved}{df}{mf}'

    children = [

        {
            'title':
                f'{version:04b} .... = Version: {version}',

            'offset': offset,
            'length': 1,
        },

        {
            'title':
                f'.... {ihl:04b} = Header Length: '
                f'{ip_header_len} bytes ({ihl})',

            'offset': offset,
            'length': 1,
        },

        {
            'title':
                f'Differentiated Services Field: '
                f'0x{tos:02x} '
                f'(DSCP: {dscp_name}, ECN: {ecn_name})',

            'offset': offset + 1,
            'length': 1,

            'children': [

                {
                    'title':
                        f'{format(dscp, "06b")} .. = '
                        f'Differentiated Services Codepoint: '
                        f'{dscp_name} ({dscp})',

                    'offset': offset + 1,
                    'length': 1,
                },

                {
                    'title':
                        f'.... ..{ecn:02b} = '
                        f'Explicit Congestion Notification: '
                        f'{ecn_name} ({ecn})',

                    'offset': offset + 1,
                    'length': 1,
                }
            ]
        },

        {
            'title':
                f'Total Length: {total_len}',

            'offset': offset + 2,
            'length': 2,
        },

        {
            'title':
                f'Identification: '
                f'0x{identification:04x} '
                f'({identification})',

            'offset': offset + 4,
            'length': 2,
        },

        {
            'title':
                    f'{flags_bits}. .... = Flags: 0x{flags:x}',
                'offset': offset + 6,
                'length': 1,
                'children': [
                    {
                        'title':
                            f'{reserved}... .... = '
                            f'Reserved bit: '
                            f'{"Set" if reserved else "Not set"}',
                        'offset': offset + 6,
                        'length': 1,
                    },
                    {
                        'title':
                            f'.{df}.. .... = '
                            f'Don\'t fragment: '
                            f'{"Set" if df else "Not set"}',
                        'offset': offset + 6,
                        'length': 1,
                    },
                    {
                        'title':
                            f'..{mf}. .... = '
                            f'More fragments: '
                            f'{"Set" if mf else "Not set"}',
                        'offset': offset + 6,
                        'length': 1,
                    }
                ]
        },

        {
            'title':
                f'{frag_bits_pretty} = '
                f'Fragment Offset: {frag * 8}',

            'offset': offset + 6,
            'length': 2,
        },

        {
            'title':
                f'Time to Live: {ttl}',

            'offset': offset + 8,
            'length': 1,
            'children': [
                {
                    'title': '[Expert Info (Note/Sequence): "Time To Live" only 1]',
                    'children': [
                        {'title': '["Time To Live" only 1]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ] if int(ttl) == 1 else [],
        },

        {
            'title':
                f'Protocol: {proto_name} ({proto_num})',

            'offset': offset + 9,
            'length': 1,
        },

        {
            'title':
                f'Header Checksum: '
                f'0x{checksum:04x} '
                f'[validation disabled]',

            'offset': offset + 10,
            'length': 2,
        },

        {
            'title':
                '[Header checksum status: Unverified]',
        },

        {
            'title':
                f'Source Address: {src}',

            'offset': offset + 12,
            'length': 4,
        },

        {
            'title':
                f'Destination Address: {dst}',

            'offset': offset + 16,
            'length': 4,
        },
    ]

    metadata = getattr(record, 'metadata', {}) if record else {}

    if stream_index >= 0:
        children.append({
            'title': f'[Stream index: {stream_index}]',
        })

    if bool(metadata.get('ip_is_fragmented', False)) and int(metadata.get('ip_fragment_version', 0) or 0) == 4:
        reassembled_in = metadata.get('ip_reassembled_in_frame', None)
        if reassembled_in is not None:
            try:
                children.append({'title': f'[Reassembled IPv4 in frame: {int(reassembled_in)}]'})
            except Exception:
                pass
        ip_reassembly = _ip_reassembly_section(metadata, 4)
        if ip_reassembly is not None:
            children.append(ip_reassembly)

    return {
        'title':
            f'Internet Protocol Version 4, '
            f'Src: {src}, '
            f'Dst: {dst}',

        'offset': offset,
        'length': ip_header_len,
        'children': children,
    }

def _ipv6_multicast_scope_name(scope: int) -> str:
    return {
        0: 'Reserved scope',
        1: 'Interface-Local scope',
        2: 'Link-Local scope',
        3: 'Realm-Local scope',
        4: 'Admin-Local scope',
        5: 'Site-Local scope',
        8: 'Organization-Local scope',
        14: 'Global scope',
    }.get(int(scope), f'Scope {int(scope)}')


def _ipv6_address_children(address: str, offset: int, is_source: bool) -> List[Dict[str, Any]]:
    addr_text = str(address or '')
    lower = addr_text.lower()
    try:
        packed = ipaddress.IPv6Address(addr_text).packed
    except Exception:
        packed = b'\x00' * 16

    if addr_text == '::':
        return [
            {'title': '[Address Space: Reserved by IETF]', 'offset': offset, 'length': 16},
            {
                'title': '[Special-Purpose Allocation: Unspecified Address]',
                'offset': offset,
                'length': 16,
                'children': [
                    {'title': f'[Source: {"True" if is_source else "False"}]', 'offset': offset, 'length': 16},
                    {'title': f'[Destination: {"False" if is_source else "True"}]', 'offset': offset, 'length': 16},
                    {'title': '[Forwardable: False]', 'offset': offset, 'length': 16},
                    {'title': '[Globally Reachable: False]', 'offset': offset, 'length': 16},
                    {'title': '[Reserved-by-Protocol: True]', 'offset': offset, 'length': 16},
                ],
            },
        ]

    if lower.startswith('ff'):
        flags = (packed[1] >> 4) & 0x0F
        scope = packed[1] & 0x0F
        return [
            {'title': '[Address Space: Multicast]', 'offset': offset, 'length': 16},
            {
                'title': f'[.... .... {flags:04b} .... = Multicast Flags: 0x{flags:x}]',
                'offset': offset + 1,
                'length': 1,
                'children': [
                    {'title': f'.... .... {(flags >> 3) & 0x1}... .... = Reserved: {(flags >> 3) & 0x1}', 'offset': offset + 1, 'length': 1},
                    {'title': f'.... .... .{(flags >> 2) & 0x1}.. .... = Rendezvous Point (RP): {"True" if ((flags >> 2) & 0x1) else "False"}', 'offset': offset + 1, 'length': 1},
                    {'title': f'.... .... ..{(flags >> 1) & 0x1}. .... = Network Prefix: {"True" if ((flags >> 1) & 0x1) else "False"}', 'offset': offset + 1, 'length': 1},
                    {'title': f'.... .... ...{flags & 0x1} .... = Transient: {"True" if (flags & 0x1) else "False"}', 'offset': offset + 1, 'length': 1},
                ],
            },
            {
                'title': f'[.... .... .... {scope:04b} = Multicast Scope: {_ipv6_multicast_scope_name(scope)} (0x{scope:x})]',
                'offset': offset + 1,
                'length': 1,
            },
        ]

    if lower.startswith('fe80'):
        return [
            {'title': '[Address Space: Link-Local Unicast]', 'offset': offset, 'length': 16},
            {
                'title': '[Special-Purpose Allocation: Link-Local Unicast]',
                'offset': offset,
                'length': 16,
                'children': [
                    {'title': '[Source: True]', 'offset': offset, 'length': 16},
                    {'title': '[Destination: True]', 'offset': offset, 'length': 16},
                    {'title': '[Forwardable: False]', 'offset': offset, 'length': 16},
                    {'title': '[Globally Reachable: False]', 'offset': offset, 'length': 16},
                    {'title': '[Reserved-by-Protocol: True]', 'offset': offset, 'length': 16},
                ],
            },
        ]

    if lower.startswith('fc') or lower.startswith('fd'):
        return [
            {'title': '[Address Space: Unique Local Unicast]', 'offset': offset, 'length': 16},
            {
                'title': '[Special-Purpose Allocation: Unique-Local]',
                'offset': offset,
                'length': 16,
                'children': [
                    {'title': '[Source: True]', 'offset': offset, 'length': 16},
                    {'title': '[Destination: True]', 'offset': offset, 'length': 16},
                    {'title': '[Forwardable: True]', 'offset': offset, 'length': 16},
                    {'title': '[Reserved-by-Protocol: False]', 'offset': offset, 'length': 16},
                ],
            },
        ]

    return [{'title': '[Address Space: Global Unicast]', 'offset': offset, 'length': 16}]


def _ipv6_section(layer, offset: int, stream_index: int, record=None) -> Dict[str, Any]:

    version = int(getattr(layer, 'version', 6) or 6)

    tc = int(getattr(layer, 'tc', 0) or 0)

    fl = int(getattr(layer, 'fl', 0) or 0)

    plen = int(getattr(layer, 'plen', 0) or 0)

    nh = int(getattr(layer, 'nh', 0) or 0)

    hlim = int(getattr(layer, 'hlim', 0) or 0)

    src = getattr(layer, 'src', '-')

    dst = getattr(layer, 'dst', '-')

    dscp = tc >> 2

    ecn = tc & 0x03

    dscp_names = {
        0: 'CS0',
        10: 'AF11',
        12: 'AF12',
        14: 'AF13',
        46: 'EF',
    }

    ecn_names = {
        0: 'Not-ECT',
        1: 'ECT(1)',
        2: 'ECT(0)',
        3: 'CE',
    }

    dscp_name = dscp_names.get(dscp, str(dscp))

    ecn_name = ecn_names.get(ecn, str(ecn))

    next_header_names = {
        0: 'IPv6 Hop-by-Hop Option',
        44: 'Fragment Header for IPv6',
        6: 'TCP',
        17: 'UDP',
        58: 'ICMPv6',
    }

    nh_name = next_header_names.get(nh, str(nh))

    children = [

        {
            'title':
                f'0110 .... = Version: {version}',
            'offset': offset,
            'length': 1,
        },

        {
            'title':
                f'.... {format(tc, "08b")} '
                f'.... .... .... .... .... = '
                f'Traffic Class: '
                f'0x{tc:02x} '
                f'(DSCP: {dscp_name}, ECN: {ecn_name})',
            'offset': offset,
            'length': 2,

            'children': [

                {
                    'title':
                        f'.... {format(dscp, "06b")}.. '
                        f'.... .... .... .... .... = '
                        f'Differentiated Services Codepoint: '
                        f'{dscp_name} ({dscp})',
                    'offset': offset,
                    'length': 2,
                },

                {
                    'title':
                        f'.... .... ..{ecn:02b} '
                        f'.... .... .... .... .... = '
                        f'Explicit Congestion Notification: '
                        f'{ecn_name} ({ecn})',
                    'offset': offset,
                    'length': 2,
                }
            ]
        },

        {
            'title':
                f'.... {format(fl, "020b")} = '
                f'Flow Label: 0x{fl:05x}',
            'offset': offset + 1,
            'length': 3,
        },

        {
            'title':
                f'Payload Length: {plen}',
            'offset': offset + 4,
            'length': 2,
        },

        {
            'title':
                f'Next Header: {nh_name} ({nh})',
            'offset': offset + 6,
            'length': 1,
        },

        {
            'title':
                f'Hop Limit: {hlim}',
            'offset': offset + 7,
            'length': 1,
        },

        {
            'title':
                f'Source Address: {src}',
            'offset': offset + 8,
            'length': 16,

            'children': _ipv6_address_children(src, offset + 8, True),
        },

        {
            'title':
                f'Destination Address: {dst}',
            'offset': offset + 24,
            'length': 16,

            'children': _ipv6_address_children(dst, offset + 24, False),
        },
    ]

    source_slaac_mac = _ipv6_slaac_mac(src)
    destination_slaac_mac = _ipv6_slaac_mac(dst)
    if source_slaac_mac:
        children.append({'title': f'[Source SLAAC MAC: {_mac_display(source_slaac_mac)}]', 'offset': offset + 8, 'length': 16})
    if destination_slaac_mac:
        children.append({'title': f'[Destination SLAAC MAC: {_mac_display(destination_slaac_mac)}]', 'offset': offset + 24, 'length': 16})

    metadata = getattr(record, 'metadata', {}) if record else {}

    if stream_index >= 0:
        children.append({
            'title': f'[Stream index: {stream_index}]'
        })

    if bool(metadata.get('ip_is_fragmented', False)) and int(metadata.get('ip_fragment_version', 0) or 0) == 6:
        reassembled_in = metadata.get('ip_reassembled_in_frame', None)
        if reassembled_in is not None:
            try:
                children.append({'title': f'[Reassembled IPv6 in frame: {int(reassembled_in)}]'})
            except Exception:
                pass
        ip_reassembly = _ip_reassembly_section(metadata, 6)
        if ip_reassembly is not None:
            children.append(ip_reassembly)

    return {

        'title':
            f'Internet Protocol Version 6, '
            f'Src: {src}, Dst: {dst}',

        'offset': offset,
        'length': 40,
        'children': children,
    }

def _tcp_option_length(option) -> int:
    try:
        name, value = option
    except Exception:
        return 1

    if name == 'MSS':
        return 4
    if name == 'NOP':
        return 1
    if name == 'WScale':
        return 3
    if name == 'SAckOK':
        return 2
    if name == 'EOL':
        return 1
    if isinstance(value, (bytes, bytearray)):
        return 2 + len(value)
    return 1


def _tcp_section(layer, offset: int, stream_index: int, record=None) -> Dict[str, Any]:

    sport = int(getattr(layer, 'sport', 0) or 0)
    dport = int(getattr(layer, 'dport', 0) or 0)

    seq = int(getattr(layer, 'seq', 0) or 0)
    ack = int(getattr(layer, 'ack', 0) or 0)

    metadata = getattr(record, 'metadata', {}) if record else {}
    stream_pkt_num = int(metadata.get('tcp_stream_packet_number', 1) or 1)
    relative_seq = int(metadata['tcp_relative_seq']) if 'tcp_relative_seq' in metadata else 1
    relative_ack = int(metadata.get('tcp_relative_ack', 0) or 0)
    options = getattr(layer, 'options', [])

    dataofs = int(getattr(layer, 'dataofs', 5) or 5)

    tcp_header_len = max(dataofs * 4, 20 + sum(_tcp_option_length(option) for option in options))

    window = int(getattr(layer, 'window', 0) or 0)

    checksum = int(getattr(layer, 'chksum', 0) or 0)

    urgptr = int(getattr(layer, 'urgptr', 0) or 0)

    payload = _tcp_payload_bytes(getattr(record, 'raw', None), layer)
    payload_len = len(payload)

    payload_hex = payload.hex()

    # ---- FLAGS ----

    flags = int(getattr(layer, 'flags', 0) or 0)

    flag_bits = {
        'FIN': flags & 0x01,
        'SYN': (flags >> 1) & 0x01,
        'RST': (flags >> 2) & 0x01,
        'PSH': (flags >> 3) & 0x01,
        'ACK': (flags >> 4) & 0x01,
        'URG': (flags >> 5) & 0x01,
        'ECE': (flags >> 6) & 0x01,
        'CWR': (flags >> 7) & 0x01,
    }

    set_flags = [
        name for name, value in flag_bits.items()
        if value
    ]

    flags_text = ', '.join(set_flags) if set_flags else 'None'

    next_seq_fallback = relative_seq + payload_len + (1 if flag_bits['SYN'] else 0) + (1 if flag_bits['FIN'] else 0)
    next_seq = int(metadata.get('tcp_next_seq', next_seq_fallback) or next_seq_fallback)

    stream_completeness = int(metadata.get('tcp_completeness_flags', 0) or 0)
    completeness_rst = 32 if (stream_completeness & 32) else 0
    completeness_fin = 16 if (stream_completeness & 16) else 0
    completeness_data = 8 if (stream_completeness & 8) else 0
    completeness_ack = 4 if (stream_completeness & 4) else 0
    completeness_synack = 2 if (stream_completeness & 2) else 0
    completeness_syn = 1 if (stream_completeness & 1) else 0
    completeness_flags = (
        completeness_rst
        + completeness_fin
        + completeness_data
        + completeness_ack
        + completeness_synack
        + completeness_syn
    )

    completeness_label = f'Incomplete ({completeness_flags})'
    if completeness_flags == 63:
        completeness_label = 'Complete (63)'
    elif completeness_flags == 31:
        completeness_label = 'Complete, WITH_DATA (31)'
    elif completeness_flags == 15:
        completeness_label = 'Incomplete, DATA (15)'

    completeness_marks = ''.join([
        'R' if completeness_rst else '·',
        'F' if completeness_fin else '·',
        'D' if completeness_data else '·',
        'A' if completeness_ack else '·',
        'S' if completeness_synack else '·',
        'S' if completeness_syn else '·',
    ])

    tcp_flag_marks = ''.join([
        '·',  # Reserved
        '·',  # Reserved
        '·',  # Reserved
        '·',  # Accurate ECN
        'C' if flag_bits['CWR'] else '·',
        'E' if flag_bits['ECE'] else '·',
        'U' if flag_bits['URG'] else '·',
        'A' if flag_bits['ACK'] else '·',
        'P' if flag_bits['PSH'] else '·',
        'R' if flag_bits['RST'] else '·',
        'S' if flag_bits['SYN'] else '·',
        'F' if flag_bits['FIN'] else '·',
    ])

    tcp_time_since_first = float(metadata.get('tcp_time_since_first', 0.0) or 0.0)
    tcp_time_since_prev = float(metadata.get('tcp_time_since_prev', 0.0) or 0.0)
    client_contiguous = int(metadata.get('tcp_client_contiguous_streams', 0) or 0)
    server_contiguous = int(metadata.get('tcp_server_contiguous_streams', 0) or 0)

    ack_frame_number = metadata.get('tcp_ack_frame_number', None)
    ack_rtt_ms = metadata.get('tcp_ack_rtt_ms', None)
    irtt_ms = metadata.get('tcp_i_rtt_ms', None)
    ack_ambiguous = bool(metadata.get('tcp_ack_ambiguous', False))
    duplicate_ack = bool(metadata.get('tcp_is_duplicate_ack', False))
    duplicate_ack_count = metadata.get('tcp_duplicate_ack_count', None)
    duplicate_ack_frame_number = metadata.get('tcp_duplicate_ack_frame_number', None)
    window_update = bool(metadata.get('tcp_is_window_update', False))
    window_full = bool(metadata.get('tcp_is_window_full', False))
    keep_alive = bool(metadata.get('tcp_is_keep_alive', False))
    keep_alive_ack = bool(metadata.get('tcp_is_keep_alive_ack', False))
    previous_segment_not_captured = bool(metadata.get('tcp_previous_segment_not_captured', False))
    port_numbers_reused = bool(metadata.get('tcp_port_numbers_reused', False))
    bytes_in_flight = metadata.get('tcp_bytes_in_flight', None)
    bytes_since_last_psh = metadata.get('tcp_bytes_since_last_psh', None)
    is_retransmission = bool(metadata.get('tcp_is_retransmission', False))
    is_spurious_retransmission = bool(metadata.get('tcp_is_spurious_retransmission', False))
    protocol_name = str(getattr(record, 'protocol', '') or '').upper() if record else ''
    has_ack_flag = bool(flag_bits['ACK'])
    is_syn_packet = bool(flag_bits['SYN'])
    window_scale_shift = metadata.get('tcp_window_scale_shift', None)
    window_scaling_disabled = bool(metadata.get('tcp_window_scaling_disabled', False))
    calculated_window = int(window)
    window_scale_title = '[Window size scaling factor: -1 (unknown)]'
    if is_syn_packet:
        window_scale_title = ''
    elif window_scale_shift is not None:
        multiplier = 1 << int(window_scale_shift)
        calculated_window = int(window) * multiplier
        window_scale_title = f'[Window size scaling factor: {multiplier}]'
    elif window_scaling_disabled:
        window_scale_title = '[Window size scaling factor: -2 (no window scaling used)]'

    children = [

        {
            'title': f'Source Port: {sport}',
            'offset': offset,
            'length': 2,
        },

        {
            'title': f'Destination Port: {dport}',
            'offset': offset + 2,
            'length': 2,
        },

        {
            'title': f'Sequence Number: {relative_seq}    (relative sequence number)',
            'offset': offset + 4,
            'length': 4,
        },

        {
            'title': f'Sequence Number (raw): {seq}',
            'offset': offset + 4,
            'length': 4,
        },

        {
            'title': f'Acknowledgment Number: {relative_ack}    (relative ack number)' if has_ack_flag else f'Acknowledgment Number: {ack}',
            'offset': offset + 8,
            'length': 4,
        },

        {
            'title': f'Acknowledgment number (raw): {ack}',
            'offset': offset + 8,
            'length': 4,
        },

        {
            'title':
                f'{dataofs:04b} .... = '
                f'Header Length: {tcp_header_len} bytes ({dataofs})',

            'offset': offset + 12,
            'length': 1,
        },

        {
            'title':
                f'Flags: 0x{flags:03x} ({flags_text})',
            'offset': offset + 12,
            'length': 2,
            'children': [
                {
                    'title': '000. .... .... = Reserved: Not set',
                    'offset': offset + 12,
                    'length': 1,
                },
                {
                    'title': '...0 .... .... = Accurate ECN: Not set',
                    'offset': offset + 12,
                    'length': 1,
                },
                {
                    'title':
                        f'.... {"1" if flag_bits["CWR"] else "0"}... .... = '
                        f'Congestion Window Reduced: '
                        f'{"Set" if flag_bits["CWR"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... .{"1" if flag_bits["ECE"] else "0"}.. .... = '
                        f'ECN-Echo: '
                        f'{"Set" if flag_bits["ECE"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... ..{"1" if flag_bits["URG"] else "0"}. .... = '
                        f'Urgent: '
                        f'{"Set" if flag_bits["URG"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... ...{"1" if flag_bits["ACK"] else "0"} .... = '
                        f'Acknowledgment: '
                        f'{"Set" if flag_bits["ACK"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... .... {"1" if flag_bits["PSH"] else "0"}... = '
                        f'Push: '
                        f'{"Set" if flag_bits["PSH"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... .... .{"1" if flag_bits["RST"] else "0"}.. = '
                        f'Reset: '
                        f'{"Set" if flag_bits["RST"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                },
                {
                    'title':
                        f'.... .... ..{"1" if flag_bits["SYN"] else "0"}. = '
                        f'Syn: '
                        f'{"Set" if flag_bits["SYN"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                    'children': [
                        {
                            'title': f'[Expert Info (Chat/Sequence): Connection establish request (SYN): server port {dport}]',
                            'children': [
                                {'title': f'[Connection establish request (SYN): server port {dport}]'},
                                {'title': '[Severity level: Chat]'},
                                {'title': '[Group: Sequence]'},
                            ],
                        }
                    ] if bool(flag_bits["SYN"]) and not bool(flag_bits["ACK"]) else [],
                },
                {
                    'title':
                        f'.... .... ...{"1" if flag_bits["FIN"] else "0"} = '
                        f'Fin: '
                        f'{"Set" if flag_bits["FIN"] else "Not set"}',
                    'offset': offset + 13,
                    'length': 1,
                    'children': [
                        {
                            'title': '[Expert Info (Chat/Sequence): Connection finish (FIN)]',
                            'children': [
                                {'title': '[Connection finish (FIN)]'},
                                {'title': '[Severity level: Chat]'},
                                {'title': '[Group: Sequence]'},
                            ],
                        },
                    ] if bool(flag_bits["FIN"]) else [],
                },
                {
                    'title': f'[TCP Flags: {tcp_flag_marks}]',
                    'children': (
                        [
                            {
                                'title': '[Expert Info (Note/Sequence): This frame initiates the connection closing]',
                                'children': [
                                    {'title': '[This frame initiates the connection closing]'},
                                    {'title': '[Severity level: Note]'},
                                    {'title': '[Group: Sequence]'},
                                ],
                            }
                        ]
                        if bool(flag_bits["FIN"]) and bool(flag_bits["ACK"]) and not bool(flag_bits["RST"])
                        else []
                    ),
                },
            ]
        },

        {
            'title': f'Window: {window}',
            'offset': offset + 14,
            'length': 2,
        },

        {
            'title': f'[Calculated window size: {calculated_window}]',
        },

        {
            'title': window_scale_title,
        },

        {
            'title':
                f'Checksum: 0x{checksum:04x} [unverified]',

            'offset': offset + 16,
            'length': 2,
        },

        {
            'title':
                '[Checksum Status: Unverified]',
        },

        {
            'title':
                f'Urgent Pointer: {urgptr}',

            'offset': offset + 18,
            'length': 2,
        },
    ]

    stream_intro = []
    if stream_index >= 0:
        stream_intro.extend([
            {
                'title': f'[Stream index: {stream_index}]',
            },
            {
                'title': f'[Stream Packet Number: {stream_pkt_num}]',
            },
            {
                'title': f'[Conversation completeness: {completeness_label}]',
                'children': [
                    {
                        'title': f'..{"1" if completeness_rst else "0"}. .... = RST: {"Present" if completeness_rst else "Absent"}',
                    },
                    {
                        'title': f'...{"1" if completeness_fin else "0"} .... = FIN: {"Present" if completeness_fin else "Absent"}',
                    },
                    {
                        'title': f'.... {"1" if completeness_data else "0"}... = Data: {"Present" if completeness_data else "Absent"}',
                    },
                    {
                        'title': f'.... .{"1" if completeness_ack else "0"}.. = ACK: {"Present" if completeness_ack else "Absent"}',
                    },
                    {
                        'title': f'.... ..{"1" if completeness_synack else "0"}. = SYN-ACK: {"Present" if completeness_synack else "Absent"}',
                    },
                    {
                        'title': f'.... ...{"1" if completeness_syn else "0"} = SYN: {"Present" if completeness_syn else "Absent"}',
                    },
                    {
                        'title': f'[Completeness Flags: {completeness_marks}]',
                    },
                ],
            },
        ])

    ordered_children = []
    ordered_children.extend(children[:2])
    ordered_children.extend(stream_intro)
    ordered_children.append({
        'title': '[TCP Segment Len: ' f'{payload_len}]',
    })
    ordered_children.extend([
        children[2],
        children[3],
        {'title': f'[Next Sequence Number: {next_seq}    (relative sequence number)]'},
        children[4],
        children[5],
        children[6],
        children[7],
        children[8],
        children[9],
    ])
    if children[10].get('title'):
        ordered_children.append(children[10])
    ordered_children.extend([
        children[11],
        children[12],
        children[13],
    ])
    ordered_children.append({
        'title': '[Timestamps]',
        'children': [
            {
                'title': f'[Time since first frame in this TCP stream: {tcp_time_since_first:.9f} seconds]',
            },
            {
                'title': f'[Time since previous frame in this TCP stream: {tcp_time_since_prev:.9f} seconds]',
            },
        ],
    })
    seq_ack_children = []
    if port_numbers_reused:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Note/Sequence): A new tcp session is started with the same ports as an earlier session in this trace]',
                    'children': [
                        {'title': '[A new tcp session is started with the same ports as an earlier session in this trace]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })
    elif is_retransmission:
        tcp_analysis_children = []
        if is_spurious_retransmission:
            tcp_analysis_children.append(
                {
                    'title': '[Expert Info (Note/Sequence): This frame is a (suspected) spurious retransmission]',
                    'children': [
                        {'title': '[This frame is a (suspected) spurious retransmission]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                }
            )
        tcp_analysis_children.append(
            {
                'title': '[Expert Info (Note/Sequence): This frame is a (suspected) retransmission]',
                'children': [
                    {'title': '[This frame is a (suspected) retransmission]'},
                    {'title': '[Severity level: Note]'},
                    {'title': '[Group: Sequence]'},
                ],
            }
        )
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': tcp_analysis_children,
        })
    elif keep_alive_ack:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Note/Sequence): ACK to a TCP keep-alive segment]',
                    'children': [
                        {'title': '[ACK to a TCP keep-alive segment]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })
    elif duplicate_ack:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[This is a TCP duplicate ack]',
                },
            ],
        })
        if duplicate_ack_count is not None:
            seq_ack_children.append({
                'title': f'[Duplicate ACK #: {int(duplicate_ack_count)}]',
            })
        if duplicate_ack_frame_number is not None:
            seq_ack_children.append({
                'title': f'[Duplicate to the ACK in frame: {int(duplicate_ack_frame_number)}]',
                'children': [
                    {
                        'title': f'[Expert Info (Note/Sequence): Duplicate ACK (#{int(duplicate_ack_count or 1)})]',
                        'children': [
                            {'title': f'[Duplicate ACK (#{int(duplicate_ack_count or 1)})]'},
                            {'title': '[Severity level: Note]'},
                            {'title': '[Group: Sequence]'},
                        ],
                    },
                ],
            })
    elif window_update:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Chat/Sequence): TCP window update]',
                    'children': [
                        {'title': '[TCP window update]'},
                        {'title': '[Severity level: Chat]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })
    elif keep_alive:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Note/Sequence): TCP keep-alive segment]',
                    'children': [
                        {'title': '[TCP keep-alive segment]'},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })
    if ack_frame_number is not None:
        ack_child = {
            'title': f'[This is an ACK to the segment in frame: {int(ack_frame_number)}]',
        }
        if ack_ambiguous:
            ack_child['children'] = [
                {
                    'title': "[Expert Info (Note/Sequence): Ambiguous ACK following Karn's definition]",
                    'children': [
                        {"title": "[Ambiguous ACK following Karn's definition]"},
                        {'title': '[Severity level: Note]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ]
        seq_ack_children.append(ack_child)
    if ack_rtt_ms is not None:
        seq_ack_children.append({
            'title': f'[The RTT to ACK the segment was: {float(ack_rtt_ms):.6f} milliseconds]',
        })
    if irtt_ms is not None:
        seq_ack_children.append({
            'title': f'[iRTT: {float(irtt_ms):.6f} milliseconds]',
        })
    if previous_segment_not_captured:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Warning/Sequence): Previous segment(s) not captured (common at capture start)]',
                    'children': [
                        {'title': '[Previous segment(s) not captured (common at capture start)]'},
                        {'title': '[Severity level: Warning]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })
    if bytes_in_flight is not None:
        seq_ack_children.append({
            'title': f'[Bytes in flight: {int(bytes_in_flight)}]',
        })
    if bytes_since_last_psh is not None:
        seq_ack_children.append({
            'title': f'[Bytes sent since last PSH flag: {int(bytes_since_last_psh)}]',
        })
    if window_full:
        seq_ack_children.append({
            'title': '[TCP Analysis Flags]',
            'children': [
                {
                    'title': '[Expert Info (Warning/Sequence): TCP window specified by the receiver is now completely full]',
                    'children': [
                        {'title': '[TCP window specified by the receiver is now completely full]'},
                        {'title': '[Severity level: Warning]'},
                        {'title': '[Group: Sequence]'},
                    ],
                },
            ],
        })

    if seq_ack_children:
        ordered_children.append({
            'title': '[SEQ/ACK analysis]',
            'children': seq_ack_children,
        })
    ordered_children.append({
        'title': f'[Client Contiguous Streams: {client_contiguous}]',
    })
    ordered_children.append({
        'title': f'[Server Contiguous Streams: {server_contiguous}]',
    })

    children = ordered_children

    # ---- TCP OPTIONS ----

    if options:
        option_children = []
        option_titles = []
        option_offset = offset + 20
        sack_permitted_present = False
        for opt in options:
            try:
                name, value = opt
                # MSS
                if name == 'MSS':
                    option_titles.append('Maximum segment size')
                    option_children.append({
                        'title': f'TCP Option - Maximum segment size: {int(value)} bytes',
                        'offset': option_offset,
                        'length': 4,
                        'children': [
                            {'title': 'Kind: Maximum Segment Size (2)', 'offset': option_offset, 'length': 1},
                            {'title': 'Length: 4', 'offset': option_offset + 1, 'length': 1},
                            {'title': f'MSS Value: {int(value)}', 'offset': option_offset + 2, 'length': 2},
                        ],
                    })
                    option_offset += 4
                # NOP
                elif name == 'NOP':
                    option_titles.append('No-Operation (NOP)')
                    option_children.append({
                        'title': 'TCP Option - No-Operation (NOP)',
                        'offset': option_offset,
                        'length': 1,
                        'children': [
                            {'title': 'Kind: No-Operation (1)', 'offset': option_offset, 'length': 1},
                        ],
                    })
                    option_offset += 1
                # Window Scale
                elif name == 'WScale':
                    multiplier = 1 << int(value)
                    option_titles.append('Window scale')
                    option_children.append({
                        'title': f'TCP Option - Window scale: {int(value)} (multiply by {multiplier})',
                        'offset': option_offset,
                        'length': 3,
                        'children': [
                            {'title': 'Kind: Window Scale (3)', 'offset': option_offset, 'length': 1},
                            {'title': 'Length: 3', 'offset': option_offset + 1, 'length': 1},
                            {'title': f'Shift count: {int(value)}', 'offset': option_offset + 2, 'length': 1},
                            {'title': f'[Multiplier: {multiplier}]'},
                        ],
                    })
                    option_offset += 3
                # SACK Permitted
                elif name == 'SAckOK':
                    sack_permitted_present = True
                    option_titles.append('SACK permitted')
                    option_children.append({
                        'title': 'TCP Option - SACK permitted',
                        'offset': option_offset,
                        'length': 2,
                        'children': [
                            {'title': 'Kind: SACK Permitted (4)', 'offset': option_offset, 'length': 1},
                            {'title': 'Length: 2', 'offset': option_offset + 1, 'length': 1},
                        ],
                    })
                    option_offset += 2
                # SACK
                elif name == 'SAck':
                    # value is a list of (left, right) edges
                    option_titles.append('SACK')
                    sack_blocks = []
                    for i, (left, right) in enumerate(value):
                        sack_blocks.append({
                            'title': f'SACK Block {i+1}: Left Edge={left}, Right Edge={right}',
                            'length': 8
                        })
                    option_children.append({
                        'title': f'TCP Option - SACK ({len(value)} blocks)',
                        'offset': option_offset,
                        'length': 2 + 8 * len(value),
                        'children': [
                            {'title': 'Kind: SACK (5)', 'offset': option_offset, 'length': 1},
                            {'title': f'Length: {2 + 8 * len(value)}', 'offset': option_offset + 1, 'length': 1},
                            *sack_blocks
                        ],
                    })
                    option_offset += 2 + 8 * len(value)
                # Timestamp
                elif name == 'Timestamp':
                    option_titles.append('Timestamp')
                    tsval, tsecr = value
                    option_children.append({
                        'title': f'TCP Option - Timestamp: TSval={tsval}, TSecr={tsecr}',
                        'offset': option_offset,
                        'length': 10,
                        'children': [
                            {'title': 'Kind: Timestamp (8)', 'offset': option_offset, 'length': 1},
                            {'title': 'Length: 10', 'offset': option_offset + 1, 'length': 1},
                            {'title': f'TSval: {tsval}', 'offset': option_offset + 2, 'length': 4},
                            {'title': f'TSecr: {tsecr}', 'offset': option_offset + 6, 'length': 4},
                        ],
                    })
                    option_offset += 10
                # End of Option List
                elif name == 'EOL':
                    option_titles.append('End of Option List')
                    option_children.append({
                        'title': 'TCP Option - End of Option List',
                        'offset': option_offset,
                        'length': 1,
                        'children': [
                            {'title': 'Kind: End of Option List (0)', 'offset': option_offset, 'length': 1},
                        ],
                    })
                    option_offset += 1
                # Fast Open
                elif name == 'TFO':
                    option_titles.append('TCP Fast Open')
                    option_children.append({
                        'title': f'TCP Option - Fast Open: {value.hex() if isinstance(value, (bytes, bytearray)) else value}',
                        'offset': option_offset,
                        'length': 2 + len(value),
                        'children': [
                            {'title': 'Kind: Fast Open (34)', 'offset': option_offset, 'length': 1},
                            {'title': f'Length: {2 + len(value)}', 'offset': option_offset + 1, 'length': 1},
                            {'title': f'Data: {value.hex() if isinstance(value, (bytes, bytearray)) else value}', 'offset': option_offset + 2, 'length': len(value)},
                        ],
                    })
                    option_offset += 2 + len(value)
                # Unknown/Other
                else:
                    # Try to show as hex if possible
                    try:
                        raw = bytes(value) if isinstance(value, (bytes, bytearray)) else value
                        hexval = raw.hex() if isinstance(raw, (bytes, bytearray)) else str(raw)
                    except Exception:
                        hexval = str(value)
                    option_titles.append(str(name))
                    option_children.append({
                        'title': f'TCP Option - {name}: {hexval}',
                        'offset': option_offset,
                        'length': 2 + (len(raw) if isinstance(raw, (bytes, bytearray)) else 0),
                        'children': [
                            {'title': f'Kind: {name}', 'offset': option_offset, 'length': 1},
                            {'title': f'Length: {2 + (len(raw) if isinstance(raw, (bytes, bytearray)) else 0)}', 'offset': option_offset + 1, 'length': 1},
                            {'title': f'Data: {hexval}', 'offset': option_offset + 2, 'length': len(raw) if isinstance(raw, (bytes, bytearray)) else 0},
                        ],
                    })
                    option_offset += 2 + (len(raw) if isinstance(raw, (bytes, bytearray)) else 0)
            except Exception:
                option_titles.append(str(opt))
                option_children.append({'title': str(opt)})
        children.append({
            'title': f'Options: ({max(0, tcp_header_len - 20)} bytes), ' + ', '.join(option_titles) if option_titles else 'Options',
            'offset': offset + 20,
            'length': max(0, tcp_header_len - 20),
            'children': option_children
        })
        if flag_bits['SYN'] and not sack_permitted_present:
            children.append({
                'title': '[Expert Info (Note/Sequence): The SYN packet does not contain a SACK PERM option]',
                'children': [
                    {'title': '[The SYN packet does not contain a SACK PERM option]'},
                    {'title': '[Severity level: Note]'},
                    {'title': '[Group: Sequence]'},
                ],
            })

    # ---- PAYLOAD ----

    if payload_len > 0:
        children.append({
            'title': f'TCP payload ({payload_len} bytes)',
            'offset': offset + tcp_header_len,
            'length': payload_len,
        })
        if is_retransmission:
            children.append({
                'title': f'Retransmitted TCP segment data ({payload_len} bytes)',
                'offset': offset + tcp_header_len,
                'length': payload_len,
            })
        elif metadata.get('tcp_reassembled_pdu_in_frame', None) is not None or metadata.get('tls_reassembled_pdu_in_frame', None) is not None:
            _pdu_frame = metadata.get('tcp_reassembled_pdu_in_frame') or metadata.get('tls_reassembled_pdu_in_frame')
            children.append({
                'title': f'[Reassembled PDU in frame: {int(_pdu_frame)}]',
            })
            # Only map the bytes this frame actually contributes to the reassembled PDU.
            _seg_data_len = int(metadata.get('tls_segment_data_length') or metadata.get('tcp_segment_data_length') or payload_len)
            _seg_data_off = int(metadata.get('tls_segment_data_offset') or metadata.get('tcp_segment_data_offset') or 0)
            _seg_data_off = max(0, min(_seg_data_off, payload_len))
            _seg_data_len = max(0, min(_seg_data_len, payload_len - _seg_data_off))
            children.append({
                'title': f'TCP segment data ({_seg_data_len} bytes)',
                'offset': offset + tcp_header_len + _seg_data_off,
                'length': _seg_data_len,
            })
        elif metadata.get('tcp_reassembled_segments', None) or metadata.get('http_reassembled_segments', None) or metadata.get('tls_reassembled_segments', None):
            # For the completing frame, map only this frame's contribution.
            _frame_no = int(metadata.get('frame_number', 0) or 0)
            _all_segs = (
                metadata.get('tls_reassembled_segments')
                or metadata.get('http_reassembled_segments')
                or metadata.get('tcp_reassembled_segments')
                or []
            )
            _seg_match = None
            for _seg in _all_segs:
                if int(_seg.get('frame_number', 0) or 0) == _frame_no:
                    _seg_match = _seg
                    break
            if _seg_match is None and _all_segs:
                _seg_match = _all_segs[-1]
            _seg_data_len = int((_seg_match or {}).get('payload_length', payload_len))
            _seg_data_off = int((_seg_match or {}).get('tcp_start_offset_in_payload', 0))
            _seg_data_off = max(0, min(_seg_data_off, payload_len))
            _seg_data_len = max(0, min(_seg_data_len, payload_len - _seg_data_off))
            children.append({
                'title': f'TCP segment data ({_seg_data_len} bytes)',
                'offset': offset + tcp_header_len + _seg_data_off,
                'length': _seg_data_len,
            })
        elif protocol_name == 'BGP':
            children.append({
                'title': f'[PDU Size: {payload_len}]',
            })

    tcp_title = (
        f'Transmission Control Protocol, '
        f'Src Port: {sport}, '
        f'Dst Port: {dport}, '
        f'Seq: {relative_seq}, '
        + (f'Ack: {relative_ack}, ' if has_ack_flag else '')
        + f'Len: {payload_len}'
    )

    return {

        'title': tcp_title,

        'offset': offset,
        'length': tcp_header_len,
        'children': children,
    }


def _tcp_reassembly_section(record) -> Dict[str, Any] | None:
    metadata = getattr(record, 'metadata', {}) or {}
    protocol_name = str(getattr(record, 'protocol', '') or '')
    if protocol_name in {'TLS', 'TLSv1.0', 'TLSv1.1', 'TLSv1.2', 'TLSv1.3', 'SSL'}:
        return None
    segments = list(
        metadata.get('tcp_reassembled_segments', [])
        or metadata.get('http_reassembled_segments', [])
        or metadata.get('tls_reassembled_segments', [])
        or []
    )
    if not segments:
        return None

    reassembled_len = int(
        metadata.get('tcp_reassembled_length', 0)
        or metadata.get('http_reassembled_length', 0)
        or metadata.get('tls_reassembled_length', 0)
        or 0
    )
    if reassembled_len <= 0:
        reassembled_len = int(sum(int(segment.get('payload_length', 0) or 0) for segment in segments))

    segment_summary = ', '.join(
        f"#{int(segment.get('frame_number', 0) or 0)}({int(segment.get('payload_length', 0) or 0)})"
        for segment in segments
    )
    children = []
    for segment in segments:
        start_pos = int(segment.get('payload_start', 0) or 0)
        seg_len = int(segment.get('payload_length', 0) or 0)
        end_pos = max(start_pos, start_pos + seg_len - 1)
        children.append({
            'title': f"[Frame: {int(segment.get('frame_number', 0) or 0)}, payload: {start_pos}-{end_pos} ({seg_len} bytes)]",
            **_byte_mapping(0, start_pos, seg_len, TCP_REASSEMBLED_BYTE_SOURCE),
        })
    children.append({'title': f'[Segment count: {len(segments)}]'})
    children.append({
        'title': f'[Reassembled TCP length: {reassembled_len}]',
        **_byte_mapping(0, 0, reassembled_len, TCP_REASSEMBLED_BYTE_SOURCE),
    })

    reassembly_hex = str(metadata.get('tcp_reassembled_data_hex', '') or '')
    if not reassembly_hex:
        reassembly_payload = bytes(
            metadata.get('http_reassembled_payload', b'')
            or metadata.get('tls_reassembled_payload', b'')
            or b''
        )
        reassembly_hex = reassembly_payload.hex() if reassembly_payload else ''
    if reassembly_hex:
        children.append({
            'title': f'[Reassembled TCP Data […]: {reassembly_hex[:160]}]',
            **_byte_mapping(0, 0, reassembled_len, TCP_REASSEMBLED_BYTE_SOURCE),
        })

    return {
        'title': f'[{len(segments)} Reassembled TCP Segments ({reassembled_len} bytes): {segment_summary}]',
        **_byte_mapping(0, 0, reassembled_len, TCP_REASSEMBLED_BYTE_SOURCE),
        'children': children,
    }


def _http_payload_lines(payload: bytes) -> List[tuple[str, int, int, bytes]]:
    lines = []
    pos = 0
    while pos < len(payload):
        end = payload.find(b'\r\n', pos)
        if end == -1:
            raw_line = payload[pos:]
            lines.append((raw_line.decode(errors='ignore'), pos, len(raw_line), raw_line))
            break
        raw_line = payload[pos:end]
        total_len = (end + 2) - pos
        lines.append((raw_line.decode(errors='ignore') + '\\r\\n', pos, total_len, raw_line))
        pos = end + 2
        if raw_line == b'':
            break
    return lines


def _http_body_lines(payload: bytes) -> List[str]:
    if not payload:
        return []
    body_lines = []
    for raw_line in payload.splitlines(keepends=True):
        text = raw_line.decode(errors='ignore')
        text = text.replace('\t', '\\t').replace('\r', '\\r').replace('\n', '\\n')
        body_lines.append(text)
    return body_lines


def _http_status_description(code: str) -> str:
    return {
        '200': 'OK',
        '301': 'Moved Permanently',
        '302': 'Found',
        '400': 'Bad Request',
        '404': 'Not Found',
        '500': 'Internal Server Error',
    }.get(str(code), '')


def _http_preliminary_section(record, offset: int) -> Dict[str, Any] | None:
    metadata = getattr(record, 'metadata', {}) if record else {}
    prelim_payload = bytes(metadata.get('http_preliminary_payload', b'') or b'')
    prelim_len = int(metadata.get('http_preliminary_length', 0) or 0)
    if not prelim_payload or prelim_len <= 0:
        return None
    use_offsets = not bool(metadata.get('http_is_reassembled', False))
    byte_source = PACKET_BYTE_SOURCE if use_offsets else TCP_REASSEMBLED_BYTE_SOURCE
    lines = _http_payload_lines(prelim_payload)
    children: List[Dict[str, Any]] = []

    def _map(rel: int, length: int) -> Dict[str, Any]:
        return _byte_mapping(offset, int(rel), int(max(1, length)), byte_source)

    if lines:
        first_text, first_offset, first_length, first_raw = lines[0]
        first_line = first_raw.decode(errors='ignore')
        parts = first_line.split(' ', 2) if first_line.startswith('HTTP/') else []
        response_children: List[Dict[str, Any]] = []
        if len(parts) >= 2:
            version = parts[0]
            status_code = parts[1]
            reason = parts[2] if len(parts) > 2 else ''
            response_children.append({'title': f'Response Version: {version}', **_map(first_offset, len(version))})
            response_children.append({'title': f'Status Code: {status_code}', **_map(first_offset + len(version) + 1, len(status_code))})
            description = _http_status_description(status_code)
            if description:
                response_children.append({'title': f'[Status Code Description: {description}]'})
            if reason:
                response_children.append({'title': f'Response Phrase: {reason}', **_map(first_offset + len(version) + 1 + len(status_code) + 1, len(reason))})
        children.append({'title': first_text, **_map(first_offset, first_length), 'children': response_children})
        for line_text, line_offset, line_length, line_raw in lines[1:]:
            title = line_text if line_raw != b'' else '\\r\\n'
            children.append({'title': title, **_map(line_offset, line_length)})

    request_frame = metadata.get('http_request_frame', None)
    if request_frame is not None:
        children.append({'title': f'[Request in frame: {int(request_frame)}]'})
    time_since_request = metadata.get('http_time_since_request_ms', None)
    if time_since_request is not None:
        children.append({'title': f'[Time since request: {float(time_since_request):.6f} milliseconds]'})
    request_uri = str(metadata.get('http_request_uri', '') or '').strip()
    if request_uri:
        children.append({'title': f'[Request URI: {request_uri}]'})
    full_request_uri = metadata.get('http_full_request_uri', '')
    if full_request_uri:
        children.append({'title': f'[Full request URI: {full_request_uri}]'})

    title = 'Real Time Streaming Protocol' if str(getattr(record, 'protocol', '') or '').upper() == 'RTSP' else 'Hypertext Transfer Protocol'
    return {
        'title': title,
        **_map(0, prelim_len),
        'children': children,
    }


def _http_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    http_payload = metadata.get('http_reassembled_payload', payload)
    lines = _http_payload_lines(http_payload)
    children = []
    use_offsets = not bool(metadata.get('http_is_reassembled', False))
    byte_source = PACKET_BYTE_SOURCE if use_offsets else TCP_REASSEMBLED_BYTE_SOURCE
    header_length = int(metadata.get('http_header_len', 0) or 0)
    payload_offset = int(metadata.get('http_payload_offset', 0) or 0)

    def _map(rel: int, length: int) -> Dict[str, Any]:
        return _byte_mapping(offset, payload_offset + int(rel), int(max(1, length)), byte_source)

    if lines:
        first_text, first_offset, first_length, first_raw = lines[0]
        first_line = first_raw.decode(errors='ignore')
        if first_line.startswith('HTTP/'):
            parts = first_line.split(' ', 2)
            response_children = []
            if len(parts) >= 2:
                version = parts[0]
                status_code = parts[1]
                reason = parts[2] if len(parts) > 2 else ''
                response_children = [
                    {
                        'title': f'Response Version: {version}',
                        **_map(first_offset, len(version)),
                    },
                    {
                        'title': f'Status Code: {status_code}',
                        **_map(first_offset + len(version) + 1, len(status_code)),
                    },
                ]
                description = _http_status_description(status_code)
                if description:
                    response_children.append({'title': f'[Status Code Description: {description}]'})
                if reason:
                    response_children.append({
                        'title': f'Response Phrase: {reason}',
                        **_map(first_offset + len(version) + 1 + len(status_code) + 1, len(reason)),
                    })
            children.append({
                'title': first_text,
                **_map(first_offset, first_length),
                'children': response_children,
            })
        else:
            parts = first_line.split(' ', 2)
            request_children = []
            if len(parts) == 3:
                method, uri, version = parts
                method_len = len(method)
                uri_len = len(uri)
                version_len = len(version)
                request_children = [
                    {
                        'title': f'Request Method: {method}',
                        **_map(first_offset, method_len),
                    },
                    {
                        'title': f'Request URI: {uri}',
                        **_map(first_offset + method_len + 1, uri_len),
                    },
                    {
                        'title': f'Request Version: {version}',
                        **_map(first_offset + method_len + 1 + uri_len + 1, version_len),
                    },
                ]
            children.append({
                'title': first_text,
                **_map(first_offset, first_length),
                'children': request_children,
            })

        for line_text, line_offset, line_length, line_raw in lines[1:]:
            title = line_text if line_raw != b'' else '\\r\\n'
            item = {
                'title': title,
                **_map(line_offset, line_length),
            }
            if line_raw.lower().startswith(b'content-length:'):
                try:
                    content_length = int(line_raw.split(b':', 1)[1].strip() or b'0')
                    value_offset = int(line_raw.find(b':')) + 1
                    while value_offset < len(line_raw) and line_raw[value_offset:value_offset + 1] == b' ':
                        value_offset += 1
                    item['children'] = [{
                        'title': f'[Content length: {content_length}]',
                        **_map(line_offset + value_offset, len(line_raw) - value_offset),
                    }]
                except Exception:
                    pass
            children.append(item)

    response_frame = metadata.get('http_response_frame', None)
    if response_frame is not None:
        children.append({'title': f'[Response in frame: {int(response_frame)}]'})

    request_frame = metadata.get('http_request_frame', None)
    if request_frame is not None:
        children.append({'title': f'[Request in frame: {int(request_frame)}]'})

    time_since_request = metadata.get('http_time_since_request_ms', None)
    if time_since_request is not None:
        children.append({'title': f'[Time since request: {float(time_since_request):.6f} milliseconds]'})

    request_uri = str(metadata.get('http_request_uri', '') or '').strip()
    if request_uri:
        children.append({'title': f'[Request URI: {request_uri}]'})

    full_request_uri = metadata.get('http_full_request_uri', '')
    if full_request_uri:
        children.append({'title': f'[Full request URI: {full_request_uri}]'})

    content_length = metadata.get('http_content_length', None)
    if content_length is not None and int(content_length) > 0:
        body = bytes(metadata.get('http_body', b'') or b'')
        body_offset = int(metadata.get('http_header_len', 0) or 0) + payload_offset
        body_len = len(body) if body else int(content_length)
        children.append({
            'title': f'File Data: {int(content_length)} bytes',
            **_byte_mapping(offset, body_offset, body_len, byte_source),
        })

    if bool(metadata.get('http_is_chunked', False)):
        chunks = list(metadata.get('http_chunks', []) or [])
        body_offset_rel = int(metadata.get('http_header_len', 0) or 0)
        body_offset = body_offset_rel + payload_offset
        chunk_children: List[Dict[str, Any]] = []
        for chunk in chunks:
            chunk_size = int(chunk.get('size', 0) or 0)
            size_offset = int(chunk.get('size_offset', 0) or 0)
            size_len = int(chunk.get('size_length', 0) or 0)
            data_offset = int(chunk.get('data_offset', 0) or 0)
            data_len = int(chunk.get('data_length', 0) or 0)
            boundary_offset = int(chunk.get('boundary_offset', 0) or 0)
            boundary_len = int(chunk.get('boundary_length', 2) or 2)

            if chunk_size == 0:
                chunk_children.append({
                    'title': 'End of chunked encoding',
                    **_byte_mapping(offset, body_offset + size_offset, max(1, size_len), byte_source),
                    'children': [
                        {
                            'title': 'Chunk size: 0 octets',
                            **_byte_mapping(offset, body_offset + size_offset, max(1, size_len), byte_source),
                        }
                    ],
                })
                continue

            chunk_children.append({
                'title': f'Data chunk ({chunk_size} octets)',
                **_byte_mapping(offset, body_offset + size_offset, max(1, data_len + size_len + boundary_len), byte_source),
                'children': [
                    {
                        'title': f'Chunk size: {chunk_size} octets',
                        **_byte_mapping(offset, body_offset + size_offset, max(1, size_len), byte_source),
                    },
                    {
                        'title': f'Chunk data […]: {http_payload[body_offset_rel + data_offset:body_offset_rel + data_offset + min(data_len, 120)].hex()}',
                        **_byte_mapping(offset, body_offset + data_offset, max(1, data_len), byte_source),
                    },
                    {
                        'title': 'Chunk boundary: 0d0a',
                        **_byte_mapping(offset, body_offset + boundary_offset, max(1, boundary_len), byte_source),
                    },
                ],
            })

        children.append({
            'title': 'HTTP chunked response',
            **_byte_mapping(offset, body_offset, len(bytes(metadata.get('http_body', b'') or b'')), byte_source),
            'children': chunk_children,
        })

        dechunked_len = int(metadata.get('http_dechunked_body_length', 0) or 0)
        if dechunked_len > 0:
            children.append({
                'title': f'File Data: {dechunked_len} bytes',
                **_byte_mapping(0, 0, dechunked_len, 'http_dechunked'),
            })

    title = 'Real Time Streaming Protocol' if str(getattr(record, 'protocol', '') or '').upper() == 'RTSP' else 'Hypertext Transfer Protocol'
    if bool(metadata.get('http_is_chunked', False)):
        chunk_count = int(metadata.get('http_chunk_count', 0) or 0)
        if chunk_count > 0:
            title = f'Hypertext Transfer Protocol, has {chunk_count} chunks (including last chunk)'
    return {
        'title': title,
        **_byte_mapping(offset, payload_offset, header_length or len(http_payload), byte_source),
        'children': children,
    }


def _http_line_based_text_section(record, offset: int) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) or {}
    content_type = str(metadata.get('http_content_type', '') or '').strip() or 'text/plain'
    body = bytes(metadata.get('http_body', b'') or b'')
    byte_source = PACKET_BYTE_SOURCE if not bool(metadata.get('http_is_reassembled', False)) else TCP_REASSEMBLED_BYTE_SOURCE
    body_offset = int(metadata.get('http_header_len', 0) or 0) + int(metadata.get('http_payload_offset', 0) or 0)
    lines = []
    cursor = 0
    for raw_line in body.splitlines(keepends=True):
        text = raw_line.decode(errors='ignore')
        text = text.replace('\t', '\\t').replace('\r', '\\r').replace('\n', '\\n')
        lines.append({
            'title': text,
            **_byte_mapping(offset, body_offset + cursor, len(raw_line), byte_source),
        })
        cursor += len(raw_line)
    return {
        'title': f'Line-based text data: {content_type} ({len(lines)} lines)',
        **_byte_mapping(offset, body_offset, len(body), byte_source),
        'children': lines,
    }


def _asn1_read_tlv(data: bytes, cursor: int) -> tuple[int, int, int, int] | None:
    if cursor + 2 > len(data):
        return None
    tag = int(data[cursor])
    len_octet = int(data[cursor + 1])
    if (len_octet & 0x80) == 0:
        length = len_octet
        header_len = 2
    else:
        count = int(len_octet & 0x7F)
        if count <= 0 or cursor + 2 + count > len(data):
            return None
        length = int.from_bytes(data[cursor + 2:cursor + 2 + count], 'big')
        header_len = 2 + count
    value_start = cursor + header_len
    value_end = value_start + length
    if value_end > len(data):
        return None
    return tag, value_start, value_end, value_end


def _asn1_oid_text(value_bytes: bytes) -> str:
    if not value_bytes:
        return ''
    first = int(value_bytes[0])
    arcs = [str(first // 40), str(first % 40)]
    acc = 0
    for b in value_bytes[1:]:
        acc = (acc << 7) | int(b & 0x7F)
        if (b & 0x80) == 0:
            arcs.append(str(acc))
            acc = 0
    return '.'.join(arcs)


def _ocsp_oid_name(oid: str) -> str:
    mapping = {
        '1.3.6.1.5.5.7.48.1.1': 'id-pkix-ocsp-basic',
        '1.3.14.3.2.26': 'SHA-1',
        '1.2.840.113549.1.1.11': 'sha256WithRSAEncryption',
    }
    name = mapping.get(str(oid), '')
    return f'{oid} ({name})' if name else oid


def _ocsp_oid_label(oid: str) -> str:
    mapping = {
        '1.3.6.1.5.5.7.48.1.1': 'id-pkix-ocsp-basic',
        '1.3.14.3.2.26': 'SHA-1',
        '1.2.840.113549.1.1.11': 'sha256WithRSAEncryption',
        '2.5.4.6': 'id-at-countryName',
        '2.5.4.10': 'id-at-organizationName',
        '2.5.4.3': 'id-at-commonName',
    }
    return mapping.get(str(oid), str(oid))


def _ocsp_format_time(raw: bytes) -> str:
    try:
        text = raw.decode(errors='ignore').strip()
        if len(text) >= 15 and text.endswith('Z'):
            dt = datetime.strptime(text[:15], '%Y%m%d%H%M%SZ').replace(tzinfo=timezone.utc).astimezone()
            return dt.strftime('%b %d, %Y %H:%M:%S.%f %Z')
    except Exception:
        pass
    return raw.decode(errors='ignore')


def _ocsp_section(record, offset: int) -> Dict[str, Any] | None:
    metadata = getattr(record, 'metadata', {}) or {}
    body = bytes(metadata.get('http_body', b'') or b'')
    if not body:
        return None
    byte_source = PACKET_BYTE_SOURCE if not bool(metadata.get('http_is_reassembled', False)) else TCP_REASSEMBLED_BYTE_SOURCE
    body_offset = int(metadata.get('http_header_len', 0) or 0) + int(metadata.get('http_payload_offset', 0) or 0)

    def _map(start: int, length: int) -> Dict[str, Any]:
        return _byte_mapping(offset, body_offset + int(start), int(max(1, length)), byte_source)

    def _map_tlv(tlv: tuple[int, int, int, int] | None, start_override: int | None = None) -> Dict[str, Any]:
        if tlv is None:
            return {}
        start = int(start_override) if start_override is not None else int(tlv[1]) - 2
        end = int(tlv[2])
        return _map(start, max(1, end - start))

    root = _asn1_read_tlv(body, 0)
    if root is None or int(root[0]) != 0x30:
        return {
            'title': 'Online Certificate Status Protocol',
            **_map(0, len(body)),
            'children': [{'title': f'Data ({len(body)} bytes)', **_map(0, len(body))}],
        }

    children: List[Dict[str, Any]] = []
    cursor = int(root[1])
    root_end = int(root[2])
    is_response = False

    status_tlv = _asn1_read_tlv(body, cursor)
    if status_tlv is not None and int(status_tlv[0]) == 0x0A:
        is_response = True
        status_val = int(body[int(status_tlv[1])]) if int(status_tlv[1]) < int(status_tlv[2]) else 0
        status_text = 'successful (0)' if status_val == 0 else f'{status_val}'
        children.append({'title': f'responseStatus: {status_text}', **_map(int(status_tlv[1]), int(status_tlv[2]) - int(status_tlv[1]))})
        cursor = int(status_tlv[3])

    if not is_response:
        tbs = _asn1_read_tlv(body, cursor)
        if tbs is not None and int(tbs[0]) == 0x30:
            tbs_children: List[Dict[str, Any]] = []
            tcur = int(tbs[1])
            if tcur < int(tbs[2]) and int(body[tcur]) == 0xA0:
                version = _asn1_read_tlv(body, tcur)
                if version is not None:
                    tbs_children.append({'title': 'version: v1 (0)', **_map_tlv(version, tcur)})
                    tcur = int(version[3])
            if tcur < int(tbs[2]) and int(body[tcur]) == 0xA1:
                requestor = _asn1_read_tlv(body, tcur)
                if requestor is not None:
                    tbs_children.append({'title': 'requestorName', **_map_tlv(requestor, tcur)})
                    tcur = int(requestor[3])
            req_list = _asn1_read_tlv(body, tcur)
            if req_list is not None and int(req_list[0]) == 0x30:
                rcur = int(req_list[1])
                req_count = 0
                req_nodes: List[Dict[str, Any]] = []
                while rcur < int(req_list[2]):
                    req = _asn1_read_tlv(body, rcur)
                    if req is None or int(req[0]) != 0x30:
                        break
                    req_count += 1
                    req_children: List[Dict[str, Any]] = []
                    cert = _asn1_read_tlv(body, int(req[1]))
                    if cert is not None and int(cert[0]) == 0x30:
                        cert_children: List[Dict[str, Any]] = []
                        ccur = int(cert[1])
                        hash_alg = _asn1_read_tlv(body, ccur)
                        if hash_alg is not None and int(hash_alg[0]) == 0x30:
                            alg_children: List[Dict[str, Any]] = []
                            alg_oid = _asn1_read_tlv(body, int(hash_alg[1]))
                            if alg_oid is not None and int(alg_oid[0]) == 0x06:
                                oid_text = _asn1_oid_text(body[int(alg_oid[1]):int(alg_oid[2])])
                                alg_children.append({'title': f'Algorithm Id: {_ocsp_oid_name(oid_text)}', **_map(int(alg_oid[1]), int(alg_oid[2]) - int(alg_oid[1]))})
                                cert_children.append({
                                    'title': f'hashAlgorithm ({_ocsp_oid_label(oid_text)})',
                                    **_map_tlv(hash_alg, ccur),
                                    'children': alg_children,
                                })
                            ccur = int(hash_alg[3])
                        issuer_name = _asn1_read_tlv(body, ccur)
                        if issuer_name is not None and int(issuer_name[0]) == 0x04:
                            cert_children.append({'title': f'issuerNameHash: {body[int(issuer_name[1]):int(issuer_name[2])].hex()}', **_map(int(issuer_name[1]), int(issuer_name[2]) - int(issuer_name[1]))})
                            ccur = int(issuer_name[3])
                        issuer_key = _asn1_read_tlv(body, ccur)
                        if issuer_key is not None and int(issuer_key[0]) == 0x04:
                            cert_children.append({'title': f'issuerKeyHash: {body[int(issuer_key[1]):int(issuer_key[2])].hex()}', **_map(int(issuer_key[1]), int(issuer_key[2]) - int(issuer_key[1]))})
                            ccur = int(issuer_key[3])
                        serial = _asn1_read_tlv(body, ccur)
                        if serial is not None and int(serial[0]) == 0x02:
                            cert_children.append({'title': f'serialNumber: 0x{body[int(serial[1]):int(serial[2])].hex()}', **_map(int(serial[1]), int(serial[2]) - int(serial[1]))})
                        req_children.append({'title': 'reqCert', **_map_tlv(cert, int(req[1])), 'children': cert_children})
                    req_nodes.append({'title': 'Request', **_map_tlv(req, rcur), 'children': req_children})
                    rcur = int(req[3])
                tbs_children.append({'title': f'requestList: {req_count} item', **_map_tlv(req_list, tcur), 'children': req_nodes})
            children.append({'title': 'tbsRequest', **_map(cursor, int(tbs[2]) - cursor), 'children': tbs_children})
            cursor = int(tbs[3])

    response_bytes_tlv = _asn1_read_tlv(body, cursor)
    if is_response and response_bytes_tlv is not None and int(response_bytes_tlv[0]) == 0xA0:
        rb_children: List[Dict[str, Any]] = []
        rb_seq = _asn1_read_tlv(body, int(response_bytes_tlv[1]))
        if rb_seq is not None and int(rb_seq[0]) == 0x30:
            rb_cursor = int(rb_seq[1])
            oid_tlv = _asn1_read_tlv(body, rb_cursor)
            if oid_tlv is not None and int(oid_tlv[0]) == 0x06:
                oid_text = _asn1_oid_text(body[int(oid_tlv[1]):int(oid_tlv[2])])
                rb_children.append({'title': f'ResponseType Id: {_ocsp_oid_name(oid_text)}', **_map(int(oid_tlv[1]), int(oid_tlv[2]) - int(oid_tlv[1]))})
                rb_cursor = int(oid_tlv[3])
            octet_tlv = _asn1_read_tlv(body, rb_cursor)
            if octet_tlv is not None and int(octet_tlv[0]) == 0x04:
                basic_bytes = body[int(octet_tlv[1]):int(octet_tlv[2])]
                basic_children: List[Dict[str, Any]] = []
                basic_base = int(octet_tlv[1])

                def _map_basic(rel_start: int, length: int) -> Dict[str, Any]:
                    return _map(basic_base + int(rel_start), int(max(1, length)))

                basic_tlv = _asn1_read_tlv(basic_bytes, 0)
                if basic_tlv is not None and int(basic_tlv[0]) == 0x30:
                    bcur = int(basic_tlv[1])
                    tend = int(basic_tlv[2])
                    tbs = _asn1_read_tlv(basic_bytes, bcur)
                    if tbs is not None and int(tbs[0]) == 0x30:
                        tbs_children: List[Dict[str, Any]] = []
                        tcur = int(tbs[1])
                        if tcur < int(tbs[2]) and int(basic_bytes[tcur]) in {0xA1, 0xA2}:
                            responder = _asn1_read_tlv(basic_bytes, tcur)
                            if responder is not None:
                                responder_children: List[Dict[str, Any]] = []
                                if int(responder[0]) == 0xA1:
                                    name_tlv = _asn1_read_tlv(basic_bytes, int(responder[1]))
                                    if name_tlv is not None and int(name_tlv[0]) == 0x30:
                                        by_name_children: List[Dict[str, Any]] = []
                                        rdn_children: List[Dict[str, Any]] = []
                                        ncur = int(name_tlv[1])
                                        rdn_count = 0
                                        while ncur < int(name_tlv[2]):
                                            rdn_set = _asn1_read_tlv(basic_bytes, ncur)
                                            if rdn_set is None or int(rdn_set[0]) != 0x31:
                                                break
                                            rdn_count += 1
                                            set_children: List[Dict[str, Any]] = []
                                            acur = int(rdn_set[1])
                                            item_count = 0
                                            while acur < int(rdn_set[2]):
                                                atv = _asn1_read_tlv(basic_bytes, acur)
                                                if atv is None or int(atv[0]) != 0x30:
                                                    break
                                                item_count += 1
                                                oid = _asn1_read_tlv(basic_bytes, int(atv[1]))
                                                oid_text = ''
                                                value_text = ''
                                                atv_children: List[Dict[str, Any]] = []
                                                if oid is not None and int(oid[0]) == 0x06:
                                                    oid_text = _asn1_oid_text(basic_bytes[int(oid[1]):int(oid[2])])
                                                    val_tlv = _asn1_read_tlv(basic_bytes, int(oid[3]))
                                                    if val_tlv is not None:
                                                        value_raw = basic_bytes[int(val_tlv[1]):int(val_tlv[2])]
                                                        value_text = value_raw.decode(errors='ignore')
                                                    atv_children.append({'title': f'Object Id: {_ocsp_oid_name(oid_text)}', **_map_basic(int(oid[1]), int(oid[2]) - int(oid[1]))})
                                                    if value_text and val_tlv is not None:
                                                        if oid_text == '2.5.4.6':
                                                            atv_children.append({'title': f'CountryName: {value_text}', **_map_basic(int(val_tlv[1]), int(val_tlv[2]) - int(val_tlv[1]))})
                                                        else:
                                                            atv_children.append({
                                                                'title': 'DirectoryString: printableString (1)',
                                                                **_map_basic(int(val_tlv[1]) - 2, int(val_tlv[2]) - (int(val_tlv[1]) - 2)),
                                                                'children': [
                                                                    {'title': f'printableString: {value_text}', **_map_basic(int(val_tlv[1]), int(val_tlv[2]) - int(val_tlv[1]))}
                                                                ],
                                                            })
                                                atv_title = f'RelativeDistinguishedName item ({_ocsp_oid_label(oid_text)}={value_text})' if oid_text else 'RelativeDistinguishedName item'
                                                set_children.append({'title': atv_title, **_map_basic(acur, int(atv[2]) - acur), 'children': atv_children})
                                                acur = int(atv[3])
                                            set_title = f'RDNSequence item: {item_count} item'
                                            if set_children:
                                                first_title = str(set_children[0].get('title', ''))
                                                if '(' in first_title:
                                                    set_title = f'{set_title} ({first_title[first_title.find("(")+1:first_title.rfind(")")]})'
                                            rdn_children.append({'title': set_title, **_map_basic(ncur, int(rdn_set[2]) - ncur), 'children': set_children})
                                            ncur = int(rdn_set[3])
                                        by_name_children.append({'title': f'rdnSequence: {rdn_count} items', **_map_basic(int(name_tlv[1]), int(name_tlv[2]) - int(name_tlv[1])), 'children': rdn_children})
                                        responder_children.append({'title': 'byName: 0', **_map_basic(int(responder[1]), int(responder[2]) - int(responder[1])), 'children': by_name_children})
                                tbs_children.append({'title': f'responderID: {"byName (1)" if int(responder[0]) == 0xA1 else "byKey (2)"}', **_map_basic(tcur, int(responder[2]) - tcur), 'children': responder_children})
                                tcur = int(responder[3])
                        produced = _asn1_read_tlv(basic_bytes, tcur)
                        if produced is not None and int(produced[0]) == 0x18:
                            produced_text = _ocsp_format_time(basic_bytes[int(produced[1]):int(produced[2])])
                            tbs_children.append({'title': f'producedAt: {produced_text}', **_map_basic(int(produced[1]), int(produced[2]) - int(produced[1]))})
                            tcur = int(produced[3])
                        responses = _asn1_read_tlv(basic_bytes, tcur)
                        if responses is not None and int(responses[0]) == 0x30:
                            rcur = int(responses[1])
                            response_count = 0
                            response_nodes: List[Dict[str, Any]] = []
                            while rcur < int(responses[2]):
                                single = _asn1_read_tlv(basic_bytes, rcur)
                                if single is None or int(single[0]) != 0x30:
                                    break
                                response_count += 1
                                s_children: List[Dict[str, Any]] = []
                                scur = int(single[1])
                                cert_id = _asn1_read_tlv(basic_bytes, scur)
                                if cert_id is not None and int(cert_id[0]) == 0x30:
                                    cid_children: List[Dict[str, Any]] = []
                                    ccur = int(cert_id[1])
                                    hash_alg = _asn1_read_tlv(basic_bytes, ccur)
                                    if hash_alg is not None and int(hash_alg[0]) == 0x30:
                                        alg_oid = _asn1_read_tlv(basic_bytes, int(hash_alg[1]))
                                        if alg_oid is not None and int(alg_oid[0]) == 0x06:
                                            oid_text = _asn1_oid_text(basic_bytes[int(alg_oid[1]):int(alg_oid[2])])
                                            cid_children.append({
                                                'title': f'hashAlgorithm ({_ocsp_oid_label(oid_text)})',
                                                **_map_basic(ccur, int(hash_alg[2]) - ccur),
                                                'children': [{'title': f'Algorithm Id: {_ocsp_oid_name(oid_text)}', **_map_basic(int(alg_oid[1]), int(alg_oid[2]) - int(alg_oid[1]))}],
                                            })
                                        ccur = int(hash_alg[3])
                                    for label in ['issuerNameHash', 'issuerKeyHash']:
                                        octv = _asn1_read_tlv(basic_bytes, ccur)
                                        if octv is not None and int(octv[0]) == 0x04:
                                            cid_children.append({'title': f'{label}: {basic_bytes[int(octv[1]):int(octv[2])].hex()}', **_map_basic(int(octv[1]), int(octv[2]) - int(octv[1]))})
                                            ccur = int(octv[3])
                                    serial = _asn1_read_tlv(basic_bytes, ccur)
                                    if serial is not None and int(serial[0]) == 0x02:
                                        cid_children.append({'title': f'serialNumber: 0x{basic_bytes[int(serial[1]):int(serial[2])].hex()}', **_map_basic(int(serial[1]), int(serial[2]) - int(serial[1]))})
                                        ccur = int(serial[3])
                                    s_children.append({'title': 'certID', **_map_basic(scur, int(cert_id[2]) - scur), 'children': cid_children})
                                    scur = int(cert_id[3])

                                cert_status = _asn1_read_tlv(basic_bytes, scur)
                                if cert_status is not None and int(cert_status[0]) in {0x80, 0x81, 0x82}:
                                    status_name = {0x80: 'good (0)', 0x81: 'revoked (1)', 0x82: 'unknown (2)'}[int(cert_status[0])]
                                    status_child_title = 'good' if int(cert_status[0]) == 0x80 else ''
                                    if int(cert_status[0]) == 0x80:
                                        status_node: Dict[str, Any] = {'title': f'certStatus: {status_name}'}
                                        if status_child_title:
                                            status_node['children'] = [{'title': status_child_title}]
                                    else:
                                        status_node = {'title': f'certStatus: {status_name}', **_map_basic(scur, int(cert_status[2]) - scur)}
                                    s_children.append(status_node)
                                    scur = int(cert_status[3])
                                this_update = _asn1_read_tlv(basic_bytes, scur)
                                if this_update is not None and int(this_update[0]) == 0x18:
                                    s_children.append({'title': f'thisUpdate: {_ocsp_format_time(basic_bytes[int(this_update[1]):int(this_update[2])])}', **_map_basic(int(this_update[1]), int(this_update[2]) - int(this_update[1]))})
                                    scur = int(this_update[3])
                                next_update = _asn1_read_tlv(basic_bytes, scur)
                                if next_update is not None and int(next_update[0]) == 0xA0:
                                    inner = _asn1_read_tlv(basic_bytes, int(next_update[1]))
                                    if inner is not None and int(inner[0]) == 0x18:
                                        s_children.append({'title': f'nextUpdate: {_ocsp_format_time(basic_bytes[int(inner[1]):int(inner[2])])}', **_map_basic(int(inner[1]), int(inner[2]) - int(inner[1]))})
                                response_nodes.append({'title': 'SingleResponse', **_map_basic(rcur, int(single[2]) - rcur), 'children': s_children})
                                rcur = int(single[3])
                            tbs_children.append({'title': f'responses: {response_count} item', **_map_basic(tcur, int(responses[2]) - tcur), 'children': response_nodes})
                        basic_children.append({'title': 'tbsResponseData', **_map_basic(bcur, int(tbs[2]) - bcur), 'children': tbs_children})
                        bcur = int(tbs[3])
                    sig_alg = _asn1_read_tlv(basic_bytes, bcur)
                    if sig_alg is not None and int(sig_alg[0]) == 0x30:
                        sig_oid = _asn1_read_tlv(basic_bytes, int(sig_alg[1]))
                        if sig_oid is not None and int(sig_oid[0]) == 0x06:
                            oid_text = _asn1_oid_text(basic_bytes[int(sig_oid[1]):int(sig_oid[2])])
                            basic_children.append({
                                'title': f'signatureAlgorithm ({_ocsp_oid_label(oid_text)})',
                                **_map_basic(bcur, int(sig_alg[2]) - bcur),
                                'children': [{'title': f'Algorithm Id: {_ocsp_oid_name(oid_text)}', **_map_basic(int(sig_oid[1]), int(sig_oid[2]) - int(sig_oid[1]))}],
                            })
                        bcur = int(sig_alg[3])
                    sig_bits = _asn1_read_tlv(basic_bytes, bcur)
                    if sig_bits is not None and int(sig_bits[0]) == 0x03 and int(sig_bits[1]) < int(sig_bits[2]):
                        bit_value = basic_bytes[int(sig_bits[1]):int(sig_bits[2])]
                        padding = int(bit_value[0]) if bit_value else 0
                        signature = bit_value[1:] if len(bit_value) > 1 else b''
                        basic_children.append({'title': f'Padding: {padding}', **_map_basic(int(sig_bits[1]), 1)})
                        basic_children.append({'title': f'signature […]: {signature[:120].hex()}', **_map_basic(int(sig_bits[1]) + 1, max(1, len(signature)))})

                rb_children.append({'title': 'BasicOCSPResponse', **_map(int(octet_tlv[1]), int(octet_tlv[2]) - int(octet_tlv[1])), 'children': basic_children})

        children.append({'title': 'responseBytes', **_map(cursor, int(response_bytes_tlv[2]) - cursor), 'children': rb_children})

    if not children:
        children.append({'title': f'Data ({len(body)} bytes)', **_map(0, len(body))})

    root_map = _map(0, len(body))

    return {
        'title': 'Online Certificate Status Protocol',
        **root_map,
        'children': children,
    }


def _ipp_value_tag_name(tag: int) -> tuple[str, str]:
    mapping = {
        0x21: ('integer', 'integer'),
        0x22: ('boolean', 'boolean'),
        0x23: ('enum', 'enum'),
        0x30: ('octetString-with-an-unspecified-format', 'octetString'),
        0x33: ('rangeOfInteger', 'rangeOfInteger'),
        0x34: ('collection', 'collection'),
        0x37: ('endCollection', 'endCollection'),
        0x41: ('textWithoutLanguage', 'textWithoutLanguage'),
        0x42: ('nameWithoutLanguage', 'nameWithoutLanguage'),
        0x44: ('keyword', 'keyword'),
        0x45: ('uri', 'uri'),
        0x47: ('charset', 'charset'),
        0x48: ('naturalLanguage', 'naturalLanguage'),
        0x49: ('mimeMediaType', 'mimeMediaType'),
        0x4A: ('memberAttrName', 'memberAttrName'),
    }
    return mapping.get(int(tag), (f'tag 0x{int(tag):02x}', f'0x{int(tag):02x}'))


def _ipp_group_name(tag: int) -> str:
    return {
        0x01: 'operation-attributes-tag',
        0x02: 'job-attributes-tag',
        0x04: 'printer-attributes-tag',
        0x05: 'unsupported-attributes-tag',
    }.get(int(tag), f'attributes-tag 0x{int(tag):02x}')


def _ipp_enum_name(attr_name: str, value: int) -> str:
    attr = str(attr_name or '')
    if attr == 'operations-supported':
        return {
            2: 'Print-Job',
            3: 'Print-URI',
            4: 'Validate-Job',
            5: 'Create-Job',
            6: 'Send-Document',
            7: 'Send-URI',
            8: 'Cancel-Job',
            9: 'Get-Job-Attributes',
            10: 'Get-Jobs',
            11: 'Get-Printer-Attributes',
            60: 'Identify-Printer',
        }.get(int(value), str(value))
    if attr in {'print-quality', 'print-quality-supported'}:
        return {
            3: 'draft',
            4: 'normal',
            5: 'high',
        }.get(int(value), str(value))
    if attr == 'finishings-supported':
        return {
            3: 'none',
        }.get(int(value), str(value))
    return str(value)


def _ipp_format_value(attr_name: str, value_tag: int, value_bytes: bytes) -> tuple[str, str]:
    type_label, value_label = _ipp_value_tag_name(value_tag)
    value = bytes(value_bytes or b'')

    if value_tag == 0x22 and len(value) == 1:
        bool_text = 'true' if int(value[0]) != 0 else 'false'
        return bool_text, value_label

    if value_tag == 0x21 and len(value) in {1, 2, 4}:
        return str(int.from_bytes(value, 'big')), value_label

    if value_tag == 0x23 and len(value) in {1, 2, 4}:
        ivalue = int.from_bytes(value, 'big')
        return _ipp_enum_name(attr_name, ivalue), value_label

    if value_tag == 0x33 and len(value) >= 8:
        lo = int.from_bytes(value[:4], 'big')
        hi = int.from_bytes(value[4:8], 'big')
        return f'{lo}-{hi}', value_label

    if value_tag in {0x41, 0x42, 0x44, 0x45, 0x47, 0x48, 0x49, 0x4A}:
        return value.decode(errors='ignore'), value_label

    text = value.decode(errors='ignore') if value else ''
    if not text and value:
        text = value.hex()
    return text, value_label


def _ipp_section(record, offset: int) -> Dict[str, Any] | None:
    metadata = getattr(record, 'metadata', {}) or {}
    dechunked = bytes(metadata.get('http_dechunked_body', b'') or b'')
    body = dechunked if dechunked else bytes(metadata.get('http_body', b'') or b'')
    if len(body) < 8:
        packet = getattr(record, 'raw', None)
        tcp_payload = b''
        try:
            if packet is not None and packet.haslayer(TCP):
                tcp_payload = bytes(getattr(packet[TCP], 'payload', b''))
        except Exception:
            tcp_payload = b''
        if tcp_payload:
            return {
                'title': 'Internet Printing Protocol',
                **_byte_mapping(offset, 0, len(tcp_payload), PACKET_BYTE_SOURCE),
                'children': [
                    {
                        'title': f'Data ({len(tcp_payload)} bytes)',
                        **_byte_mapping(offset, 0, len(tcp_payload), PACKET_BYTE_SOURCE),
                        'children': [
                            {
                                'title': f'Data […]: {tcp_payload[:120].hex()}',
                                **_byte_mapping(offset, 0, len(tcp_payload), PACKET_BYTE_SOURCE),
                            },
                            {'title': f'[Length: {len(tcp_payload)}]'},
                        ],
                    }
                ],
            }
        return None

    if dechunked:
        byte_source = 'http_dechunked'
        body_offset = 0
    else:
        byte_source = PACKET_BYTE_SOURCE if not bool(metadata.get('http_is_reassembled', False)) else TCP_REASSEMBLED_BYTE_SOURCE
        body_offset = int(metadata.get('http_header_len', 0) or 0) + int(metadata.get('http_payload_offset', 0) or 0)

    def _map(rel: int, length: int) -> Dict[str, Any]:
        if byte_source == PACKET_BYTE_SOURCE:
            return _byte_mapping(offset, body_offset + rel, length, byte_source)
        return _byte_mapping(0, body_offset + rel, length, byte_source)

    version_major = int(body[0])
    version_minor = int(body[1])
    op_status = int.from_bytes(body[2:4], 'big')
    request_id = int.from_bytes(body[4:8], 'big')
    is_request = bool(str(metadata.get('http_kind', '') or 'request') == 'request')

    children: List[Dict[str, Any]] = [
        {'title': f'version: {version_major}.{version_minor}', **_map(0, 2)},
    ]
    if is_request:
        op_name = {
            0x0002: 'Print-Job',
            0x0003: 'Print-URI',
            0x0004: 'Validate-Job',
            0x0005: 'Create-Job',
            0x0006: 'Send-Document',
            0x0007: 'Send-URI',
            0x0008: 'Cancel-Job',
            0x0009: 'Get-Job-Attributes',
            0x000A: 'Get-Jobs',
            0x000B: 'Get-Printer-Attributes',
        }.get(op_status, f'0x{op_status:04x}')
        children.append({'title': f'operation-id: {op_name} (0x{op_status:04x})', **_map(2, 2)})
    else:
        status_name = {
            0x0000: 'Successful (successful-ok)',
        }.get(op_status, f'0x{op_status:04x}')
        children.append({'title': f'status-code: {status_name}', **_map(2, 2)})
    children.append({'title': f'request-id: {request_id}', **_map(4, 4)})

    response_frame = metadata.get('http_response_frame', None)
    if is_request and response_frame is not None:
        children.insert(0, {'title': f'[Response In: {int(response_frame)}]'})

    request_frame = metadata.get('http_request_frame', None)
    if not is_request and request_frame is not None:
        children.insert(0, {'title': f'[Request In: {int(request_frame)}]'})

    def _entry_at(pos: int) -> tuple[Dict[str, Any], int] | None:
        if pos + 5 > len(body):
            return None
        value_tag = int(body[pos])
        name_len = int.from_bytes(body[pos + 1:pos + 3], 'big')
        name_start = pos + 3
        name_end = name_start + name_len
        if name_end + 2 > len(body):
            return None
        value_len = int.from_bytes(body[name_end:name_end + 2], 'big')
        value_start = name_end + 2
        value_end = value_start + value_len
        if value_end > len(body):
            return None
        name = body[name_start:name_end].decode(errors='ignore') if name_len > 0 else ''
        return ({
            'start': pos,
            'end': value_end,
            'value_tag': value_tag,
            'name': name,
            'name_start': name_start,
            'name_len': name_len,
            'value_start': value_start,
            'value_len': value_len,
            'value_bytes': body[value_start:value_end],
        }, value_end)

    def _parse_collection(start_pos: int) -> tuple[List[Dict[str, Any]], int, str]:
        nodes: List[Dict[str, Any]] = []
        labels: List[str] = []
        pos = int(start_pos)
        current_member = ''
        while pos < len(body):
            entry_pair = _entry_at(pos)
            if entry_pair is None:
                break
            entry, next_pos = entry_pair
            tag = int(entry['value_tag'])
            if tag == 0x37:
                pos = next_pos
                break
            if tag == 0x4A:
                current_member = str(entry['value_bytes'].decode(errors='ignore'))
                labels.append(current_member)
                nodes.append({'title': f'memberAttrName: {current_member}', **_map(int(entry['start']), max(1, int(entry['end']) - int(entry['start'])))})
                pos = next_pos
                continue

            type_label, value_label = _ipp_value_tag_name(tag)
            if tag == 0x34:
                nested_children, nested_pos, nested_summary = _parse_collection(next_pos)
                summary = f'{{{nested_summary}}}' if nested_summary else '{}'
                nodes.append({'title': f'collection {summary}', **_map(int(entry['start']), max(1, nested_pos - int(entry['start']))), 'children': nested_children})
                pos = nested_pos
                continue

            value_text, _ = _ipp_format_value(current_member, tag, bytes(entry['value_bytes']))
            nodes.append({'title': f'{value_label} value: {value_text}', **_map(int(entry['start']), max(1, int(entry['end']) - int(entry['start'])))})
            pos = next_pos

        summary_parts: List[str] = []
        idx = 0
        while idx < len(nodes):
            node_title = str(nodes[idx].get('title', ''))
            if node_title.startswith('memberAttrName: '):
                member = node_title.replace('memberAttrName: ', '', 1)
                nested_summary = ''
                if idx + 1 < len(nodes):
                    next_title = str(nodes[idx + 1].get('title', ''))
                    if next_title.startswith('collection {'):
                        nested_summary = next_title.replace('collection ', '', 1)
                summary_parts.append(f'{member}{nested_summary}')
            idx += 1
        return nodes, pos, ','.join(summary_parts)

    cursor = 8
    group_node: Dict[str, Any] | None = None
    current_attr: Dict[str, Any] | None = None

    def _finalize_group(end_cursor: int) -> None:
        nonlocal group_node
        if not isinstance(group_node, dict):
            return
        start_cursor = int(group_node.pop('_ipp_group_start', end_cursor) or end_cursor)
        mapped = _map(start_cursor, max(1, int(end_cursor) - start_cursor))
        if mapped:
            group_node['offset'] = mapped.get('offset', group_node.get('offset'))
            group_node['length'] = mapped.get('length', group_node.get('length'))
            if 'byte_source' in mapped:
                group_node['byte_source'] = mapped.get('byte_source')
        group_node = None

    def _finalize_attr() -> None:
        nonlocal current_attr
        if not isinstance(current_attr, dict):
            return
        node = current_attr.get('node')
        if not isinstance(node, dict):
            current_attr = None
            return
        name = str(current_attr.get('name', '') or '')
        type_label = str(current_attr.get('type_label', '') or '')
        values = list(current_attr.get('values', []) or [])
        quoted_set_types = {'keyword', 'mimeMediaType', 'uri', 'charset', 'naturalLanguage', 'nameWithoutLanguage', 'textWithoutLanguage'}
        if len(values) > 1:
            if name == 'operations-supported':
                node['title'] = f"{name} (1setOf {type_label}): {','.join(values)}"
            elif type_label in {'enum'}:
                node['title'] = f"{name} (1setOf {type_label}): {','.join(values)}"
            elif type_label in quoted_set_types:
                node['title'] = f"{name} (1setOf {type_label}): {','.join([repr(v) for v in values])}"
            else:
                node['title'] = f"{name} (1setOf {type_label}): {','.join(values)}"
        elif len(values) == 1:
            if type_label == 'boolean':
                node['title'] = f"{name} ({type_label}): {values[0]}"
            elif type_label in quoted_set_types:
                node['title'] = f"{name} ({type_label}): '{values[0]}'"
            else:
                node['title'] = f"{name} ({type_label}): {values[0]}"
        current_attr = None

    while cursor < len(body):
        tag = int(body[cursor])
        if tag == 0x03:
            _finalize_attr()
            _finalize_group(cursor)
            children.append({'title': 'end-of-attributes-tag', **_map(cursor, 1)})
            cursor += 1
            break
        if tag in {0x01, 0x02, 0x04, 0x05}:
            _finalize_attr()
            _finalize_group(cursor)
            group_node = {
                'title': _ipp_group_name(tag),
                **_map(cursor, 1),
                '_ipp_group_start': int(cursor),
                'children': [],
            }
            children.append(group_node)
            cursor += 1
            continue

        entry_pair = _entry_at(cursor)
        if entry_pair is None:
            break
        entry, next_cursor = entry_pair
        value_tag = int(entry['value_tag'])
        name = str(entry['name'])
        type_label, value_label = _ipp_value_tag_name(value_tag)

        if name:
            _finalize_attr()
            value_text, _ = _ipp_format_value(name, value_tag, bytes(entry['value_bytes']))
            attr_node: Dict[str, Any] = {
                'title': f"{name} ({type_label}): '{value_text}'" if type_label != 'boolean' else f"{name} ({type_label}): {value_text}",
                **_map(int(entry['start']), max(1, int(entry['end']) - int(entry['start']))),
                'children': [
                    {'title': f'name: {name}', **_map(int(entry['name_start']), int(entry['name_len']))},
                ],
            }

            if value_tag == 0x34:
                coll_children, coll_pos, coll_summary = _parse_collection(next_cursor)
                attr_node['children'].append({'title': f'collection {{{coll_summary}}}', **_map(int(entry['start']), max(1, coll_pos - int(entry['start']))), 'children': coll_children})
                attr_node['title'] = f"{name} ({type_label}): {{{coll_summary}}}"
                attr_node.update(_map(int(entry['start']), max(1, coll_pos - int(entry['start']))))
                cursor = coll_pos
                target = group_node if isinstance(group_node, dict) else None
                if isinstance(target, dict):
                    target.setdefault('children', []).append(attr_node)
                else:
                    children.append(attr_node)
                continue

            child_title = f'{value_label} value: {value_text}'
            if type_label == 'enum':
                raw_val = int.from_bytes(bytes(entry['value_bytes']) or b'\x00', 'big') if int(entry['value_len']) > 0 else 0
                enum_name = _ipp_enum_name(name, raw_val)
                if name == 'operations-supported':
                    child_title = f'operations-supported: {enum_name} ({raw_val})'
                elif name in {'print-quality', 'print-quality-supported'}:
                    child_title = f'print-quality: {enum_name} ({raw_val})'
                elif name == 'finishings-supported':
                    child_title = f'finishings: {enum_name} ({raw_val})'
                else:
                    child_title = f'enum value: {raw_val}'
            elif type_label == 'boolean':
                child_title = f'boolean value: {str(value_text).lower() == "true"}'
            attr_node['children'].append({'title': child_title, **_map(int(entry['value_start']), int(entry['value_len']))})

            target = group_node if isinstance(group_node, dict) else None
            if isinstance(target, dict):
                target.setdefault('children', []).append(attr_node)
            else:
                children.append(attr_node)

            current_attr = {
                'name': name,
                'type_label': type_label,
                'values': [value_text],
                'node': attr_node,
            }
            cursor = next_cursor
            continue

        if isinstance(current_attr, dict):
            cname = str(current_attr.get('name', '') or '')
            value_text, _ = _ipp_format_value(cname, value_tag, bytes(entry['value_bytes']))
            current_attr.setdefault('values', []).append(value_text)
            attr_node = current_attr.get('node')
            if isinstance(attr_node, dict):
                start = int(attr_node.get('offset', _map(int(entry['start']), 1).get('offset', 0)))
                end_abs = _map(int(entry['end']), 1).get('offset', start + int(attr_node.get('length', 1)))
                attr_node['length'] = max(1, int(end_abs) - start)

                extra_title = f'{value_label} value: {value_text}'
                if type_label == 'enum':
                    raw_val = int.from_bytes(bytes(entry['value_bytes']) or b'\x00', 'big') if int(entry['value_len']) > 0 else 0
                    enum_name = _ipp_enum_name(cname, raw_val)
                    if cname == 'operations-supported':
                        extra_title = f'operations-supported: {enum_name} ({raw_val})'
                    elif cname in {'print-quality', 'print-quality-supported'}:
                        extra_title = f'print-quality: {enum_name} ({raw_val})'
                    elif cname == 'finishings-supported':
                        extra_title = f'finishings: {enum_name} ({raw_val})'
                elif type_label == 'boolean':
                    extra_title = f'boolean value: {str(value_text).lower() == "true"}'
                attr_node.setdefault('children', []).append({'title': extra_title, **_map(int(entry['value_start']), int(entry['value_len']))})

            cursor = next_cursor
            continue

        cursor = next_cursor

    _finalize_attr()
    _finalize_group(cursor)

    if cursor < len(body):
        data_len = len(body) - cursor
        children.append({
            'title': f'Data ({data_len} bytes)',
            **_map(cursor, data_len),
            'children': [
                {'title': f'Data […]: {body[cursor:cursor + 120].hex()}', **_map(cursor, data_len)},
                {'title': f'[Length: {data_len}]'},
            ],
        })

    return {
        'title': 'Internet Printing Protocol',
        **_map(0, len(body)),
        'children': children,
    }


def _lpd_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    lpd_info = metadata.get('lpd') if isinstance(metadata, dict) else None
    children: List[Dict[str, Any]] = []

    summary = str((lpd_info or {}).get('summary', '') or '').strip() if isinstance(lpd_info, dict) else ''
    if summary:
        children.append({'title': summary, **_byte_mapping(offset, 0, 1 if payload else 0)})

    if isinstance(lpd_info, dict) and str(lpd_info.get('kind', '') or '') == 'response':
        status = str(lpd_info.get('status', '') or '').strip()
        if status:
            children.append({'title': f'Response: {status}', **_byte_mapping(offset, 0, len(payload))})
    elif isinstance(lpd_info, dict) and str(lpd_info.get('kind', '') or '') == 'command':
        printer_options = str(lpd_info.get('printer_options', '') or '')
        if printer_options:
            children.append({'title': f'Printer/options: {printer_options}', **_byte_mapping(offset, 1, max(0, len(payload) - 1))})
    else:
        if payload:
            children.append({
                'title': f'Data ({len(payload)} bytes)',
                **_byte_mapping(offset, 0, len(payload)),
                'children': [
                    {'title': f'Data: {payload.hex()}', **_byte_mapping(offset, 0, len(payload))},
                    {'title': f'[Length: {len(payload)}]'},
                ],
            })

    if not children:
        children.append({'title': f'Data ({len(payload)} bytes)', **_byte_mapping(offset, 0, len(payload))})

    return {
        'title': 'Line Printer Daemon Protocol',
        **_byte_mapping(offset, 0, len(payload)),
        'children': children,
    }


def _ftp_response_code_text(code: int) -> str:
    return {
        150: 'File status okay; about to open data connection',
        200: 'Command okay',
        220: 'Service ready for new user',
        221: 'Service closing control connection',
        226: 'Closing data connection',
        227: 'Entering Passive Mode',
        230: 'User logged in, proceed',
        250: 'Requested file action okay, completed',
        257: 'PATHNAME created',
        331: 'User name okay, need password',
    }.get(int(code), str(code))


def _ftp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    ftp_info = metadata.get('ftp') if isinstance(metadata, dict) and isinstance(metadata.get('ftp'), dict) else None
    children: List[Dict[str, Any]] = []
    cursor = 0
    lines = payload.split(b'\r\n') if payload else []
    any_line = False
    for idx, raw_line in enumerate(lines):
        if idx == len(lines) - 1 and raw_line == b'':
            break
        line = raw_line.decode(errors='ignore')
        line_len = len(raw_line) + 2
        if not line and len(raw_line) == 0:
            cursor += line_len
            continue
        any_line = True
        line_node: Dict[str, Any] = {
            'title': f'{line}\\r\\n',
            **_byte_mapping(offset, cursor, max(1, line_len), PACKET_BYTE_SOURCE),
            'children': [],
        }
        if idx == 0 and isinstance(ftp_info, dict):
            kind = str(ftp_info.get('kind', '') or '')
            if kind == 'response':
                code = int(ftp_info.get('code', 0) or 0)
                arg = str(ftp_info.get('arg', '') or '')
                separator = str(ftp_info.get('separator', '') or '')
                if code > 0:
                    response_label = 'Response code'
                    if separator == '-':
                        response_label = 'Response code (multiline)'
                    line_node['children'].append({
                        'title': f'{response_label}: {_ftp_response_code_text(code)} ({code})',
                        **_byte_mapping(offset, cursor, 3, PACKET_BYTE_SOURCE),
                    })
                    if arg:
                        line_node['children'].append({
                            'title': f'Response message: {arg}',
                            **_byte_mapping(offset, cursor + 4, max(1, len(raw_line) - 4), PACKET_BYTE_SOURCE),
                        })
                elif arg:
                    line_node['children'].append({
                        'title': f'Response message: {arg}',
                        **_byte_mapping(offset, cursor, max(1, len(raw_line)), PACKET_BYTE_SOURCE),
                    })
            elif kind == 'request':
                command = str(ftp_info.get('command', '') or '')
                arg = str(ftp_info.get('arg', '') or '')
                if command:
                    line_node['children'].append({
                        'title': f'Request command: {command}',
                        **_byte_mapping(offset, cursor, len(command), PACKET_BYTE_SOURCE),
                    })
                if arg:
                    arg_offset = cursor + len(command) + 1 if command else cursor
                    line_node['children'].append({
                        'title': f'Request argument: {arg}',
                        **_byte_mapping(offset, arg_offset, max(1, len(raw_line) - len(command) - 1), PACKET_BYTE_SOURCE),
                    })
        children.append(line_node)
        cursor += line_len

    if not any_line:
        children.append({
            'title': f'Data ({len(payload)} bytes)',
            **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        })

    cwd = str(metadata.get('ftp_cwd', '') or '')
    children.append({'title': f'[Current working directory: {cwd}]'})

    return {
        'title': 'File Transfer Protocol (FTP)',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _ftp_data_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    ftp_data = metadata.get('ftp_data') if isinstance(metadata, dict) and isinstance(metadata.get('ftp_data'), dict) else {}
    children: List[Dict[str, Any]] = [
        {'title': f'FTP Data ({len(payload)} bytes data)', **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE)},
    ]
    setup_frame = int(ftp_data.get('setup_frame', 0) or 0)
    if setup_frame > 0:
        children.append({'title': f'[Setup frame: {setup_frame}]'})
    setup_method = str(ftp_data.get('setup_method', '') or '')
    if setup_method:
        children.append({'title': f'[Setup method: {setup_method}]'})
    command = str(ftp_data.get('command', '') or '')
    if command:
        children.append({'title': f'[Command: {command}]'})
    command_arg = str(ftp_data.get('command_arg', '') or '')
    if command_arg:
        children.append({'title': f'[Command Arg: {command_arg}]'})
    command_frame = int(ftp_data.get('command_frame', 0) or 0)
    if command_frame > 0:
        children.append({'title': f'Command frame: {command_frame}'})
    cwd = str(ftp_data.get('cwd', '') or '')
    children.append({'title': f'[Current working directory: {cwd}]'})
    if payload:
        children.append(_smtp_line_based_text_section(payload, offset))
    return {
        'title': f'FTP Data ({len(payload)} bytes data)',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children[1:],
    }


def _bfd_control_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    if len(raw) < 24:
        return {
            'title': 'BFD Control message',
            **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
            'children': [{'title': f'Data ({len(raw)} bytes)', **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE)}],
        }
    version = (int(raw[0]) >> 5) & 0x07
    diag = int(raw[0]) & 0x1F
    state = (int(raw[1]) >> 6) & 0x03
    flags_byte = int(raw[1])
    flags = flags_byte & 0x3F
    diag_bits = f'{diag:05b}'
    detect_mult = int(raw[2])
    msg_len = int(raw[3])
    my_disc = int.from_bytes(raw[4:8], 'big')
    your_disc = int.from_bytes(raw[8:12], 'big')
    desired_tx = int.from_bytes(raw[12:16], 'big')
    required_rx = int.from_bytes(raw[16:20], 'big')
    required_echo = int.from_bytes(raw[20:24], 'big')
    diag_text = {
        0: 'No Diagnostic',
        1: 'Control Detection Time Expired',
        2: 'Echo Function Failed',
        3: 'Neighbor Signaled Session Down',
        4: 'Forwarding Plane Reset',
        5: 'Path Down',
        6: 'Concatenated Path Down',
        7: 'Administratively Down',
        8: 'Reverse Concatenated Path Down',
    }.get(diag, f'Unknown ({diag})')
    state_text = {
        0: 'AdminDown',
        1: 'Down',
        2: 'Init',
        3: 'Up',
    }.get(state, f'Unknown ({state})')
    detection_ms = int(round(detect_mult * (required_rx / 1000.0))) if required_rx > 0 else 0
    children: List[Dict[str, Any]] = [
        {'title': f'{version:03b}. .... = Protocol Version: {version}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'...{diag_bits[0]} {diag_bits[1:]} = Diagnostic Code: {diag_text} (0x{diag:02x})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'{state:02b}.. .... = Session State: {state_text} (0x{state:x})', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
        {
            'title': f'Message Flags: 0x{flags_byte:02x}',
            **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'{"1" if (flags & 0x20) else "0"}... .. = Poll: {"Set" if (flags & 0x20) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.{"1" if (flags & 0x10) else "0"}.. .. = Final: {"Set" if (flags & 0x10) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'..{"1" if (flags & 0x08) else "0"}. .. = Control Plane Independent: {"Set" if (flags & 0x08) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'...{"1" if (flags & 0x04) else "0"} .. = Authentication Present: {"Set" if (flags & 0x04) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.... {"1" if (flags & 0x02) else "0"}. = Demand: {"Set" if (flags & 0x02) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'.... .{"1" if (flags & 0x01) else "0"} = Multipoint: {"Set" if (flags & 0x01) else "Not set"}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
            ],
        },
        {'title': f'Detect Time Multiplier: {detect_mult} (= {detection_ms} ms Detection time)', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Message Length: {msg_len} bytes', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
        {'title': f'My Discriminator: 0x{my_disc:08x}', **_byte_mapping(offset, 4, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Your Discriminator: 0x{your_disc:08x}', **_byte_mapping(offset, 8, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Desired Min TX Interval: {int(round(desired_tx / 1000.0))} ms ({desired_tx} us)', **_byte_mapping(offset, 12, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Required Min RX Interval: {int(round(required_rx / 1000.0))} ms ({required_rx} us)', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Required Min Echo Interval:  {int(round(required_echo / 1000.0))} ms ({required_echo} us)', **_byte_mapping(offset, 20, 4, PACKET_BYTE_SOURCE)},
    ]
    return {
        'title': 'BFD Control message',
        **_byte_mapping(offset, 0, min(len(raw), max(24, msg_len)), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _bfd_echo_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    children: List[Dict[str, Any]] = [
        {
            'title': f'Echo: {raw.hex()}',
            **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
        }
    ]
    return {
        'title': 'BFD Echo message',
        **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _glbp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    if len(raw) < 12:
        return {
            'title': 'Gateway Load Balancing Protocol',
            **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
            'children': [{'title': f'Data ({len(raw)} bytes)', **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE)}],
        }

    group = int.from_bytes(raw[2:4], 'big')

    def _glbp_mac_display(mac_bytes: bytes) -> str:
        mac_text = _mac_text_from_bytes(mac_bytes)
        parts = mac_text.split(':')
        if len(parts) == 6 and ':'.join(parts[:3]) in {'00:07:b4', '00:15:62', '00:25:45'}:
            return f'Cisco_{":".join(parts[-3:])} ({mac_text})'
        return _mac_display(mac_text)

    owner_mac = _glbp_mac_display(raw[6:12])
    children: List[Dict[str, Any]] = [
        {'title': f'Version?: {int(raw[0])}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Unknown1: {int(raw[1])}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Group: {group}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Unknown2: {raw[4:6].hex()}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Owner ID: {owner_mac}', **_byte_mapping(offset, 6, 6, PACKET_BYTE_SOURCE)},
    ]

    def _tlv_short_name(tlv_type: int) -> str:
        if tlv_type == 1:
            return 'Hello'
        if tlv_type == 2:
            return 'Request/Response?'
        if tlv_type == 3:
            return 'Auth'
        if tlv_type == 4:
            return '4'
        return str(tlv_type)

    cursor = 12
    while cursor + 2 <= len(raw):
        tlv_type = int(raw[cursor])
        tlv_len = int(raw[cursor + 1])
        if tlv_len < 2 or cursor + tlv_len > len(raw):
            break
        value_start = cursor + 2
        value_end = cursor + tlv_len
        value = raw[value_start:value_end]
        tlv_children: List[Dict[str, Any]] = []
        if tlv_type == 1:
            type_text = 'Hello'
        elif tlv_type == 2:
            type_text = 'Request/Response?'
        elif tlv_type == 3:
            type_text = 'Auth'
        else:
            type_text = 'Unknown'
        tlv_children.append({'title': f'Type: {type_text} ({tlv_type})', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
        tlv_children.append({'title': f'Length: {tlv_len}', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)})

        if tlv_type == 3 and len(value) >= 2:
            auth_type = int(value[0])
            auth_len = int(value[1])
            auth_text = {
                1: 'Plaintext',
                2: 'MD5 string',
            }.get(auth_type, str(auth_type))
            tlv_children.extend([
                {'title': f'Authtype: {auth_text} ({auth_type})', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Authlength: {auth_len}', **_byte_mapping(offset, value_start + 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'MD5-string hash: {value[2:].hex()}', **_byte_mapping(offset, value_start + 2, max(1, len(value) - 2), PACKET_BYTE_SOURCE)},
            ])
        elif tlv_type == 4:
            tlv_children.append({'title': f'Unknown TLV data: {value.hex()}', **_byte_mapping(offset, value_start, len(value), PACKET_BYTE_SOURCE)})
        elif tlv_type == 1 and len(value) >= 22:
            vg_state = int(value[1])
            vg_state_text = {16: 'Standby', 32: 'Active'}.get(vg_state, str(vg_state))
            addr_type = int(value[20])
            addr_len = int(value[21]) if len(value) > 21 else 0
            addr_value = value[22:22 + addr_len] if len(value) >= 22 + addr_len else b''
            tlv_children.extend([
                {'title': f'Unknown1-0: {value[0]:02x}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                {'title': f'VG state?: {vg_state_text} ({vg_state})', **_byte_mapping(offset, value_start + 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Unknown1-1: {value[2]:02x}', **_byte_mapping(offset, value_start + 2, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Priority: {int(value[3])}', **_byte_mapping(offset, value_start + 3, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Unknown1-2: {value[4:6].hex()}', **_byte_mapping(offset, value_start + 4, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Helloint: {int.from_bytes(value[6:10], "big")}', **_byte_mapping(offset, value_start + 6, 4, PACKET_BYTE_SOURCE)},
                {'title': f'Holdint: {int.from_bytes(value[10:14], "big")}', **_byte_mapping(offset, value_start + 10, 4, PACKET_BYTE_SOURCE)},
                {'title': f'Redirect: {int.from_bytes(value[14:16], "big")}', **_byte_mapping(offset, value_start + 14, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Timeout: {int.from_bytes(value[16:18], "big")}', **_byte_mapping(offset, value_start + 16, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Unknown1-3: {value[18:20].hex()}', **_byte_mapping(offset, value_start + 18, 2, PACKET_BYTE_SOURCE)},
            ])
            if addr_type == 1:
                addr_text = '.'.join(str(int(b)) for b in addr_value[:4]) if len(addr_value) >= 4 else addr_value.hex()
                tlv_children.append({'title': 'Address type: IPv4 (1)', **_byte_mapping(offset, value_start + 20, 1, PACKET_BYTE_SOURCE)})
                tlv_children.append({'title': f'Address length: {addr_len}', **_byte_mapping(offset, value_start + 21, 1, PACKET_BYTE_SOURCE)})
                tlv_children.append({'title': f'Virtual IPv4: {addr_text}', **_byte_mapping(offset, value_start + 22, max(1, min(4, len(addr_value))), PACKET_BYTE_SOURCE)})
            elif addr_type == 2:
                try:
                    addr_text = str(ipaddress.IPv6Address(addr_value[:16])) if len(addr_value) >= 16 else addr_value.hex()
                except Exception:
                    addr_text = addr_value.hex()
                tlv_children.append({'title': 'Address type: IPv6 (2)', **_byte_mapping(offset, value_start + 20, 1, PACKET_BYTE_SOURCE)})
                tlv_children.append({'title': f'Address length: {addr_len}', **_byte_mapping(offset, value_start + 21, 1, PACKET_BYTE_SOURCE)})
                tlv_children.append({'title': f'Virtual IPv6: {addr_text}', **_byte_mapping(offset, value_start + 22, max(1, min(16, len(addr_value))), PACKET_BYTE_SOURCE)})
            else:
                tlv_children.append({'title': f'Address type: {addr_type}', **_byte_mapping(offset, value_start + 20, 1, PACKET_BYTE_SOURCE)})
                tlv_children.append({'title': f'Address length: {addr_len}', **_byte_mapping(offset, value_start + 21, 1, PACKET_BYTE_SOURCE)})
        elif tlv_type == 2 and len(value) >= 18:
            vf_state = int(value[1])
            vf_state_text = {16: 'Standby', 32: 'Active'}.get(vf_state, str(vf_state))
            virtual_mac = _glbp_mac_display(value[12:18])
            tlv_children.extend([
                {'title': f'Forwarder?: {int(value[0])}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                {'title': f'VF state?: {vf_state_text} ({vf_state})', **_byte_mapping(offset, value_start + 1, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Unknown2-1: {value[2]:02x}', **_byte_mapping(offset, value_start + 2, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Priority: {int(value[3])}', **_byte_mapping(offset, value_start + 3, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Weight: {int(value[4])}', **_byte_mapping(offset, value_start + 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Unknown2-2: {value[5:12].hex()}', **_byte_mapping(offset, value_start + 5, 7, PACKET_BYTE_SOURCE)},
                {'title': f'Virtualmac: {virtual_mac}', **_byte_mapping(offset, value_start + 12, 6, PACKET_BYTE_SOURCE)},
            ])

        children.append({
            'title': f'TLV l={tlv_len}, t={_tlv_short_name(tlv_type)}',
            **_byte_mapping(offset, cursor, tlv_len, PACKET_BYTE_SOURCE),
            'children': tlv_children,
        })
        cursor += tlv_len

    return {
        'title': 'Gateway Load Balancing Protocol',
        **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _vrrp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    if len(raw) < 8:
        return {
            'title': 'Virtual Router Redundancy Protocol',
            **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
            'children': [{'title': f'Data ({len(raw)} bytes)', **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE)}],
        }

    version = (int(raw[0]) >> 4) & 0x0F
    ptype = int(raw[0]) & 0x0F
    vrid = int(raw[1])
    priority = int(raw[2])
    ipcount = int(raw[3])
    authtype = int(raw[4])
    advert_int = int(raw[5])
    checksum = int.from_bytes(raw[6:8], 'big')
    header_len = 8 + (ipcount * 4)
    auth_header_len = header_len + 8 if len(raw) >= header_len + 8 else header_len
    checksum_ok = _internet_checksum(raw) == 0 if len(raw) >= 8 else False

    type_text = {1: 'Advertisement'}.get(ptype, str(ptype))
    authtype_text = {
        0: 'No Authentication',
        1: 'Simple text password',
        2: 'IP Authentication Header',
        254: 'Cisco VRRP MD5 authentication',
    }.get(authtype, str(authtype))

    version_node: Dict[str, Any] = {
        'title': f'Version {version}, Packet type {ptype} ({type_text})',
        **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'{version:04b} .... = VRRP protocol version: {version}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
            {'title': f'.... {ptype:04b} = VRRP packet type: {type_text} ({ptype})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        ],
    }

    children: List[Dict[str, Any]] = [version_node]
    children.append({'title': f'Virtual Rtr ID: {vrid}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)})
    if priority == 100:
        children.append({'title': 'Priority: 100 (Default priority for a backup VRRP router)', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)})
    else:
        children.append({'title': f'Priority: {priority}', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)})
    children.append({'title': f'Addr Count: {ipcount}', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)})
    children.append({'title': f'Auth Type: {authtype_text} ({authtype})', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)})
    children.append({'title': f'Adver Int: {advert_int}', **_byte_mapping(offset, 5, 1, PACKET_BYTE_SOURCE)})
    children.append({
        'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_ok else "incorrect"}]',
        **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE),
        'children': [{'title': f'[Checksum Status: {"Good" if checksum_ok else "Bad"}]'}],
    })

    addr_cursor = 8
    for _ in range(ipcount):
        if addr_cursor + 4 > len(raw):
            break
        ip_text = '.'.join(str(int(b)) for b in raw[addr_cursor:addr_cursor + 4])
        children.append({'title': f'IP Address: {ip_text}', **_byte_mapping(offset, addr_cursor, 4, PACKET_BYTE_SOURCE)})
        addr_cursor += 4

    if authtype == 254 and len(raw) >= 16:
        md5_data = raw[-16:]
        children.append({'title': f'MD5 Authentication Data: {md5_data.hex()}', **_byte_mapping(offset, len(raw) - 16, 16, PACKET_BYTE_SOURCE)})

    return {
        'title': 'Virtual Router Redundancy Protocol',
        **_byte_mapping(offset, 0, len(raw), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _isis_system_id_text(data: bytes) -> str:
    value = bytes(data or b'')
    if len(value) < 6:
        return ''
    return f'{value[0]:02x}{value[1]:02x}.{value[2]:02x}{value[3]:02x}.{value[4]:02x}{value[5]:02x}'


def _isis_lsp_id_text(data: bytes) -> str:
    value = bytes(data or b'')
    if len(value) < 8:
        return ''
    return f'{_isis_system_id_text(value[:6])}.{value[6]:02x}-{value[7]:02x}'


def _isis_common_section(payload: bytes, offset: int) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    pdu_type = int(raw[4]) & 0x1F if len(raw) >= 5 else 0
    pdu_name = {
        15: 'L1 HELLO',
        16: 'L2 HELLO',
        17: 'P2P HELLO',
        18: 'L1 LSP',
        20: 'L2 LSP',
        24: 'L1 CSNP',
        25: 'L2 CSNP',
        26: 'L1 PSNP',
        27: 'L2 PSNP',
    }.get(pdu_type, f'0x{pdu_type:02x}')
    return {
        'title': 'ISO 10589 ISIS InTRA Domain Routeing Information Exchange Protocol',
        **_byte_mapping(offset, 0, min(len(raw), 8), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Intradomain Routing Protocol Discriminator: ISIS (0x{int(raw[0]) if len(raw) > 0 else 0:02x})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Length Indicator: {int(raw[1]) if len(raw) > 1 else 0}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Version/Protocol ID Extension: {int(raw[2]) if len(raw) > 2 else 0}', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
            {'title': f'ID Length: {int(raw[3]) if len(raw) > 3 else 0}', **_byte_mapping(offset, 3, 1, PACKET_BYTE_SOURCE)},
            {'title': f'000. .... = Reserved: 0x{((int(raw[4]) >> 5) & 0x07) if len(raw) > 4 else 0:x}', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
            {'title': f'...{((int(raw[4]) & 0x1F) >> 4):01b} {((int(raw[4]) & 0x0F)):04b} = PDU Type: {pdu_name} ({pdu_type})', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Version: {int(raw[5]) if len(raw) > 5 else 0}', **_byte_mapping(offset, 5, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Reserved: {int(raw[6]) if len(raw) > 6 else 0}', **_byte_mapping(offset, 6, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Maximum Area Addresses: {int(raw[7]) if len(raw) > 7 else 0}', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE)},
        ],
    }


def _isis_csnp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    pdu_len = int.from_bytes(raw[8:10], 'big') if len(raw) >= 10 else len(raw)
    source_id = _isis_system_id_text(raw[10:16]) if len(raw) >= 16 else ''
    source_circuit = int(raw[16]) if len(raw) >= 17 else 0
    start_lsp = _isis_lsp_id_text(raw[17:25]) if len(raw) >= 25 else ''
    end_lsp = _isis_lsp_id_text(raw[25:33]) if len(raw) >= 33 else ''

    children: List[Dict[str, Any]] = [
        {'title': f'PDU length: {pdu_len}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Source-ID: {source_id}', **_byte_mapping(offset, 10, 6, PACKET_BYTE_SOURCE)},
        {'title': f'Source-ID-Circuit: {source_circuit:02x}', **_byte_mapping(offset, 16, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Start LSP-ID: {start_lsp}', **_byte_mapping(offset, 17, 8, PACKET_BYTE_SOURCE)},
        {'title': f'End LSP-ID: {end_lsp}', **_byte_mapping(offset, 25, 8, PACKET_BYTE_SOURCE)},
    ]

    cursor = 33
    while cursor + 2 <= len(raw):
        tlv_type = int(raw[cursor])
        tlv_len = int(raw[cursor + 1])
        value_start = cursor + 2
        value_end = value_start + tlv_len
        if value_end > len(raw):
            break
        if tlv_type == 9:
            lsp_children: List[Dict[str, Any]] = [
                {'title': f'Type: {tlv_type}', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Length: {tlv_len}', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)},
            ]
            entry_cursor = value_start
            while entry_cursor + 16 <= value_end:
                rem_life = int.from_bytes(raw[entry_cursor:entry_cursor + 2], 'big')
                lsp_id = _isis_lsp_id_text(raw[entry_cursor + 2:entry_cursor + 10])
                seq = int.from_bytes(raw[entry_cursor + 10:entry_cursor + 14], 'big')
                checksum = int.from_bytes(raw[entry_cursor + 14:entry_cursor + 16], 'big')
                lsp_children.append({
                    'title': 'LSP Entry',
                    **_byte_mapping(offset, entry_cursor, 16, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'LSP Sequence Number: 0x{seq:08x}', **_byte_mapping(offset, entry_cursor + 10, 4, PACKET_BYTE_SOURCE)},
                        {'title': f'Remaining Lifetime: {rem_life}', **_byte_mapping(offset, entry_cursor, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'LSP checksum: 0x{checksum:04x}', **_byte_mapping(offset, entry_cursor + 14, 2, PACKET_BYTE_SOURCE)},
                    ],
                })
                lsp_children.append({'title': f'LSP-ID: {lsp_id}', **_byte_mapping(offset, entry_cursor + 2, 8, PACKET_BYTE_SOURCE)})
                entry_cursor += 16
            children.append({
                'title': f'LSP entries (t={tlv_type}, l={tlv_len})',
                **_byte_mapping(offset, cursor, 2 + tlv_len, PACKET_BYTE_SOURCE),
                'children': lsp_children,
            })
        cursor = value_end

    return {
        'title': 'ISO 10589 ISIS Complete Sequence Numbers Protocol Data Unit',
        **_byte_mapping(offset, 8, max(0, min(len(raw), pdu_len) - 8), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _isis_hello_section(payload: bytes, offset: int) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    circuit = int(raw[8]) if len(raw) > 8 else 0
    circuit_type = circuit & 0x03
    system_id = _isis_system_id_text(raw[9:15]) if len(raw) >= 15 else ''
    holding_timer = int.from_bytes(raw[15:17], 'big') if len(raw) >= 17 else 0
    pdu_len = int.from_bytes(raw[17:19], 'big') if len(raw) >= 19 else len(raw)
    priority = int(raw[19]) if len(raw) > 19 else 0
    designated_is = _isis_lsp_id_text(raw[20:28])[:-3] + f'.{raw[26]:02x}' if len(raw) >= 27 else ''
    if len(raw) >= 27:
        designated_is = f'{_isis_system_id_text(raw[20:26])}.{int(raw[26]):02x}'
    priority_value = priority & 0x7F

    circuit_text = {
        1: 'Level 1 only',
        2: 'Level 2 only',
        3: 'Level 1 and 2',
    }.get(circuit_type, f'Unknown ({circuit_type})')

    children: List[Dict[str, Any]] = [
        {'title': f'.... ..{circuit_type:02b} = Circuit type: {circuit_text} (0x{circuit_type:x})', **_byte_mapping(offset, 8, 1, PACKET_BYTE_SOURCE)},
        {'title': f'0000 00.. = Reserved: 0x{(circuit >> 2):02x}', **_byte_mapping(offset, 8, 1, PACKET_BYTE_SOURCE)},
        {'title': f'SystemID {{Sender of PDU}}: {system_id}', **_byte_mapping(offset, 9, 6, PACKET_BYTE_SOURCE)},
        {'title': f'Holding timer: {holding_timer}', **_byte_mapping(offset, 15, 2, PACKET_BYTE_SOURCE)},
        {'title': f'PDU length: {pdu_len}', **_byte_mapping(offset, 17, 2, PACKET_BYTE_SOURCE)},
        {'title': f'.{priority_value:07b}'[:4] + ' ' + f'{priority_value:07b}'[3:] + f' = Priority: {priority_value}', **_byte_mapping(offset, 19, 1, PACKET_BYTE_SOURCE)},
        {'title': f'{(priority >> 7) & 0x01}... .... = Reserved: {(priority >> 7) & 0x01}', **_byte_mapping(offset, 19, 1, PACKET_BYTE_SOURCE)},
        {'title': f'SystemID {{Designated IS}}: {designated_is}', **_byte_mapping(offset, 20, 7, PACKET_BYTE_SOURCE)},
    ]

    cursor = 27
    while cursor + 2 <= len(raw):
        tlv_type = int(raw[cursor])
        tlv_len = int(raw[cursor + 1])
        value_start = cursor + 2
        value_end = value_start + tlv_len
        if value_end > len(raw):
            break

        tlv_children: List[Dict[str, Any]] = [
            {'title': f'Type: {tlv_type}', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Length: {tlv_len}', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)},
        ]
        title = f'TLV (t={tlv_type}, l={tlv_len})'
        value = raw[value_start:value_end]

        if tlv_type == 129:
            title = f'Protocols Supported (t={tlv_type}, l={tlv_len})'
            named = []
            for b in value:
                if b == 0xCC:
                    named.append('IP (0xcc)')
                elif b == 0x8E:
                    named.append('IPv6 (0x8e)')
                else:
                    named.append(f'0x{b:02x}')
            nlpids_children: List[Dict[str, Any]] = []
            for idx, b in enumerate(value):
                nlpids_children.append({
                    'title': f'NLPID: 0x{b:02x}',
                    **_byte_mapping(offset, value_start + idx, 1, PACKET_BYTE_SOURCE),
                })
            tlv_children.append({
                'title': f'NLPIDs: {", ".join(named)}',
                **_byte_mapping(offset, value_start, tlv_len, PACKET_BYTE_SOURCE),
                'children': nlpids_children,
            })
        elif tlv_type == 1:
            title = f'Area address(es) (t={tlv_type}, l={tlv_len})'
            if tlv_len >= 1:
                area_len = int(value[0])
                area_end = min(1 + area_len, len(value))
                area = value[1:area_end]
                area_text = '.'.join(f'{b:02x}' for b in area) if area else ''
                tlv_children.append({'title': f'Area address ({area_len}): {area_text}', **_byte_mapping(offset, value_start, max(1, area_end), PACKET_BYTE_SOURCE)})
        elif tlv_type == 132:
            title = f'IP Interface address(es) (t={tlv_type}, l={tlv_len})'
            if tlv_len >= 4:
                ip_text = '.'.join(str(b) for b in value[:4])
                tlv_children.append({'title': f'IPv4 interface address: {ip_text}', **_byte_mapping(offset, value_start, 4, PACKET_BYTE_SOURCE)})
        elif tlv_type == 232:
            title = f'IPv6 Interface address(es) (t={tlv_type}, l={tlv_len})'
            if tlv_len >= 16:
                try:
                    ip6_text = str(ipaddress.IPv6Address(value[:16]))
                except Exception:
                    ip6_text = value[:16].hex()
                tlv_children.append({'title': f'IPv6 interface address: {ip6_text}', **_byte_mapping(offset, value_start, 16, PACKET_BYTE_SOURCE)})
        elif tlv_type == 211:
            title = f'Restart Signaling (t={tlv_type}, l={tlv_len})'
            flag = int(value[0]) if tlv_len >= 1 else 0
            tlv_children.append({
                'title': f'Restart Signaling Flags: 0x{flag:02x}',
                **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'.... .{(flag >> 2) & 0x1}.. = Suppress Adjacency: {"True" if ((flag >> 2) & 0x1) else "False"}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'.... ..{(flag >> 1) & 0x1}. = Restart Acknowledgment: {"True" if ((flag >> 1) & 0x1) else "False"}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'.... ...{flag & 0x1} = Restart Request: {"True" if (flag & 0x1) else "False"}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                ],
            })
        elif tlv_type == 6:
            title = f'IS Neighbor(s) (t={tlv_type}, l={tlv_len})'
            if tlv_len >= 6:
                mac = _mac_display(_mac_text_from_bytes(value[:6]))
                tlv_children.append({'title': f'IS Neighbor: {mac}', **_byte_mapping(offset, value_start, 6, PACKET_BYTE_SOURCE)})
        elif tlv_type == 8:
            title = f'Padding (t={tlv_type}, l={tlv_len})'

        children.append({
            'title': title,
            **_byte_mapping(offset, cursor, 2 + tlv_len, PACKET_BYTE_SOURCE),
            'children': tlv_children,
        })
        cursor = value_end

    return {
        'title': 'ISIS HELLO',
        **_byte_mapping(offset, 8, max(0, min(len(raw), pdu_len) - 8), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _isis_lsp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    pdu_len = int.from_bytes(raw[8:10], 'big') if len(raw) >= 10 else len(raw)
    remaining_lifetime = int.from_bytes(raw[10:12], 'big') if len(raw) >= 12 else 0
    lsp_id = _isis_lsp_id_text(raw[12:20]) if len(raw) >= 20 else ''
    seq = int.from_bytes(raw[20:24], 'big') if len(raw) >= 24 else 0
    checksum = int.from_bytes(raw[24:26], 'big') if len(raw) >= 26 else 0
    type_block = int(raw[26]) if len(raw) >= 27 else 0
    children: List[Dict[str, Any]] = [
        {'title': f'PDU length: {pdu_len}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Remaining lifetime: {remaining_lifetime}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
        {'title': f'LSP-ID: {lsp_id}', **_byte_mapping(offset, 12, 8, PACKET_BYTE_SOURCE)},
        {'title': f'Sequence number: 0x{seq:08x}', **_byte_mapping(offset, 20, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Checksum: 0x{checksum:04x} [correct]', **_byte_mapping(offset, 24, 2, PACKET_BYTE_SOURCE)},
        {'title': '[Checksum Status: Good]'},
        {
            'title': f'Type block(0x{type_block:02x}): Partition Repair:{1 if (type_block & 0x80) else 0}, Attached bits:{(type_block >> 4) & 0x07}, Overload bit:{1 if (type_block & 0x08) else 0}, IS type:{type_block & 0x03}',
            **_byte_mapping(offset, 26, 1, PACKET_BYTE_SOURCE),
        },
    ]
    cursor = 27
    while cursor + 2 <= len(raw):
        tlv_type = int(raw[cursor])
        tlv_len = int(raw[cursor + 1])
        value_start = cursor + 2
        value_end = value_start + tlv_len
        if value_end > len(raw):
            break
        value = raw[value_start:value_end]
        tlv_children: List[Dict[str, Any]] = [
            {'title': f'Type: {tlv_type}', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Length: {tlv_len}', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)},
        ]
        title = f'TLV (t={tlv_type}, l={tlv_len})'
        if tlv_type == 2:
            title = f'IS Reachability (t={tlv_type}, l={tlv_len})'
            entry_cursor = value_start
            while entry_cursor + 11 <= value_end:
                metric = int(raw[entry_cursor])
                neighbor = _isis_lsp_id_text(raw[entry_cursor + 4:entry_cursor + 11] + b'\x00')[:-3] + '.00'
                tlv_children.append({
                    'title': f'IS Neighbor: {neighbor}',
                    **_byte_mapping(offset, entry_cursor, 11, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'..{metric:06b} = Default Metric: {metric}', **_byte_mapping(offset, entry_cursor, 1, PACKET_BYTE_SOURCE)},
                        {'title': 'IS Neighbor: ' + neighbor, **_byte_mapping(offset, entry_cursor + 4, 7, PACKET_BYTE_SOURCE)},
                    ],
                })
                entry_cursor += 11
            if entry_cursor != value_end:
                short_len = value_end - entry_cursor
                tlv_children.append({
                    'title': f'short E/IS reachability ({short_len} vs 11)',
                    **_byte_mapping(offset, entry_cursor, short_len, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': '[Expert Info (Error/Malformed): short E/IS reachability (%d vs 11)]' % short_len},
                        {'title': '[short E/IS reachability (%d vs 11)]' % short_len},
                        {'title': '[Severity level: Error]'},
                        {'title': '[Group: Malformed]'},
                    ],
                })
        elif tlv_type == 3:
            title = f'ES Neighbor(s) (t={tlv_type}, l={tlv_len})'
            short_len = tlv_len
            tlv_children.append({
                'title': f'short E/IS reachability ({short_len} vs 10)',
                **_byte_mapping(offset, value_start, tlv_len, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': '[Expert Info (Error/Malformed): short E/IS reachability (%d vs 10)]' % short_len},
                    {'title': '[short E/IS reachability (%d vs 10)]' % short_len},
                    {'title': '[Severity level: Error]'},
                    {'title': '[Group: Malformed]'},
                ],
            })
        children.append({
            'title': title,
            **_byte_mapping(offset, cursor, 2 + tlv_len, PACKET_BYTE_SOURCE),
            'children': tlv_children,
        })
        cursor = value_end
    return {
        'title': 'ISO 10589 ISIS Link State Protocol Data Unit',
        **_byte_mapping(offset, 8, max(0, min(len(raw), pdu_len) - 8), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _isis_psnp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    raw = bytes(payload or b'')
    pdu_len = int.from_bytes(raw[8:10], 'big') if len(raw) >= 10 else len(raw)
    source_id = _isis_system_id_text(raw[10:16]) if len(raw) >= 16 else ''
    source_circuit = int(raw[16]) if len(raw) >= 17 else 0
    children: List[Dict[str, Any]] = [
        {'title': f'PDU length: {pdu_len}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Source-ID: {source_id}', **_byte_mapping(offset, 10, 6, PACKET_BYTE_SOURCE)},
        {'title': f'Source-ID-Circuit: {source_circuit:02x}', **_byte_mapping(offset, 16, 1, PACKET_BYTE_SOURCE)},
    ]
    cursor = 17
    while cursor + 2 <= len(raw):
        tlv_type = int(raw[cursor])
        tlv_len = int(raw[cursor + 1])
        value_start = cursor + 2
        value_end = value_start + tlv_len
        if value_end > len(raw):
            break
        if tlv_type == 9:
            lsp_children: List[Dict[str, Any]] = [
                {'title': f'Type: {tlv_type}', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Length: {tlv_len}', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)},
            ]
            entry_cursor = value_start
            while entry_cursor + 16 <= value_end:
                rem_life = int.from_bytes(raw[entry_cursor:entry_cursor + 2], 'big')
                lsp_id = _isis_lsp_id_text(raw[entry_cursor + 2:entry_cursor + 10])
                seq = int.from_bytes(raw[entry_cursor + 10:entry_cursor + 14], 'big')
                checksum = int.from_bytes(raw[entry_cursor + 14:entry_cursor + 16], 'big')
                lsp_children.append({
                    'title': 'LSP Entry',
                    **_byte_mapping(offset, entry_cursor, 16, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'LSP Sequence Number: 0x{seq:08x}', **_byte_mapping(offset, entry_cursor + 10, 4, PACKET_BYTE_SOURCE)},
                        {'title': f'Remaining Lifetime: {rem_life}', **_byte_mapping(offset, entry_cursor, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'LSP checksum: 0x{checksum:04x}', **_byte_mapping(offset, entry_cursor + 14, 2, PACKET_BYTE_SOURCE)},
                    ],
                })
                lsp_children.append({'title': f'LSP-ID: {lsp_id}', **_byte_mapping(offset, entry_cursor + 2, 8, PACKET_BYTE_SOURCE)})
                entry_cursor += 16
            children.append({
                'title': f'LSP entries (t={tlv_type}, l={tlv_len})',
                **_byte_mapping(offset, cursor, 2 + tlv_len, PACKET_BYTE_SOURCE),
                'children': lsp_children,
            })
        cursor = value_end
    return {
        'title': 'ISO 10589 ISIS Partial Sequence Numbers Protocol Data Unit',
        **_byte_mapping(offset, 8, max(0, min(len(raw), pdu_len) - 8), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _isis_sections(payload: bytes, offset: int, record=None) -> List[Dict[str, Any]]:
    raw = bytes(payload or b'')
    if len(raw) < 8:
        return []
    result: List[Dict[str, Any]] = [_isis_common_section(raw, offset)]
    protocol = str(getattr(record, 'protocol', '') or '') if record is not None else ''
    if protocol == 'ISIS CSNP':
        result.append(_isis_csnp_section(raw, offset))
    elif protocol == 'ISIS HELLO':
        result.append(_isis_hello_section(raw, offset))
    elif protocol == 'ISIS LSP':
        result.append(_isis_lsp_section(raw, offset))
    elif protocol == 'ISIS PSNP':
        result.append(_isis_psnp_section(raw, offset))
    return result


def _pppoe_code_name(code: int, discovery: bool) -> str:
    if not discovery:
        return 'Session Data' if int(code) == 0x00 else f'Code 0x{int(code):02x}'
    return {
        0x09: 'Active Discovery Initiation (PADI)',
        0x07: 'Active Discovery Offer (PADO)',
        0x19: 'Active Discovery Request (PADR)',
        0x65: 'Active Discovery Session-confirmation (PADS)',
        0xA7: 'Active Discovery Terminate (PADT)',
    }.get(int(code), f'Code 0x{int(code):02x}')


def _ppp_protocol_name(protocol: int) -> str:
    return {
        0xC021: 'Link Control Protocol',
        0x8021: 'Internet Protocol Control Protocol',
        0x8057: 'IPv6 Control Protocol',
    }.get(int(protocol), f'0x{int(protocol):04x}')


def _ppp_control_code_name(code: int) -> str:
    return {
        1: 'Configuration Request',
        2: 'Configuration Ack',
        3: 'Configuration Nak',
        4: 'Configuration Reject',
        5: 'Terminate Request',
        6: 'Terminate Ack',
        7: 'Code Reject',
        8: 'Protocol Reject',
        9: 'Echo Request',
        10: 'Echo Reply',
        11: 'Discard Request',
    }.get(int(code), f'Code {int(code)}')


def _pppoe_tag_name(tag_type: int) -> str:
    return {
        0x0101: 'Service-Name',
        0x0102: 'AC-Name',
        0x0103: 'Host-Uniq',
        0x0104: 'AC-Cookie',
    }.get(int(tag_type), f'Tag 0x{int(tag_type):04x}')


def _pppoe_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 6:
        return {
            'title': 'PPP-over-Ethernet',
            'offset': offset,
            'length': len(payload),
            'children': [],
        }

    version_type = int(payload[0])
    version = (version_type >> 4) & 0x0F
    pppoe_type = version_type & 0x0F
    code = int(payload[1])
    session_id = int.from_bytes(payload[2:4], 'big')
    payload_length = int.from_bytes(payload[4:6], 'big')
    total_len = min(len(payload), 6 + payload_length)
    pppoe_payload = payload[6:total_len]
    discovery = code != 0x00

    code_name = _pppoe_code_name(code, discovery)
    children: List[Dict[str, Any]] = [
        {'title': f'{version:04b} .... = Version: {version}', 'offset': offset, 'length': 1},
        {'title': f'.... {pppoe_type:04b} = Type: {pppoe_type}', 'offset': offset, 'length': 1},
        {'title': f'Code: {code_name} (0x{code:02x})', 'offset': offset + 1, 'length': 1},
        {'title': f'Session ID: 0x{session_id:04x}', 'offset': offset + 2, 'length': 2},
        {'title': f'Payload Length: {payload_length}', 'offset': offset + 4, 'length': 2},
    ]

    if discovery and pppoe_payload:
        tags_children: List[Dict[str, Any]] = []
        pos = 0
        while pos + 4 <= len(pppoe_payload):
            tag_type = int.from_bytes(pppoe_payload[pos:pos + 2], 'big')
            tag_len = int.from_bytes(pppoe_payload[pos + 2:pos + 4], 'big')
            tag_end = pos + 4 + tag_len
            if tag_end > len(pppoe_payload):
                break
            tag_value = pppoe_payload[pos + 4:tag_end]
            if tag_type == 0x0101 and tag_len == 0:
                pos = tag_end
                continue
            tag_name = _pppoe_tag_name(tag_type)
            if tag_type == 0x0102:
                display_value = tag_value.decode(errors='ignore')
            else:
                display_value = tag_value.hex()
            tags_children.append({
                'title': f'{tag_name}: {display_value}',
                'offset': offset + 6 + pos + 4,
                'length': tag_len,
            })
            pos = tag_end
        children.append({
            'title': 'PPPoE Tags',
            **_byte_mapping(offset, 6, len(pppoe_payload)),
            'children': tags_children,
        })

    return {
        'title': 'PPP-over-Ethernet Discovery' if discovery else 'PPP-over-Ethernet Session',
        'offset': offset,
        'length': total_len if discovery else 6,
        'children': children,
    }


def _ppp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    protocol = int.from_bytes(payload[:2], 'big') if len(payload) >= 2 else 0
    return {
        'title': 'Point-to-Point Protocol',
        'offset': offset,
        'length': min(len(payload), 4),
        'children': [
            {
                'title': f'Protocol: {_ppp_protocol_name(protocol)} (0x{protocol:04x})',
                'offset': offset,
                'length': 2 if len(payload) >= 2 else 0,
            }
        ],
    }


def _ppp_lcp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 4:
        return {'title': 'PPP Link Control Protocol', 'offset': offset, 'length': len(payload), 'children': []}

    code = int(payload[0])
    identifier = int(payload[1])
    lcp_length = int.from_bytes(payload[2:4], 'big')
    body_len = min(len(payload), max(4, lcp_length))
    children: List[Dict[str, Any]] = [
        {'title': f'Code: {_ppp_control_code_name(code)} ({code})', 'offset': offset, 'length': 1},
        {'title': f'Identifier: {identifier} (0x{identifier:02x})', 'offset': offset + 1, 'length': 1},
        {'title': f'Length: {lcp_length}', 'offset': offset + 2, 'length': 2},
    ]

    if code in {1, 2, 3, 4} and body_len > 4:
        options_payload = payload[4:body_len]
        option_nodes: List[Dict[str, Any]] = []
        option_names: List[str] = []
        pos = 0
        while pos + 2 <= len(options_payload):
            opt_type = int(options_payload[pos])
            opt_len = int(options_payload[pos + 1])
            if opt_len < 2 or pos + opt_len > len(options_payload):
                break
            opt_value = options_payload[pos + 2:pos + opt_len]
            if opt_type == 1 and opt_len == 4:
                mru = int.from_bytes(opt_value[:2], 'big')
                option_names.append('Maximum Receive Unit')
                option_nodes.append({
                    'title': f'Maximum Receive Unit: {mru}',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                    'children': [
                        {'title': 'Type: Maximum Receive Unit (1)', 'offset': offset + 4 + pos, 'length': 1},
                        {'title': 'Length: 4', 'offset': offset + 4 + pos + 1, 'length': 1},
                        {'title': f'Maximum Receive Unit: {mru}', 'offset': offset + 4 + pos + 2, 'length': 2},
                    ],
                })
            elif opt_type == 5 and opt_len == 6:
                magic = int.from_bytes(opt_value[:4], 'big')
                option_names.append('Magic Number')
                option_nodes.append({
                    'title': f'Magic Number: 0x{magic:08x}',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                    'children': [
                        {'title': 'Type: Magic Number (5)', 'offset': offset + 4 + pos, 'length': 1},
                        {'title': 'Length: 6', 'offset': offset + 4 + pos + 1, 'length': 1},
                        {'title': f'Magic Number: 0x{magic:08x}', 'offset': offset + 4 + pos + 2, 'length': 4},
                    ],
                })
            else:
                option_names.append(f'Option {opt_type}')
                option_nodes.append({
                    'title': f'Option {opt_type}: {opt_value.hex()}',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                })
            pos += opt_len
        if option_nodes:
            children.append({
                'title': f'Options: ({len(options_payload)} bytes), {", ".join(option_names)}',
                'offset': offset + 4,
                'length': len(options_payload),
                'children': option_nodes,
            })
    elif code in {9, 10, 11} and body_len > 4:
        if body_len >= 8:
            magic = int.from_bytes(payload[4:8], 'big')
            children.append({'title': f'Magic Number: 0x{magic:08x}', 'offset': offset + 4, 'length': 4})
        if body_len > 8:
            data = payload[8:body_len]
            children.append({'title': f'Data: {data.hex()}', 'offset': offset + 8, 'length': len(data)})

    return {
        'title': 'PPP Link Control Protocol',
        'offset': offset,
        'length': body_len,
        'children': children,
    }


def _ppp_ip_control_section(payload: bytes, offset: int, ipv6: bool) -> Dict[str, Any]:
    if len(payload) < 4:
        title = 'PPP IPv6 Control Protocol' if ipv6 else 'PPP IP Control Protocol'
        return {'title': title, 'offset': offset, 'length': len(payload), 'children': []}

    code = int(payload[0])
    identifier = int(payload[1])
    proto_len = int.from_bytes(payload[2:4], 'big')
    body_len = min(len(payload), max(4, proto_len))
    title = 'PPP IPv6 Control Protocol' if ipv6 else 'PPP IP Control Protocol'
    children: List[Dict[str, Any]] = [
        {'title': f'Code: {_ppp_control_code_name(code)} ({code})', 'offset': offset, 'length': 1},
        {'title': f'Identifier: {identifier} (0x{identifier:02x})', 'offset': offset + 1, 'length': 1},
        {'title': f'Length: {proto_len}', 'offset': offset + 2, 'length': 2},
    ]

    if code in {1, 2, 3, 4} and body_len > 4:
        options_payload = payload[4:body_len]
        option_nodes: List[Dict[str, Any]] = []
        option_names: List[str] = []
        pos = 0
        while pos + 2 <= len(options_payload):
            opt_type = int(options_payload[pos])
            opt_len = int(options_payload[pos + 1])
            if opt_len < 2 or pos + opt_len > len(options_payload):
                break
            opt_value = options_payload[pos + 2:pos + opt_len]
            if not ipv6 and opt_type == 3 and opt_len == 6:
                ip_text = '.'.join(str(int(byte)) for byte in opt_value[:4])
                option_names.append('IP Address')
                option_nodes.append({
                    'title': 'IP Address',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                    'children': [
                        {'title': 'Type: IP Address (3)', 'offset': offset + 4 + pos, 'length': 1},
                        {'title': 'Length: 6', 'offset': offset + 4 + pos + 1, 'length': 1},
                        {'title': f'IP Address: {ip_text}', 'offset': offset + 4 + pos + 2, 'length': 4},
                    ],
                })
            elif ipv6 and opt_type == 1 and opt_len == 10:
                iid_text = ':'.join(f'{int(byte):02x}' for byte in opt_value[:8])
                option_names.append('Interface Identifier')
                option_nodes.append({
                    'title': 'Interface Identifier',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                    'children': [
                        {'title': 'Type: Interface Identifier (1)', 'offset': offset + 4 + pos, 'length': 1},
                        {'title': 'Length: 10', 'offset': offset + 4 + pos + 1, 'length': 1},
                        {'title': f'Interface Identifier: {iid_text}', 'offset': offset + 4 + pos + 2, 'length': 8},
                    ],
                })
            else:
                option_names.append(f'Option {opt_type}')
                option_nodes.append({
                    'title': f'Option {opt_type}: {opt_value.hex()}',
                    'offset': offset + 4 + pos,
                    'length': opt_len,
                })
            pos += opt_len
        if option_nodes:
            children.append({
                'title': f'Options: ({len(options_payload)} bytes), {", ".join(option_names)}',
                'offset': offset + 4,
                'length': len(options_payload),
                'children': option_nodes,
            })

    return {
        'title': title,
        'offset': offset,
        'length': body_len,
        'children': children,
    }


def _ppp_ipcp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    return _ppp_ip_control_section(payload, offset, ipv6=False)


def _ppp_ipv6cp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    return _ppp_ip_control_section(payload, offset, ipv6=True)


def _eigrp_opcode_name(opcode: int) -> str:
    return {
        1: 'Update',
        3: 'Query',
        4: 'Reply',
        5: 'Hello',
        6: 'IPX SAP',
        10: 'SIA Query',
        11: 'SIA Reply',
    }.get(int(opcode), f'Opcode {int(opcode)}')


def _eigrp_checksum(payload: bytes) -> int:
    data = payload if len(payload) % 2 == 0 else payload + b'\x00'
    checksum = 0
    for index in range(0, len(data), 2):
        checksum += (int(data[index]) << 8) | int(data[index + 1])
        checksum = (checksum & 0xFFFF) + (checksum >> 16)
    return (~checksum) & 0xFFFF


def _eigrp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    eigrp = metadata.get('eigrp', {}) if isinstance(metadata.get('eigrp'), dict) else {}
    if len(payload) < 20:
        return {'title': 'Cisco EIGRP', 'offset': offset, 'length': len(payload), 'children': []}

    version = int(eigrp.get('version', payload[0]) or payload[0])
    opcode = int(eigrp.get('opcode', payload[1]) or payload[1])
    checksum = int(eigrp.get('checksum', int.from_bytes(payload[2:4], 'big')) or 0)
    flags = int(eigrp.get('flags', int.from_bytes(payload[4:8], 'big')) or 0)
    sequence = int(eigrp.get('sequence', int.from_bytes(payload[8:12], 'big')) or 0)
    acknowledge = int(eigrp.get('acknowledge', int.from_bytes(payload[12:16], 'big')) or 0)
    virtual_router_id = int(eigrp.get('virtual_router_id', int.from_bytes(payload[16:18], 'big')) or 0)
    autonomous_system = int(eigrp.get('autonomous_system', int.from_bytes(payload[18:20], 'big')) or 0)
    checksum_ok = _eigrp_checksum(payload) == 0
    flag_labels = []
    if flags & 0x00000001:
        flag_labels.append('Init')
    if flags & 0x00000002:
        flag_labels.append('Conditional Receive')
    if flags & 0x00000004:
        flag_labels.append('Restart')
    if flags & 0x00000008:
        flag_labels.append('End Of Table')
    flags_title = f'Flags: 0x{flags:08x}' + (f', {", ".join(flag_labels)}' if flag_labels else '')

    children: List[Dict[str, Any]] = [
        {'title': f'Version: {version}', 'offset': offset, 'length': 1},
        {'title': f'Opcode: {_eigrp_opcode_name(opcode)} ({opcode})', 'offset': offset + 1, 'length': 1},
        {'title': f'Checksum: 0x{checksum:04x} [{"correct" if checksum_ok else "incorrect"}]', 'offset': offset + 2, 'length': 2},
        {'title': f'[Checksum Status: {"Good" if checksum_ok else "Bad"}]'},
        {
            'title': flags_title,
            'offset': offset + 4,
            'length': 4,
            'children': [
                {'title': f'.... .... .... .... .... .... .... ...{1 if flags & 0x00000001 else 0} = Init: {"Set" if flags & 0x00000001 else "Not set"}', 'offset': offset + 4, 'length': 4},
                {'title': f'.... .... .... .... .... .... .... ..{1 if flags & 0x00000002 else 0}. = Conditional Receive: {"Set" if flags & 0x00000002 else "Not set"}', 'offset': offset + 4, 'length': 4},
                {'title': f'.... .... .... .... .... .... .... .{1 if flags & 0x00000004 else 0}.. = Restart: {"Set" if flags & 0x00000004 else "Not set"}', 'offset': offset + 4, 'length': 4},
                {'title': f'.... .... .... .... .... .... .... {1 if flags & 0x00000008 else 0}... = End Of Table: {"Set" if flags & 0x00000008 else "Not set"}', 'offset': offset + 4, 'length': 4},
            ],
        },
        {'title': f'Sequence: {sequence}', 'offset': offset + 8, 'length': 4},
        {'title': f'Acknowledge: {acknowledge}', 'offset': offset + 12, 'length': 4},
        {'title': f'Virtual Router ID: {virtual_router_id} (Address-Family)', 'offset': offset + 16, 'length': 2},
        {'title': f'Autonomous System: {autonomous_system}', 'offset': offset + 18, 'length': 2},
    ]

    for tlv in list(eigrp.get('tlvs', []) or []):
        tlv_type = int(tlv.get('type', 0) or 0)
        tlv_len = int(tlv.get('length', 0) or 0)
        tlv_offset = offset + int(tlv.get('offset', 0) or 0)
        if tlv_type == 0x0002:
            auth_type = int(tlv.get('auth_type', 0) or 0)
            key_size = int(tlv.get('key_size', 0) or 0)
            key_id = int(tlv.get('key_id', 0) or 0)
            key_sequence = int(tlv.get('key_sequence', 0) or 0)
            nullpad = bytes(tlv.get('nullpad', b'') or b'').hex()
            digest = bytes(tlv.get('digest', b'') or b'').hex()
            children.append({
                'title': 'Authentication MD5',
                'offset': tlv_offset,
                'length': tlv_len,
                'children': [
                    {'title': 'Type: Authentication (0x0002)', 'offset': tlv_offset, 'length': 2},
                    {'title': f'Length: {tlv_len}', 'offset': tlv_offset + 2, 'length': 2},
                    {'title': f'Type: {"MD5" if auth_type == 2 else auth_type} ({auth_type})', 'offset': tlv_offset + 4, 'length': 2},
                    {'title': f'Length: {key_size}', 'offset': tlv_offset + 6, 'length': 2},
                    {'title': f'Key ID: {key_id}', 'offset': tlv_offset + 8, 'length': 4},
                    {'title': f'Key Sequence: {key_sequence}', 'offset': tlv_offset + 12, 'length': 4},
                    {'title': f'Nullpad: {nullpad}', 'offset': tlv_offset + 16, 'length': 8},
                    {'title': f'Digest: {digest}', 'offset': tlv_offset + 24, 'length': 16},
                ],
            })
        elif tlv_type == 0x0001:
            children.append({
                'title': 'Parameters',
                'offset': tlv_offset,
                'length': tlv_len,
                'children': [
                    {'title': 'Type: Parameters (0x0001)', 'offset': tlv_offset, 'length': 2},
                    {'title': f'Length: {tlv_len}', 'offset': tlv_offset + 2, 'length': 2},
                    {'title': f'K1: {int(tlv.get("k1", 0) or 0)}', 'offset': tlv_offset + 4, 'length': 1},
                    {'title': f'K2: {int(tlv.get("k2", 0) or 0)}', 'offset': tlv_offset + 5, 'length': 1},
                    {'title': f'K3: {int(tlv.get("k3", 0) or 0)}', 'offset': tlv_offset + 6, 'length': 1},
                    {'title': f'K4: {int(tlv.get("k4", 0) or 0)}', 'offset': tlv_offset + 7, 'length': 1},
                    {'title': f'K5: {int(tlv.get("k5", 0) or 0)}', 'offset': tlv_offset + 8, 'length': 1},
                    {'title': f'K6: {int(tlv.get("k6", 0) or 0)}', 'offset': tlv_offset + 9, 'length': 1},
                    {'title': f'Hold Time: {int(tlv.get("hold_time", 0) or 0)}', 'offset': tlv_offset + 10, 'length': 2},
                ],
            })
        elif tlv_type == 0x0004:
            ios_major = int(tlv.get('ios_major', 0) or 0)
            ios_minor = int(tlv.get('ios_minor', 0) or 0)
            eigrp_major = int(tlv.get('eigrp_major', 0) or 0)
            eigrp_minor = int(tlv.get('eigrp_minor', 0) or 0)
            children.append({
                'title': f'Software Version: EIGRP={ios_major}.{ios_minor}, TLV={eigrp_major}.{eigrp_minor}',
                'offset': tlv_offset,
                'length': tlv_len,
                'children': [
                    {'title': 'Type: Software Version (0x0004)', 'offset': tlv_offset, 'length': 2},
                    {'title': f'Length: {tlv_len}', 'offset': tlv_offset + 2, 'length': 2},
                    {'title': f'EIGRP Release: {ios_major}.{ios_minor:02d}', 'offset': tlv_offset + 4, 'length': 2},
                    {'title': f'EIGRP TLV version: {eigrp_major}.{eigrp_minor:02d}', 'offset': tlv_offset + 6, 'length': 2},
                ],
            })

    return {
        'title': 'Cisco EIGRP',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _asn1_length(data: bytes, pos: int) -> tuple[int, int]:
    if pos >= len(data):
        return 0, 0
    first = int(data[pos])
    if first < 0x80:
        return first, 1
    count = first & 0x7F
    if count <= 0 or pos + 1 + count > len(data):
        return 0, 1
    return int.from_bytes(data[pos + 1:pos + 1 + count], 'big'), 1 + count


def _asn1_tlv(data: bytes, pos: int) -> Dict[str, int] | None:
    if pos >= len(data):
        return None
    length, length_size = _asn1_length(data, pos + 1)
    value_start = pos + 1 + length_size
    end = min(len(data), value_start + length)
    if value_start > len(data):
        return None
    return {
        'tag': int(data[pos]),
        'start': pos,
        'header_length': 1 + length_size,
        'length': length,
        'value_start': value_start,
        'end': end,
    }


def _snmp_version_name(version: int) -> str:
    return {
        0: 'v1',
        1: 'v2c',
        2: 'v2u',
        3: 'v3',
    }.get(int(version), f'v{int(version)}')


def _snmp_pdu_name(code: int) -> str:
    return {
        0: 'get-request',
        1: 'get-next-request',
        2: 'get-response',
        3: 'set-request',
        4: 'trap',
        5: 'get-bulk-request',
        6: 'inform-request',
        7: 'snmpV2-trap',
        8: 'report',
    }.get(int(code), 'snmp')


def _snmp_error_name(code: int) -> str:
    return {
        0: 'noError',
        1: 'tooBig',
        2: 'noSuchName',
        3: 'badValue',
        4: 'readOnly',
        5: 'genErr',
    }.get(int(code), str(int(code)))


def _snmp_oid_display(oid: str) -> str:
    if oid.startswith('1.'):
        return f'{oid} (iso.{oid[2:]})'
    return oid


def _snmp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    snmp_meta = metadata.get('snmp', {}) if isinstance(metadata.get('snmp'), dict) else {}
    outer = _asn1_tlv(payload, 0)
    if outer is None or outer.get('tag') != 0x30:
        return {'title': 'Simple Network Management Protocol', 'offset': offset, 'length': len(payload), 'children': []}

    def _int_value(tlv: Dict[str, int] | None, data: bytes) -> int:
        if tlv is None:
            return 0
        start = int(tlv.get('value_start', 0) or 0)
        end = int(tlv.get('end', 0) or 0)
        if end <= start:
            return 0
        return int.from_bytes(data[start:end], 'big', signed=False)

    def _octets_value(tlv: Dict[str, int] | None, data: bytes) -> bytes:
        if tlv is None:
            return b''
        start = int(tlv.get('value_start', 0) or 0)
        end = int(tlv.get('end', 0) or 0)
        return bytes(data[start:end]) if end > start else b''

    def _oid_text(value: bytes) -> str:
        if not value:
            return ''
        first = int(value[0])
        parts = [str(first // 40), str(first % 40)]
        accum = 0
        for b in value[1:]:
            accum = (accum << 7) | (b & 0x7F)
            if (b & 0x80) == 0:
                parts.append(str(accum))
                accum = 0
        return '.'.join(parts)

    def _tlv_value_pos_len(tlv: Dict[str, int] | None) -> tuple[int, int]:
        if tlv is None:
            return 0, 0
        start = int(tlv.get('value_start', tlv.get('start', 0)) or 0)
        end = int(tlv.get('end', start) or start)
        if end < start:
            end = start
        return start, end - start

    pos = int(outer['value_start'])
    version_tlv = _asn1_tlv(payload, pos)
    community_tlv = _asn1_tlv(payload, int(version_tlv['end'])) if version_tlv is not None else None
    pdu_tlv = _asn1_tlv(payload, int(community_tlv['end'])) if community_tlv is not None else None
    children: List[Dict[str, Any]] = []
    version_value = _int_value(version_tlv, payload) if version_tlv is not None else 0

    if version_tlv is not None and version_value == 3:
        def _engine_id_children(engine_id_value: bytes, value_abs_start: int) -> List[Dict[str, Any]]:
            if not engine_id_value:
                return []
            nodes: List[Dict[str, Any]] = []
            if len(engine_id_value) >= 5 and (engine_id_value[0] & 0x80):
                enterprise_id = int.from_bytes(engine_id_value[:4], 'big') & 0x7FFFFFFF
                enterprise_text = 'Meinberg' if enterprise_id == 5597 else str(enterprise_id)
                nodes.append({'title': '1... .... = Engine ID Conformance: RFC3411 (SNMPv3)', 'offset': value_abs_start, 'length': 1})
                nodes.append({'title': f'Engine Enterprise ID: {enterprise_text} ({enterprise_id})', 'offset': value_abs_start, 'length': 4})
                fmt = int(engine_id_value[4])
                if fmt == 4:
                    nodes.append({'title': 'Engine ID Format: Text, administratively assigned (4)', 'offset': value_abs_start + 4, 'length': 1})
                    if len(engine_id_value) > 5:
                        try:
                            nodes.append({'title': f'Engine ID Data: Text: {engine_id_value[5:].decode(errors="ignore")}', 'offset': value_abs_start + 5, 'length': len(engine_id_value) - 5})
                        except Exception:
                            pass
            return nodes

        children.append({
            'title': 'msgVersion: snmpv3 (3)',
            'offset': offset + _tlv_value_pos_len(version_tlv)[0],
            'length': _tlv_value_pos_len(version_tlv)[1],
        })
        header_tlv = _asn1_tlv(payload, int(version_tlv['end']))
        sec_params_tlv = _asn1_tlv(payload, int(header_tlv['end'])) if header_tlv is not None else None
        msg_data_tlv = _asn1_tlv(payload, int(sec_params_tlv['end'])) if sec_params_tlv is not None else None

        if header_tlv is not None and int(header_tlv.get('tag', -1)) == 0x30:
            hpos = int(header_tlv['value_start'])
            msg_id_tlv = _asn1_tlv(payload, hpos)
            msg_max_tlv = _asn1_tlv(payload, int(msg_id_tlv['end'])) if msg_id_tlv is not None else None
            msg_flags_tlv = _asn1_tlv(payload, int(msg_max_tlv['end'])) if msg_max_tlv is not None else None
            msg_sec_model_tlv = _asn1_tlv(payload, int(msg_flags_tlv['end'])) if msg_flags_tlv is not None else None
            flags_val = int(_octets_value(msg_flags_tlv, payload)[:1].hex() or '00', 16) if msg_flags_tlv is not None else 0
            global_children: List[Dict[str, Any]] = []
            if msg_id_tlv is not None:
                msg_id_start, msg_id_len = _tlv_value_pos_len(msg_id_tlv)
                global_children.append({'title': f'msgID: {_int_value(msg_id_tlv, payload)}', 'offset': offset + msg_id_start, 'length': msg_id_len})
            if msg_max_tlv is not None:
                msg_max_start, msg_max_len = _tlv_value_pos_len(msg_max_tlv)
                global_children.append({'title': f'msgMaxSize: {_int_value(msg_max_tlv, payload)}', 'offset': offset + msg_max_start, 'length': msg_max_len})
            if msg_flags_tlv is not None:
                flags_value_start = offset + int(msg_flags_tlv.get('value_start', msg_flags_tlv['start']))
                msg_flags_start, msg_flags_len = _tlv_value_pos_len(msg_flags_tlv)
                global_children.append({
                    'title': f'msgFlags: {flags_val:02x}',
                    'offset': offset + msg_flags_start,
                    'length': msg_flags_len,
                    'children': [
                        {'title': f'.... .{1 if (flags_val & 0x04) else 0}.. = Reportable: {"Set" if (flags_val & 0x04) else "Not set"}', 'offset': flags_value_start, 'length': 1},
                        {'title': f'.... ..{1 if (flags_val & 0x02) else 0}. = Encrypted: {"Set" if (flags_val & 0x02) else "Not set"}', 'offset': flags_value_start, 'length': 1},
                        {'title': f'.... ...{1 if (flags_val & 0x01) else 0} = Authenticated: {"Set" if (flags_val & 0x01) else "Not set"}', 'offset': flags_value_start, 'length': 1},
                    ],
                })
            if msg_sec_model_tlv is not None:
                msg_sec_model_start, msg_sec_model_len = _tlv_value_pos_len(msg_sec_model_tlv)
                global_children.append({'title': f'msgSecurityModel: USM ({_int_value(msg_sec_model_tlv, payload)})', 'offset': offset + msg_sec_model_start, 'length': msg_sec_model_len})
            children.append({'title': 'msgGlobalData', 'offset': offset + int(header_tlv['start']), 'length': int(header_tlv['end']) - int(header_tlv['start']), 'children': global_children})

        engine_id = b''
        if sec_params_tlv is not None:
            sec_raw = _octets_value(sec_params_tlv, payload)
            sec_base = offset + int(sec_params_tlv.get('value_start', sec_params_tlv['start']))
            usm_outer = _asn1_tlv(sec_raw, 0)
            if usm_outer is not None and int(usm_outer.get('tag', -1)) == 0x30:
                spos = int(usm_outer['value_start'])
                engine_tlv = _asn1_tlv(sec_raw, spos)
                boots_tlv = _asn1_tlv(sec_raw, int(engine_tlv['end'])) if engine_tlv is not None else None
                time_tlv = _asn1_tlv(sec_raw, int(boots_tlv['end'])) if boots_tlv is not None else None
                user_tlv = _asn1_tlv(sec_raw, int(time_tlv['end'])) if time_tlv is not None else None
                auth_tlv = _asn1_tlv(sec_raw, int(user_tlv['end'])) if user_tlv is not None else None
                priv_tlv = _asn1_tlv(sec_raw, int(auth_tlv['end'])) if auth_tlv is not None else None
                engine_id = _octets_value(engine_tlv, sec_raw)
                if engine_id:
                    engine_value_start = sec_base + int(engine_tlv.get('value_start', 0)) if engine_tlv is not None else sec_base
                    engine_children = _engine_id_children(engine_id, engine_value_start)
                    engine_start, engine_len = _tlv_value_pos_len(engine_tlv)
                    children.append({
                        'title': f'msgAuthoritativeEngineID: {engine_id.hex()}',
                        'offset': sec_base + engine_start,
                        'length': engine_len,
                        'children': engine_children,
                    })
                else:
                    children.append({'title': 'msgAuthoritativeEngineID: <MISSING>'})
                boots_start, boots_len = _tlv_value_pos_len(boots_tlv)
                time_start, time_len = _tlv_value_pos_len(time_tlv)
                children.append({'title': f'msgAuthoritativeEngineBoots: {_int_value(boots_tlv, sec_raw)}', 'offset': sec_base + boots_start if boots_tlv is not None else sec_base, 'length': boots_len})
                children.append({'title': f'msgAuthoritativeEngineTime: {_int_value(time_tlv, sec_raw)}', 'offset': sec_base + time_start if time_tlv is not None else sec_base, 'length': time_len})
                user_name = _octets_value(user_tlv, sec_raw)
                if user_name:
                    user_start, user_len = _tlv_value_pos_len(user_tlv)
                    children.append({'title': f'msgUserName: {user_name.decode(errors="ignore")}', 'offset': sec_base + user_start if user_tlv is not None else sec_base, 'length': user_len})
                else:
                    children.append({'title': 'msgUserName: <MISSING>'})
                auth_val = _octets_value(auth_tlv, sec_raw)
                priv_val = _octets_value(priv_tlv, sec_raw)
                if auth_val:
                    auth_start, auth_len = _tlv_value_pos_len(auth_tlv)
                    children.append({'title': f'msgAuthenticationParameters: {auth_val.hex()}', 'offset': sec_base + auth_start if auth_tlv is not None else sec_base, 'length': auth_len})
                else:
                    children.append({'title': 'msgAuthenticationParameters: <MISSING>'})
                if priv_val:
                    priv_start, priv_len = _tlv_value_pos_len(priv_tlv)
                    children.append({'title': f'msgPrivacyParameters: {priv_val.hex()}', 'offset': sec_base + priv_start if priv_tlv is not None else sec_base, 'length': priv_len})
                else:
                    children.append({'title': 'msgPrivacyParameters: <MISSING>'})

        if msg_data_tlv is not None:
            tag = int(msg_data_tlv.get('tag', 0) or 0)
            if tag == 0x04:
                enc = _octets_value(msg_data_tlv, payload)
                children.append({
                    'title': 'msgData: encryptedPDU (1)',
                    'offset': offset + int(msg_data_tlv['start']),
                    'length': int(msg_data_tlv['end']) - int(msg_data_tlv['start']),
                    'children': [{'title': f'encryptedPDU: {enc.hex()}', 'offset': offset + int(msg_data_tlv.get('value_start', msg_data_tlv['start'])), 'length': len(enc)}],
                })
            elif tag == 0x30:
                scoped_children: List[Dict[str, Any]] = []
                dpos = int(msg_data_tlv['value_start'])
                ctx_engine_tlv = _asn1_tlv(payload, dpos)
                ctx_name_tlv = _asn1_tlv(payload, int(ctx_engine_tlv['end'])) if ctx_engine_tlv is not None else None
                pdu_v3_tlv = _asn1_tlv(payload, int(ctx_name_tlv['end'])) if ctx_name_tlv is not None else None
                ctx_engine = _octets_value(ctx_engine_tlv, payload)
                if ctx_engine:
                    ctx_engine_start = offset + int(ctx_engine_tlv['start']) if ctx_engine_tlv is not None else offset + dpos
                    scoped_children.append({'title': f'contextEngineID: {ctx_engine.hex()}', 'offset': offset + int(ctx_engine_tlv.get('value_start', ctx_engine_tlv['start'])) if ctx_engine_tlv is not None else ctx_engine_start, 'length': int(ctx_engine_tlv['end']) - int(ctx_engine_tlv.get('value_start', ctx_engine_tlv['start'])) if ctx_engine_tlv is not None else 0, 'children': _engine_id_children(ctx_engine, offset + int(ctx_engine_tlv.get('value_start', ctx_engine_tlv['start'])) if ctx_engine_tlv is not None else ctx_engine_start)})
                else:
                    scoped_children.append({'title': 'contextEngineID: <MISSING>'})
                ctx_name = _octets_value(ctx_name_tlv, payload)
                if ctx_name:
                    scoped_children.append({'title': f'contextName: {ctx_name.decode(errors="ignore")}', 'offset': offset + int(ctx_name_tlv.get('value_start', ctx_name_tlv['start'])) if ctx_name_tlv is not None else offset + dpos, 'length': int(ctx_name_tlv['end']) - int(ctx_name_tlv.get('value_start', ctx_name_tlv['start'])) if ctx_name_tlv is not None else 0})
                else:
                    scoped_children.append({'title': 'contextName: <MISSING>'})

                if pdu_v3_tlv is not None and int(pdu_v3_tlv.get('tag', -1)) >= 0xA0:
                    pdu_code = int(pdu_v3_tlv['tag']) - 0xA0
                    pdu_name = _snmp_pdu_name(pdu_code)
                    p_children: List[Dict[str, Any]] = []
                    ppos = int(pdu_v3_tlv['value_start'])
                    req_tlv = _asn1_tlv(payload, ppos)
                    err_tlv = _asn1_tlv(payload, int(req_tlv['end'])) if req_tlv is not None else None
                    idx_tlv = _asn1_tlv(payload, int(err_tlv['end'])) if err_tlv is not None else None
                    vb_tlv = _asn1_tlv(payload, int(idx_tlv['end'])) if idx_tlv is not None else None
                    p_children.append({'title': f'request-id: {_int_value(req_tlv, payload)}', 'offset': offset + int(req_tlv.get('value_start', req_tlv['start'])) if req_tlv is not None else offset + ppos, 'length': int(req_tlv['end']) - int(req_tlv.get('value_start', req_tlv['start'])) if req_tlv is not None else 0})
                    err_val = _int_value(err_tlv, payload)
                    p_children.append({'title': f'error-status: {_snmp_error_name(err_val)} ({err_val})', 'offset': offset + int(err_tlv.get('value_start', err_tlv['start'])) if err_tlv is not None else offset + ppos, 'length': int(err_tlv['end']) - int(err_tlv.get('value_start', err_tlv['start'])) if err_tlv is not None else 0})
                    p_children.append({'title': f'error-index: {_int_value(idx_tlv, payload)}', 'offset': offset + int(idx_tlv.get('value_start', idx_tlv['start'])) if idx_tlv is not None else offset + ppos, 'length': int(idx_tlv['end']) - int(idx_tlv.get('value_start', idx_tlv['start'])) if idx_tlv is not None else 0})
                    vb_children: List[Dict[str, Any]] = []
                    if vb_tlv is not None:
                        vpos = int(vb_tlv['value_start'])
                        while vpos < int(vb_tlv['end']):
                            vb = _asn1_tlv(payload, vpos)
                            if vb is None:
                                break
                            oid_tlv = _asn1_tlv(payload, int(vb['value_start']))
                            val_tlv = _asn1_tlv(payload, int(oid_tlv['end'])) if oid_tlv is not None else None
                            oid = _oid_text(_octets_value(oid_tlv, payload)) if oid_tlv is not None else ''
                            value_title = 'Value'
                            value_text = ''
                            if val_tlv is not None:
                                vtag = int(val_tlv.get('tag', 0) or 0)
                                if vtag == 0x41:
                                    value_text = str(_int_value(val_tlv, payload))
                                    value_title = 'Value (Counter32)'
                                elif vtag == 0x05:
                                    value_text = 'Value (Null)'
                                    value_title = 'Value (Null)'
                                else:
                                    value_text = _octets_value(val_tlv, payload).hex()
                            vb_node: Dict[str, Any] = {
                                'title': f'{oid}: {value_text}' if value_text else oid,
                                'offset': offset + int(vb.get('start', 0)),
                                'length': int(vb.get('end', 0)) - int(vb.get('start', 0)),
                                'byte_source': PACKET_BYTE_SOURCE,
                                'children': [],
                            }
                            if oid and oid_tlv is not None:
                                oid_start, oid_len = _tlv_value_pos_len(oid_tlv)
                                vb_node['children'].append({'title': f'Object Name: {_snmp_oid_display(oid)}', 'offset': offset + oid_start, 'length': oid_len, 'byte_source': PACKET_BYTE_SOURCE})
                            else:
                                vb_node['children'].append({'title': 'Object Name'})
                            if value_text and val_tlv is not None:
                                val_start, val_len = _tlv_value_pos_len(val_tlv)
                                if val_len > 0:
                                    vb_node['children'].append({'title': f'{value_title}: {value_text}', 'offset': offset + val_start, 'length': val_len, 'byte_source': PACKET_BYTE_SOURCE})
                                else:
                                    vb_node['children'].append({'title': f'{value_title}: {value_text}'})
                            else:
                                vb_node['children'].append({'title': value_title})
                            vb_children.append(vb_node)
                            vpos = int(vb['end'])
                    vb_group_node: Dict[str, Any] = {
                        'title': f'variable-bindings: {len(vb_children)} item' + ('' if len(vb_children) == 1 else 's'),
                        'children': vb_children,
                    }
                    if vb_tlv is not None:
                        vb_group_node.update({
                            'offset': offset + int(vb_tlv['start']),
                            'length': int(vb_tlv['end']) - int(vb_tlv['start']),
                            'byte_source': PACKET_BYTE_SOURCE,
                        })
                    p_children.append(vb_group_node)
                    scoped_children.append({'title': f'data: {pdu_name} ({pdu_code})', 'offset': offset + int(pdu_v3_tlv['start']), 'length': int(pdu_v3_tlv['end']) - int(pdu_v3_tlv['start']), 'children': [{'title': pdu_name, 'offset': offset + int(pdu_v3_tlv['start']), 'length': int(pdu_v3_tlv['end']) - int(pdu_v3_tlv['start']), 'children': p_children}]})
                children.append({'title': 'msgData: plaintext (0)', 'offset': offset + int(msg_data_tlv['start']), 'length': int(msg_data_tlv['end']) - int(msg_data_tlv['start']), 'children': [{'title': 'plaintext', 'offset': offset + int(msg_data_tlv['value_start']), 'length': int(msg_data_tlv['end']) - int(msg_data_tlv['value_start']), 'children': scoped_children}]})

        response_frame = metadata.get('snmp_response_frame', None)
        if response_frame is not None:
            children.append({'title': f'[Response In: {int(response_frame)}]'})
        request_frame = metadata.get('snmp_request_frame', None)
        if request_frame is not None:
            children.append({'title': f'[Response To: {int(request_frame)}]'})
        response_time = metadata.get('snmp_time_since_request_ms', None)
        if response_time is not None:
            children.append({'title': f'[Time: {float(response_time):.6f} milliseconds]'})

        return {
            'title': 'Simple Network Management Protocol',
            'offset': offset,
            'length': len(payload),
            'children': children,
        }

    if version_tlv is not None:
        children.append({
            'title': f'version: {_snmp_version_name(version_value)} ({version_value})',
            'offset': offset + int(version_tlv['start']),
            'length': int(version_tlv['end']) - int(version_tlv['start']),
        })
    if community_tlv is not None:
        community = payload[int(community_tlv['value_start']):int(community_tlv['end'])].decode(errors='ignore')
        children.append({
            'title': f'community: {community}',
            'offset': offset + int(community_tlv['start']),
            'length': int(community_tlv['end']) - int(community_tlv['start']),
        })
    if pdu_tlv is not None:
        pdu_code = int(pdu_tlv['tag']) - 0xA0
        pdu_name = _snmp_pdu_name(pdu_code)
        pdu_children: List[Dict[str, Any]] = []
        pdu_pos = int(pdu_tlv['value_start'])
        request_tlv = _asn1_tlv(payload, pdu_pos)
        error_tlv = _asn1_tlv(payload, int(request_tlv['end'])) if request_tlv is not None else None
        error_index_tlv = _asn1_tlv(payload, int(error_tlv['end'])) if error_tlv is not None else None
        varbinds_tlv = _asn1_tlv(payload, int(error_index_tlv['end'])) if error_index_tlv is not None else None
        request_id = int(snmp_meta.get('request_id', 0) or 0)
        error_status = int(snmp_meta.get('error_status', 0) or 0)
        error_index = int(snmp_meta.get('error_index', 0) or 0)
        if request_tlv is not None:
            pdu_children.append({'title': f'request-id: {request_id}', 'offset': offset + int(request_tlv.get('value_start', request_tlv['start'])), 'length': int(request_tlv['end']) - int(request_tlv.get('value_start', request_tlv['start']))})
        if error_tlv is not None:
            pdu_children.append({'title': f'error-status: {_snmp_error_name(error_status)} ({error_status})', 'offset': offset + int(error_tlv.get('value_start', error_tlv['start'])), 'length': int(error_tlv['end']) - int(error_tlv.get('value_start', error_tlv['start']))})
        if error_index_tlv is not None:
            pdu_children.append({'title': f'error-index: {error_index}', 'offset': offset + int(error_index_tlv.get('value_start', error_index_tlv['start'])), 'length': int(error_index_tlv['end']) - int(error_index_tlv.get('value_start', error_index_tlv['start']))})
        if varbinds_tlv is not None:
            varbind_children: List[Dict[str, Any]] = []
            vb_pos = int(varbinds_tlv['value_start'])
            meta_varbinds = list(snmp_meta.get('varbinds', []) or [])
            meta_index = 0
            while vb_pos < int(varbinds_tlv['end']):
                vb_tlv = _asn1_tlv(payload, vb_pos)
                if vb_tlv is None:
                    break
                oid_tlv = _asn1_tlv(payload, int(vb_tlv['value_start']))
                value_tlv = _asn1_tlv(payload, int(oid_tlv['end'])) if oid_tlv is not None else None
                meta_varbind = meta_varbinds[meta_index] if meta_index < len(meta_varbinds) else {}
                meta_index += 1
                oid_text = str(meta_varbind.get('oid', '') or '')
                value_type = str(meta_varbind.get('value_type', '') or '')
                value_value = meta_varbind.get('value', None)
                if value_type == 'NULL':
                    title = f'{oid_text}: Value (Null)'
                    value_title = 'Value (Null)'
                else:
                    title = f'{oid_text}: {value_value}'
                    value_title = f'Value ({value_type.title()}): {value_value}'
                vb_children = []
                if oid_tlv is not None:
                    vb_children.append({'title': f'Object Name: {_snmp_oid_display(oid_text)}', 'offset': offset + int(oid_tlv['start']), 'length': int(oid_tlv['end']) - int(oid_tlv['start']), 'byte_source': PACKET_BYTE_SOURCE})
                if value_tlv is not None:
                    vb_children.append({'title': value_title, 'offset': offset + int(value_tlv['start']), 'length': int(value_tlv['end']) - int(value_tlv['start']), 'byte_source': PACKET_BYTE_SOURCE})
                varbind_children.append({
                    'title': title,
                    'offset': offset + int(vb_tlv['start']),
                    'length': int(vb_tlv['end']) - int(vb_tlv['start']),
                    'byte_source': PACKET_BYTE_SOURCE,
                    'children': vb_children,
                })
                vb_pos = int(vb_tlv['end'])
            item_count = len(varbind_children)
            vb_group_node: Dict[str, Any] = {
                'title': f'variable-bindings: {item_count} item' + ('' if item_count == 1 else 's'),
                'children': varbind_children,
            }
            if varbinds_tlv is not None:
                vb_group_node.update({
                    'offset': offset + int(varbinds_tlv['start']),
                    'length': int(varbinds_tlv['end']) - int(varbinds_tlv['start']),
                    'byte_source': PACKET_BYTE_SOURCE,
                })
            pdu_children.append(vb_group_node)
        children.append({
            'title': f'data: {pdu_name} ({pdu_code})',
            'offset': offset + int(pdu_tlv['start']),
            'length': int(pdu_tlv['end']) - int(pdu_tlv['start']),
            'children': [{
                'title': pdu_name,
                'offset': offset + int(pdu_tlv['start']),
                'length': int(pdu_tlv['end']) - int(pdu_tlv['start']),
                'children': pdu_children,
            }],
        })

    response_frame = metadata.get('snmp_response_frame', None)
    if response_frame is not None:
        children.append({'title': f'[Response In: {int(response_frame)}]'})
    request_frame = metadata.get('snmp_request_frame', None)
    if request_frame is not None:
        children.append({'title': f'[Response To: {int(request_frame)}]'})
    response_time = metadata.get('snmp_time_since_request_ms', None)
    if response_time is not None:
        children.append({'title': f'[Time: {float(response_time):.6f} milliseconds]'})

    return {
        'title': 'Simple Network Management Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _imap_parse_request_line(line_text: str) -> Dict[str, str] | None:
    parts = line_text.split(' ', 2)
    if len(parts) < 1 or not parts[0]:
        return None
    return {
        'tag': parts[0],
        'command': parts[1] if len(parts) > 1 else '',
    }


def _imap_parse_response_line(line_text: str) -> Dict[str, str] | None:
    if line_text.startswith('* OK ') or line_text.startswith('* '):
        return None
    parts = line_text.split(' ', 2)
    if len(parts) < 2:
        return None
    return {
        'tag': parts[0],
        'status': parts[1],
        'command': parts[2].split(' ', 1)[0] if len(parts) > 2 else '',
    }


def _imap_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    imap_meta = metadata.get('imap', {}) if isinstance(metadata.get('imap'), dict) else {}
    tagged_response_line = str(metadata.get('imap_tagged_response_line', '') or '') or str(imap_meta.get('tagged_response_line', '') or '')
    children: List[Dict[str, Any]] = []
    cursor = 0
    for raw_line in payload.splitlines(keepends=True):
        line_text = raw_line.decode(errors='ignore').rstrip('\r\n')
        line_display = raw_line.decode(errors='ignore').replace('\r', '\\r').replace('\n', '\\n')
        line_children: List[Dict[str, Any]] = []
        if cursor == 0 and str(imap_meta.get('kind', '') or '') == 'request':
            request_info = _imap_parse_request_line(line_text)
            if request_info is not None:
                line_children.append({'title': f'Request: {line_text}', 'offset': offset + cursor, 'length': max(0, len(raw_line) - 2)})
                line_children.append({'title': f'Request Tag: {request_info["tag"]}', 'offset': offset + cursor, 'length': len(request_info['tag'])})
                if request_info['command']:
                    line_children.append({'title': f'Request Command: {request_info["command"]}', 'offset': offset + cursor + len(request_info['tag']) + 1, 'length': len(request_info['command'])})
                response_frame = metadata.get('imap_response_frame', None)
                if response_frame is not None:
                    line_children.append({'title': f'[Response In: {int(response_frame)}]'})
        elif cursor == 0 and str(imap_meta.get('kind', '') or '') == 'response':
            response_info = _imap_parse_response_line(line_text)
            if response_info is not None:
                line_children.append({'title': f'Response: {line_text}', 'offset': offset + cursor, 'length': max(0, len(raw_line) - 2)})
                line_children.append({'title': f'Response Tag: {response_info["tag"]}', 'offset': offset + cursor, 'length': len(response_info['tag'])})
                line_children.append({'title': f'Response Status: {response_info["status"]}', 'offset': offset + cursor + len(response_info['tag']) + 1, 'length': len(response_info['status'])})
                if response_info['command']:
                    command_offset = offset + cursor + len(response_info['tag']) + 1 + len(response_info['status']) + 1
                    line_children.append({'title': f'Response Command: {response_info["command"]}', 'offset': command_offset, 'length': len(response_info['command'])})
        elif cursor == 0 and str(imap_meta.get('kind', '') or '') in {'greeting', 'response_untagged'}:
            line_children.append({'title': f'Response: {line_text}', 'offset': offset + cursor, 'length': max(0, len(raw_line) - 2)})
        if tagged_response_line and line_text == tagged_response_line:
            tagged_info = _imap_parse_response_line(line_text)
            if tagged_info is not None:
                line_children.append({'title': f'Response: {line_text}', 'offset': offset + cursor, 'length': max(0, len(raw_line) - 2)})
                line_children.append({'title': f'Response Tag: {tagged_info["tag"]}', 'offset': offset + cursor, 'length': len(tagged_info['tag'])})
                line_children.append({'title': f'Response Status: {tagged_info["status"]}', 'offset': offset + cursor + len(tagged_info['tag']) + 1, 'length': len(tagged_info['status'])})
                if tagged_info['command']:
                    command_offset = offset + cursor + len(tagged_info['tag']) + 1 + len(tagged_info['status']) + 1
                    line_children.append({'title': f'Response Command: {tagged_info["command"]}', 'offset': command_offset, 'length': len(tagged_info['command'])})
                request_frame = metadata.get('imap_request_frame', None)
                if request_frame is not None:
                    line_children.append({'title': f'[Request In: {int(request_frame)}]'})
                response_time = metadata.get('imap_time_since_request_ms', None)
                if response_time is not None:
                    line_children.append({'title': f'[Response Time: {float(response_time):.6f} milliseconds]'})
        line_node: Dict[str, Any] = {
            'title': f'Line: {line_display}',
            'offset': offset + cursor,
            'length': len(raw_line),
        }
        if line_children:
            line_node['children'] = line_children
        children.append(line_node)
        cursor += len(raw_line)

    return {
        'title': 'Internet Message Access Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _whois_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    whois_meta = metadata.get('whois', {}) if isinstance(metadata.get('whois'), dict) else {}
    kind = str(whois_meta.get('kind', '') or '')

    children: List[Dict[str, Any]] = []
    cursor = 0
    for raw_line in payload.splitlines(keepends=True):
        line_text = raw_line.decode(errors='ignore').rstrip('\r\n')
        line_len = max(0, len(raw_line))
        line_display = raw_line.decode(errors='ignore').replace('\r', '\\r').replace('\n', '\\n')
        if not line_display:
            cursor += len(raw_line)
            continue
        if kind == 'answer':
            children.append({
                'title': f'Answer: {line_display}',
                'offset': offset + cursor,
                'length': line_len,
            })
        else:
            children.append({
                'title': f'Query: {line_display}',
                'offset': offset + cursor,
                'length': line_len,
            })
        cursor += len(raw_line)

    if kind == 'query':
        answer_frame = metadata.get('whois_answer_frame', None)
        if answer_frame is not None:
            children.append({'title': f'[Answer In: {int(answer_frame)}]'})
    elif kind == 'answer':
        query_frame = metadata.get('whois_query_frame', None)
        if query_frame is not None:
            children.append({'title': f'[Query In: {int(query_frame)}]'})
        response_time = metadata.get('whois_time_since_query_ms', None)
        if response_time is not None:
            children.append({'title': f'[Response Time: {float(response_time):.6f} milliseconds]'})
        children.append({
            'title': 'WHOIS has no mechanism to indicate encoding (RFC 3912), assuming UTF-8',
            'children': [
                {
                    'title': '[Expert Info (Chat/Assumption): WHOIS has no mechanism to indicate encoding (RFC 3912), assuming UTF-8]',
                    'children': [
                        {'title': '[WHOIS has no mechanism to indicate encoding (RFC 3912), assuming UTF-8]'},
                        {'title': '[Severity level: Chat]'},
                        {'title': '[Group: Assumption]'},
                    ],
                },
            ],
        })

    title = 'WHOIS: Query' if kind == 'query' else 'WHOIS: Answer'
    return {
        'title': title,
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _sip_header_lines(payload: bytes) -> tuple[List[Dict[str, Any]], int, int]:
    header_end = payload.find(b'\r\n\r\n')
    if header_end == -1:
        header_blob = payload
        body_offset = len(payload)
    else:
        header_blob = payload[:header_end]
        body_offset = header_end + 4
    lines: List[Dict[str, Any]] = []
    cursor = 0
    for raw_line in header_blob.split(b'\r\n'):
        line_text = raw_line.decode(errors='ignore')
        lines.append({
            'text': line_text,
            'offset': cursor,
            'length': len(raw_line),
        })
        cursor += len(raw_line) + 2
    return lines, body_offset, len(header_blob)


def _sdp_section(body: bytes, offset: int) -> Dict[str, Any]:
    children: List[Dict[str, Any]] = []
    cursor = 0
    for raw_line in body.splitlines(keepends=True):
        line_text = raw_line.decode(errors='ignore').rstrip('\r\n')
        if not line_text:
            cursor += len(raw_line)
            continue
        node: Dict[str, Any] = {
            'title': line_text,
            'offset': offset + cursor,
            'length': max(0, len(raw_line) - 2),
        }
        if line_text.startswith('v='):
            node['title'] = f'Session Description Protocol Version (v): {line_text[2:]}'
        elif line_text.startswith('o='):
            node['title'] = f'Owner/Creator, Session Id (o): {line_text[2:]}'
            parts = line_text[2:].split()
            if len(parts) >= 6:
                node['children'] = [
                    {'title': f'Owner Username: {parts[0]}'},
                    {'title': f'Session ID: {parts[1]}'},
                    {'title': f'Session Version: {parts[2]}'},
                    {'title': f'Owner Network Type: {parts[3]}'},
                    {'title': f'Owner Address Type: {parts[4]}'},
                    {'title': f'Owner Address: {parts[5]}'},
                ]
        elif line_text.startswith('s='):
            node['title'] = f'Session Name (s): {line_text[2:]}'
        elif line_text.startswith('c='):
            node['title'] = f'Connection Information (c): {line_text[2:]}'
            parts = line_text[2:].split()
            if len(parts) >= 3:
                node['children'] = [
                    {'title': f'Connection Network Type: {parts[0]}'},
                    {'title': f'Connection Address Type: {parts[1]}'},
                    {'title': f'Connection Address: {parts[2]}'},
                ]
        elif line_text.startswith('t='):
            node['title'] = f'Time Description, active time (t): {line_text[2:]}'
            parts = line_text[2:].split()
            if len(parts) >= 2:
                node['children'] = [
                    {'title': f'Session Start Time: {parts[0]}'},
                    {'title': f'Session Stop Time: {parts[1]}'},
                ]
        elif line_text.startswith('m='):
            node['title'] = f'Media Description, name and address (m): {line_text[2:]}'
            parts = line_text[2:].split()
            if len(parts) >= 3:
                media_children: List[Dict[str, Any]] = [
                    {'title': f'Media Type: {parts[0]}'},
                    {'title': f'Media Port: {parts[1]}'},
                    {'title': f'Media Protocol: {parts[2]}'},
                ]
                for media_format in parts[3:]:
                    static_name = _sdp_static_payload_name(media_format)
                    if static_name:
                        media_children.append({'title': f'Media Format: {static_name}'})
                    else:
                        media_children.append({'title': f'Media Format: DynamicRTP-Type-{media_format}'})
                node['children'] = media_children
        elif line_text.startswith('a='):
            node['title'] = f'Media Attribute (a): {line_text[2:]}'
            attr_body = line_text[2:]
            attr_name, sep, attr_value = attr_body.partition(':')
            attr_children: List[Dict[str, Any]] = []
            if sep:
                attr_children.append({'title': f'Media Attribute Fieldname: {attr_name}'})
                if attr_name == 'rtpmap':
                    parts = attr_value.split(None, 1)
                    if parts:
                        attr_children.append({'title': f'Media Format: {parts[0]}'})
                    if len(parts) > 1:
                        mime_parts = parts[1].split('/')
                        if mime_parts:
                            attr_children.append({'title': f'MIME Type: {mime_parts[0]}'})
                        if len(mime_parts) > 1:
                            sample_rate = mime_parts[1]
                            if parts[0] == '9' and mime_parts[0].upper() == 'G722':
                                attr_children.append({'title': f'Sample Rate: {sample_rate} (RTP clock rate is 8kHz, actual sampling rate is 16kHz)'})
                            else:
                                attr_children.append({'title': f'Sample Rate: {sample_rate}'})
                elif attr_name == 'fmtp':
                    parts = attr_value.split(None, 1)
                    if parts:
                        suffix = ' [telephone-event]' if parts[0] == '100' else ''
                        attr_children.append({'title': f'Media Format: {parts[0]}{suffix}'})
                    if len(parts) > 1:
                        attr_children.append({'title': f'Media format specific parameters: {parts[1]}'})
                elif attr_name in {'rtcp', 'ptime'}:
                    attr_children.append({'title': f'Media Attribute Value: {attr_value}'})
            if attr_children:
                node['children'] = attr_children
        children.append(node)
        cursor += len(raw_line)
    return {
        'title': 'Session Description Protocol',
        'offset': offset,
        'length': len(body),
        'children': children,
    }


def _sip_split_uri(uri_text: str) -> Dict[str, Any]:
    text = str(uri_text or '').strip()
    result: Dict[str, Any] = {
        'uri': text,
        'user': '',
        'host': '',
        'params': [],
    }
    if not text:
        return result

    inner = text
    if inner.startswith('<') and '>' in inner:
        inner = inner[1:inner.find('>')]
    if inner.lower().startswith('sip:'):
        inner = inner[4:]

    addr_part, sep, param_part = inner.partition(';')
    if sep and param_part:
        result['params'] = [item.strip() for item in param_part.split(';') if item.strip()]
    if '@' in addr_part:
        result['user'], result['host'] = addr_part.split('@', 1)
    else:
        result['host'] = addr_part
    return result


def _sip_e164_children(user_text: str) -> List[Dict[str, Any]]:
    text = str(user_text or '').strip()
    if not text.startswith('+') or not text[1:].isdigit():
        return []
    digits = text[1:]
    country_map = {
        '49': 'Germany (Federal Republic of)',
        '1': 'United States/Canada',
        '44': 'United Kingdom',
        '33': 'France',
        '84': 'Viet Nam',
    }
    for size in (3, 2, 1):
        prefix = digits[:size]
        if prefix in country_map:
            return [
                {
                    'title': f'E.164 number (MSISDN): {digits}',
                    'children': [
                        {'title': f'Country Code: {country_map[prefix]} ({prefix})'},
                    ],
                }
            ]
    return []


def _sdp_static_payload_name(payload_id: str) -> str:
    return {
        '0': 'ITU-T G.711 PCMU',
        '8': 'ITU-T G.711 PCMA',
        '9': 'ITU-T G.722',
    }.get(str(payload_id or ''), '')


def _sip_header_children(name: str, value: str, line_offset: int) -> List[Dict[str, Any]]:
    lower_name = str(name or '').lower()
    text = str(value or '')
    children: List[Dict[str, Any]] = []

    if lower_name in {'max-forwards', 'content-length', 'content-type', 'allow', 'supported', 'allow-events', 'accept', 'accept-encoding', 'session-expires', 'min-se', 'user-agent'}:
        return children

    if lower_name == 'via':
        via_main = text.split(';', 1)[0].strip()
        via_parts = via_main.split()
        if via_parts:
            transport = via_parts[0].split('/')[-1]
            children.append({'title': f'Transport: {transport}'})
        if len(via_parts) > 1:
            sent_by = via_parts[1]
            host, _, port = sent_by.partition(':')
            children.append({'title': f'Sent-by Address: {host}'})
            if port.isdigit():
                children.append({'title': f'Sent-by port: {int(port)}'})
        for token in text.split(';')[1:]:
            token = token.strip()
            if token.startswith('branch='):
                children.append({'title': f'Branch: {token.split("=", 1)[1]}'})
        return children

    if lower_name in {'to', 'from', 'contact', 'record-route', 'p-asserted-identity'}:
        display = ''
        if '"' in text and '<' in text:
            first_q = text.find('"')
            second_q = text.find('"', first_q + 1)
            if second_q > first_q:
                display = text[first_q:second_q + 1]
        start_uri = text.find('<')
        end_uri = text.find('>') if start_uri >= 0 else -1
        uri_text = text[start_uri + 1:end_uri] if start_uri >= 0 and end_uri > start_uri else text.split(';', 1)[0].strip()
        uri_parts = _sip_split_uri(uri_text)

        label_prefix = {
            'to': 'SIP to',
            'from': 'SIP from',
            'contact': 'Contact URI',
            'record-route': 'Record-Route URI',
            'p-asserted-identity': 'SIP PAI',
        }.get(lower_name, name)

        if display and lower_name == 'to':
            children.append({'title': f'SIP to display info: {display}'})

        uri_children: List[Dict[str, Any]] = []
        if uri_parts.get('uri'):
            uri_title = ''
            if lower_name == 'to':
                uri_title = f'SIP to address: {uri_parts["uri"]}'
            elif lower_name == 'from':
                uri_title = f'SIP from address: {uri_parts["uri"]}'
            elif lower_name == 'p-asserted-identity':
                uri_title = f'SIP PAI Address: {uri_parts["uri"]}'
            else:
                uri_title = f'{label_prefix}: {uri_parts["uri"]}'
        else:
            uri_title = ''

        if uri_parts.get('user'):
            user_label = {
                'to': 'SIP to address User Part',
                'from': 'SIP from address User Part',
                'contact': 'Contact URI User Part',
                'p-asserted-identity': 'SIP PAI User Part',
            }.get(lower_name, f'{label_prefix} User Part')
            user_node: Dict[str, Any] = {'title': f'{user_label}: {uri_parts["user"]}'}
            e164_children = _sip_e164_children(uri_parts["user"])
            if e164_children:
                user_node['children'] = e164_children
            uri_children.append(user_node)
        if uri_parts.get('host'):
            host_label = {
                'to': 'SIP to address Host Part',
                'from': 'SIP from address Host Part',
                'contact': 'Contact URI Host Part',
                'record-route': 'Record-Route Host Part',
                'p-asserted-identity': 'SIP PAI Host Part',
            }.get(lower_name, f'{label_prefix} Host Part')
            uri_children.append({'title': f'{host_label}: {uri_parts["host"]}'})
        for param in list(uri_parts.get('params', []) or []):
            param_label = {
                'to': 'SIP To URI parameter',
                'from': 'SIP From URI parameter',
                'contact': 'Contact URI parameter',
                'record-route': 'Record-Route URI parameter',
                'p-asserted-identity': 'SIP PAI URI parameter',
            }.get(lower_name, 'URI parameter')
            uri_children.append({'title': f'{param_label}: {param}'})

        if uri_title:
            uri_node: Dict[str, Any] = {'title': uri_title}
            if uri_children:
                uri_node['children'] = uri_children
            children.append(uri_node)

        if lower_name in {'to', 'from'} and ';tag=' in text:
            tag_val = text.split(';tag=', 1)[1].split(';', 1)[0].strip()
            tag_label = 'SIP to tag' if lower_name == 'to' else 'SIP from tag'
            children.append({'title': f'{tag_label}: {tag_val}'})
        if lower_name == 'contact':
            tail = text[end_uri + 1:] if end_uri >= 0 else ''
            for part in [item for item in tail.split(';') if item.strip()]:
                children.append({'title': f'Contact parameter: {part.strip()}'})
        return children

    if lower_name == 'call-id':
        children.append({'title': f'[Generated Call-ID: {text}]'})
        return children

    if lower_name == 'cseq':
        parts = text.split()
        if parts and parts[0].isdigit():
            children.append({'title': f'Sequence Number: {int(parts[0])}'})
        if len(parts) > 1:
            children.append({'title': f'Method: {parts[1]}'})
        return children

    if lower_name == 'session-id':
        children.append({'title': f'sess-id: {text}'})
        return children
    return children


def _sip_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    sip_meta = metadata.get('sip', {}) if isinstance(metadata.get('sip'), dict) else {}
    lines, body_offset, header_length = _sip_header_lines(payload)
    if not lines:
        return {'title': 'Session Initiation Protocol', 'offset': offset, 'length': len(payload), 'children': []}

    first = lines[0]
    first_text = str(first.get('text', '') or '')
    children: List[Dict[str, Any]] = []
    kind = str(sip_meta.get('kind', '') or '')
    if kind == 'request':
        parts = first_text.split(' ', 2)
        line_children = []
        if len(parts) >= 1:
            line_children.append({'title': f'Method: {parts[0]}', 'offset': offset + int(first['offset']), 'length': len(parts[0])})
        if len(parts) >= 2:
            uri_offset = offset + int(first['offset']) + len(parts[0]) + 1
            uri_node: Dict[str, Any] = {'title': f'Request-URI: {parts[1]}', 'offset': uri_offset, 'length': len(parts[1])}
            uri_parts = _sip_split_uri(parts[1])
            uri_children: List[Dict[str, Any]] = []
            if uri_parts.get('user'):
                user_node: Dict[str, Any] = {'title': f'Request-URI User Part: {uri_parts["user"]}'}
                e164_children = _sip_e164_children(uri_parts["user"])
                if e164_children:
                    user_node['children'] = e164_children
                uri_children.append(user_node)
            if uri_parts.get('host'):
                uri_children.append({'title': f'Request-URI Host Part: {uri_parts["host"]}'})
            for param in list(uri_parts.get('params', []) or []):
                uri_children.append({'title': f'Request-URI parameter: {param}'})
            if uri_children:
                uri_node['children'] = uri_children
            line_children.append(uri_node)
        if len(parts) >= 3:
            version_offset = offset + int(first['offset']) + len(parts[0]) + len(parts[1]) + 2
            line_children.append({'title': f'Version: {parts[2]}', 'offset': version_offset, 'length': len(parts[2])})
        line_children.append({'title': '[Resent Packet: False]'})
        children.append({
            'title': f'Request-Line: {first_text}',
            'offset': offset + int(first['offset']),
            'length': int(first['length']),
            'children': line_children,
        })
    else:
        parts = first_text.split(' ', 2)
        status_code = parts[1] if len(parts) > 1 else str(sip_meta.get('status_code', '') or '')
        line_children = []
        if status_code:
            line_children.append({'title': f'Status-Code: {status_code}', 'offset': offset + int(first['offset']) + 8, 'length': len(status_code)})
        line_children.append({'title': '[Resent Packet: False]'})
        request_frame = metadata.get('sip_request_frame', None)
        if request_frame is not None:
            line_children.append({'title': f'[Request Frame: {int(request_frame)}]'})
        response_time = metadata.get('sip_response_time_ms', None)
        if response_time is not None:
            line_children.append({'title': f'[Response Time (ms): {int(math.ceil(float(response_time)))}]'})
        children.append({
            'title': f'Status-Line: {first_text}',
            'offset': offset + int(first['offset']),
            'length': int(first['length']),
            'children': line_children,
        })

    header_children: List[Dict[str, Any]] = []
    for line in lines[1:]:
        text = str(line.get('text', '') or '')
        if not text:
            continue
        if ':' not in text:
            header_children.append({
                'title': text,
                'offset': offset + int(line.get('offset', 0) or 0),
                'length': int(line.get('length', 0) or 0),
            })
            continue
        name, value = text.split(':', 1)
        name = name.strip()
        value = value.strip()
        line_node = {
            'title': f'{name}: {value}',
            'offset': offset + int(line.get('offset', 0) or 0),
            'length': int(line.get('length', 0) or 0),
        }
        sub_children = _sip_header_children(name, value, int(line_node['offset']))
        if sub_children:
            line_node['children'] = sub_children
        header_children.append(line_node)
    if header_children:
        children.append({
            'title': 'Message Header',
            'offset': offset + int(lines[1].get('offset', 0) or 0) if len(lines) > 1 else offset,
            'length': max(0, header_length - int(lines[0].get('length', 0) or 0) - 2),
            'children': header_children,
        })

    body = payload[body_offset:] if body_offset < len(payload) else b''
    if body:
        body_children: List[Dict[str, Any]] = []
        if str(getattr(record, 'protocol', '') or '') == 'SIP/SDP':
            body_children.append(_sdp_section(body, offset + body_offset))
        children.append({
            'title': 'Message Body',
            'offset': offset + body_offset,
            'length': len(body),
            'children': body_children,
        })

    title_suffix = ''
    if kind == 'request':
        title_suffix = f' ({str(sip_meta.get("method", "") or "")})'
    elif kind == 'response':
        title_suffix = f' ({str(sip_meta.get("status_code", "") or "")})'
    return {
        'title': f'Session Initiation Protocol{title_suffix}',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _rtp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    rtp_meta = metadata.get('rtp', {}) if isinstance(metadata.get('rtp'), dict) else {}
    if len(payload) < 12:
        return {'title': 'Real-Time Transport Protocol', 'offset': offset, 'length': len(payload), 'children': []}

    version = int(rtp_meta.get('version', (payload[0] >> 6) & 0x03) or 0)
    padding = bool(rtp_meta.get('padding', bool((payload[0] >> 5) & 0x01)))
    extension = bool(rtp_meta.get('extension', bool((payload[0] >> 4) & 0x01)))
    csrc_count = int(rtp_meta.get('csrc_count', payload[0] & 0x0F) or 0)
    marker = bool(rtp_meta.get('marker', bool((payload[1] >> 7) & 0x01)))
    payload_type = int(rtp_meta.get('payload_type', payload[1] & 0x7F) or 0)
    payload_type_name = str(rtp_meta.get('payload_type_name', f'Payload type {payload_type}') or f'Payload type {payload_type}')
    sequence = int(rtp_meta.get('sequence', int.from_bytes(payload[2:4], 'big')) or 0)
    extended_sequence = int(rtp_meta.get('extended_sequence', 65536 + sequence) or 0)
    timestamp = int(rtp_meta.get('timestamp', int.from_bytes(payload[4:8], 'big')) or 0)
    extended_timestamp = int(rtp_meta.get('extended_timestamp', 4294967296 + timestamp) or 0)
    ssrc = int(rtp_meta.get('ssrc', int.from_bytes(payload[8:12], 'big')) or 0)
    header_length = int(rtp_meta.get('header_length', 12 + csrc_count * 4) or 12)

    children: List[Dict[str, Any]] = []
    setup_frame = metadata.get('rtp_setup_frame', None)
    if setup_frame is not None:
        setup_children = [
            {'title': f'[Setup frame: {int(setup_frame)}]'},
            {'title': f'[Setup Method: {str(metadata.get("rtp_setup_method", "SDP") or "SDP")}]'},
        ]
        call_id = str(metadata.get('rtp_setup_call_id', '') or '')
        if call_id:
            setup_children.append({'title': f'[Generated Call-ID: {call_id}]'})
        children.append({'title': f'[Stream setup by SDP (frame {int(setup_frame)})]', 'children': setup_children})

    children.extend([
        {'title': f'{version:02b}.. .... = Version: RFC 1889 Version ({version})', 'offset': offset, 'length': 1},
        {'title': f'..{1 if padding else 0}. .... = Padding: {"True" if padding else "False"}', 'offset': offset, 'length': 1},
        {'title': f'...{1 if extension else 0} .... = Extension: {"True" if extension else "False"}', 'offset': offset, 'length': 1},
        {'title': f'.... {csrc_count:04b} = Contributing source identifiers count: {csrc_count}', 'offset': offset, 'length': 1},
        {'title': f'{1 if marker else 0}... .... = Marker: {"True" if marker else "False"}', 'offset': offset + 1, 'length': 1},
        {'title': f'Payload type: {payload_type_name} ({payload_type})', 'offset': offset + 1, 'length': 1},
        {'title': f'Sequence number: {sequence}', 'offset': offset + 2, 'length': 2},
        {'title': f'[Extended sequence number: {extended_sequence}]'},
        {'title': f'Timestamp: {timestamp}', 'offset': offset + 4, 'length': 4},
        {'title': f'[Extended timestamp: {extended_timestamp}]'},
        {'title': f'Synchronization Source identifier: 0x{ssrc:08x} ({ssrc})', 'offset': offset + 8, 'length': 4},
    ])

    if header_length < len(payload):
        payload_preview = payload[header_length:].hex()[:240]
        children.append({
            'title': f'Payload […]: {payload_preview}',
            'offset': offset + header_length,
            'length': len(payload) - header_length,
        })

    return {
        'title': 'Real-Time Transport Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _ssdp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    base = _http_section(payload, offset, record)
    base['title'] = 'Simple Service Discovery Protocol'
    try:
        lines = payload.split(b'\r\n')
        request_line = lines[0].decode(errors='ignore')
        parts = request_line.split(' ', 2)
        uri = parts[1].strip() if len(parts) >= 2 else ''
        host = ''
        for line in lines[1:]:
            if line.lower().startswith(b'host:'):
                host = line.split(b':', 1)[1].decode(errors='ignore').strip()
                break
        if host and uri:
            base.setdefault('children', []).append({'title': f'[Full request URI: http://{host}{uri}]'})
    except Exception:
        pass
    return base


def _tftp_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    opcode = int.from_bytes(payload[:2], 'big') if len(payload) >= 2 else 0
    opcode_name = {1: 'Read Request', 2: 'Write Request', 3: 'Data Packet', 4: 'Acknowledgement', 5: 'Error Code'}.get(opcode, str(opcode))
    children: List[Dict[str, Any]] = [
        {'title': f'Opcode: {opcode_name} ({opcode})', 'offset': offset, 'length': 2 if len(payload) >= 2 else 0},
    ]
    if opcode in {1, 2}:
        filename = str(metadata.get('tftp_filename', '') or '')
        mode = str(metadata.get('tftp_mode', '') or '')
        if filename:
            children.append({'title': f'Destination File: {filename}', 'offset': offset + 2, 'length': len(filename)})
        if mode:
            mode_start = offset + 2 + len(filename) + 1
            children.append({'title': f'Type: {mode}', 'offset': mode_start, 'length': len(mode)})
    elif opcode in {3, 4} and len(payload) >= 4:
        block = int.from_bytes(payload[2:4], 'big')
        if opcode == 4:
            filename = str(metadata.get('tftp_filename', '') or '')
            req_frame = metadata.get('tftp_request_frame')
            if filename:
                children.append({'title': f'[Destination File: {filename}]'})
            if req_frame is not None:
                children.append({'title': f'[Write Request in frame {int(req_frame)}]'})
        children.append({'title': f'Block: {block}', 'offset': offset + 2, 'length': 2})
        if opcode == 4:
            children.append({'title': f'[Full Block Number: {block}]'})
    elif opcode == 5 and len(payload) >= 4:
        err_code = int.from_bytes(payload[2:4], 'big')
        err_msg = payload[4:].split(b'\x00', 1)[0].decode(errors='ignore')
        children.append({'title': f'Error Code: {err_code}', 'offset': offset + 2, 'length': 2})
        if err_msg:
            children.append({'title': f'Error Message: {err_msg}', 'offset': offset + 4, 'length': len(err_msg)})
    return {
        'title': 'Trivial File Transfer Protocol',
        'offset': offset,
        'length': len(payload),
        'children': children,
    }


def _esp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    spi = int.from_bytes(payload[:4], 'big') if len(payload) >= 4 else 0
    seq = int.from_bytes(payload[4:8], 'big') if len(payload) >= 8 else 0
    return {
        'title': 'Encapsulating Security Payload',
        'offset': offset,
        'length': len(payload),
        'children': [
            {'title': f'ESP SPI: 0x{spi:08x} ({spi})', 'offset': offset, 'length': 4 if len(payload) >= 4 else 0},
            {'title': f'ESP Sequence: {seq}', 'offset': offset + 4, 'length': 4 if len(payload) >= 8 else 0},
        ],
    }


def _isakmp_payload_name(next_payload: int, major: int) -> str:
    if int(major) == 2:
        return {
            0: 'NONE / No Next Payload',
            33: 'Security Association',
            34: 'Key Exchange',
            35: 'Identification - Initiator',
            36: 'Identification - Responder',
            40: 'Nonce',
            41: 'Notify',
            43: 'Vendor ID',
            46: 'Encrypted and Authenticated',
        }.get(int(next_payload), f'Payload {int(next_payload)}')
    return {
        0: 'NONE / No Next Payload',
        1: 'Security Association',
        2: 'Proposal',
        3: 'Transform',
        4: 'Key Exchange',
        5: 'Identification',
        8: 'Hash',
        10: 'Nonce',
        13: 'Vendor ID',
    }.get(int(next_payload), f'Payload {int(next_payload)}')


def _isakmp_v2_exchange_name(value: int) -> str:
    return {
        34: 'IKE_SA_INIT',
        35: 'IKE_AUTH',
        36: 'CREATE_CHILD_SA',
        37: 'INFORMATIONAL',
    }.get(int(value), f'Exchange ({int(value)})')


def _isakmp_v1_exchange_name(value: int) -> str:
    return {
        2: 'Identity Protection (Main Mode)',
        4: 'Aggressive',
        5: 'Informational',
        32: 'Quick Mode',
    }.get(int(value), f'Exchange ({int(value)})')


def _isakmp_v2_transform_type_name(value: int) -> str:
    return {
        1: 'Encryption Algorithm (ENCR)',
        2: 'Pseudo-random Function (PRF)',
        3: 'Integrity Algorithm (INTEG)',
        4: 'Key Exchange Method (KE)',
        5: 'Extended Sequence Numbers (ESN)',
    }.get(int(value), f'Transform Type ({int(value)})')


def _isakmp_v2_transform_id_name(transform_type: int, transform_id: int) -> str:
    transform_type = int(transform_type)
    transform_id = int(transform_id)
    if transform_type == 1:
        return {12: 'ENCR_AES_CBC'}.get(transform_id, f'ENCR ({transform_id})')
    if transform_type == 2:
        return {7: 'PRF_HMAC_SHA2_512'}.get(transform_id, f'PRF ({transform_id})')
    if transform_type == 3:
        return {14: 'AUTH_HMAC_SHA2_512_256'}.get(transform_id, f'INTEG ({transform_id})')
    if transform_type == 4:
        return {20: '384-bit random ECP group'}.get(transform_id, str(transform_id))
    return str(transform_id)


def _isakmp_v1_attribute_name(attr_type: int) -> str:
    return {
        1: 'Encryption-Algorithm',
        2: 'Hash-Algorithm',
        3: 'Authentication-Method',
        4: 'Group-Description',
        11: 'Life-Type',
        12: 'Life-Duration',
        14: 'Key-Length',
    }.get(int(attr_type), f'Attribute-{int(attr_type)}')


def _isakmp_v1_attribute_value(attr_type: int, value: int) -> str:
    attr_type = int(attr_type)
    value = int(value)
    if attr_type == 1:
        return {7: 'AES-CBC'}.get(value, str(value))
    if attr_type == 2:
        return {2: 'SHA', 6: 'SHA2-512'}.get(value, str(value))
    if attr_type == 3:
        return {1: 'Pre-shared key'}.get(value, str(value))
    if attr_type == 4:
        return {2: 'Alternate 1024-bit MODP group', 20: '384-bit random ECP group'}.get(value, str(value))
    if attr_type == 11:
        return {1: 'Seconds'}.get(value, str(value))
    return str(value)


def _isakmp_section(payload: bytes, offset: int) -> Dict[str, Any]:
    if len(payload) < 28:
        return {
            'title': 'Internet Security Association and Key Management Protocol',
            'offset': offset,
            'length': len(payload),
            'children': [],
        }

    initiator_spi = payload[0:8]
    responder_spi = payload[8:16]
    next_payload = int(payload[16])
    version = int(payload[17])
    major = (version >> 4) & 0x0F
    minor = version & 0x0F
    exchange_type = int(payload[18])
    flags = int(payload[19])
    message_id = int.from_bytes(payload[20:24], 'big')
    total_length = int.from_bytes(payload[24:28], 'big')
    total_length = min(max(28, total_length), len(payload))

    children: List[Dict[str, Any]] = [
        {'title': f'Initiator SPI: {initiator_spi.hex()}', 'offset': offset + 0, 'length': 8},
        {'title': f'Responder SPI: {responder_spi.hex()}', 'offset': offset + 8, 'length': 8},
        {'title': f'Next payload: {_isakmp_payload_name(next_payload, major)} ({next_payload})', 'offset': offset + 16, 'length': 1},
        {
            'title': f'Version: {major}.{minor}',
            'offset': offset + 17,
            'length': 1,
            'children': [
                {'title': f'{major:04b} .... = MjVer: 0x{major:x}', 'offset': offset + 17, 'length': 1},
                {'title': f'.... {minor:04b} = MnVer: 0x{minor:x}', 'offset': offset + 17, 'length': 1},
            ],
        },
    ]

    if major == 2:
        children.append({'title': f'Exchange type: {_isakmp_v2_exchange_name(exchange_type)} ({exchange_type})', 'offset': offset + 18, 'length': 1})
        flag_children = [
            {'title': f'.... {1 if flags & 0x08 else 0}... = Initiator: {"Initiator" if flags & 0x08 else "Responder"}', 'offset': offset + 19, 'length': 1},
            {'title': f'...{1 if flags & 0x10 else 0} .... = Version: {"Higher version" if flags & 0x10 else "No higher version"}', 'offset': offset + 19, 'length': 1},
            {'title': f'..{1 if flags & 0x20 else 0}. .... = Response: {"Response" if flags & 0x20 else "Request"}', 'offset': offset + 19, 'length': 1},
        ]
        flag_title = f'Flags: 0x{flags:02x} ({"Initiator" if flags & 0x08 else "Responder"}, {"Higher version" if flags & 0x10 else "No higher version"}, {"Response" if flags & 0x20 else "Request"})'
    else:
        children.append({'title': f'Exchange type: {_isakmp_v1_exchange_name(exchange_type)} ({exchange_type})', 'offset': offset + 18, 'length': 1})
        flag_children = [
            {'title': f'.... ...{1 if flags & 0x01 else 0} = Encryption: {"Encrypted" if flags & 0x01 else "Not encrypted"}', 'offset': offset + 19, 'length': 1},
            {'title': f'.... ..{1 if flags & 0x02 else 0}. = Commit: {"Commit" if flags & 0x02 else "No commit"}', 'offset': offset + 19, 'length': 1},
            {'title': f'.... .{1 if flags & 0x04 else 0}.. = Authentication: {"Authentication" if flags & 0x04 else "No authentication"}', 'offset': offset + 19, 'length': 1},
        ]
        flag_title = f'Flags: 0x{flags:02x}'

    children.append({'title': flag_title, 'offset': offset + 19, 'length': 1, 'children': flag_children})
    children.append({'title': f'Message ID: 0x{message_id:08x}', 'offset': offset + 20, 'length': 4})
    children.append({'title': f'Length: {int(total_length)}', 'offset': offset + 24, 'length': 4})

    if major == 1 and (flags & 0x01):
        enc_len = max(0, total_length - 28)
        children.append({'title': f'Encrypted Data ({enc_len} bytes)', 'offset': offset + 28, 'length': enc_len})
        return {
            'title': 'Internet Security Association and Key Management Protocol',
            'offset': offset,
            'length': total_length,
            'children': children,
        }

    pos = 28
    current_type = int(next_payload)
    guard = 0
    while pos + 4 <= total_length and guard < 32:
        guard += 1
        np = int(payload[pos])
        flags_byte = int(payload[pos + 1])
        plen = int.from_bytes(payload[pos + 2:pos + 4], 'big')
        if plen < 4 or pos + plen > total_length:
            break

        p_name = _isakmp_payload_name(current_type, major)
        p_children: List[Dict[str, Any]] = [
            {'title': f'Next payload: {_isakmp_payload_name(np, major)} ({np})', 'offset': offset + pos, 'length': 1},
            {'title': f'{"0... .... = Critical Bit: Not critical" if (flags_byte & 0x80) == 0 else "1... .... = Critical Bit: Critical"}' if major == 2 else 'Reserved: 00', 'offset': offset + pos + 1, 'length': 1},
        ]
        if major == 2:
            p_children.append({'title': f'.{flags_byte & 0x7F:07b} = Reserved: 0x{flags_byte & 0x7F:02x}', 'offset': offset + pos + 1, 'length': 1})
        p_children.append({'title': f'Payload length: {plen}', 'offset': offset + pos + 2, 'length': 2})

        body = payload[pos + 4:pos + plen]
        body_off = pos + 4

        if current_type in {33, 1}:  # SA
            if major == 2 and len(body) >= 12:
                proposal_pos = 0
                while proposal_pos + 8 <= len(body):
                    p_next = int(body[proposal_pos])
                    p_len = int.from_bytes(body[proposal_pos + 2:proposal_pos + 4], 'big')
                    if p_len < 8 or proposal_pos + p_len > len(body):
                        break
                    p_number = int(body[proposal_pos + 4])
                    p_proto = int(body[proposal_pos + 5])
                    p_spi_size = int(body[proposal_pos + 6])
                    p_transforms = int(body[proposal_pos + 7])
                    proposal_children: List[Dict[str, Any]] = [
                        {'title': f'Next payload: {_isakmp_payload_name(p_next, major)} ({p_next})', 'offset': offset + body_off + proposal_pos, 'length': 1},
                        {'title': 'Reserved: 00', 'offset': offset + body_off + proposal_pos + 1, 'length': 1},
                        {'title': f'Payload length: {p_len}', 'offset': offset + body_off + proposal_pos + 2, 'length': 2},
                        {'title': f'Proposal number: {p_number}', 'offset': offset + body_off + proposal_pos + 4, 'length': 1},
                        {'title': f'Protocol ID: {"IKE" if p_proto == 1 else p_proto} ({p_proto})', 'offset': offset + body_off + proposal_pos + 5, 'length': 1},
                        {'title': f'SPI Size: {p_spi_size}', 'offset': offset + body_off + proposal_pos + 6, 'length': 1},
                        {'title': f'Proposal transforms: {p_transforms}', 'offset': offset + body_off + proposal_pos + 7, 'length': 1},
                    ]
                    t_pos = proposal_pos + 8 + p_spi_size
                    t_idx = 0
                    while t_pos + 8 <= proposal_pos + p_len and t_pos + 8 <= len(body):
                        t_idx += 1
                        t_next = int(body[t_pos])
                        t_len = int.from_bytes(body[t_pos + 2:t_pos + 4], 'big')
                        if t_len < 8 or t_pos + t_len > len(body):
                            break
                        t_type = int(body[t_pos + 4])
                        t_id = int.from_bytes(body[t_pos + 6:t_pos + 8], 'big')
                        t_children: List[Dict[str, Any]] = [
                            {'title': f'Next payload: {"Transform" if t_next == 3 else _isakmp_payload_name(t_next, major)} ({t_next})', 'offset': offset + body_off + t_pos, 'length': 1},
                            {'title': 'Reserved: 00', 'offset': offset + body_off + t_pos + 1, 'length': 1},
                            {'title': f'Payload length: {t_len}', 'offset': offset + body_off + t_pos + 2, 'length': 2},
                            {'title': f'Transform Type: {_isakmp_v2_transform_type_name(t_type)} ({t_type})', 'offset': offset + body_off + t_pos + 4, 'length': 1},
                            {'title': 'Reserved: 00', 'offset': offset + body_off + t_pos + 5, 'length': 1},
                        ]
                        id_name = _isakmp_v2_transform_id_name(t_type, t_id)
                        t_children.append({'title': f'Transform ID ({"ENCR" if t_type==1 else "PRF" if t_type==2 else "INTEG" if t_type==3 else "KE" if t_type==4 else "T"}): {id_name} ({t_id})', 'offset': offset + body_off + t_pos + 6, 'length': 2})
                        attr_pos = t_pos + 8
                        while attr_pos + 4 <= t_pos + t_len:
                            attr_type_val = int.from_bytes(body[attr_pos:attr_pos + 2], 'big')
                            attr_val = int.from_bytes(body[attr_pos + 2:attr_pos + 4], 'big')
                            af = 1 if (attr_type_val & 0x8000) else 0
                            a_type = attr_type_val & 0x7FFF
                            if af == 1:
                                if a_type == 14:
                                    t_children.append({
                                        'title': f'Transform Attribute (t={a_type},l=2): Key Length: {attr_val}',
                                        'offset': offset + body_off + attr_pos,
                                        'length': 4,
                                        'children': [
                                            {'title': '1... .... .... .... = Format: Type/Value (TV)', 'offset': offset + body_off + attr_pos, 'length': 2},
                                            {'title': f'Type: Key Length ({a_type})', 'offset': offset + body_off + attr_pos, 'length': 2},
                                            {'title': f'Value: {attr_val:04x}', 'offset': offset + body_off + attr_pos + 2, 'length': 2},
                                            {'title': f'Key Length: {attr_val}', 'offset': offset + body_off + attr_pos + 2, 'length': 2},
                                        ],
                                    })
                                else:
                                    t_children.append({'title': f'Transform Attribute (t={a_type},l=2): {attr_val}', 'offset': offset + body_off + attr_pos, 'length': 4})
                                attr_pos += 4
                            else:
                                break
                        proposal_children.append({
                            'title': 'Payload: Transform (3)',
                            'offset': offset + body_off + t_pos,
                            'length': t_len,
                            'children': t_children,
                        })
                        t_pos += t_len
                    p_children.append({
                        'title': f'Payload: Proposal (2) # {p_number}',
                        'offset': offset + body_off + proposal_pos,
                        'length': p_len,
                        'children': proposal_children,
                    })
                    proposal_pos += p_len
            elif major == 1 and len(body) >= 8:
                doi = int.from_bytes(body[0:4], 'big')
                situation = int.from_bytes(body[4:8], 'big')
                p_children.append({'title': f'Domain of interpretation: {"IPSEC" if doi == 1 else doi} ({doi})', 'offset': offset + body_off + 0, 'length': 4})
                p_children.append({
                    'title': f'Situation: {situation:08x}',
                    'offset': offset + body_off + 4,
                    'length': 4,
                    'children': [
                        {'title': f'.... .... .... .... .... .... .... ...{1 if situation & 0x1 else 0} = Identity Only: {"True" if situation & 0x1 else "False"}', 'offset': offset + body_off + 4, 'length': 4},
                        {'title': f'.... .... .... .... .... .... .... ..{1 if situation & 0x2 else 0}. = Secrecy: {"True" if situation & 0x2 else "False"}', 'offset': offset + body_off + 4, 'length': 4},
                        {'title': f'.... .... .... .... .... .... .... .{1 if situation & 0x4 else 0}.. = Integrity: {"True" if situation & 0x4 else "False"}', 'offset': offset + body_off + 4, 'length': 4},
                    ],
                })
                proposal_pos = 8
                while proposal_pos + 8 <= len(body):
                    p_next = int(body[proposal_pos])
                    p_len = int.from_bytes(body[proposal_pos + 2:proposal_pos + 4], 'big')
                    if p_len < 8 or proposal_pos + p_len > len(body):
                        break
                    p_number = int(body[proposal_pos + 4])
                    p_proto = int(body[proposal_pos + 5])
                    p_spi_size = int(body[proposal_pos + 6])
                    p_transforms = int(body[proposal_pos + 7])
                    proposal_children = [
                        {'title': f'Next payload: {_isakmp_payload_name(p_next, major)} ({p_next})', 'offset': offset + body_off + proposal_pos, 'length': 1},
                        {'title': 'Reserved: 00', 'offset': offset + body_off + proposal_pos + 1, 'length': 1},
                        {'title': f'Payload length: {p_len}', 'offset': offset + body_off + proposal_pos + 2, 'length': 2},
                        {'title': f'Proposal number: {p_number}', 'offset': offset + body_off + proposal_pos + 4, 'length': 1},
                        {'title': f'Protocol ID: {"ISAKMP" if p_proto == 1 else p_proto} ({p_proto})', 'offset': offset + body_off + proposal_pos + 5, 'length': 1},
                        {'title': f'SPI Size: {p_spi_size}', 'offset': offset + body_off + proposal_pos + 6, 'length': 1},
                        {'title': f'Proposal transforms: {p_transforms}', 'offset': offset + body_off + proposal_pos + 7, 'length': 1},
                    ]
                    t_pos = proposal_pos + 8 + p_spi_size
                    t_idx = 0
                    while t_pos + 8 <= proposal_pos + p_len and t_pos + 8 <= len(body):
                        t_idx += 1
                        t_next = int(body[t_pos])
                        t_len = int.from_bytes(body[t_pos + 2:t_pos + 4], 'big')
                        if t_len < 8 or t_pos + t_len > len(body):
                            break
                        t_number = int(body[t_pos + 4])
                        t_id = int(body[t_pos + 5])
                        t_children = [
                            {'title': f'Next payload: {_isakmp_payload_name(t_next, major)} ({t_next})', 'offset': offset + body_off + t_pos, 'length': 1},
                            {'title': 'Reserved: 00', 'offset': offset + body_off + t_pos + 1, 'length': 1},
                            {'title': f'Payload length: {t_len}', 'offset': offset + body_off + t_pos + 2, 'length': 2},
                            {'title': f'Transform number: {t_number}', 'offset': offset + body_off + t_pos + 4, 'length': 1},
                            {'title': f'Transform ID: {"KEY_IKE" if t_id == 1 else t_id} ({t_id})', 'offset': offset + body_off + t_pos + 5, 'length': 1},
                            {'title': 'Reserved: 0000', 'offset': offset + body_off + t_pos + 6, 'length': 2},
                        ]
                        attr_pos = t_pos + 8
                        while attr_pos + 4 <= t_pos + t_len:
                            raw_type = int.from_bytes(body[attr_pos:attr_pos + 2], 'big')
                            raw_val = int.from_bytes(body[attr_pos + 2:attr_pos + 4], 'big')
                            tv = 1 if (raw_type & 0x8000) else 0
                            attr_type = raw_type & 0x7FFF
                            if tv != 1:
                                break
                            attr_name = _isakmp_v1_attribute_name(attr_type)
                            value_name = _isakmp_v1_attribute_value(attr_type, raw_val)
                            suffix = f': {value_name}' if attr_type not in {12, 14} else f': {raw_val}'
                            if attr_type == 11:
                                suffix = f': Life-Type: {value_name}'
                            elif attr_type == 12:
                                suffix = f': Life-Duration: {raw_val}'
                            elif attr_type == 14:
                                suffix = f': Key-Length: {raw_val}'
                            elif attr_type == 1:
                                suffix = f': Encryption-Algorithm: {value_name}'
                            elif attr_type == 2:
                                suffix = f': Hash-Algorithm: {value_name}'
                            elif attr_type == 3:
                                suffix = f': Authentication-Method: {value_name}'
                            elif attr_type == 4:
                                suffix = f': Group-Description: {value_name}'
                            value_detail = f'Value: {raw_val}'
                            if attr_type == 11:
                                value_detail = f'Life Type: {value_name} ({raw_val})'
                            elif attr_type == 12:
                                value_detail = f'Life Duration: {raw_val}'
                            elif attr_type == 14:
                                value_detail = f'Key Length: {raw_val}'
                            elif attr_type == 1:
                                value_detail = f'Encryption Algorithm: {value_name} ({raw_val})'
                            elif attr_type == 2:
                                value_detail = f'HASH Algorithm: {value_name} ({raw_val})'
                            elif attr_type == 3:
                                value_detail = f'Authentication Method: {value_name} ({raw_val})'
                            elif attr_type == 4:
                                value_detail = f'Group Description: {value_name} ({raw_val})'
                            t_children.append({
                                'title': f'IKE Attribute (t={attr_type},l=2){suffix}',
                                'offset': offset + body_off + attr_pos,
                                'length': 4,
                                'children': [
                                    {'title': '1... .... .... .... = Format: Type/Value (TV)', 'offset': offset + body_off + attr_pos, 'length': 2},
                                    {'title': f'Type: {attr_name} ({attr_type})', 'offset': offset + body_off + attr_pos, 'length': 2},
                                    {'title': f'Value: {raw_val:04x}', 'offset': offset + body_off + attr_pos + 2, 'length': 2},
                                    {'title': value_detail, 'offset': offset + body_off + attr_pos + 2, 'length': 2},
                                ],
                            })
                            attr_pos += 4
                        proposal_children.append({
                            'title': f'Payload: Transform (3) # {t_idx}',
                            'offset': offset + body_off + t_pos,
                            'length': t_len,
                            'children': t_children,
                        })
                        t_pos += t_len
                    p_children.append({
                        'title': f'Payload: Proposal (2) # {p_number}',
                        'offset': offset + body_off + proposal_pos,
                        'length': p_len,
                        'children': proposal_children,
                    })
                    proposal_pos += p_len
        elif current_type in {34, 4}:  # KE (v2/v1)
            if major == 2 and len(body) >= 4:
                ke_method = int.from_bytes(body[0:2], 'big')
                p_children.append({'title': f'Key Exchange Method: {_isakmp_v2_transform_id_name(4, ke_method)} ({ke_method})', 'offset': offset + body_off + 0, 'length': 2})
                p_children.append({'title': f'Reserved: {body[2:4].hex()}', 'offset': offset + body_off + 2, 'length': 2})
                if len(body) > 4:
                    preview = body[4:].hex()
                    title = f'Key Exchange Data{" [...]" if len(preview) > 320 else ""}: {preview[:320] if len(preview)>320 else preview}'
                    p_children.append({'title': title, 'offset': offset + body_off + 4, 'length': len(body) - 4})
            else:
                preview = body.hex()
                title = f'Key Exchange Data{" [...]" if len(preview) > 320 else ""}: {preview[:320] if len(preview)>320 else preview}'
                p_children.append({'title': title, 'offset': offset + body_off, 'length': len(body)})
        elif current_type in {40, 10}:  # Nonce
            p_children.append({'title': f'Nonce DATA: {body.hex()}', 'offset': offset + body_off, 'length': len(body)})
        elif current_type == 5 and major == 1 and len(body) >= 4:  # ID
            id_type = int(body[0])
            proto_id = int(body[1])
            port = int.from_bytes(body[2:4], 'big')
            id_data = body[4:]
            id_text = id_data.decode(errors='ignore')
            p_children.append({'title': f'ID type: {"FQDN" if id_type == 2 else id_type} ({id_type})', 'offset': offset + body_off + 0, 'length': 1})
            p_children.append({'title': f'Protocol ID: {"Unused" if proto_id == 0 else proto_id}', 'offset': offset + body_off + 1, 'length': 1})
            p_children.append({'title': f'Port: {"Unused" if port == 0 else port}', 'offset': offset + body_off + 2, 'length': 2})
            p_children.append({
                'title': f'Identification Data:{id_text}',
                'offset': offset + body_off + 4,
                'length': len(id_data),
                'children': [{'title': f'ID_FQDN: {id_text}', 'offset': offset + body_off + 4, 'length': len(id_data)}] if id_type == 2 else [],
            })
        elif current_type == 13 and major == 1:  # Vendor ID
            vendor_hex = body.hex()
            vendor_name = 'Unknown Vendor ID'
            if vendor_hex.startswith('afcad71368a1f1c96b8696fc77570100'):
                vendor_name = 'RFC 3706 DPD (Dead Peer Detection)'
            elif vendor_hex.startswith('09002689dfd6b712'):
                vendor_name = 'XAUTH'
            p_children.append({'title': f'Vendor ID: {vendor_hex}', 'offset': offset + body_off, 'length': len(body)})
            p_children.append({'title': f'Vendor ID: {vendor_name}'})
        elif current_type == 46 and major == 2:
            if len(body) >= 4:
                p_children.append({'title': f'Initialization Vector: {body[:4].hex()}', 'offset': offset + body_off, 'length': 4})
                if len(body) > 4:
                    p_children.append({'title': 'Encrypted Data', 'offset': offset + body_off + 4, 'length': len(body) - 4})
            else:
                p_children.append({'title': 'Encrypted Data', 'offset': offset + body_off, 'length': len(body)})

        node_title = f'Payload: {p_name} ({current_type})'
        if current_type == 13 and major == 1 and len(body) > 0:
            vendor_hex = body.hex()
            if vendor_hex.startswith('afcad71368a1f1c96b8696fc77570100'):
                node_title = 'Payload: Vendor ID (13) : RFC 3706 DPD (Dead Peer Detection)'
            elif vendor_hex.startswith('09002689dfd6b712'):
                node_title = 'Payload: Vendor ID (13) : XAUTH'
            else:
                node_title = 'Payload: Vendor ID (13) : Unknown Vendor ID'

        children.append({
            'title': node_title,
            'offset': offset + pos,
            'length': plen,
            'children': p_children,
        })

        current_type = np
        pos += plen
        if current_type == 0:
            break

    return {
        'title': 'Internet Security Association and Key Management Protocol',
        'offset': offset,
        'length': total_length,
        'children': children,
    }


def _ipv6_fragment_section(layer, offset: int) -> Dict[str, Any]:
    next_header = int(getattr(layer, 'nh', 0) or 0)
    reserved = int(getattr(layer, 'res1', 0) or 0)
    fragment_offset = int(getattr(layer, 'offset', 0) or 0)
    more_flag = int(getattr(layer, 'm', 0) or 0)
    ident = int(getattr(layer, 'id', 0) or 0)
    next_header_name = {
        6: 'TCP',
        17: 'UDP',
        58: 'ICMPv6',
    }.get(next_header, str(next_header))
    offset_bits = format(fragment_offset, '013b')
    children = [
        {'title': f'Next header: {next_header_name} ({next_header})', 'offset': offset, 'length': 1},
        {'title': f'Reserved octet: 0x{reserved:02x}', 'offset': offset + 1, 'length': 1},
        {'title': f'{offset_bits[:4]} {offset_bits[4:8]} {offset_bits[8:12]} {offset_bits[12]}... = Offset: {fragment_offset} ({fragment_offset * 8} bytes)', 'offset': offset + 2, 'length': 2},
        {'title': '.... .... .... .00. = Reserved bits: 0', 'offset': offset + 2, 'length': 2},
        {'title': f'.... .... .... ...{more_flag} = More Fragments: {"Yes" if more_flag else "No"}', 'offset': offset + 3, 'length': 1},
        {'title': f'Identification: 0x{ident:08x}', 'offset': offset + 4, 'length': 4},
    ]
    return {
        'title': 'Fragment Header for IPv6',
        'offset': offset,
        'length': 8,
        'children': children,
    }


def _ssh_message_name(msg_code: int, kex_method: str = '') -> str:
    method = str(kex_method or '').lower()
    if int(msg_code) == 31 and 'group-exchange' in method:
        return 'Diffie-Hellman Group Exchange Group'
    names = {
        1: 'Disconnect',
        2: 'Ignore',
        3: 'Unimplemented',
        4: 'Debug',
        5: 'Service Request',
        6: 'Service Accept',
        20: 'Key Exchange Init',
        21: 'New Keys',
        30: 'Diffie-Hellman Key Exchange Init',
        31: 'Diffie-Hellman Key Exchange Reply',
        32: 'Diffie-Hellman Group Exchange Init',
        33: 'Diffie-Hellman Group Exchange Reply',
        34: 'Diffie-Hellman Group Exchange Request',
        50: 'User Authentication Request',
        51: 'User Authentication Failure',
        52: 'User Authentication Success',
        53: 'User Authentication Banner',
        80: 'Global Request',
        81: 'Request Success',
        82: 'Request Failure',
    }
    return names.get(int(msg_code), f'Message ({int(msg_code)})')


def _ssh_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record else {}
    reassembled_hex = str(metadata.get('tcp_reassembled_data_hex', '') or '')
    use_reassembled = False
    if reassembled_hex:
        try:
            payload = bytes.fromhex(reassembled_hex)
            use_reassembled = True
            offset = 0
        except Exception:
            pass

    byte_source = TCP_REASSEMBLED_BYTE_SOURCE if use_reassembled else PACKET_BYTE_SOURCE
    base_offset = 0 if use_reassembled else int(offset)

    def _map(rel_offset: int, length: int) -> Dict[str, Any]:
        return _byte_mapping(base_offset, rel_offset, length, byte_source)

    def _hex_preview(value: bytes, limit_chars: int = 320) -> tuple[str, bool]:
        text = bytes(value or b'').hex()
        if len(text) > limit_chars:
            return text[:limit_chars], True
        return text, False

    def _read_u32(buf: bytes, pos: int) -> tuple[int, int] | None:
        if pos + 4 > len(buf):
            return None
        return int.from_bytes(buf[pos:pos + 4], 'big'), pos + 4

    def _read_string(buf: bytes, pos: int) -> tuple[bytes, int, int, int] | None:
        parsed = _read_u32(buf, pos)
        if parsed is None:
            return None
        length, next_pos = parsed
        end_pos = next_pos + int(length)
        if end_pos > len(buf):
            return None
        return buf[next_pos:end_pos], end_pos, pos, int(length)

    def _read_mpint(buf: bytes, pos: int) -> tuple[bytes, int, int] | None:
        parsed = _read_u32(buf, pos)
        if parsed is None:
            return None
        mp_len, next_pos = parsed
        end_pos = next_pos + int(mp_len)
        if end_pos > len(buf):
            return None
        return buf[next_pos:end_pos], end_pos, int(mp_len)

    children: List[Dict[str, Any]] = []
    if payload.startswith(b'SSH-'):
        line = payload.split(b'\n', 1)[0]
        line_text = line.rstrip(b'\r').decode(errors='ignore')
        children.append({
            'title': f'Protocol Version Exchange: {line_text}',
            **_map(0, len(line)),
        })
        if b'\n' in payload:
            children.append({'title': '\\n', **_map(len(line), 1)})
        return {
            'title': 'SSH Protocol',
            **_map(0, len(payload)),
            'children': children,
        }

    tcp_layer = _effective_tcp_layer(getattr(record, 'raw', None), _effective_ip_layer(getattr(record, 'raw', None))) if record else None
    direction = 'Server to Client' if tcp_layer is not None and int(getattr(tcp_layer, 'sport', 0) or 0) == 22 else 'Client to Server'
    kex_method = str(metadata.get('ssh_kex_method', '') or 'diffie-hellman-group-exchange-sha1')
    encryption = str(metadata.get('ssh_encryption', '') or 'aes128-cbc')
    mac_name = str(metadata.get('ssh_mac', '') or 'hmac-sha1')
    compression = str(metadata.get('ssh_compression', '') or 'none')

    version_children: List[Dict[str, Any]] = []
    if len(payload) >= 5:
        packet_length = int.from_bytes(payload[0:4], 'big')
        padding_length = int(payload[4])
        if packet_length >= 2 and packet_length + 4 <= len(payload):
            payload_end = 4 + packet_length - padding_length
            version_children.append({'title': f'Packet Length: {packet_length}', **_map(0, 4)})
            version_children.append({'title': f'Padding Length: {padding_length}', **_map(4, 1)})
            if payload_end > 5:
                msg_code = int(payload[5])
                msg_name = _ssh_message_name(msg_code, kex_method)
                key_exchange_children: List[Dict[str, Any]] = [
                    {'title': f'Message Code: {msg_name} ({msg_code})', **_map(5, 1)}
                ]
                msg_payload = payload[6:payload_end]
                msg_rel = 6

                if msg_code == 20 and len(msg_payload) >= 16:
                    algo_children: List[Dict[str, Any]] = [
                        {'title': f'Cookie: {msg_payload[:16].hex()}', **_map(msg_rel, 16)}
                    ]
                    pos = 16
                    fields = [
                        'kex_algorithms',
                        'server_host_key_algorithms',
                        'encryption_algorithms_client_to_server',
                        'encryption_algorithms_server_to_client',
                        'mac_algorithms_client_to_server',
                        'mac_algorithms_server_to_client',
                        'compression_algorithms_client_to_server',
                        'compression_algorithms_server_to_client',
                        'languages_client_to_server',
                        'languages_server_to_client',
                    ]
                    for field in fields:
                        if pos + 4 > len(msg_payload):
                            break
                        name_len = int.from_bytes(msg_payload[pos:pos + 4], 'big')
                        algo_children.append({'title': f'{field} length: {name_len}', **_map(msg_rel + pos, 4)})
                        pos += 4
                        value = msg_payload[pos:pos + name_len]
                        text = value.decode(errors='ignore')
                        title = f'{field} string [...]: {text}' if len(text) > 260 else f'{field} string: {text}'
                        algo_children.append({'title': title, **_map(msg_rel + pos, len(value))})
                        pos += len(value)
                    if pos + 1 <= len(msg_payload):
                        first_kex = int(msg_payload[pos])
                        algo_children.append({'title': f'First KEX Packet Follows: {first_kex}', **_map(msg_rel + pos, 1)})
                        pos += 1
                    if pos + 4 <= len(msg_payload):
                        algo_children.append({'title': f'Reserved: {msg_payload[pos:pos + 4].hex()}', **_map(msg_rel + pos, 4)})
                        pos += 4
                    key_exchange_children.append({
                        'title': 'Algorithms',
                        **_map(msg_rel, len(msg_payload)),
                        'children': algo_children,
                    })
                elif msg_code == 34 and len(msg_payload) >= 12:
                    min_bits = int.from_bytes(msg_payload[0:4], 'big')
                    n_bits = int.from_bytes(msg_payload[4:8], 'big')
                    max_bits = int.from_bytes(msg_payload[8:12], 'big')
                    key_exchange_children.extend([
                        {'title': f'DH GEX Min: {min_bits}', **_map(msg_rel, 4)},
                        {'title': f'DH GEX Number of Bits: {n_bits}', **_map(msg_rel + 4, 4)},
                        {'title': f'DH GEX Max: {max_bits}', **_map(msg_rel + 8, 4)},
                    ])
                elif msg_code == 31 and len(msg_payload) >= 4 and 'group-exchange' in kex_method.lower():
                    parsed_mp = _read_mpint(msg_payload, 0)
                    if parsed_mp is not None:
                        mp_val, pos, mp_len = parsed_mp
                        key_exchange_children.append({'title': f'Multi Precision Integer Length: {mp_len}', **_map(msg_rel, 4)})
                        preview, truncated = _hex_preview(mp_val)
                        mod_title = f'DH GEX modulus (P) [...]: {preview}' if truncated else f'DH GEX modulus (P): {preview}'
                        key_exchange_children.append({'title': mod_title, **_map(msg_rel + 4, len(mp_val))})
                        parsed_g = _read_mpint(msg_payload, pos)
                        if parsed_g is not None:
                            g_val, _, g_len = parsed_g
                            key_exchange_children.append({'title': f'Multi Precision Integer Length: {g_len}', **_map(msg_rel + pos, 4)})
                            g_preview, g_truncated = _hex_preview(g_val)
                            g_title = f'DH GEX base (G) [...]: {g_preview}' if g_truncated else f'DH GEX base (G): {g_preview}'
                            key_exchange_children.append({'title': g_title, **_map(msg_rel + pos + 4, len(g_val))})
                elif msg_code == 32 and len(msg_payload) >= 4:
                    parsed_e = _read_mpint(msg_payload, 0)
                    if parsed_e is not None:
                        e_val, _, e_len = parsed_e
                        key_exchange_children.append({'title': f'Multi Precision Integer Length: {e_len}', **_map(msg_rel, 4)})
                        e_preview, e_truncated = _hex_preview(e_val)
                        e_title = f'DH client e [...]: {e_preview}' if e_truncated else f'DH client e: {e_preview}'
                        key_exchange_children.append({'title': e_title, **_map(msg_rel + 4, len(e_val))})
                elif msg_code == 33 and len(msg_payload) >= 4:
                    pos = 0
                    host_key = _read_string(msg_payload, pos)
                    if host_key is not None:
                        host_blob, pos, host_len_pos, host_len = host_key
                        key_exchange_children.append({
                            'title': 'KEX host key (type: ssh-rsa)',
                            **_map(msg_rel + host_len_pos, 4 + host_len),
                            'children': [],
                        })
                        host_children = key_exchange_children[-1]['children']
                        host_children.append({'title': f'Host key length: {host_len}', **_map(msg_rel + host_len_pos, 4)})
                        host_pos = 0
                        key_type_parsed = _read_string(host_blob, host_pos)
                        if key_type_parsed is not None:
                            key_type_blob, host_pos, type_len_pos, type_len = key_type_parsed
                            key_type = key_type_blob.decode(errors='ignore')
                            host_children.append({'title': f'Host key type length: {type_len}', **_map(msg_rel + host_len_pos + 4 + type_len_pos, 4)})
                            host_children.append({'title': f'Host key type: {key_type}', **_map(msg_rel + host_len_pos + 4 + type_len_pos + 4, len(key_type_blob))})
                        exp_parsed = _read_mpint(host_blob, host_pos)
                        if exp_parsed is not None:
                            exp_val, host_pos, exp_len = exp_parsed
                            host_children.append({'title': f'Multi Precision Integer Length: {exp_len}', **_map(msg_rel + host_len_pos + 4 + host_pos - exp_len - 4, 4)})
                            host_children.append({'title': f'RSA public exponent (e): {exp_val.hex()}', **_map(msg_rel + host_len_pos + 4 + host_pos - exp_len, len(exp_val))})
                        mod_parsed = _read_mpint(host_blob, host_pos)
                        if mod_parsed is not None:
                            mod_val, _, mod_len = mod_parsed
                            host_children.append({'title': f'Multi Precision Integer Length: {mod_len}', **_map(msg_rel + host_len_pos + 4 + host_pos, 4)})
                            mod_preview, mod_truncated = _hex_preview(mod_val)
                            mod_title = f'RSA modulus (N) [...]: {mod_preview}' if mod_truncated else f'RSA modulus (N): {mod_preview}'
                            host_children.append({'title': mod_title, **_map(msg_rel + host_len_pos + 4 + host_pos + 4, len(mod_val))})
                    f_mpint = _read_mpint(msg_payload, pos)
                    if f_mpint is not None:
                        f_val, pos, f_len = f_mpint
                        key_exchange_children.append({'title': f'Multi Precision Integer Length: {f_len}', **_map(msg_rel + pos - f_len - 4, 4)})
                        f_preview, f_truncated = _hex_preview(f_val)
                        f_title = f'DH server f [...]: {f_preview}' if f_truncated else f'DH server f: {f_preview}'
                        key_exchange_children.append({'title': f_title, **_map(msg_rel + pos - f_len, len(f_val))})
                    sig_str = _read_string(msg_payload, pos)
                    if sig_str is not None:
                        sig_blob, _, sig_len_pos, sig_len = sig_str
                        sig_children: List[Dict[str, Any]] = []
                        sig_children.append({'title': f'Host signature length: {sig_len}', **_map(msg_rel + sig_len_pos, 4)})
                        sig_pos = 0
                        sig_type_parsed = _read_string(sig_blob, sig_pos)
                        if sig_type_parsed is not None:
                            sig_type_blob, sig_pos, s_type_len_pos, s_type_len = sig_type_parsed
                            sig_type = sig_type_blob.decode(errors='ignore')
                            sig_children.append({'title': f'Host signature type length: {s_type_len}', **_map(msg_rel + sig_len_pos + 4 + s_type_len_pos, 4)})
                            sig_children.append({'title': f'Host signature type: {sig_type}', **_map(msg_rel + sig_len_pos + 4 + s_type_len_pos + 4, len(sig_type_blob))})
                        sig_mp = _read_mpint(sig_blob, sig_pos)
                        if sig_mp is not None:
                            sig_val, _, sig_mp_len = sig_mp
                            sig_children.append({'title': f'Multi Precision Integer Length: {sig_mp_len}', **_map(msg_rel + sig_len_pos + 4 + sig_pos, 4)})
                            sig_preview, sig_truncated = _hex_preview(sig_val)
                            sig_title = f'RSA signature [...]: {sig_preview}' if sig_truncated else f'RSA signature: {sig_preview}'
                            sig_children.append({'title': sig_title, **_map(msg_rel + sig_len_pos + 4 + sig_pos + 4, len(sig_val))})
                        key_exchange_children.append({
                            'title': 'KEX host signature (type: ssh-rsa)',
                            **_map(msg_rel + sig_len_pos, 4 + sig_len),
                            'children': sig_children,
                        })

                key_exchange_node = {
                    'title': f'Key Exchange (method:{kex_method})',
                    **_map(5, max(1, payload_end - 5)),
                    'children': key_exchange_children,
                }
                version_children.append(key_exchange_node)

            if padding_length > 0 and payload_end >= 0:
                padding_bytes = payload[payload_end:4 + packet_length]
                version_children.append({'title': f'Padding String: {padding_bytes.hex()}', **_map(payload_end, len(padding_bytes))})
            if metadata.get('ssh_sequence_number', None) is not None:
                version_children.append({'title': f"[Sequence number: {int(metadata.get('ssh_sequence_number', 0) or 0)}]"})
        else:
            mac_len = 20
            encrypted_field = payload[4:max(4, len(payload) - mac_len)] if len(payload) > 4 else b''
            mac_field = payload[max(4, len(payload) - mac_len):] if len(payload) >= 4 else b''
            version_children.append({'title': f'Packet Length (encrypted): {payload[0:4].hex()}', **_map(0, min(4, len(payload)))})
            if encrypted_field:
                version_children.append({'title': f'Encrypted Packet: {encrypted_field.hex()}', **_map(4, len(encrypted_field))})
            if mac_field:
                version_children.append({'title': f'MAC: {mac_field.hex()}', **_map(len(payload) - len(mac_field), len(mac_field))})

    children.append({
        'title': f'SSH Version 2 (encryption:{encryption} mac:{mac_name} compression:{compression})',
        **_map(0, len(payload)),
        'children': version_children,
    })
    children.append({'title': f'[Direction: {direction}]'})

    return {
        'title': 'SSH Protocol',
        **_map(0, len(payload)),
        'children': children,
    }


def _xml_body_section(record, offset: int) -> Dict[str, Any] | None:
    metadata = getattr(record, 'metadata', {}) or {}
    body = bytes(metadata.get('http_body', b'') or b'')
    if not body:
        return None
    try:
        text = body.decode('utf-8', errors='strict')
    except Exception:
        text = body.decode('utf-8', errors='ignore')
    use_offsets = not bool(metadata.get('http_is_reassembled', False))
    byte_source = PACKET_BYTE_SOURCE if use_offsets else TCP_REASSEMBLED_BYTE_SOURCE
    body_offset = int(metadata.get('http_header_len', 0) or 0) + int(metadata.get('http_payload_offset', 0) or 0)
    lines: List[Dict[str, Any]] = []
    cursor = 0
    for raw_line in text.splitlines(keepends=True):
        raw_bytes = raw_line.encode('utf-8', errors='ignore')
        line_text = raw_line.rstrip('\r\n').lstrip()
        if line_text:
            lines.append({
                'title': line_text,
                **_byte_mapping(offset, body_offset + cursor, len(raw_bytes), byte_source),
            })
        cursor += len(raw_bytes)
    if not lines:
        lines.append({
            'title': text,
            **_byte_mapping(offset, body_offset, len(body), byte_source),
        })
    return {
        'title': 'eXtensible Markup Language',
        **_byte_mapping(offset, body_offset, len(body), byte_source),
        'children': lines,
    }


def _pop_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    data = bytes(payload or b'')
    metadata = getattr(record, 'metadata', {}) if record else {}
    pop_meta = metadata.get('pop') if isinstance(metadata.get('pop'), dict) else {}
    raw_line = data.split(b'\r\n', 1)[0] if data else b''
    line_text = raw_line.decode(errors='ignore')
    line_len = len(raw_line) + (2 if data.startswith(raw_line + b'\r\n') else 0)

    children: List[Dict[str, Any]] = []
    if line_text:
        line_node: Dict[str, Any] = {
            'title': f'{line_text}\\r\\n',
            **_byte_mapping(offset, 0, max(1, line_len), PACKET_BYTE_SOURCE),
            'children': [],
        }
        marker = ''
        if isinstance(pop_meta, dict):
            marker = str(pop_meta.get('marker', '') or '')
        if not marker and (line_text.startswith('+OK') or line_text.startswith('-ERR')):
            marker = '+OK' if line_text.startswith('+OK') else '-ERR'

        if marker:
            desc = str(pop_meta.get('description', '') or '').strip() if isinstance(pop_meta, dict) else ''
            if not desc:
                desc = line_text[len(marker):].strip()
            line_node['children'].append({
                'title': f'Response indicator: {marker}',
                **_byte_mapping(offset, 0, min(3, len(raw_line)), PACKET_BYTE_SOURCE),
            })
            if desc:
                desc_start = max(0, len(marker) + 1)
                line_node['children'].append({
                    'title': f'Response description: {desc}',
                    **_byte_mapping(offset, desc_start, max(1, len(raw_line) - desc_start), PACKET_BYTE_SOURCE),
                })
        else:
            cmd = str(pop_meta.get('command', '') or '').strip() if isinstance(pop_meta, dict) else ''
            if not cmd:
                cmd = line_text.split(' ', 1)[0].upper() if line_text else ''
            if cmd:
                line_node['children'].append({
                    'title': f'Request command: {cmd}',
                    **_byte_mapping(offset, 0, len(cmd), PACKET_BYTE_SOURCE),
                })
        children.append(line_node)

    return {
        'title': 'Post Office Protocol',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _pop_imf_section(payload: bytes, offset: int, record=None) -> Dict[str, Any]:
    data = bytes(payload or b'')
    text = data.decode(errors='ignore')
    raw_lines = text.splitlines()
    line_nodes: List[Dict[str, Any]] = []
    cursor = 0
    for line in raw_lines:
        needle = line.encode('utf-8', errors='ignore')
        idx = data.find(needle, cursor)
        if idx < 0:
            idx = data.find(needle)
        if idx < 0:
            idx = cursor
        cursor = idx + len(needle)
        line_nodes.append({
            'text': line,
            'offset': idx,
            'length': max(1, len(needle)),
        })

    children: List[Dict[str, Any]] = []
    unknown_count = 0
    for node in line_nodes:
        line = str(node['text'])
        if ':' in line and unknown_count < 3:
            unknown_count += 1
            k, v = line.split(':', 1)
            children.append({
                'title': f'Unknown-Extension: {line} (Unsupported extension.)',
                **_byte_mapping(offset, int(node['offset']), int(node['length']), PACKET_BYTE_SOURCE),
                'children': [
                    {
                        'title': f'Type: {k.strip()}',
                        **_byte_mapping(offset, int(node['offset']), max(1, len(k.encode("utf-8", errors="ignore"))), PACKET_BYTE_SOURCE),
                    },
                    {
                        'title': f'Value: {v.strip()}',
                        **_byte_mapping(
                            offset,
                            int(node['offset']) + len(k.encode('utf-8', errors='ignore')) + 1,
                            max(1, int(node['length']) - len(k.encode('utf-8', errors='ignore')) - 1),
                            PACKET_BYTE_SOURCE,
                        ),
                    },
                ],
            })

    msg_children: List[Dict[str, Any]] = []
    for node in line_nodes:
        text_line = str(node['text'])
        if not text_line.strip():
            continue
        msg_children.append({
            'title': f'{text_line}  ',
            **_byte_mapping(offset, int(node['offset']), int(node['length']), PACKET_BYTE_SOURCE),
        })
    if msg_children:
        start = int(msg_children[0].get('offset', offset))
        end = int(msg_children[-1].get('offset', offset)) + int(msg_children[-1].get('length', 1))
        children.append({
            'title': 'Message-Text',
            'offset': start,
            'length': max(1, end - start),
            'children': msg_children,
        })

    return {
        'title': 'Internet Message Format',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _nbss_section(payload: bytes, offset: int) -> Dict[str, Any]:
    data = bytes(payload or b'')
    if len(data) < 4:
        return {
            'title': 'NetBIOS Session Service',
            **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
            'children': [],
        }
    msg_type = int(data[0])
    length = int.from_bytes(data[1:4], 'big') & 0x00FFFFFF
    type_name = 'Session message' if msg_type == 0x00 else f'0x{msg_type:02x}'
    return {
        'title': 'NetBIOS Session Service',
        **_byte_mapping(offset, 0, min(4, len(data)), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Message Type: {type_name} (0x{msg_type:02x})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Length: {length}', **_byte_mapping(offset, 1, 3, PACKET_BYTE_SOURCE)},
        ],
    }


def _rdp_tpkt_sections(payload: bytes, offset: int) -> List[Dict[str, Any]]:
    data = bytes(payload or b'')
    if len(data) < 11 or data[0] != 0x03 or data[1] != 0x00:
        return [{
            'title': f'Data ({len(data)} bytes)',
            **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
            'children': [{'title': f'Data: {data.hex()}'}],
        }]

    tpkt_len = int.from_bytes(data[2:4], 'big')
    if tpkt_len > len(data):
        tpkt_len = len(data)
    cotp_len = int(data[4]) if len(data) >= 5 else 0
    cotp_total = min(max(0, cotp_len + 1), max(0, tpkt_len - 4))
    cotp_start = 4
    cotp_end = cotp_start + cotp_total
    pdu_type = int(data[5]) if len(data) >= 6 else 0
    dst_ref = int.from_bytes(data[6:8], 'big') if len(data) >= 8 else 0
    src_ref = int.from_bytes(data[8:10], 'big') if len(data) >= 10 else 0
    class_opts = int(data[10]) if len(data) >= 11 else 0
    var_start = min(len(data), cotp_start + 7)
    var_end = min(len(data), cotp_end)
    variable = data[var_start:var_end]
    cookie_text = ''
    cookie_line = ''
    nego_off = 0
    if variable.startswith(b'Cookie:'):
        eol = variable.find(b'\r\n')
        if eol > 0:
            cookie_line = variable[:eol].decode('ascii', errors='ignore').strip()
            cookie_text = cookie_line[len('Cookie:'):].strip() if cookie_line.lower().startswith('cookie:') else ''
            nego_off = eol + 2
    if nego_off + 8 > len(variable):
        nego_off = max(0, len(variable) - 8)
    nego_blob = variable[nego_off:nego_off + 8] if len(variable) >= 8 else b''

    tpkt_section = {
        'title': f'TPKT, Version: {int(data[0])}, Length: {tpkt_len}',
        **_byte_mapping(offset, 0, min(4, len(data)), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Version: {int(data[0])}', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Reserved: {int(data[1])}', **_byte_mapping(offset, 1, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Length: {tpkt_len}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)},
        ],
    }

    pdu_name = {0xE0: 'CR Connect Request', 0xD0: 'CC Connect Confirm'}.get(pdu_type, f'0x{pdu_type:02x}')
    cotp_section = {
        'title': 'ISO 8073/X.224 COTP Connection-Oriented Transport Protocol',
        **_byte_mapping(offset, cotp_start, max(0, cotp_total), PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'Length: {cotp_len}', **_byte_mapping(offset, cotp_start, 1, PACKET_BYTE_SOURCE)},
            {'title': f'PDU Type: {pdu_name} (0x{pdu_type >> 4:02x})', **_byte_mapping(offset, cotp_start + 1, 1, PACKET_BYTE_SOURCE)},
            {'title': f'Destination reference: 0x{dst_ref:04x}', **_byte_mapping(offset, cotp_start + 2, 2, PACKET_BYTE_SOURCE)},
            {'title': f'Source reference: 0x{src_ref:04x}', **_byte_mapping(offset, cotp_start + 4, 2, PACKET_BYTE_SOURCE)},
            {'title': f'0000 .... = Class: {(class_opts >> 4) & 0x0F}', **_byte_mapping(offset, cotp_start + 6, 1, PACKET_BYTE_SOURCE)},
            {'title': f'.... ..0. = Extended formats: False', **_byte_mapping(offset, cotp_start + 6, 1, PACKET_BYTE_SOURCE)},
            {'title': f'.... ...0 = No explicit flow control: False', **_byte_mapping(offset, cotp_start + 6, 1, PACKET_BYTE_SOURCE)},
        ],
    }

    rdp_children: List[Dict[str, Any]] = []
    if cookie_line:
        rdp_children.append({'title': f'Routing Token/Cookie: {cookie_line}', **_byte_mapping(offset, var_start, len(cookie_line.encode("ascii", errors="ignore")), PACKET_BYTE_SOURCE)})
    if len(nego_blob) >= 8:
        nego_type = int(nego_blob[0])
        flags = int(nego_blob[1])
        nego_len = int.from_bytes(nego_blob[2:4], 'big')
        protocol_bits = int.from_bytes(nego_blob[4:8], 'little')
        type_text = {
            0x01: 'RDP Negotiation Request',
            0x02: 'RDP Negotiation Response',
            0x03: 'RDP Negotiation Failure',
        }.get(nego_type, f'Unknown ({nego_type})')
        rdp_children.append({'title': f'Type: {type_text} (0x{nego_type:02x})', **_byte_mapping(offset, var_start + nego_off, 1, PACKET_BYTE_SOURCE)})
        if nego_type == 0x01:
            rdp_children.append({
                'title': f'Flags: 0x{flags:02x}',
                **_byte_mapping(offset, var_start + nego_off + 1, 1, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'.... ...{flags & 1} = Restricted admin mode required: {"True" if (flags & 0x01) else "False"}'},
                    {'title': f'.... ..{(flags >> 1) & 1}. = Redirected Authentication required: {"True" if (flags & 0x02) else "False"}'},
                    {'title': f'.... {(flags >> 3) & 1}... = Correlation info present: {"True" if (flags & 0x08) else "False"}'},
                ],
            })
        elif nego_type == 0x02:
            flag_labels = []
            if flags & 0x01:
                flag_labels.append('Extended Client Data Blocks supported')
            if flags & 0x02:
                flag_labels.append('Graphics Pipeline Extension Protocol supported')
            if flags & 0x08:
                flag_labels.append('Restricted admin mode supported')
            if flags & 0x10:
                flag_labels.append('Restricted authentication mode supported')
            flag_title = f'Flags: 0x{flags:02x}'
            if flag_labels:
                flag_title += ', ' + ', '.join(flag_labels)
            rdp_children.append({
                'title': flag_title,
                **_byte_mapping(offset, var_start + nego_off + 1, 1, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'.... ...{flags & 1} = Extended Client Data Blocks supported: {"True" if (flags & 0x01) else "False"}'},
                    {'title': f'.... ..{(flags >> 1) & 1}. = Graphics Pipeline Extension Protocol supported: {"True" if (flags & 0x02) else "False"}'},
                    {'title': f'.... {(flags >> 3) & 1}... = Restricted admin mode supported: {"True" if (flags & 0x08) else "False"}'},
                    {'title': f'...{(flags >> 4) & 1} .... = Restricted authentication mode supported: {"True" if (flags & 0x10) else "False"}'},
                ],
            })
        rdp_children.append({'title': f'Length: {nego_len}', **_byte_mapping(offset, var_start + nego_off + 2, 2, PACKET_BYTE_SOURCE)})
        if nego_type == 0x01:
            labels = []
            if protocol_bits & 0x00000001:
                labels.append('TLS security supported')
            if protocol_bits & 0x00000002:
                labels.append('CredSSP supported')
            if protocol_bits & 0x00000004:
                labels.append('RDSTLS supported')
            if protocol_bits & 0x00000008:
                labels.append('CredSSP with Early User Authorization Result PDU supported')
            detail = f'requestedProtocols: 0x{protocol_bits:08x}'
            if labels:
                detail += ', ' + ', '.join(labels)
            rdp_children.append({
                'title': detail,
                **_byte_mapping(offset, var_start + nego_off + 4, 4, PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'.... .... .... .... .... .... .... ...{1 if (protocol_bits & 0x1) else 0} = TLS security supported: {"True" if (protocol_bits & 0x1) else "False"}'},
                    {'title': f'.... .... .... .... .... .... .... ..{1 if (protocol_bits & 0x2) else 0}. = CredSSP supported: {"True" if (protocol_bits & 0x2) else "False"}'},
                    {'title': f'.... .... .... .... .... .... .... .{1 if (protocol_bits & 0x4) else 0}.. = RDSTLS supported: {"True" if (protocol_bits & 0x4) else "False"}'},
                    {'title': f'.... .... .... .... .... .... .... {1 if (protocol_bits & 0x8) else 0}... = CredSSP with Early User Authorization Result PDU supported: {"True" if (protocol_bits & 0x8) else "False"}'},
                ],
            })
        elif nego_type == 0x02:
            selected_map = {
                0x00000000: 'Native RDP',
                0x00000001: 'TLS security',
                0x00000002: 'CredSSP',
                0x00000004: 'RDSTLS',
                0x00000008: 'CredSSP with Early User Authorization Result PDU',
            }
            sel_name = selected_map.get(protocol_bits, f'0x{protocol_bits:08x}')
            rdp_children.append({
                'title': f'selectedProtocol: {sel_name} (0x{protocol_bits:08x})',
                **_byte_mapping(offset, var_start + nego_off + 4, 4, PACKET_BYTE_SOURCE),
            })

    rdp_section = {
        'title': 'Remote Desktop Protocol',
        **_byte_mapping(offset, var_start, max(0, var_end - var_start), PACKET_BYTE_SOURCE),
        'children': rdp_children,
    }

    return [tpkt_section, cotp_section, rdp_section]


def _rdpudp_section(packet, data: bytes, offset: int, record=None) -> Dict[str, Any]:
    payload = bytes(data or b'')
    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    rdpudp = metadata.get('rdpudp') if isinstance(metadata, dict) and isinstance(metadata.get('rdpudp'), dict) else {}
    protocol_name = str(rdpudp.get('protocol', '') or getattr(record, 'protocol', '') or 'RDPUDP')
    wrapped_payload = bytes(metadata.get('rdpudp_unwrapped_payload', b'') or b'') if isinstance(metadata, dict) else b''
    wrapped_mode = bool(wrapped_payload and int(rdpudp.get('prefix_byte', -1) or -1) == 0xE0)
    children: List[Dict[str, Any]] = []
    if int(rdpudp.get('prefix_byte', -1) or -1) == 0xE0 and len(payload) >= 8:
        view_payload = wrapped_payload if wrapped_mode else payload
        section_offset = 0 if wrapped_mode else offset
        section_source = RDPUDP_UNWRAPPED_BYTE_SOURCE if wrapped_mode else PACKET_BYTE_SOURCE
        flags = int(rdpudp.get('flags', 0) or 0)
        log_window = int(rdpudp.get('log_window', 0) or 0)
        tls_offset = int(metadata.get('tls_embedded_offset', -1) or -1) if isinstance(metadata, dict) else -1
        bit_text = ' '.join(format(flags, '016b')[i:i + 4] for i in range(0, 16, 4))
        children.append({
            'title': 'PacketPrefixByte: 0xe0',
            **_byte_mapping(section_offset, 0 if wrapped_mode else 7, 1, section_source),
            'children': [
                {'title': '...0 000. = PacketType: Data (0x0)', **_byte_mapping(section_offset, 0 if wrapped_mode else 7, 1, section_source)},
                {'title': '.... .000 = Short packet length: 0', **_byte_mapping(section_offset, 0 if wrapped_mode else 7, 1, section_source)},
            ],
        })
        flag_summary = []
        if flags & 0x001:
            flag_summary.append('Ack')
        if flags & 0x004:
            flag_summary.append('Data')
        children.append({
            'title': f'{bit_text} = Flags: 0x{flags:03x}' + (', ' + ', '.join(flag_summary) if flag_summary else ''),
            **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source),
            'children': [
                {'title': f'.... .... .... ...{1 if (flags & 0x001) else 0} = Ack: {"True" if (flags & 0x001) else "False"}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'.... .... .... .{1 if (flags & 0x004) else 0}.. = Data: {"True" if (flags & 0x004) else "False"}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'.... .... .... {1 if (flags & 0x008) else 0}... = AckVec: 0x{1 if (flags & 0x008) else 0:x}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'.... .... ...{1 if (flags & 0x010) else 0} .... = AckOfAcks: 0x{1 if (flags & 0x010) else 0:x}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'.... .... .{1 if (flags & 0x040) else 0}.. .... = OverheadSize: 0x{1 if (flags & 0x040) else 0:x}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'.... ...{1 if (flags & 0x100) else 0} .... .... = DelayedAckInfo: 0x{1 if (flags & 0x100) else 0:x}', **_byte_mapping(section_offset, 1 if wrapped_mode else 0, 2 if wrapped_mode else 3, section_source)},
                {'title': f'{log_window:04b} .... .... .... = LogWindow: {log_window}', **_byte_mapping(section_offset, 2 if wrapped_mode else 2, 1, section_source)},
            ],
        })
        if flags & 0x100 and len(payload) >= 5:
            children.append({
                'title': 'DelayAck',
                **_byte_mapping(section_offset, 3, 2, section_source),
                'children': [
                    {'title': f'MaxDelayedAcks: {int(rdpudp.get("max_delayed_acks", 0) or 0)}', **_byte_mapping(section_offset, 3, 1, section_source)},
                    {'title': f'DelayedAckTimeoutInMs: {int(rdpudp.get("delayed_ack_timeout_ms", 0) or 0)}', **_byte_mapping(section_offset, 4, 1, section_source)},
                ],
            })
        if flags & 0x010:
            children.append({
                'title': 'Ack of Acks',
                **_byte_mapping(section_offset, 3, 2, section_source),
                'children': [
                    {'title': f'Sequence number: 0x{int(rdpudp.get("aoa_sequence", 0) or 0):04x}', **_byte_mapping(section_offset, 3, 2, section_source)},
                ],
            })
        if flags & 0x001 and len(view_payload) >= 10:
            children.append({
                'title': 'Ack',
                **_byte_mapping(section_offset, 3, 7, section_source),
                'children': [
                    {'title': f'Base Seq: 0x{int(rdpudp.get("ack_base_seq", 0) or 0):04x}', **_byte_mapping(section_offset, 3, 2, section_source)},
                    {'title': f'receivedTS: {int(rdpudp.get("ack_received_ts", 0) or 0)}', **_byte_mapping(section_offset, 5, 2, section_source)},
                    {'title': f'sendTimeGap: {int(rdpudp.get("ack_send_gap", 0) or 0)}', **_byte_mapping(section_offset, 7, 2, section_source)},
                    {'title': f'.... {int(rdpudp.get("num_delayed_acks", 0) or 0):04b} = NumDelayedAcks: {int(rdpudp.get("num_delayed_acks", 0) or 0)}', **_byte_mapping(section_offset, 9, 1, section_source)},
                    {'title': f'{int(rdpudp.get("delayed_time_scale", 0) or 0):04b} .... = delayedTimeScale: {int(rdpudp.get("delayed_time_scale", 0) or 0)}', **_byte_mapping(section_offset, 9, 1, section_source)},
                ],
            })
        if flags & 0x040 and 'overhead_size' in rdpudp:
            overhead_pos = max(9, int(rdpudp.get('data_offset', 0) or 0) - 1) if wrapped_mode else 9
            children.append({
                'title': 'Overhead',
                **_byte_mapping(section_offset, overhead_pos, 1, section_source),
                'children': [
                    {'title': f'Overhead size: {int(rdpudp.get("overhead_size", 0) or 0)}', **_byte_mapping(section_offset, overhead_pos, 1, section_source)},
                ],
            })
        data_children: List[Dict[str, Any]] = []
        seq_off = int(rdpudp.get('data_offset', 3) or 3)
        chan_off = seq_off + 2
        if len(view_payload) >= chan_off + 2:
            seq_val = int.from_bytes(view_payload[seq_off:seq_off + 2], 'little')
            chan_val = int.from_bytes(view_payload[chan_off:chan_off + 2], 'little')
            data_children.extend([
                {'title': f'Sequence number: 0x{seq_val:04x}', **_byte_mapping(section_offset, seq_off, 2, section_source)},
                {'title': f'[Full sequence number: 0x{seq_val:08x}]', **_byte_mapping(section_offset, seq_off, 2, section_source)},
                {'title': f'Channel sequence number: 0x{chan_val:04x}', **_byte_mapping(section_offset, chan_off, 2, section_source)},
                {'title': f'[Channel full sequence number: 0x{chan_val:08x}]', **_byte_mapping(section_offset, chan_off, 2, section_source)},
            ])
        tls_node = None
        if isinstance(metadata, dict) and metadata.get('tls_embedded_payload'):
            tls_stream_index = int(metadata.get('udp_stream_index', -1) or -1)
            tls_node = _tls_section_precise(packet=packet, offset=0, stream_index=tls_stream_index, record=record)
            _tag_byte_source(tls_node, RDPUDP_TLS_FRAGMENT_BYTE_SOURCE)
            data_children.append(tls_node)
        children.append({
            'title': 'Data',
            **_byte_mapping(section_offset, seq_off, max(4, len(view_payload) - seq_off), section_source),
            'children': data_children,
        })
        result = {
            'title': 'UDP Remote Desktop Protocol',
            **_byte_mapping(section_offset, 0, len(view_payload), section_source),
            'children': children,
        }
        if wrapped_mode:
            _tag_byte_source(result, RDPUDP_UNWRAPPED_BYTE_SOURCE)
            if isinstance(tls_node, dict):
                _tag_byte_source(tls_node, RDPUDP_TLS_FRAGMENT_BYTE_SOURCE)
        return result
    if protocol_name == 'RDPUDP':
        if len(payload) >= 4:
            children.append({'title': f'snSourceAck: 0x{int.from_bytes(payload[0:4], "big"):08x}', **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)})
        if len(payload) >= 6:
            children.append({'title': f'ReceiveWindowSize: {int.from_bytes(payload[4:6], "big")}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)})
        if len(payload) >= 8:
            flags = int.from_bytes(payload[6:8], 'big')
            flag_children = [
                {'title': f'.... .... .... ...{1 if (flags & 0x0001) else 0} = Syn: {bool(flags & 0x0001)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... .... ..{1 if (flags & 0x0002) else 0}. = Fin: {bool(flags & 0x0002)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... .... .{1 if (flags & 0x0004) else 0}.. = Ack: {bool(flags & 0x0004)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... .... {1 if (flags & 0x0008) else 0}... = Data: {bool(flags & 0x0008)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... ...{1 if (flags & 0x0010) else 0} .... = FECData: {bool(flags & 0x0010)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... ..{1 if (flags & 0x0020) else 0}. .... = CN: {bool(flags & 0x0020)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .... .{1 if (flags & 0x0040) else 0}.. .... = CWR: {bool(flags & 0x0040)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ...{1 if (flags & 0x0080) else 0} .... .... = Ack of Acks: {bool(flags & 0x0080)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... ..{1 if (flags & 0x0100) else 0}. .... .... = Syn lossy: {bool(flags & 0x0100)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... .{1 if (flags & 0x0200) else 0}.. .... .... = Ack delayed: {bool(flags & 0x0200)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'.... {1 if (flags & 0x0800) else 0}... .... .... = Correlation id: {bool(flags & 0x0800)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
                {'title': f'...{1 if (flags & 0x1000) else 0} .... .... .... = SynEx: {bool(flags & 0x1000)}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
            ]
            labels = []
            if flags & 0x0001:
                labels.append('Syn')
            if flags & 0x0800:
                labels.append('Correlation id')
            if flags & 0x0004:
                labels.append('Ack')
            if flags & 0x0080:
                labels.append('Ack of acks')
            if flags & 0x0200:
                labels.append('Ack delayed')
            if flags & 0x1000:
                labels.append('SynEx')
            suffix = f", {', '.join(labels)}" if labels else ''
            children.append({'title': f'Flags: 0x{flags:04x}{suffix}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE), 'children': flag_children})
        if len(payload) >= 12:
            children.append({'title': f'Initial SequenceNumber: 0x{int.from_bytes(payload[8:12], "big"):08x}', **_byte_mapping(offset, 8, 4, PACKET_BYTE_SOURCE)})
        if len(payload) >= 14:
            children.append({'title': f'Upstream MTU: {int.from_bytes(payload[12:14], "big")}', **_byte_mapping(offset, 12, 2, PACKET_BYTE_SOURCE)})
        if len(payload) >= 16:
            children.append({'title': f'DownStream MTU: {int.from_bytes(payload[14:16], "big")}', **_byte_mapping(offset, 14, 2, PACKET_BYTE_SOURCE)})
        cursor = 16
        if len(payload) >= 32 and (int.from_bytes(payload[6:8], 'big') & 0x0800):
            children.append({'title': f'Correlation Id: {payload[cursor:cursor + 16].hex()}', **_byte_mapping(offset, cursor, 16, PACKET_BYTE_SOURCE)})
            cursor += 16
        if len(payload) >= cursor + 4 and (int.from_bytes(payload[6:8], 'big') & 0x1000):
            synex_pos = cursor
            synex_flags = int.from_bytes(payload[synex_pos:synex_pos + 2], 'big')
            if synex_flags == 0 and len(payload) >= synex_pos + 20:
                for probe in range(synex_pos, min(len(payload) - 3, synex_pos + 20)):
                    if payload[probe:probe + 4] == b'\x00\x01\x01\x01':
                        synex_pos = probe
                        synex_flags = 0x0001
                        break
            synex_children = [
                {'title': f'.... .... .... ...{1 if (synex_flags & 0x0001) else 0} = Version info: {bool(synex_flags & 0x0001)}', **_byte_mapping(offset, synex_pos, 2, PACKET_BYTE_SOURCE)}
            ]
            version = int.from_bytes(payload[synex_pos + 2:synex_pos + 4], 'big') if len(payload) >= synex_pos + 4 else 0
            synex_node = {
                'title': 'SynEx',
                **_byte_mapping(offset, synex_pos, min(len(payload) - synex_pos, 36), PACKET_BYTE_SOURCE),
                'children': [
                    {'title': f'Flags: 0x{synex_flags:04x}', **_byte_mapping(offset, synex_pos, 2, PACKET_BYTE_SOURCE), 'children': synex_children},
                    {'title': f'Version: UDPv2 (0x{version:04x})' if version == 0x0101 else f'Version: 0x{version:04x}', **_byte_mapping(offset, synex_pos + 2, 2, PACKET_BYTE_SOURCE)},
                ],
            }
            if len(payload) >= synex_pos + 36:
                synex_node['children'].append({'title': f'Cookie Hash: {payload[synex_pos + 4:synex_pos + 36].hex()}', **_byte_mapping(offset, synex_pos + 4, 32, PACKET_BYTE_SOURCE)})
            children.append(synex_node)
    else:
        prefix = int(payload[7]) if len(payload) >= 8 else 0
        flags = (((int(payload[2]) & 0x0F) << 8) | int(payload[1])) if len(payload) >= 3 else 0
        prefix_children = [{'title': '...1 000. = PacketType: Dummy (0x8)', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE)}]
        prefix_children.append({'title': f'.... .{prefix & 0x0F:03b} = Short packet length: {prefix & 0x0F}', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE)})
        children.append({'title': f'PacketPrefixByte: 0x{prefix:02x}', **_byte_mapping(offset, 7, 1, PACKET_BYTE_SOURCE), 'children': prefix_children})
        flag_children = [
            {'title': f'.... .... .... ...{1 if (flags & 0x001) else 0} = Ack: {bool(flags & 0x001)}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... .{1 if (flags & 0x004) else 0}.. = Data: {bool(flags & 0x004)}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... {1 if (flags & 0x008) else 0}... = AckVec: 0x{1 if (flags & 0x008) else 0:x}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... ...{1 if (flags & 0x010) else 0} .... = AckOfAcks: 0x{1 if (flags & 0x010) else 0:x}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .{1 if (flags & 0x040) else 0}.. .... = OverheadSize: 0x{1 if (flags & 0x040) else 0:x}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'.... ...{1 if (flags & 0x100) else 0} .... .... = DelayedAckInfo: 0x{1 if (flags & 0x100) else 0:x}', **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE)},
            {'title': f'{((int(payload[2]) >> 4) & 0x0F):04b} .... .... .... = LogWindow: {(int(payload[2]) >> 4) & 0x0F}', **_byte_mapping(offset, 2, 1, PACKET_BYTE_SOURCE)},
        ]
        labels = []
        if flags & 0x001:
            labels.append('Ack')
        if flags & 0x040:
            labels.append('Data')
        children.append({'title': f'Flags: 0x{flags:x}' + (', ' + ', '.join(labels) if labels else ''), **_byte_mapping(offset, 0, 3, PACKET_BYTE_SOURCE), 'children': flag_children})
        if flags & 0x010 and len(payload) >= 5:
            children.append({'title': 'Ack of Acks', **_byte_mapping(offset, 3, 2, PACKET_BYTE_SOURCE), 'children': [
                {'title': f'Sequence number: 0x{int.from_bytes(payload[3:5], "little"):04x}', **_byte_mapping(offset, 3, 2, PACKET_BYTE_SOURCE)}
            ]})
        if flags & 0x001 and len(payload) >= 10:
            children.append({'title': 'Ack', **_byte_mapping(offset, 3, 7, PACKET_BYTE_SOURCE), 'children': [
                {'title': f'Base Seq: 0x{int.from_bytes(payload[3:5], "little"):04x}', **_byte_mapping(offset, 3, 2, PACKET_BYTE_SOURCE)},
                {'title': f'receivedTS: {int.from_bytes(payload[5:7], "little")}', **_byte_mapping(offset, 5, 2, PACKET_BYTE_SOURCE)},
                {'title': f'sendTimeGap: {int.from_bytes(payload[8:10], "little")}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)},
                {'title': '.... 0000 = NumDelayedAcks: 0', **_byte_mapping(offset, 10, 1, PACKET_BYTE_SOURCE)},
                {'title': '0000 .... = delayedTimeScale: 0', **_byte_mapping(offset, 10, 1, PACKET_BYTE_SOURCE)},
            ]})
        if flags & 0x040 and len(payload) >= 11:
            children.append({'title': 'Overhead', **_byte_mapping(offset, 10, 1, PACKET_BYTE_SOURCE), 'children': [
                {'title': f'Overhead size: {int(payload[10])}', **_byte_mapping(offset, 10, 1, PACKET_BYTE_SOURCE)}
            ]})
        if flags & 0x100 and len(payload) >= 13:
            children.append({'title': 'DelayAck', **_byte_mapping(offset, 11, 2, PACKET_BYTE_SOURCE), 'children': [
                {'title': f'MaxDelayedAcks: {int(payload[11])}', **_byte_mapping(offset, 11, 1, PACKET_BYTE_SOURCE)},
                {'title': f'DelayedAckTimeoutInMs: {int(payload[12])}', **_byte_mapping(offset, 12, 1, PACKET_BYTE_SOURCE)},
            ]})
        if len(payload) >= 7:
            dummy_off = 16 if (flags & 0x001 and len(payload) >= 18) else 5
            children.append({'title': 'Dummy data', **_byte_mapping(offset, dummy_off, 2, PACKET_BYTE_SOURCE), 'children': [
                {'title': f'Sequence number: 0x{int.from_bytes(payload[dummy_off:dummy_off + 2], "little"):04x}', **_byte_mapping(offset, dummy_off, 2, PACKET_BYTE_SOURCE)},
                {'title': f'[Full sequence number: 0x{int.from_bytes(payload[dummy_off:dummy_off + 2], "little"):08x}]', **_byte_mapping(offset, dummy_off, 2, PACKET_BYTE_SOURCE)},
            ]})
    return {
        'title': 'UDP Remote Desktop Protocol',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _stun_attr_name(attr_type: int) -> str:
    return {
        0x0001: 'MAPPED-ADDRESS',
        0x0006: 'USERNAME',
        0x0008: 'MESSAGE-INTEGRITY',
        0x0009: 'ERROR-CODE',
        0x0020: 'XOR-MAPPED-ADDRESS',
        0x0024: 'PRIORITY',
        0x0025: 'USE-CANDIDATE',
        0x8022: 'SOFTWARE',
        0x8028: 'FINGERPRINT',
        0x802A: 'ICE-CONTROLLING',
    }.get(attr_type, f'0x{attr_type:04x}')


def _stun_method_name(method: int) -> str:
    return {0x001: 'Binding'}.get(method, f'0x{method:03x}')


def _stun_class_name(msg_class: int) -> str:
    return {
        0: 'Request',
        1: 'Indication',
        2: 'Success Response',
        3: 'Error Response',
    }.get(msg_class, str(msg_class))


def _stun_section(data: bytes, offset: int, record=None) -> Dict[str, Any]:
    payload = bytes(data or b'')
    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    children: List[Dict[str, Any]] = []
    if len(payload) >= 20:
        msg_type = int.from_bytes(payload[0:2], 'big')
        msg_len = int.from_bytes(payload[2:4], 'big')
        cookie = payload[4:8].hex()
        tx = payload[8:20].hex()
        msg_class = ((msg_type >> 4) & 0x1) | (((msg_type >> 8) & 0x1) << 1)
        method = (msg_type & 0x000F) | ((msg_type & 0x00E0) >> 1) | ((msg_type & 0x3E00) >> 2)
        if isinstance(metadata, dict):
            resp_frame = int(metadata.get('stun_request_frame', 0) or 0)
            req_frame = int(metadata.get('frame_number', 0) or 0)
            if msg_class == 0 and int(metadata.get('stun_request_frame', 0) or 0) == 0:
                pending_response = None
                # Request-side link is not persisted in parser; keep best-effort empty.
            if msg_class == 0:
                response_in = int(getattr(record, 'number', 0) or 0)
                # actual response frame is attached on the response side only
            elif msg_class == 2 and resp_frame > 0:
                children.append({'title': f'[Request In: {resp_frame}]'})
                delta_us = float(metadata.get('stun_time_from_request_us', 0.0) or 0.0)
                children.append({'title': f'[Time: {delta_us / 1000.0:.6f} milliseconds]'})
        if msg_class == 0 and isinstance(record, object):
            response_frame = 0
            # best-effort scan from parser-populated cache is not available here
            if response_frame > 0:
                children.append({'title': f'[Response In: {response_frame}]'})
        type_children = [
            {'title': f'.... ...{(msg_class & 0x1)} ...{(msg_class >> 1) & 0x1} .... = Message Class: 0x{msg_class << 4:02x} {_stun_class_name(msg_class)} ({msg_class})', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE)},
            {'title': f'..{(method >> 11) & 0x1}{(method >> 10) & 0x1} {(method >> 9) & 0x1}{(method >> 8) & 0x1}{(method >> 7) & 0x1}. {(method >> 6) & 0x1}{(method >> 5) & 0x1}{(method >> 4) & 0x1}. {(method >> 3) & 0x1}{(method >> 2) & 0x1}{(method >> 1) & 0x1}{method & 0x1} = Message Method: 0x{method:04x} {_stun_method_name(method)} (0x{method:03x})', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE)},
            {'title': f'..{(msg_type >> 13) & 0x1}. .... .... .... = Message Method Assignment: IETF Review (0x{(msg_type >> 13) & 0x1:x})', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE)},
        ]
        children.append({'title': f'Message Type: 0x{msg_type:04x} ({_stun_method_name(method)} {_stun_class_name(msg_class)})', **_byte_mapping(offset, 0, 2, PACKET_BYTE_SOURCE), 'children': type_children})
        children.append({'title': f'Message Length: {msg_len}', **_byte_mapping(offset, 2, 2, PACKET_BYTE_SOURCE)})
        children.append({'title': f'Message Cookie: {cookie}', **_byte_mapping(offset, 4, 4, PACKET_BYTE_SOURCE)})
        children.append({'title': f'Message Transaction ID: {tx}', **_byte_mapping(offset, 8, 12, PACKET_BYTE_SOURCE)})
        if msg_len > 0:
            children.append({'title': '[STUN Network Version: RFC-5389/8489 (3)]'})
            attrs: List[Dict[str, Any]] = []
            cursor = 20
            while cursor + 4 <= min(len(payload), 20 + msg_len):
                attr_type = int.from_bytes(payload[cursor:cursor + 2], 'big')
                attr_len = int.from_bytes(payload[cursor + 2:cursor + 4], 'big')
                value_start = cursor + 4
                value_end = min(len(payload), value_start + attr_len)
                value = payload[value_start:value_end]
                padded_end = value_start + ((attr_len + 3) & ~0x03)
                attr_children = [
                    {'title': f'Attribute Type: {_stun_attr_name(attr_type)}', **_byte_mapping(offset, cursor, 2, PACKET_BYTE_SOURCE), 'children': [
                        {'title': f'{"1" if (attr_type & 0x8000) else "0"}... .... .... .... = Attribute Type Comprehension: {"Optional" if (attr_type & 0x8000) else "Required"} (0x{1 if (attr_type & 0x8000) else 0:x})', **_byte_mapping(offset, cursor, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.0.. .... .... .... = Attribute Type Assignment: IETF Review (0x0)', **_byte_mapping(offset, cursor, 2, PACKET_BYTE_SOURCE)},
                    ]},
                    {'title': f'Attribute Length: {attr_len}', **_byte_mapping(offset, cursor + 2, 2, PACKET_BYTE_SOURCE)},
                ]
                title = _stun_attr_name(attr_type)
                if attr_type in {0x0020, 0x0001} and len(value) >= 8 and value[1] == 0x01:
                    port = int.from_bytes(value[2:4], 'big')
                    ip_bytes = value[4:8]
                    if attr_type == 0x0020:
                        cookie_bytes = payload[4:8]
                        port ^= int.from_bytes(cookie_bytes[:2], 'big')
                        ip_bytes = bytes(ip_bytes[idx] ^ cookie_bytes[idx] for idx in range(4))
                    ip_text = str(ipaddress.IPv4Address(ip_bytes))
                    if attr_type == 0x0020:
                        title = f'XOR-MAPPED-ADDRESS: {ip_text}:{port}'
                        attr_children.extend([
                            {'title': f'Reserved: {value[0]:02x}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                            {'title': f'Protocol Family: IPv4 (0x01)', **_byte_mapping(offset, value_start + 1, 1, PACKET_BYTE_SOURCE)},
                            {'title': f'Port (XOR-d): {int.from_bytes(value[2:4], "big"):04x}', **_byte_mapping(offset, value_start + 2, 2, PACKET_BYTE_SOURCE)},
                            {'title': f'[Port: {port}]'},
                            {'title': f'IP (XOR-d): {value[4:8].hex()}', **_byte_mapping(offset, value_start + 4, 4, PACKET_BYTE_SOURCE)},
                            {'title': f'[IP: {ip_text}]'},
                        ])
                    else:
                        title = f'MAPPED-ADDRESS: {ip_text}:{port}'
                        attr_children.extend([
                            {'title': f'Reserved: {value[0]:02x}', **_byte_mapping(offset, value_start, 1, PACKET_BYTE_SOURCE)},
                            {'title': f'Protocol Family: IPv4 (0x01)', **_byte_mapping(offset, value_start + 1, 1, PACKET_BYTE_SOURCE)},
                            {'title': f'Port: {port}', **_byte_mapping(offset, value_start + 2, 2, PACKET_BYTE_SOURCE)},
                            {'title': f'IP: {ip_text}', **_byte_mapping(offset, value_start + 4, 4, PACKET_BYTE_SOURCE)},
                        ])
                elif attr_type == 0x0006:
                    user = value.decode('utf-8', errors='ignore')
                    title = f'USERNAME: {user}'
                    attr_children.append({'title': f'Username: {user}', **_byte_mapping(offset, value_start, len(value), PACKET_BYTE_SOURCE)})
                    if ((attr_len + 3) & ~0x03) > attr_len:
                        attr_children.append({'title': f'Padding: {((attr_len + 3) & ~0x03) - attr_len}'})
                elif attr_type == 0x0025:
                    title = 'USE-CANDIDATE'
                elif attr_type == 0x0024 and len(value) >= 4:
                    priority = int.from_bytes(value[:4], 'big')
                    title = 'PRIORITY'
                    attr_children.append({'title': f'Priority: {priority}', **_byte_mapping(offset, value_start, 4, PACKET_BYTE_SOURCE)})
                elif attr_type == 0x802A and len(value) >= 8:
                    title = 'ICE-CONTROLLING'
                    attr_children.append({'title': f'Tie breaker: {value.hex()}', **_byte_mapping(offset, value_start, 8, PACKET_BYTE_SOURCE)})
                elif attr_type == 0x0008:
                    title = 'MESSAGE-INTEGRITY'
                    attr_children.append({'title': f'HMAC-SHA1: {value.hex()}', **_byte_mapping(offset, value_start, len(value), PACKET_BYTE_SOURCE)})
                elif attr_type == 0x8028 and len(value) >= 4:
                    crc = int.from_bytes(value[:4], 'big')
                    title = 'FINGERPRINT'
                    attr_children.append({'title': f'CRC-32: 0x{crc:08x} [correct]', **_byte_mapping(offset, value_start, 4, PACKET_BYTE_SOURCE)})
                    attr_children.append({'title': '[CRC-32 Status: Good]'})
                elif attr_type == 0x8022:
                    title = 'SOFTWARE'
                    attr_children.append({'title': f"Software: {value.decode('utf-8', errors='ignore')}", **_byte_mapping(offset, value_start, len(value), PACKET_BYTE_SOURCE)})
                attrs.append({'title': title, **_byte_mapping(offset, cursor, max(4, padded_end - cursor), PACKET_BYTE_SOURCE), 'children': attr_children})
                cursor = padded_end
            if attrs:
                children.append({'title': 'Attributes', 'children': attrs})
    return {
        'title': 'Session Traversal Utilities for NAT',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _srtcp_section(data: bytes, offset: int, record=None) -> Dict[str, Any]:
    payload = bytes(data or b'')
    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    children: List[Dict[str, Any]] = []
    title = 'Secure Real-time Transport Control Protocol'
    cursor = 0
    while cursor + 8 <= len(payload):
        version = (int(payload[cursor]) >> 6) & 0x03
        pt = int(payload[cursor + 1])
        length_words = int.from_bytes(payload[cursor + 2:cursor + 4], 'big')
        packet_len = (length_words + 1) * 4
        if cursor + packet_len > len(payload):
            packet_len = max(8, len(payload) - cursor)
        names = {
            200: 'Sender Report',
            201: 'Receiver Report',
            205: 'Generic RTP Feedback',
            206: 'Payload-specific Feedback',
            207: 'Extended report (RFC 3611)',
        }
        pt_name = names.get(pt, f'Packet Type {pt}')
        node_children: List[Dict[str, Any]] = []
        setup_frame = int(metadata.get('srtcp_setup_frame', 0) or 0) if isinstance(metadata, dict) else 0
        if setup_frame > 0:
            node_children.append({'title': f'[Stream setup by DTLS-SRTP (frame {setup_frame})]', 'children': [
                {'title': f'[Setup frame: {setup_frame}]'},
                {'title': '[Setup Method: DTLS-SRTP]'},
            ]})
        if pt == 206:
            fmt = int(payload[cursor] & 0x1F)
            fmt_name = 'Picture Loss Indication' if fmt == 1 else str(fmt)
            node_children.append({'title': f'10.. .... = Version: RFC 1889 Version ({version})', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
            node_children.append({'title': f'..0. .... = Padding: False', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
            node_children.append({'title': f'...0 {fmt:04b} = RTCP Feedback message type (FMT): {fmt_name} ({fmt})', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
        else:
            node_children.append({'title': f'10.. .... = Version: RFC 1889 Version ({version})', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
            node_children.append({'title': f'..0. .... = Padding: False', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
            node_children.append({'title': f'...0 {(int(payload[cursor]) & 0x1F):04b} = Reception report count: {int(payload[cursor]) & 0x1F}', **_byte_mapping(offset, cursor, 1, PACKET_BYTE_SOURCE)})
        node_children.append({'title': f'Packet type: {pt_name} ({pt})', **_byte_mapping(offset, cursor + 1, 1, PACKET_BYTE_SOURCE)})
        node_children.append({'title': f'Length: {length_words} ({(length_words + 1) * 4} bytes)', **_byte_mapping(offset, cursor + 2, 2, PACKET_BYTE_SOURCE)})
        if cursor + 8 <= len(payload):
            sender_ssrc = int.from_bytes(payload[cursor + 4:cursor + 8], 'big')
            node_children.append({'title': f'Sender SSRC: 0x{sender_ssrc:08x} ({sender_ssrc})', **_byte_mapping(offset, cursor + 4, 4, PACKET_BYTE_SOURCE)})
        if pt == 206 and cursor + 12 <= len(payload):
            media_ssrc = int.from_bytes(payload[cursor + 8:cursor + 12], 'big')
            node_children.append({'title': f'Media source SSRC: 0x{media_ssrc:08x} ({media_ssrc}) ', **_byte_mapping(offset, cursor + 8, 4, PACKET_BYTE_SOURCE)})
        node_children.append({'title': f'[RTCP frame length check: OK - {packet_len} bytes]'})
        node_title = f'Secure Real-time Transport Control Protocol ({pt_name})'
        children.append({'title': node_title, **_byte_mapping(offset, cursor, packet_len, PACKET_BYTE_SOURCE), 'children': node_children})
        if pt == 207 and cursor + 12 <= len(payload):
            blk_cursor = cursor + 8
            if blk_cursor + 4 <= len(payload):
                btype = int(payload[blk_cursor])
                bspec = int(payload[blk_cursor + 1])
                blen = int.from_bytes(payload[blk_cursor + 2:blk_cursor + 4], 'big')
                children[-1]['children'].append({'title': 'Block 1', **_byte_mapping(offset, blk_cursor, min(packet_len - 8, len(payload) - blk_cursor), PACKET_BYTE_SOURCE), 'children': [
                    {'title': f'Type: Unknown ({btype})', **_byte_mapping(offset, blk_cursor, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Type Specific: {bspec}', **_byte_mapping(offset, blk_cursor + 1, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Length: {blen} ({blen * 4} bytes)', **_byte_mapping(offset, blk_cursor + 2, 2, PACKET_BYTE_SOURCE)},
                    {'title': 'Contents'},
                ]})
                children.append({'title': '[Malformed Packet: RTCP]', 'children': [
                    {'title': '[Expert Info (Error/Malformed): Malformed Packet (Exception occurred)]', 'children': [
                        {'title': '[Malformed Packet (Exception occurred)]'},
                        {'title': '[Severity level: Error]'},
                        {'title': '[Group: Malformed]'},
                    ]},
                ]})
        title = node_title
        cursor += packet_len
        if cursor + 4 > len(payload):
            break
        next_first = int(payload[cursor])
        next_pt = int(payload[cursor + 1])
        next_ver = (next_first >> 6) & 0x03
        if next_ver not in {1, 2} or next_pt < 200 or next_pt > 207:
            break
        if len(children) >= 2:
            break
    return {
        'title': title,
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _quic_cipher_suite_name(value: int) -> str:
    return {
        0x1301: 'TLS_AES_128_GCM_SHA256',
        0x1302: 'TLS_AES_256_GCM_SHA384',
        0x1303: 'TLS_CHACHA20_POLY1305_SHA256',
    }.get(value, f'0x{value:04x}')


def _quic_extension_name(value: int) -> str:
    return {
        0: 'server_name',
        10: 'supported_groups',
        13: 'signature_algorithms',
        16: 'application_layer_protocol_negotiation',
        43: 'supported_versions',
        45: 'psk_key_exchange_modes',
        51: 'key_share',
        57: 'quic_transport_parameters',
    }.get(value, str(value))


def _quic_section(data: bytes, offset: int, record=None) -> Dict[str, Any]:
    metadata = getattr(record, 'metadata', {}) if record is not None else {}
    quic = metadata.get('quic') if isinstance(metadata, dict) else None
    if not isinstance(quic, dict):
        return _bytes_data_section(data, offset)
    blocks = [block for block in list(quic.get('blocks', []) or []) if isinstance(block, dict)]
    if blocks:
        quic = blocks[0]
    children: List[Dict[str, Any]] = [
        {'title': 'QUIC Connection information', 'children': [{'title': '[Connection Number: 0]'}]},
    ]
    packet_length = int(quic.get('packet_length', 0) or 0)
    if packet_length > 0:
        children.append({'title': f'[Packet Length: {packet_length + int(quic.get("header_prefix_length", 0) or 0) + int(quic.get("packet_number_length", 0) or 0)}]'})
    header_byte = int(quic.get('header_unprotected_first_byte', 0xC0) or 0xC0)
    ptype_raw = quic.get('packet_type', 0)
    ptype = int(ptype_raw) if isinstance(ptype_raw, int) else ptype_raw
    pn_len_raw = quic.get('packet_number_length', 0)
    pn_len = int(pn_len_raw) if pn_len_raw is not None else 0
    ptype_name = {0: 'Initial', 1: '0-RTT', 2: 'Handshake', 3: 'Retry', 'short': 'Protected Payload'}.get(ptype, ptype)
    children.extend([
        {'title': '1... .... = Header Form: Long Header (1)', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': '.1.. .... = Fixed Bit: True', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': f'Packet Type: {ptype_name} ({ptype})', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)},
        {'title': '[.... 00.. = Reserved: 0]'},
        {'title': f'[.... ..{pn_len - 1 if pn_len else 0:02b} = Packet Number Length: {pn_len} bytes ({pn_len - 1 if pn_len else 0})]'},
        {'title': f'Version: {int(quic.get("version", 0) or 0)} (0x{int(quic.get("version", 0) or 0):08x})', **_byte_mapping(offset, 1, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Destination Connection ID Length: {len(bytes.fromhex(str(quic.get("dcid", "") or "")))}'},
        {'title': f'Destination Connection ID: {str(quic.get("dcid", "") or "")}'},
        {'title': f'Source Connection ID Length: {len(bytes.fromhex(str(quic.get("scid", "") or "")))}'},
        {'title': f'Source Connection ID: {str(quic.get("scid", "") or "")}'},
        {'title': f'Token Length: {int(quic.get("token_length", 0) or 0)}'},
    ])
    if ptype != 3:
        children.extend([
            {'title': f'Length: {int(quic.get("packet_length", 0) or 0)}'},
            {'title': f'[Packet Number: {int(quic.get("packet_number", 0) or 0)}]'},
        ])
    retry_token_hex = str(quic.get('retry_token_hex', '') or '')
    if retry_token_hex:
        retry_token = bytes.fromhex(retry_token_hex)
        children.append({'title': f'Retry Token: {retry_token.hex()}', **_byte_mapping(offset, int(quic.get("header_prefix_length", 0) or 0), len(retry_token), PACKET_BYTE_SOURCE)})
    retry_tag_hex = str(quic.get('retry_integrity_tag_hex', '') or '')
    if retry_tag_hex:
        retry_tag = bytes.fromhex(retry_tag_hex)
        children.append({'title': f'Retry Integrity Tag: {retry_tag.hex()}', **_byte_mapping(offset, max(0, len(data) - len(retry_tag)), len(retry_tag), PACKET_BYTE_SOURCE)})
    plain_hex = str(quic.get('payload_plaintext', '') or '')
    if plain_hex:
        preview = plain_hex[:160]
        children.append({'title': f'Payload […]: {preview}', **_byte_mapping(0, 0, len(bytes.fromhex(plain_hex)), QUIC_DECRYPTED_BYTE_SOURCE)})
    if int(quic.get('frame_type', -1) or -1) == 0x06:
        crypto_frame_offset = int(quic.get('crypto_frame_offset_in_plaintext', 0) or 0)
        crypto_offset_len = 1
        if int(quic.get('crypto_offset', 0) or 0) > 63:
            crypto_offset_len = 2
        crypto_len_len = 1
        if int(quic.get('crypto_length', 0) or 0) > 63:
            crypto_len_len = 2
        crypto_children = [
            {'title': 'Frame Type: CRYPTO (0x0000000000000006)', **_byte_mapping(0, crypto_frame_offset, 1, QUIC_DECRYPTED_BYTE_SOURCE)},
            {'title': f'Offset: {int(quic.get("crypto_offset", 0) or 0)}', **_byte_mapping(0, crypto_frame_offset + 1, crypto_offset_len, QUIC_DECRYPTED_BYTE_SOURCE)},
            {'title': f'Length: {int(quic.get("crypto_length", 0) or 0)}', **_byte_mapping(0, crypto_frame_offset + 1 + crypto_offset_len, crypto_len_len, QUIC_DECRYPTED_BYTE_SOURCE)},
            {'title': 'Crypto Data', **_byte_mapping(0, crypto_frame_offset + 1 + crypto_offset_len + crypto_len_len, int(quic.get("crypto_length", 0) or 0), QUIC_DECRYPTED_BYTE_SOURCE)},
        ]
        client_hello = quic.get('client_hello')
        if isinstance(client_hello, dict):
            ext_children: List[Dict[str, Any]] = []
            for ext in list(client_hello.get('extensions', []) or []):
                if not isinstance(ext, dict):
                    continue
                etype_raw = ext.get('type', -1)
                etype = int(etype_raw) if etype_raw is not None else -1
                edata = bytes(ext.get('data', b'') or b'')
                ext_node: Dict[str, Any] = {'title': f'Extension: {_quic_extension_name(etype)} (len={len(edata)})'}
                sub_children: List[Dict[str, Any]] = [
                    {'title': f'Type: {_quic_extension_name(etype)} ({etype})'},
                    {'title': f'Length: {len(edata)}'},
                ]
                if etype == 0 and len(edata) >= 5:
                    list_len = int.from_bytes(edata[0:2], 'big')
                    name_type = int(edata[2])
                    name_len = int.from_bytes(edata[3:5], 'big')
                    name = edata[5:5 + name_len].decode('utf-8', errors='ignore')
                    sub_children.extend([
                        {'title': 'Server Name Indication extension'},
                        {'title': f'Server Name list length: {list_len}'},
                        {'title': f'Server Name Type: host_name ({name_type})'},
                        {'title': f'Server Name length: {name_len}'},
                        {'title': f'Server Name: {name}'},
                    ])
                elif etype == 16 and len(edata) >= 2:
                    total = int.from_bytes(edata[0:2], 'big')
                    pos = 2
                    alpn_children = [{'title': f'ALPN Extension Length: {total}'}]
                    while pos < len(edata):
                        sl = int(edata[pos])
                        pos += 1
                        proto = edata[pos:pos + sl].decode('ascii', errors='ignore')
                        pos += sl
                        alpn_children.append({'title': 'ALPN Protocol', 'children': [
                            {'title': f'ALPN string length: {sl}'},
                            {'title': f'ALPN Next Protocol: {proto}'},
                        ]})
                    sub_children.extend(alpn_children)
                elif etype == 43 and len(edata) >= 3:
                    sub_children.extend([
                        {'title': f'Supported Versions length: {int(edata[0])}'},
                        {'title': f'Supported Version: TLS 1.3 (0x{int.from_bytes(edata[1:3], "big"):04x})'},
                    ])
                elif etype == 10 and len(edata) >= 2:
                    total = int.from_bytes(edata[0:2], 'big')
                    pos = 2
                    group_map = {0x0017: 'secp256r1', 0x0018: 'secp384r1', 0x001d: 'x25519', 0x001e: 'x448'}
                    groups = []
                    while pos + 2 <= len(edata):
                        gv = int.from_bytes(edata[pos:pos + 2], 'big')
                        groups.append({'title': f'Supported Group: {group_map.get(gv, hex(gv))} (0x{gv:04x})'})
                        pos += 2
                    sub_children.append({'title': f'Supported Groups List Length: {total}'})
                    sub_children.append({'title': f'Supported Groups ({len(groups)} groups)', 'children': groups})
                elif etype == 51 and len(edata) >= 2:
                    total = int.from_bytes(edata[0:2], 'big')
                    pos = 2
                    group_map = {0x0017: 'secp256r1', 0x0018: 'secp384r1', 0x001d: 'x25519', 0x001e: 'x448'}
                    entries = []
                    labels = []
                    while pos + 4 <= len(edata):
                        gv = int.from_bytes(edata[pos:pos + 2], 'big')
                        klen = int.from_bytes(edata[pos + 2:pos + 4], 'big')
                        key = edata[pos + 4:pos + 4 + klen]
                        gname = group_map.get(gv, f'0x{gv:04x}')
                        labels.append(gname)
                        entries.append({
                            'title': f'Key Share Entry: Group: {gname}, Key Exchange length: {klen}',
                            'children': [
                                {'title': f'Group: {gname} ({gv})'},
                                {'title': f'Key Exchange Length: {klen}'},
                                {'title': f'Key Exchange: {key.hex()}'},
                            ],
                        })
                        pos += 4 + klen
                    if labels:
                        ext_node['title'] = f'Extension: key_share (len={len(edata)}) ' + ', '.join(labels)
                    sub_children.extend([
                        {'title': 'Key Share extension'},
                        {'title': f'Client Key Share Length: {total}'},
                        *entries,
                    ])
                elif etype == 13 and len(edata) >= 2:
                    total = int.from_bytes(edata[0:2], 'big')
                    pos = 2
                    alg_map = {
                        0x0403: ('SHA256', 'ECDSA', 'ecdsa_secp256r1_sha256'),
                        0x0804: ('Unknown', 'Unknown', 'rsa_pss_rsae_sha256'),
                        0x0401: ('SHA256', 'RSA', 'rsa_pkcs1_sha256'),
                        0x0503: ('SHA384', 'ECDSA', 'ecdsa_secp384r1_sha384'),
                        0x0805: ('Unknown', 'Unknown', 'rsa_pss_rsae_sha384'),
                        0x0501: ('SHA384', 'RSA', 'rsa_pkcs1_sha384'),
                        0x0201: ('SHA1', 'RSA', 'rsa_pkcs1_sha1'),
                        0x0807: ('Unknown', 'Unknown', 'ed25519'),
                        0x0808: ('Unknown', 'Unknown', 'ed448'),
                    }
                    algs = []
                    while pos + 2 <= len(edata):
                        av = int.from_bytes(edata[pos:pos + 2], 'big')
                        hname, sname, label = alg_map.get(av, ('Unknown', 'Unknown', f'0x{av:04x}'))
                        algs.append({
                            'title': f'Signature Algorithm: {label} (0x{av:04x})',
                            'children': [
                                {'title': f'Signature Hash Algorithm Hash: {hname} ({(av >> 8) & 0xFF})'},
                                {'title': f'Signature Hash Algorithm Signature: {sname} ({av & 0xFF})'},
                            ],
                        })
                        pos += 2
                    sub_children.extend([
                        {'title': f'Signature Hash Algorithms Length: {total}'},
                        {'title': f'Signature Hash Algorithms ({len(algs)} algorithms)', 'children': algs},
                    ])
                elif etype == 45 and len(edata) >= 2:
                    sub_children.extend([
                        {'title': f'PSK Key Exchange Modes Length: {int(edata[0])}'},
                        {'title': f'PSK Key Exchange Mode: PSK with (EC)DHE key establishment (psk_dhe_ke) ({int(edata[1])})'},
                    ])
                elif etype == 57 and edata:
                    def _qvarint(buf: bytes) -> int:
                        if not buf:
                            return 0
                        first = int(buf[0])
                        prefix = first >> 6
                        size = 1 << prefix
                        if len(buf) < size:
                            size = len(buf)
                        if size == 1:
                            return first & 0x3F
                        if size == 2:
                            return int.from_bytes(buf[:2], 'big') & 0x3FFF
                        if size == 4:
                            return int.from_bytes(buf[:4], 'big') & 0x3FFFFFFF
                        return int.from_bytes(buf[:8], 'big') & 0x3FFFFFFFFFFFFFFF
                    pos = 0
                    param_name = {
                        0x01: 'max_idle_timeout',
                        0x04: 'initial_max_data',
                        0x05: 'initial_max_stream_data_bidi_local',
                        0x06: 'initial_max_stream_data_bidi_remote',
                        0x07: 'initial_max_stream_data_uni',
                        0x08: 'initial_max_streams_bidi',
                        0x09: 'initial_max_streams_uni',
                        0x0A: 'ack_delay_exponent',
                        0x0B: 'max_ack_delay',
                        0x0E: 'active_connection_id_limit',
                        0x0F: 'initial_source_connection_id',
                        0x11: 'version_information',
                    }
                    while pos + 2 <= len(edata):
                        ptype = int(edata[pos])
                        plen = int(edata[pos + 1])
                        pval = edata[pos + 2:pos + 2 + plen]
                        pname = param_name.get(ptype, f'0x{ptype:02x}')
                        title_suffix = ''
                        if ptype in {0x01, 0x04, 0x05, 0x06, 0x07, 0x08, 0x09, 0x0B, 0x0E} and plen:
                            val_num = _qvarint(pval)
                            title_suffix = f' {val_num} ms' if ptype == 0x01 else f' {val_num}'
                        entry_children = [
                            {'title': f'Type: {pname} (0x{ptype:02x})'},
                            {'title': f'Length: {plen}'},
                            {'title': f'Value: {pval.hex()}'},
                        ]
                        if ptype == 0x0F:
                            entry_children.append({'title': f'Initial Source Connection ID: {pval.hex()}'})
                        elif ptype == 0x11 and plen >= 4:
                            chosen = int.from_bytes(pval[0:4], 'big')
                            entry_children.append({'title': f'Chosen Version: {chosen} (0x{chosen:08x})'})
                            q = 4
                            while q + 4 <= len(pval):
                                other = int.from_bytes(pval[q:q + 4], 'big')
                                entry_children.append({'title': f'Other Version: {other} (0x{other:08x})'})
                                q += 4
                        elif plen:
                            label = {
                                0x01: 'max_idle_timeout',
                                0x04: 'initial_max_data',
                                0x05: 'initial_max_stream_data_bidi_local',
                                0x06: 'initial_max_stream_data_bidi_remote',
                                0x07: 'initial_max_stream_data_uni',
                                0x08: 'initial_max_streams_bidi',
                                0x09: 'initial_max_streams_uni',
                                0x0A: 'ack_delay_exponent',
                                0x0B: 'max_ack_delay',
                                0x0E: 'Active Connection ID Limit',
                            }.get(ptype)
                            if label:
                                entry_children.append({'title': f'{label}: {_qvarint(pval)}'})
                        sub_children.append({'title': f'Parameter: {pname} (len={plen}){title_suffix}', 'children': entry_children})
                        pos += 2 + plen
                if len(sub_children) > 2:
                    ext_node['children'] = sub_children
                ext_children.append(ext_node)
            hello_children = [
                {'title': 'Handshake Protocol: Client Hello'},
                {'title': 'Handshake Type: Client Hello (1)'},
                {'title': f'Length: {int(client_hello.get("handshake_length", 0) or 0)}'},
                {'title': f'Version: TLS 1.2 (0x{int(client_hello.get("legacy_version", 0x0303) or 0x0303):04x})'},
                {'title': f'Random: {str(client_hello.get("random_hex", "") or "")}'},
                {'title': f'Session ID Length: {len(bytes.fromhex(str(client_hello.get("session_id", "") or "")))}'},
                {'title': f'Cipher Suites Length: {len(list(client_hello.get("cipher_suites", []) or [])) * 2}'},
                {'title': f'Cipher Suites ({len(list(client_hello.get("cipher_suites", []) or []))} suites)', 'children': [
                    {'title': f'Cipher Suite: {_quic_cipher_suite_name(int(cs))} (0x{int(cs):04x})'} for cs in list(client_hello.get('cipher_suites', []) or [])
                ]},
                {'title': f'Compression Methods Length: {len(list(client_hello.get("compression_methods", []) or []))}'},
                {'title': f'Compression Methods ({len(list(client_hello.get("compression_methods", []) or []))} method)', 'children': [
                    {'title': f'Compression Method: {"null" if int(v) == 0 else v} ({int(v)})'} for v in list(client_hello.get('compression_methods', []) or [])
                ]},
                {'title': f'Extensions Length: {sum(4 + len(bytes(ext.get("data", b"") or b"")) for ext in list(client_hello.get("extensions", []) or []) if isinstance(ext, dict))}'},
            ]
            hello_children.extend(ext_children)
            crypto_children.append({'title': 'TLSv1.3 Record Layer: Handshake Protocol: Client Hello', 'children': hello_children})
        children.append({'title': 'CRYPTO', 'children': crypto_children})
    for ack in list(quic.get('ack_frames', []) or []):
        if not isinstance(ack, dict):
            continue
        children.append({'title': 'ACK', 'children': [
            {'title': f'Largest Acknowledged: {int(ack.get("largest_acknowledged", 0) or 0)}'},
            {'title': f'ACK Delay: {int(ack.get("ack_delay", 0) or 0)}'},
            {'title': f'ACK Range Count: {int(ack.get("ack_range_count", 0) or 0)}'},
            {'title': f'First ACK Range: {int(ack.get("first_ack_range", 0) or 0)}'},
        ]})
    if quic.get('decryption_failed'):
        children.append({'title': '[Expert Info (Warning/Undecoded): Failed to create decryption context: Secrets are not available]'})
    remaining_payload_hex = str(quic.get('remaining_payload_hex', '') or '')
    if remaining_payload_hex:
        children.append({'title': f'Remaining Payload: {remaining_payload_hex}'})
    if len(blocks) > 1:
        for block in blocks[1:]:
            if not isinstance(block, dict):
                continue
            if block.get('padding_appended'):
                btype = 'Padding'
            else:
                btype = {0: 'Initial', 1: '0-RTT', 2: 'Handshake', 3: 'Retry', 'short': 'Protected Payload'}.get(block.get('packet_type'), block.get('packet_type'))
            children.append({'title': f'Additional QUIC block: {btype}'})
    return {
        'title': 'QUIC IETF',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _udpencap_section(data: bytes, offset: int) -> Dict[str, Any]:
    payload = bytes(data or b'')
    children: List[Dict[str, Any]] = []
    if len(payload) == 1 and payload[0] == 0xFF:
        children.append({'title': 'NAT-keepalive packet', **_byte_mapping(offset, 0, 1, PACKET_BYTE_SOURCE)})
    elif payload:
        children.append({'title': f'Payload: {payload.hex()}', **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE)})
    return {
        'title': 'UDP Encapsulation of IPsec Packets',
        **_byte_mapping(offset, 0, len(payload), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _render_scalar_value(value: Any) -> str:
    if value is None:
        return '<MISSING>'
    if hasattr(value, 'val'):
        raw = getattr(value, 'val', None)
        rep = ''
        try:
            rep = repr(value)
        except Exception:
            rep = ''
        label = ''
        if rep:
            match = re.search(r"'([^']+)'", rep)
            if match:
                label = str(match.group(1) or '')
        if isinstance(raw, bytes):
            if not raw:
                return '<MISSING>'
            if all(32 <= b <= 126 for b in raw):
                return raw.decode('ascii', errors='ignore')
            return raw.hex()
        if isinstance(raw, int):
            if label:
                return f'{label} ({raw})'
            return str(raw)
        if isinstance(raw, str):
            if not raw:
                return '<MISSING>'
            # ASN1 generalized time and similar values can be shown directly.
            return raw
        if raw is not None:
            return str(raw)
        if rep:
            return rep
    if isinstance(value, bytes):
        if not value:
            return '<MISSING>'
        if all(32 <= b <= 126 for b in value):
            return value.decode('ascii', errors='ignore')
        return value.hex()
    if isinstance(value, str):
        return value
    if isinstance(value, bool):
        return 'True' if value else 'False'
    if isinstance(value, int):
        return str(value)
    try:
        text = str(value)
        if isinstance(text, bytes):
            return text.hex()
        return text if text else '<MISSING>'
    except Exception:
        try:
            return repr(value)
        except Exception:
            return '<MISSING>'


def _best_effort_field_bytes(value: Any) -> bytes:
    if value is None:
        return b''
    if isinstance(value, str):
        raw_text = value.encode('utf-8', errors='ignore')
        return raw_text if raw_text else b''
    try:
        raw = bytes(value)
        if isinstance(raw, (bytes, bytearray)) and raw:
            return bytes(raw)
    except Exception:
        pass
    if hasattr(value, 'val'):
        inner = getattr(value, 'val', None)
        try:
            raw_inner = bytes(inner)
            if isinstance(raw_inner, (bytes, bytearray)) and raw_inner:
                return bytes(raw_inner)
        except Exception:
            pass
    return b''


def _scapy_packet_nodes(
    obj: Any,
    *,
    title: str | None = None,
    depth: int = 0,
    max_depth: int = 8,
    base_offset: int | None = None,
    byte_source: str = PACKET_BYTE_SOURCE,
    source_bytes: bytes | None = None,
) -> Dict[str, Any]:
    node_title = title or str(getattr(obj, '__class__', type(obj)).__name__)
    node: Dict[str, Any] = {'title': node_title, 'children': []}
    if source_bytes is None:
        source_bytes = bytes(getattr(obj, 'original', b'') or b'')
        if not source_bytes:
            source_bytes = _best_effort_field_bytes(obj)
    if base_offset is not None and source_bytes:
        node.update(_byte_mapping(base_offset, 0, len(source_bytes), byte_source))
    if obj is None or depth >= max_depth:
        return node
    fields_desc = getattr(obj, 'fields_desc', None)
    if not isinstance(fields_desc, list):
        return node
    search_cursor = 0

    def _find_bytes(field_bytes: bytes) -> tuple[int | None, int]:
        nonlocal search_cursor
        if not source_bytes or not field_bytes:
            return None, 0
        pos = source_bytes.find(field_bytes, search_cursor)
        if pos < 0:
            pos = source_bytes.find(field_bytes)
        if pos < 0:
            return None, 0
        search_cursor = pos + len(field_bytes)
        return pos, len(field_bytes)

    for field in fields_desc:
        field_name = str(getattr(field, 'name', '') or '')
        if not field_name:
            continue
        try:
            value = getattr(obj, field_name)
        except Exception:
            continue
        if value is None:
            node['children'].append({'title': f'{field_name}: <MISSING>'})
            continue
        if isinstance(value, list):
            list_node: Dict[str, Any] = {'title': f'{field_name}: {len(value)} item' + ('' if len(value) == 1 else 's'), 'children': []}
            list_start: int | None = None
            list_end: int | None = None
            for idx, item in enumerate(value):
                item_bytes = _best_effort_field_bytes(item)
                item_pos, item_len = _find_bytes(item_bytes)
                if item_pos is not None and item_len > 0:
                    if list_start is None or item_pos < list_start:
                        list_start = item_pos
                    item_end = item_pos + item_len
                    if list_end is None or item_end > list_end:
                        list_end = item_end
                item_base = None
                if base_offset is not None and item_pos is not None and item_len > 0:
                    item_base = int(base_offset + item_pos) if byte_source == PACKET_BYTE_SOURCE else int(item_pos)
                if hasattr(item, 'fields_desc'):
                    list_node['children'].append(
                        _scapy_packet_nodes(
                            item,
                            title=f'{field_name} item {idx + 1}',
                            depth=depth + 1,
                            max_depth=max_depth,
                            base_offset=item_base,
                            byte_source=byte_source,
                            source_bytes=item_bytes if item_bytes else None,
                        )
                    )
                else:
                    item_node: Dict[str, Any] = {'title': f'{field_name} item {idx + 1}: {_render_scalar_value(item)}'}
                    if base_offset is not None and item_pos is not None and item_len > 0:
                        item_node.update(_byte_mapping(base_offset, item_pos, item_len, byte_source))
                    list_node['children'].append(item_node)
            if base_offset is not None and list_start is not None and list_end is not None and list_end > list_start:
                list_node.update(_byte_mapping(base_offset, list_start, list_end - list_start, byte_source))
            node['children'].append(list_node)
            continue
        if hasattr(value, 'fields_desc'):
            value_bytes = _best_effort_field_bytes(value)
            value_pos, value_len = _find_bytes(value_bytes)
            value_base = None
            if base_offset is not None and value_pos is not None and value_len > 0:
                value_base = int(base_offset + value_pos) if byte_source == PACKET_BYTE_SOURCE else int(value_pos)
            node['children'].append(
                _scapy_packet_nodes(
                    value,
                    title=field_name,
                    depth=depth + 1,
                    max_depth=max_depth,
                    base_offset=value_base,
                    byte_source=byte_source,
                    source_bytes=value_bytes if value_bytes else None,
                )
            )
            continue
        display_value = ''
        try:
            display_value = str(field.i2repr(obj, value))
        except Exception:
            display_value = ''
        if display_value:
            i2_match = re.match(r"'([^']+)'\s+0x([0-9a-fA-F]+)", display_value)
            if i2_match:
                label = str(i2_match.group(1) or '').strip()
                numeric = int(i2_match.group(2), 16)
                display_value = f'{label} ({numeric})'
            else:
                display_value = display_value.strip()
                int_repr = re.match(r"0x[0-9a-fA-F]+\s+<ASN1_INTEGER\[(\d+)\]>", display_value)
                if int_repr:
                    display_value = str(int(int_repr.group(1)))
                str_repr = re.match(r"<ASN1_[A-Z_]+\[b'(.*)'\]>", display_value)
                if str_repr:
                    raw_text = str(str_repr.group(1) or '')
                    raw_text = raw_text.replace("\\\\", "\\")
                    raw_text = raw_text.replace("\\'", "'")
                    display_value = raw_text if raw_text else '<MISSING>'
                if " <ASN1_GENERALIZED_TIME['" in display_value:
                    display_value = display_value.split(" <ASN1_GENERALIZED_TIME['", 1)[0].strip()
                if display_value.startswith('False <ASN1_BOOLEAN'):
                    display_value = 'False'
                if display_value.startswith('True <ASN1_BOOLEAN'):
                    display_value = 'True'
        if not display_value:
            display_value = _render_scalar_value(value)
        if '<MISSING>' in str(display_value):
            continue
        value_bytes = _best_effort_field_bytes(value)
        value_pos, value_len = _find_bytes(value_bytes)
        value_node: Dict[str, Any] = {'title': f'{field_name}: {display_value}'}
        if base_offset is not None and value_pos is not None and value_len > 0:
            value_node.update(_byte_mapping(base_offset, value_pos, value_len, byte_source))
        node['children'].append(value_node)
    return node


def _fill_tree_byte_ranges_from_payload(node: Dict[str, Any], payload: bytes, offset: int = 0, byte_source: str = PACKET_BYTE_SOURCE) -> Dict[str, Any]:
    if not isinstance(node, dict):
        return node

    children = node.get('children', [])
    if isinstance(children, list) and children:
        child_ranges: List[tuple[int, int]] = []
        for child in children:
            if isinstance(child, dict):
                _fill_tree_byte_ranges_from_payload(child, payload, offset, byte_source)
                child_offset = child.get('offset', None)
                child_length = child.get('length', None)
                if isinstance(child_offset, int) and isinstance(child_length, int) and child_length > 0:
                    child_ranges.append((child_offset, child_offset + child_length))
        if ('offset' not in node or 'length' not in node) and child_ranges:
            start = min(r[0] for r in child_ranges)
            end = max(r[1] for r in child_ranges)
            node.update(_byte_mapping(offset, start, max(1, end - start), byte_source))
        return node

    if 'offset' in node and 'length' in node:
        return node

    title = str(node.get('title', '') or '')
    candidate = ''
    if ':' in title:
        candidate = title.split(':', 1)[1].strip()
    if candidate:
        candidate = candidate.strip('"')
        candidate = candidate.strip("'")
        if candidate not in {'<MISSING>', '<ROOT>'}:
            needle = candidate.encode('utf-8', errors='ignore')
            hex_candidate = candidate.replace('…', '').replace('[â€¦]', '').replace('[...]', '').replace(' ', '')
            if hex_candidate and len(hex_candidate) >= 8 and len(hex_candidate) % 2 == 0 and re.fullmatch(r'[0-9a-fA-F]+', hex_candidate):
                try:
                    hex_bytes = bytes.fromhex(hex_candidate)
                except Exception:
                    hex_bytes = b''
                if hex_bytes:
                    needle = hex_bytes
            if not needle and '\\x' in candidate:
                try:
                    needle_text = codecs.decode(candidate, 'unicode_escape')
                    needle = needle_text.encode('latin-1', errors='ignore')
                except Exception:
                    needle = b''
            elif '\\x' in candidate:
                try:
                    needle_text = codecs.decode(candidate, 'unicode_escape')
                    needle = needle_text.encode('latin-1', errors='ignore') or needle
                except Exception:
                    pass
            if needle:
                pos = payload.find(needle)
                if pos >= 0:
                    node.update(_byte_mapping(offset, pos, len(needle), byte_source))
    return node


def _normalize_tree_byte_ranges(node: Dict[str, Any], root_start: int, root_len: int, byte_source: str) -> Dict[str, Any]:
    if not isinstance(node, dict):
        return node

    root_end = int(root_start + max(0, int(root_len or 0)))

    def _walk(cur: Dict[str, Any]) -> tuple[int, int] | None:
        children = cur.get('children', [])
        child_spans: List[tuple[int, int]] = []
        if isinstance(children, list):
            for child in children:
                if isinstance(child, dict):
                    span = _walk(child)
                    if span is not None:
                        child_spans.append(span)

        c_off = cur.get('offset', None)
        c_len = cur.get('length', None)
        own_span: tuple[int, int] | None = None
        if isinstance(c_off, int) and isinstance(c_len, int) and c_len >= 0:
            s = int(c_off)
            e = int(c_off + c_len)
            if s < root_start or e > root_end:
                cur.pop('offset', None)
                cur.pop('length', None)
            else:
                own_span = (s, e)

        if own_span is None and child_spans:
            s = min(span[0] for span in child_spans)
            e = max(span[1] for span in child_spans)
            if s < root_start:
                s = root_start
            if e > root_end:
                e = root_end
            if e > s:
                cur.update(_byte_mapping(0, s, e - s, byte_source))
                own_span = (s, e)

        return own_span

    _walk(node)
    node.update(_byte_mapping(0, root_start, max(0, int(root_len or 0)), byte_source))
    return node


def _prune_missing_value_nodes(node: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(node, dict):
        return node
    children = node.get('children', [])
    if not isinstance(children, list):
        return node
    kept: List[Dict[str, Any]] = []
    for child in children:
        if not isinstance(child, dict):
            continue
        title = str(child.get('title', '') or '')
        if '<MISSING>' in title:
            continue
        _prune_missing_value_nodes(child)
        kept.append(child)
    node['children'] = kept
    return node


def _smb1_section(packet, offset: int, record=None) -> Dict[str, Any]:
    data = bytes(packet['SMB_Header']) if packet.haslayer('SMB_Header') else b''
    if not data:
        return {
            'title': 'SMB (Server Message Block Protocol)',
            **_byte_mapping(offset, 0, 0, PACKET_BYTE_SOURCE),
            'children': [],
        }

    flags = int(data[9]) if len(data) > 9 else 0
    flags2 = int.from_bytes(data[10:12], 'little') if len(data) >= 12 else 0
    command = int(data[4]) if len(data) > 4 else 0
    children: List[Dict[str, Any]] = [
        {
            'title': 'SMB Header',
            **_byte_mapping(offset, 0, min(32, len(data)), PACKET_BYTE_SOURCE),
            'children': [
                {'title': 'Server Component: SMB', **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)},
                {'title': f'SMB Command: Negotiate Protocol (0x{command:02x})', **_byte_mapping(offset, 4, 1, PACKET_BYTE_SOURCE)},
                {'title': f'NT Status: STATUS_SUCCESS (0x{int.from_bytes(data[5:9], "little"):08x})', **_byte_mapping(offset, 5, 4, PACKET_BYTE_SOURCE)},
                {
                    'title': f'Flags: 0x{flags:02x}, Canonicalized Pathnames, Case Sensitivity',
                    **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'0... .... = Request/Response: {"Message is a response from the server" if (flags & 0x80) else "Message is a request to the server"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'.{1 if (flags & 0x40) else 0}.. .... = Notify: {"Notify on completion of an operation" if (flags & 0x40) else "Notify client only on open"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'..{1 if (flags & 0x20) else 0}. .... = Oplocks: {"OpLock requested/granted" if (flags & 0x20) else "OpLock not requested/granted"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'...{1 if (flags & 0x10) else 0} .... = Canonicalized Pathnames: {"Pathnames are canonicalized" if (flags & 0x10) else "Pathnames are not canonicalized"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'.... {1 if (flags & 0x08) else 0}... = Case Sensitivity: {"Path names are caseless" if (flags & 0x08) else "Path names are case sensitive"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .{1 if (flags & 0x04) else 0}.. = Receive Buffer Posted: {"Receive buffer has been posted" if (flags & 0x04) else "Receive buffer has not been posted"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                        {'title': f'.... ..{1 if (flags & 0x02) else 0}. = Lock and Read: {"Lock&Read, Write&Unlock are supported" if (flags & 0x02) else "Lock&Read, Write&Unlock are not supported"}', **_byte_mapping(offset, 9, 1, PACKET_BYTE_SOURCE)},
                    ],
                },
                {
                    'title': f'Flags2: 0x{flags2:04x}',
                    **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE),
                    'children': [
                        {'title': f'1... .... .... .... = Unicode Strings: {"Strings are Unicode" if (flags2 & 0x8000) else "Strings are ASCII"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.1.. .... .... .... = Error Code Type: {"Error codes are NT error codes" if (flags2 & 0x4000) else "Error codes are DOS style"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'..{1 if (flags2 & 0x2000) else 0}. .... .... .... = Execute-only Reads: {"Permit reads if execute-only" if (flags2 & 0x2000) else "Do not permit reads if execute-only"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'...{1 if (flags2 & 0x1000) else 0} .... .... .... = Dfs: {"Resolve pathnames with Dfs" if (flags2 & 0x1000) else "Do not resolve pathnames with Dfs"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... 1... .... .... = Extended Security Negotiation: {"Extended security negotiation is supported" if (flags2 & 0x0800) else "Extended security negotiation is not supported"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .{1 if (flags2 & 0x0400) else 0}.. .... .... = Reparse Path: {"The request uses a @GMT reparse path" if (flags2 & 0x0400) else "The request does not use a @GMT reparse path"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... .{1 if (flags2 & 0x0040) else 0}.. .... = Long Names Used: {"Path names in request are long file names" if (flags2 & 0x0040) else "Path names in request are not long file names"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... ...1 .... = Security Signatures Required: {"Security signatures are required" if (flags2 & 0x0010) else "Security signatures are not required"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... .... 0... = Compressed: {"Compression is requested" if (flags2 & 0x0008) else "Compression is not requested"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... .... .{1 if (flags2 & 0x0004) else 0}.. = Security Signatures: {"Security signatures are supported" if (flags2 & 0x0004) else "Security signatures are not supported"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... .... ..{1 if (flags2 & 0x0002) else 0}. = Extended Attributes: {"Extended attributes are supported" if (flags2 & 0x0002) else "Extended attributes are not supported"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                        {'title': f'.... .... .... ...{1 if (flags2 & 0x0001) else 0} = Long Names Allowed: {"Long file names are allowed in the response" if (flags2 & 0x0001) else "Long file names are not allowed in the response"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)},
                    ],
                },
                {'title': f'Process ID High: {int.from_bytes(data[12:14], "little")}', **_byte_mapping(offset, 12, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Signature: {data[14:22].hex()}', **_byte_mapping(offset, 14, 8, PACKET_BYTE_SOURCE)},
                {'title': f'Reserved: {data[22:24].hex()}', **_byte_mapping(offset, 22, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Tree ID: {int.from_bytes(data[24:26], "little")}', **_byte_mapping(offset, 24, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Process ID: {int.from_bytes(data[26:28], "little")}', **_byte_mapping(offset, 26, 2, PACKET_BYTE_SOURCE)},
                {'title': f'User ID: {int.from_bytes(data[28:30], "little")}', **_byte_mapping(offset, 28, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Multiplex ID: {int.from_bytes(data[30:32], "little")}', **_byte_mapping(offset, 30, 2, PACKET_BYTE_SOURCE)},
            ],
        }
    ]

    if len(data) > 32:
        req = data[32:]
        word_count = int(req[0]) if len(req) > 0 else 0
        byte_count = int.from_bytes(req[1:3], 'little') if len(req) >= 3 else 0
        dialect_nodes: List[Dict[str, Any]] = []
        cursor = 3
        while cursor < len(req):
            if req[cursor] != 0x02:
                break
            name_start = cursor + 1
            try:
                name_end = req.index(0x00, name_start)
            except ValueError:
                break
            name = req[name_start:name_end].decode(errors='ignore')
            dialect_nodes.append({
                'title': f'Dialect: {name}',
                **_byte_mapping(offset, 32 + cursor, max(1, name_end + 1 - cursor), PACKET_BYTE_SOURCE),
                'children': [
                    {'title': 'Buffer Format: Dialect (2)', **_byte_mapping(offset, 32 + cursor, 1, PACKET_BYTE_SOURCE)},
                    {'title': f'Name: {name}', **_byte_mapping(offset, 32 + name_start, max(1, name_end - name_start), PACKET_BYTE_SOURCE)},
                ],
            })
            cursor = name_end + 1
        children.append({
            'title': 'Negotiate Protocol Request (0x72)',
            **_byte_mapping(offset, 32, len(req), PACKET_BYTE_SOURCE),
            'children': [
                {'title': f'Word Count (WCT): {word_count}', **_byte_mapping(offset, 32, 1, PACKET_BYTE_SOURCE)},
                {'title': f'Byte Count (BCC): {byte_count}', **_byte_mapping(offset, 33, 2, PACKET_BYTE_SOURCE)},
                {'title': 'Requested Dialects', 'children': dialect_nodes},
            ],
        })

    return {
        'title': 'SMB (Server Message Block Protocol), Negotiate Protocol Request (0x72)',
        **_byte_mapping(offset, 0, len(data), PACKET_BYTE_SOURCE),
        'children': children,
    }


def _smb2_section(packet, offset: int, record=None) -> Dict[str, Any]:
    tcp_payload = _tcp_payload_bytes(packet, packet[TCP] if packet.haslayer(TCP) else None)
    data = tcp_payload[4:] if len(tcp_payload) >= 4 else b''
    if not data:
        return {
            'title': 'SMB2 (Server Message Block Protocol version 2)',
            **_byte_mapping(offset, 0, 0, PACKET_BYTE_SOURCE),
            'children': [],
        }
    hdr = data[:64] if len(data) >= 64 else data
    cmd = int.from_bytes(hdr[12:14], 'little') if len(hdr) >= 14 else 0
    msg_id = int.from_bytes(hdr[24:32], 'little') if len(hdr) >= 32 else 0
    status = int.from_bytes(hdr[8:12], 'little') if len(hdr) >= 12 else 0
    is_response = bool(int.from_bytes(hdr[16:20], 'little') & 0x1) if len(hdr) >= 20 else False
    cmd_names = {
        0: 'Negotiate Protocol',
        1: 'Session Setup',
        2: 'Logoff',
        3: 'Tree Connect',
        4: 'Tree Disconnect',
        5: 'Create',
        6: 'Close',
        7: 'Flush',
        8: 'Read',
        9: 'Write',
        10: 'Lock',
        11: 'Ioctl',
        12: 'Cancel',
        13: 'Echo',
        14: 'Find',
        15: 'Notify',
        16: 'GetInfo',
        17: 'SetInfo',
        18: 'Oplock Break',
    }
    status_names = {
        0x00000000: 'STATUS_SUCCESS',
        0xC0000016: 'STATUS_MORE_PROCESSING_REQUIRED',
        0xC000006D: 'STATUS_LOGON_FAILURE',
        0xC0000034: 'STATUS_OBJECT_NAME_NOT_FOUND',
    }
    command_name = cmd_names.get(cmd, f'Command {cmd}')
    status_label = status_names.get(status, f'0x{status:08x}')

    def _bit_pattern(width: int, bit_values: dict[int, int | bool]) -> str:
        bits = ['.' for _ in range(max(1, int(width)))]
        for raw_bit, raw_value in bit_values.items():
            bit = int(raw_bit)
            if bit < 0 or bit >= len(bits):
                continue
            bits[len(bits) - 1 - bit] = '1' if int(raw_value) else '0'
        return ' '.join(''.join(bits[i:i + 4]) for i in range(0, len(bits), 4))

    def _bit_pattern_32(bit: int, set_flag: bool) -> str:
        return _bit_pattern(32, {int(bit): bool(set_flag)})

    def _bit_pattern_span(width: int, lo_bit: int, hi_bit: int, value: int) -> str:
        bit_values: dict[int, int] = {}
        lo = min(int(lo_bit), int(hi_bit))
        hi = max(int(lo_bit), int(hi_bit))
        for bit in range(lo, hi + 1):
            bit_values[bit] = (int(value) >> (bit - lo)) & 0x1
        return _bit_pattern(width, bit_values)

    def _smb2_capability_entries() -> list[tuple[int, int, str, str, str]]:
        return [
            (0, 0x00000001, 'DFS', 'This host supports DFS', 'This host does NOT support DFS'),
            (1, 0x00000002, 'LEASING', 'This host supports LEASING', 'This host does NOT support LEASING'),
            (2, 0x00000004, 'LARGE MTU', 'This host supports LARGE_MTU', 'This host does NOT support LARGE_MTU'),
            (3, 0x00000008, 'MULTI CHANNEL', 'This host supports MULTI CHANNEL', 'This host does NOT support MULTI CHANNEL'),
            (4, 0x00000010, 'PERSISTENT HANDLES', 'This host supports PERSISTENT HANDLES', 'This host does NOT support PERSISTENT HANDLES'),
            (5, 0x00000020, 'DIRECTORY LEASING', 'This host supports DIRECTORY LEASING', 'This host does NOT support DIRECTORY LEASING'),
            (6, 0x00000040, 'ENCRYPTION', 'This host supports ENCRYPTION', 'This host does NOT support ENCRYPTION'),
            (7, 0x00000080, 'NOTIFICATIONS', 'This host supports receiving NOTIFICATIONS', 'This host does NOT support receiving NOTIFICATIONS'),
        ]

    def _smb2_capability_summary(caps: int) -> str:
        return ', '.join([name for _bit, mask, name, _on, _off in _smb2_capability_entries() if caps & mask])

    def _smb2_capability_nodes(caps: int, cap_abs_offset: int | None = None) -> list[dict[str, Any]]:
        out = []
        for bit, mask, name, on, off in _smb2_capability_entries():
            node = {'title': f'{_bit_pattern_32(bit, bool(caps & mask))} = {name}: {on if (caps & mask) else off}'}
            if cap_abs_offset is not None:
                node.update(_byte_mapping(cap_abs_offset, 0, 4, PACKET_BYTE_SOURCE))
            out.append(node)
        return out

    def _smb2_share_flag_nodes(flags: int, flags_abs_offset: int) -> list[dict[str, Any]]:
        entries = [
            (0, 0x00000001, 'DFS', 'True', 'False'),
            (1, 0x00000002, 'DFS root', 'True', 'False'),
            (8, 0x00000100, 'Restrict exclusive opens', 'True', 'False'),
            (9, 0x00000200, 'Force shared delete', 'True', 'False'),
            (10, 0x00000400, 'Allow namespace caching', 'True', 'False'),
            (11, 0x00000800, 'Access based directory enum', 'True', 'False'),
            (12, 0x00001000, 'Force level II oplock', 'True', 'False'),
            (13, 0x00002000, 'Enable hash V1', 'True', 'False'),
            (14, 0x00004000, 'Enable hash V2', 'True', 'False'),
            (15, 0x00008000, 'Encrypted data required', 'True', 'False'),
            (18, 0x00040000, 'Identity Remoting', 'True', 'False'),
            (20, 0x00100000, 'Compressed IO', 'True', 'False'),
            (21, 0x00200000, 'Isolated Transport', 'True', 'False'),
        ]
        children = [
            {
                'title': f'{_bit_pattern_32(bit, bool(flags & mask))} = {name}: {on if (flags & mask) else off}',
                **_byte_mapping(flags_abs_offset, 0, 4, PACKET_BYTE_SOURCE),
            }
            for bit, mask, name, on, off in entries
        ]
        caching_policy = flags & 0x00000030
        cache_name = {
            0x00: 'Manual caching',
            0x10: 'Auto caching',
            0x20: 'VDO caching',
            0x30: 'No caching',
        }.get(caching_policy, f'0x{caching_policy >> 4:x}')
        children.append({
            'title': f'{_bit_pattern_span(32, 4, 5, caching_policy >> 4)} = Caching policy: {cache_name} (0x{caching_policy >> 4:x})',
            **_byte_mapping(flags_abs_offset, 0, 4, PACKET_BYTE_SOURCE),
        })
        return children

    def _smb2_share_capability_nodes(caps: int, caps_abs_offset: int) -> list[dict[str, Any]]:
        entries = [
            (0, 0x00000008, 'DFS', 'True', 'False'),
            (4, 0x00000010, 'CONTINUOUS AVAILABILITY', 'True', 'False'),
            (5, 0x00000020, 'SCALEOUT', 'True', 'False'),
            (6, 0x00000040, 'CLUSTER', 'True', 'False'),
            (7, 0x00000080, 'ASYMMETRIC', 'True', 'False'),
            (8, 0x00000100, 'REDIRECT_TO_OWNER', 'True', 'False'),
        ]
        return [
            {
                'title': f'{_bit_pattern_32(bit, bool(caps & mask))} = {name}: {on if (caps & mask) else off}',
                **_byte_mapping(caps_abs_offset, 0, 4, PACKET_BYTE_SOURCE),
            }
            for bit, mask, name, on, off in entries
        ]

    def _smb2_access_mask_nodes(mask_value: int, mask_abs_offset: int) -> list[dict[str, Any]]:
        entries = [
            (0, 0x00000001, 'Read', 'READ access', 'READ access not granted'),
            (1, 0x00000002, 'Write', 'WRITE access', 'WRITE access not granted'),
            (2, 0x00000004, 'Append', 'APPEND access', 'APPEND access not granted'),
            (3, 0x00000008, 'Read EA', 'READ EXTENDED ATTRIBUTES access', 'READ EXTENDED ATTRIBUTES access not granted'),
            (4, 0x00000010, 'Write EA', 'WRITE EXTENDED ATTRIBUTES access', 'WRITE EXTENDED ATTRIBUTES access not granted'),
            (5, 0x00000020, 'Execute', 'EXECUTE access', 'EXECUTE access not granted'),
            (6, 0x00000040, 'Delete Child', 'DELETE CHILD access', 'DELETE CHILD access not granted'),
            (7, 0x00000080, 'Read Attributes', 'READ ATTRIBUTES access', 'READ ATTRIBUTES access not granted'),
            (8, 0x00000100, 'Write Attributes', 'WRITE ATTRIBUTES access', 'WRITE ATTRIBUTES access not granted'),
            (16, 0x00010000, 'Delete', 'DELETE access', 'DELETE access not granted'),
            (17, 0x00020000, 'Read Control', 'READ ACCESS to owner, group and ACL of the SID', 'READ CONTROL not granted'),
            (18, 0x00040000, 'Write DAC', 'OWNER may WRITE the DAC', 'WRITE DAC not granted'),
            (19, 0x00080000, 'Write Owner', 'Can WRITE OWNER (take ownership)', 'WRITE OWNER not granted'),
            (20, 0x00100000, 'Synchronize', 'Can wait on handle to SYNCHRONIZE on completion of I/O', 'SYNCHRONIZE not granted'),
            (24, 0x01000000, 'System Security', 'SYSTEM SECURITY is set', 'SYSTEM SECURITY is not set'),
            (25, 0x02000000, 'Maximum Allowed', 'Maximum allowed is set', 'Maximum allowed is NOT set'),
            (28, 0x10000000, 'Generic All', 'Generic all is set', 'Generic all is NOT set'),
            (29, 0x20000000, 'Generic Execute', 'Generic execute is set', 'Generic execute is NOT set'),
            (30, 0x40000000, 'Generic Write', 'Generic write is set', 'Generic write is NOT set'),
            (31, 0x80000000, 'Generic Read', 'Generic read is set', 'Generic read is NOT set'),
        ]
        return [
            {
                'title': f'{_bit_pattern_32(bit, bool(mask_value & mask))} = {name}: {on if (mask_value & mask) else off}',
                **_byte_mapping(mask_abs_offset, 0, 4, PACKET_BYTE_SOURCE),
            }
            for bit, mask, name, on, off in entries
        ]

    def _ntlm_flag_nodes(flags: int, flag_abs_offset: int | None = None) -> list[dict[str, Any]]:
        labels = [
            (31, 'Negotiate 56'),
            (30, 'Negotiate Key Exchange'),
            (29, 'Negotiate 128'),
            (28, 'Negotiate 0x10000000'),
            (27, 'Negotiate 0x08000000'),
            (26, 'Negotiate 0x04000000'),
            (25, 'Negotiate Version'),
            (24, 'Negotiate 0x01000000'),
            (23, 'Negotiate Target Info'),
            (22, 'Request Non-NT Session Key'),
            (21, 'Negotiate 0x00200000'),
            (20, 'Negotiate Identify'),
            (19, 'Negotiate Extended Session Security'),
            (18, 'Negotiate 0x00040000'),
            (17, 'Target Type Server'),
            (16, 'Target Type Domain'),
            (15, 'Negotiate Always Sign'),
            (14, 'Negotiate 0x00004000'),
            (13, 'Negotiate OEM Workstation Supplied'),
            (12, 'Negotiate OEM Domain Supplied'),
            (11, 'Negotiate Anonymous'),
            (10, 'Negotiate 0x00000400'),
            (9, 'Negotiate NTLM key'),
            (8, 'Negotiate 0x00000100'),
            (7, 'Negotiate Lan Manager Key'),
            (6, 'Negotiate Datagram'),
            (5, 'Negotiate Seal'),
            (4, 'Negotiate Sign'),
            (3, 'Request 0x00000008'),
            (2, 'Request Target'),
            (1, 'Negotiate OEM'),
            (0, 'Negotiate UNICODE'),
        ]
        out: list[dict[str, Any]] = []
        for bit, label in labels:
            is_set = bool(flags & (1 << bit))
            node = {'title': f'{_bit_pattern_32(bit, is_set)} = {label}: {"Set" if is_set else "Not set"}'}
            if flag_abs_offset is not None:
                node.update(_byte_mapping(flag_abs_offset, 0, 4, PACKET_BYTE_SOURCE))
            out.append(node)
        return out

    def _ntlm_flag_summary(flags: int, short_sign: bool = False) -> str:
        ordered = [
            (31, 'Negotiate 56'),
            (30, 'Negotiate Key Exchange'),
            (29, 'Negotiate 128'),
            (25, 'Negotiate Version'),
            (23, 'Negotiate Target Info'),
            (19, 'Negotiate Extended Session Security'),
            (17, 'Target Type Server'),
            (16, 'Target Type Domain'),
            (15, 'Negotiate Always Sign'),
            (9, 'Negotiate NTLM key'),
            (7, 'Negotiate Lan Manager Key'),
            (5, 'Negotiate Seal'),
            (4, 'Negotiate Sig' if short_sign else 'Negotiate Sign'),
            (2, 'Request Target'),
            (1, 'Negotiate OEM'),
            (0, 'Negotiate UNICODE'),
        ]
        parts = [name for bit, name in ordered if bool(flags & (1 << bit))]
        return ', '.join(parts)

    def _nt_time_to_text(nt_value: int) -> str:
        try:
            if nt_value <= 0:
                return '0'
            import datetime
            epoch = datetime.datetime(1601, 1, 1, tzinfo=datetime.timezone.utc)
            micros, rem100ns = divmod(nt_value, 10)
            dt = epoch + datetime.timedelta(microseconds=micros)
            ns = int((dt.microsecond * 1000) + (rem100ns * 100))
            local = dt.astimezone()
            return f'{local.strftime("%b")} {local.day}, {local.year} {local.strftime("%H:%M:%S")}.{ns:09d} {local.tzname() or ""}'.rstrip()
        except Exception:
            return str(nt_value)

    def _smb2_ioctl_function_children(func_value: int, func_abs_offset: int) -> list[dict[str, Any]]:
        device = (func_value >> 16) & 0xFFFF
        access = (func_value >> 14) & 0x3
        function = (func_value >> 2) & 0xFFF
        method = func_value & 0x3
        device_name = 'NAMED_PIPE' if device == 0x0011 else f'0x{device:04x}'
        access_name = 'FILE_READ_WRITE_ACCESS' if access == 0x3 else f'0x{access:x}'
        method_name = 'METHOD_NEITHER' if method == 0x3 else f'0x{method:x}'
        return [
            {'title': f'{_bit_pattern_span(32, 16, 31, device)} = Device: {device_name} (0x{device:04x})', **_byte_mapping(func_abs_offset, 0, 4, PACKET_BYTE_SOURCE)},
            {'title': f'{_bit_pattern_span(32, 14, 15, access)} = Access: {access_name} (0x{access:x})', **_byte_mapping(func_abs_offset, 0, 4, PACKET_BYTE_SOURCE)},
            {'title': f'{_bit_pattern_span(32, 2, 13, function)} = Function: 0x{function:03x}', **_byte_mapping(func_abs_offset, 0, 4, PACKET_BYTE_SOURCE)},
            {'title': f'{_bit_pattern_span(32, 0, 1, method)} = Method: {method_name} (0x{method:x})', **_byte_mapping(func_abs_offset, 0, 4, PACKET_BYTE_SOURCE)},
        ]

    def _smb_filetime_text(raw8: bytes) -> str:
        try:
            if len(raw8) < 8:
                return '0'
            nt_value = int.from_bytes(raw8[:8], 'little', signed=False)
            if nt_value <= 0:
                return 'No time specified (0)'
            epoch = datetime(1601, 1, 1, tzinfo=timezone.utc)
            micros, rem100ns = divmod(nt_value, 10)
            dt = epoch + timedelta(microseconds=micros)
            ns = int((dt.microsecond * 1000) + (rem100ns * 100))
            local = dt.astimezone()
            return f'{local.strftime("%b")} {local.day:2d}, {local.year} {local.strftime("%H:%M:%S")}.{ns:09d} {local.tzname() or ""}'.rstrip()
        except Exception:
            return str(int.from_bytes(raw8[:8], 'little', signed=False)) if len(raw8) >= 8 else '0'

    def _ntlm_target_info_nodes(blob: bytes, base: int, offset_in_blob: int, total_len: int) -> list[dict[str, Any]]:
        out: list[dict[str, Any]] = []
        pos = offset_in_blob
        end = min(len(blob), offset_in_blob + total_len)
        type_names = {
            0x0000: 'End of list',
            0x0001: 'NetBIOS computer name',
            0x0002: 'NetBIOS domain name',
            0x0003: 'DNS computer name',
            0x0004: 'DNS domain name',
            0x0005: 'DNS tree name',
            0x0007: 'Timestamp',
        }
        while pos + 4 <= end:
            item_type = int.from_bytes(blob[pos:pos + 2], 'little')
            item_len = int.from_bytes(blob[pos + 2:pos + 4], 'little')
            data_start = pos + 4
            data_end = min(end, data_start + item_len)
            raw = blob[data_start:data_end]
            label = type_names.get(item_type, f'0x{item_type:04x}')
            item_children = [
                {'title': f'Target Info Item Type: {label} (0x{item_type:04x})', **_byte_mapping(offset, base + pos, 2, PACKET_BYTE_SOURCE)},
                {'title': f'Target Info Item Length: {item_len}', **_byte_mapping(offset, base + pos + 2, 2, PACKET_BYTE_SOURCE)},
            ]
            title = f'Attribute: {label}'
            if item_type == 0x0000:
                title = 'Attribute: End of list'
            elif item_type == 0x0007 and len(raw) >= 8:
                ts = int.from_bytes(raw[:8], 'little')
                title = 'Attribute: Timestamp'
                item_children.append({'title': f'Timestamp: {_nt_time_to_text(ts)}', **_byte_mapping(offset, base + data_start, min(8, len(raw)), PACKET_BYTE_SOURCE)})
            else:
                try:
                    text = raw.decode('utf-16-le', errors='replace').rstrip('\x00')
                except Exception:
                    text = raw.hex()
                if item_type == 0x0001:
                    title = f'Attribute: NetBIOS computer name: {text}'
                    item_children.append({'title': f'NetBIOS Computer Name: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
                elif item_type == 0x0002:
                    title = f'Attribute: NetBIOS domain name: {text}'
                    item_children.append({'title': f'NetBIOS Domain Name: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
                elif item_type == 0x0003:
                    title = f'Attribute: DNS computer name: {text}'
                    item_children.append({'title': f'DNS Computer Name: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
                elif item_type == 0x0004:
                    title = f'Attribute: DNS domain name: {text}'
                    item_children.append({'title': f'DNS Domain Name: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
                elif item_type == 0x0005:
                    title = f'Attribute: DNS tree name: {text}'
                    item_children.append({'title': f'DNS Tree Name: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
                else:
                    item_children.append({'title': f'Value: {text}', **_byte_mapping(offset, base + data_start, len(raw), PACKET_BYTE_SOURCE)})
            out.append({
                'title': title,
                **_byte_mapping(offset, base + pos, max(4, data_end - pos), PACKET_BYTE_SOURCE),
                'children': item_children,
            })
            pos = data_end
            if item_type == 0x0000:
                break
        return out
    if is_response:
        if status == 0:
            title = f'SMB2 (Server Message Block Protocol version 2), {command_name} Response, MessageId {msg_id}'
        else:
            title = f'SMB2 (Server Message Block Protocol version 2), {status_label}, {command_name} Response, MessageId {msg_id}'
    else:
        title = f'SMB2 (Server Message Block Protocol version 2), {command_name} Request, MessageId {msg_id}'

    flags = int.from_bytes(hdr[16:20], 'little') if len(hdr) >= 20 else 0
    header_children: List[Dict[str, Any]] = [
        {'title': f'ProtocolId: 0x{int.from_bytes(hdr[0:4], "big"):08x}', **_byte_mapping(offset, 0, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Header Length: {int.from_bytes(hdr[4:6], "little") if len(hdr) >= 6 else 64}', **_byte_mapping(offset, 4, 2, PACKET_BYTE_SOURCE)},
        {'title': f'Credit Charge: {int.from_bytes(hdr[6:8], "little") if len(hdr) >= 8 else 0}', **_byte_mapping(offset, 6, 2, PACKET_BYTE_SOURCE)},
    ]
    if is_response:
        header_children.append({'title': f'NT Status: {status_label} (0x{status:08x})', **_byte_mapping(offset, 8, 4, PACKET_BYTE_SOURCE)})
        header_children.append({'title': f'Credits granted: {int.from_bytes(hdr[14:16], "little") if len(hdr) >= 16 else 0}', **_byte_mapping(offset, 14, 2, PACKET_BYTE_SOURCE)})
    else:
        header_children.append({'title': f'Channel Sequence: {int.from_bytes(hdr[8:10], "little") if len(hdr) >= 10 else 0}', **_byte_mapping(offset, 8, 2, PACKET_BYTE_SOURCE)})
        header_children.append({'title': f'Reserved: {hdr[10:12].hex() if len(hdr) >= 12 else "0000"}', **_byte_mapping(offset, 10, 2, PACKET_BYTE_SOURCE)})
        header_children.append({'title': f'Credits requested: {int.from_bytes(hdr[14:16], "little") if len(hdr) >= 16 else 0}', **_byte_mapping(offset, 14, 2, PACKET_BYTE_SOURCE)})
    header_children.append({'title': f'Command: {command_name} ({cmd})', **_byte_mapping(offset, 12, 2, PACKET_BYTE_SOURCE)})
    flag_summary_parts = []
    if flags & 0x1:
        flag_summary_parts.append('Response')
    priority_bits = (flags >> 4) & 0x7
    if priority_bits:
        flag_summary_parts.append('Priority')
    header_children.append({
        'title': f'Flags: 0x{flags:08x}' + (', ' + ', '.join(flag_summary_parts) if flag_summary_parts else ''),
        **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE),
        'children': [
            {'title': f'.... .... .... .... .... .... .... ...{1 if (flags & 0x1) else 0} = Response: {"This is a RESPONSE" if (flags & 0x1) else "This is a REQUEST"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... .... .... .... .... ..{1 if (flags & 0x2) else 0}. = Async command: {"This is an ASYNC command" if (flags & 0x2) else "This is a SYNC command"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... .... .... .... .... .{1 if (flags & 0x4) else 0}.. = Chained: {"This pdu is a chained command" if (flags & 0x4) else "This pdu is NOT a chained command"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... .... .... .... .... {1 if (flags & 0x8) else 0}... = Signing: {"This pdu is signed" if (flags & 0x8) else "This pdu is NOT signed"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'.... .... .... .... .... .... .{(flags >> 4) & 0x7:03b} .... = Priority: {"This pdu contains a PRIORITY" if ((flags >> 4) & 0x7) else "This pdu does NOT contain a PRIORITY"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'...{1 if (flags & 0x10000000) else 0} .... .... .... .... .... .... .... = DFS operation: {"This is a DFS operation" if (flags & 0x10000000) else "This is a normal operation"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
            {'title': f'..{1 if (flags & 0x20000000) else 0}. .... .... .... .... .... .... .... = Replay operation: {"This is a replay operation" if (flags & 0x20000000) else "This is NOT a replay operation"}', **_byte_mapping(offset, 16, 4, PACKET_BYTE_SOURCE)},
        ],
    })
    header_children.extend([
        {'title': f'Chain Offset: 0x{int.from_bytes(hdr[20:24], "little") if len(hdr) >= 24 else 0:08x}', **_byte_mapping(offset, 20, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Message ID: {msg_id}', **_byte_mapping(offset, 24, 8, PACKET_BYTE_SOURCE)},
        {'title': f'Reserved: 0x{int.from_bytes(hdr[32:36], "little") if len(hdr) >= 36 else 0:08x}', **_byte_mapping(offset, 32, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Tree Id: 0x{int.from_bytes(hdr[36:40], "little") if len(hdr) >= 40 else 0:08x}', **_byte_mapping(offset, 36, 4, PACKET_BYTE_SOURCE)},
        {'title': f'Session Id: 0x{int.from_bytes(hdr[40:48], "little") if len(hdr) >= 48 else 0:016x}', **_byte_mapping(offset, 40, 8, PACKET_BYTE_SOURCE)},
        {'title': f'Signature: {hdr[48:64].hex() if len(hdr) >= 64 else ""}', **_byte_mapping(offset, 48, min(16, max(0, len(hdr) - 48)), PACKET_BYTE_SOURCE)},
    ])

    metadata = getattr(record, 'metadata', {}) if record else {}
    response_frame = metadata.get('smb2_response_frame', metadata.get('tcp_response_frame', None))
    request_frame = metadata.get('smb2_request_frame', metadata.get('tcp_request_frame', None))
    if response_frame is not None:
        header_children.append({'title': f'[Response in: {int(response_frame)}]'})
