                            version_local = _byte_mapping(offset, cursor + s1, max(0, q - s1), local_byte_source)
                            _name_text, q2 = _ber_text_at(bytes(chunk), q)
                            name_local = _byte_mapping(offset, cursor + q, max(0, q2 - q), local_byte_source)
